INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('2', 'ሐዋርያዊ ተልዕኮ', '028', '<p>የዚህ ትምህርት መሰረታዊ ዓላማ የቤተ ክርስቲያን አገልጋዮች በተለይ ሰባኪያነ ወንጌል መምህራን፣አባቶች ካህናት እና ዲያቆናት የስብከት ዘዴ እንዲሁም ከአንድ ሰባኪ የሚጠበቁ ነገሮች ምንድን ናቸው አንድ ሰባኪስ ሰባኪ ለመባል ምን ማሟላት አለበት የሚለዉን ነገር መሰረት ለማስጨበጥ የሚረዳ ትምህርት ነው።</p>', '', '', 'ከፍተኛ', '', '250.00', 'ዲ/ን ሶፎንያስ ደመቀ', 'uploads/course_pdfs/1782256244_c5f19218bf.pdf', '', '', '', '', '', '', '', '', '', '2026-06-24 02:10:44', NULL, NULL);
INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('3', 'አገልግሎት እና መንፈሳዊ ሕይወት', '029', '<p>በዚህ ኮርስ የቤተ ክርስቲያን ልጆች ስለ መንፈሳዊ ሕይወት ምንነት፣ስለ አገልግሎት እና የበረከት ዉጤቱ ተረድተው ክርስቲያኖች ከቃል ይልቅ የተግባር ሰዎች የሚሆኑበት የትምህርት አይነት ነው።</p>', '', '', 'ከፍተኛ', '', '300.00', 'ዲ/ን ሶፎንያስ ደመቀ', 'uploads/course_pdfs/1782258075_a551589c5e.pdf', '', '', '', '', '', '', '', '', '', '2026-06-24 02:41:15', NULL, NULL);
INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('4', 'ነገረ ቅባት', '030', '<p>ይህ የትምህርት አይነት እንደዋናነት በነገረ መለኮት ነገረ ሥጋዌ ላይ ያጠነጠነ ሲሆን ነገረ ቅባት ከተዋሕዶ ጋር ያለው የአስተምህሮ ልዩነት ምንድን ነው የሚለዉን እያነጻጸርን የምንመለከትበት ነው።</p>', '', '', 'ከፍተኛ', '', '350.00', 'ዲ/ን ሶፎንያስ ደመቀ', NULL, '', '', '', '', '', '', '', '', '', '2026-06-24 02:46:48', NULL, NULL);
INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('5', 'ነገረ ሃይማኖት', '027', '<p>ይህ ትምህርት የሚያተኩረዉ የቤተ ክርስቲያን ልጆች ምሥጢረ ሥላሴን፣ከ3ቱ አካል አንዱ አካል እግዚአብሔር ወልድ ማለትም ምሥጢረ ሥጋዌን  ምንነት እና ግንዛቤ በሰፊዉ እንዲረዱ የሚያደርግ ሲሆን በአጠቃላይ 5ቱን አዕማደ ምሥጢር የሚያውቁበት የትምህርት ክፍል ነው።</p>', '', '', 'ከፍተኛ', '', '500.00', 'ዲ/ን ሶፎንያስ ደመቀ', 'uploads/course_pdfs/1782259088_b781b796a9.pdf', '', '', '', '', '', '', '', '', '', '2026-06-24 02:58:08', NULL, NULL);
INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('6', 'ሐዋርያዊ ተልዕኮ', '012', '<div>\n<p><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <em><span style=\"text-decoration: underline;\">&nbsp;ሐዋርያዊ ተልዕኮ እና ኦርቶዶክሳዊ የስብከት ዘዴ</span></em></strong></p>\n</div>\n<div>❖.ስብከት የሚለው ቃል \"ሰበከ\" አስተማረ፣ አዋጀ ነገረ ከሚለው የግዕዝ&nbsp;ቃል የተገኘ ነው፡፡በግሪክ፣ኬሪግማ(kerygma) በእንግሊዝኛ sermonl&nbsp;ይባላል፡፡ ተዛማጅ /ተመሳሳይ/ የሆነ ትርጉም አለው፡፡ ማስተማር አዋጅ&nbsp;መንገር የሚለውን ይተረጉማሉ፡፡</div>\n<div>↪ የቤተክርስቲያን ዋናው ተልዕኮዋ ሰዎችን..</div>\n<div>✦ . ከአለማመን ወደ ማመን ማምጣት፣</div>\n<div>✦ . ያመኑትን ደግሞ በእምነታቸው ማጽናት ነው፡፡</div>\n<div>&nbsp;</div>\n<div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"text-decoration: underline;\"><em><strong> የስብከት አይነቶች</strong></em></span></div>\n<div>✳.ይዘትን መሠረት በማድረግ የስብከት ዓይነት በሦስት ይከፈላሉ፡፡</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; እነርሱም:-</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 👉፩ኛ.ትምህርት</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 👉፪ኛ.ትምህርታዊ ስብከት እና</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 👉፫ኛ.ስብከት ናቸው።</div>\n<div>\n<div>✔ በአጭሩ ስለ ስብከት አይነቶች ጠቅለል አድርገን ስንመለከት&nbsp;እነዚህን ነጥቦች ማየት እንቺላለን።</div>\n<div><strong>✳.ኬሪግማቲክ:</strong>-የማያምኑን አረማውያን ሰዎችን እግዚአብሔርን&nbsp;ካለማመን ወደ ማመን የምንመልስበት የስብከት ዓይነት ነው።</div>\n<div><strong>✳.ዲዳክቲክ(ዲያሌክቲክ):-</strong>ያመኑትን፣ነገር ግን ያልጠነከሩትን አዲስ&nbsp;አማንያንን፤ንዑስ ክርስቲያንን የምንጸናበት የስብከት አይነት ነው።</div>\n<div>↪ አምነው የነበሩ፣ነገር ግን በልዩ ልዩ ምክንያት የዓለማውያን ጠባይ&nbsp;የወረሳቸውን የማነጽ የስብከት አይነት ነው።</div>\n<div><strong>✳.ፕራግማቲክ(ፕራክሎቲክ):-</strong>አምነው&nbsp;በእምነት፤በእውቀት፤በምግባር የጸኑትን መጠበቅና ወደ ተግባራዊ&nbsp;አኗኗር የምንሸጋገርበት ለቅድስና ሕይወት የምናበቃበት የስብከት&nbsp;ዓይነት ነው፡፡</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"text-decoration: underline;\"><em><strong>የመልካም መምህር(ሰባኪ) ባህርያት</strong></em></span></div>\n<div>\n<div>❶.በእምነት እና በእውቀት በመስተማር (ትምህርት)፣</div>\n<div>\n<div>❷.መጻሕፍትን ማንበብ፣</div>\n<div>\n<div>❸.ቀናዒነት፣</div>\n<div>\n<div>❹.ክርስቲያናዊ ሕይወት፣</div>\n<div>\n<div>❺.የማይፈራና የማያፍር መሆን፣</div>\n<div>\n<div>&nbsp;➏.አላስፈላጊ እንቅስቃሴ አለማድረግ፣</div>\n<div>\n<div>❼.መጥኖ ማስተማር የሚቺል፤</div>\n<div>\n<div>❽.አርዓያ ክህነት(አለባበስ)፣</div>\n<div>\n<div>❾.ከመስበኩ በፊት ቅድመ ዝግጅት ማድረግ፣</div>\n<div>\n<div>❿.ራስን አለመስበክ፤</div>\n<div>\n<div>⓫.ርእሱን መጠበቅ፤</div>\n<div>\n<div>⓬.ድምፁን መመጠን፣</div>\n<div>\n<div>⓭.የሰባኪውና አድማጩ ግንኙነት፣</div>\n<div>\n<div>⓮.ራስን መሆን፣</div>\n<div>\n<div>⓯.የተሰባክያንን ሥነ ልቡና መረዳት፣</div>\n<div>\n<div>⓰.ንግግሩ ኦርቶዶክሳዊ ላህይ ያለው መሆን አለበት፣</div>\n<div>\n<div>⓱.ቁረጠኝነት ሊኖረው ይገባል።</div>\n<div>&nbsp;</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"text-decoration: underline;\"><em><strong>&nbsp;የኦርቶዶክሳዊ ስብከት መለያ ጠባያት</strong></em></span></div>\n<div> &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;\n<div>\n<ul style=\"list-style-type: square;\">\n<li>ነገረ መለኮታዊ፣</li>\n<li>መጽሐፋዊ፣</li>\n<li>\n<div>ጥምረት ያለው፣</div>\n</li>\n<li>\n<div>ማኅበራዊ ኑሮን በተመለከተ፣</div>\n</li>\n<li>\n<div>ሥርአተ ቤተ ክርስቲያን፣</div>\n</li>\n</ul>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<strong><em><span style=\"text-decoration: underline;\">የስብከት ዝግጅት</span></em></strong></div>\n<div>💠.አንድ ስብከት ፮ ንዑሳን ዘርፎችና&nbsp;ክፍሎች አሉት።እነርሱም:-</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✳.ርእስ</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✳.ዓላማ</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✳.መግቢያ</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✳.ዋና ክፍል</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✳.ምክር</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✳.መደምደሚያ</div>\n<div>&nbsp;</div>\n<div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"text-decoration: underline;\"><strong>የስብከተ ወንጌል መንገዶች</strong></span></div>\n<div>❖.የስብከተ ወንጌል መንገዶችን በሚከተሉት መንገዶች መክፈል&nbsp;ይቻላል።እነርሱም:-</div>\n<div>✳.ብቻ ለብቻ (ለአንድ ሰው)</div>\n<div>✳.ለጥቂት ሰዎች (ለደቀ መዛሙርት፣ ለቤተሰቦች)</div>\n<div>✳.ለሕዝብ</div>\n<div>✳.ለማኅበር፣ . .</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <em><span style=\"text-decoration: underline;\"><strong>ሐዋርያዊነት</strong></span></em></div>\n<div>\n<div>✳.<strong>ሐዋርያ</strong> የሚለው ቃል \"<span style=\"text-decoration: underline;\"><strong>ሖረ</strong></span>\" ሄደ ከሚለው የግዕዝ ግስ የተገኘ&nbsp;ሲሆን፤ሐዋርያ ማለት የተላከ፣የተመረጠና የተጠራ ማለት ነው።</div>\n<div>\n<div><strong>✳.ሐዋርያዊነት&nbsp;</strong></div>\n<div>\n<ul style=\"list-style-type: circle;\">\n<li>ለአገልግሎት የሚፋጠን፣</li>\n<li>የቅዱሳንን አሠረ ፍኖት (ፈለግ) የተከተለ፣</li>\n<li>ብቁና ንቁ የሆነ፣</li>\n<li>የሐዋርያዊነትን ተልዕኮ በተግባር የሚያሳይ ማለት ነው፡፡</li>\n</ul>\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<em><span style=\"text-decoration: underline;\"><strong>ሐዋርያዊ ሊጠነቀቅባቸው የሚገቡ ጉዳዮች</strong></span></em></p>\n<div>❶.ወገንተኝነት፤</div>\n<div>\n<div>❷.ከንቱ ውዳሴ፣</div>\n<div>\n<div>❸.ለምድራዊ ጥቅም ማገልገል፣</div>\n<div>\n<div>❹.ከፈተናዎች መጠበቅ ነው።</div>\n<div>\n<ul>\n<li><strong>ማጠቃለያ</strong>፦ይህ ትምህርት በጣም ሰፊና ወሳኝ ሲሆን ከብዙ በጥቂቱ በውስጡ እነዚህን ነጥቦች ይዟል።</li>\n</ul>\n</div>\n<div>\n<p>&nbsp;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>', '<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"text-decoration: underline;\"><strong>ሐዋርያዊ ተልዕኮ እና ኦርቶዶክሳዊ የስብከት ዘዴ</strong></span></h1>\n<div>❖.ስብከት የሚለው ቃል \"ሰበከ\" አስተማረ፣ አዋጀ ነገረ ከሚለው የግዕዝ&nbsp;ቃል የተገኘ ነው፡፡በግሪክ፣ኬሪግማ(kerygma) በእንግሊዝኛ sermonl&nbsp;ይባላል፡፡ ተዛማጅ /ተመሳሳይ/ የሆነ ትርጉም አለው፡፡ ማስተማር አዋጅመንገር የሚለውን ይተረጉማሉ፡፡</div>\n<div>↪ የቤተክርስቲያን ዋናው ተልዕኮዋ ሰዎችን..</div>\n<div>✦ . ከአለማመን ወደ ማመን ማምጣት፣</div>\n<div>✦ . ያመኑትን ደግሞ በእምነታቸው ማጽናት ነው፡፡</div>\n<div>\"<strong><em>በስብከት ሞኝነት የሚያምኑትን ሊያድን የእግዚአብሔር በጎ ፈቃድ&nbsp;ሆኗልና</em></strong>\"1ኛ ቆሮ 1&divide;21</div>\n<div>↪ ስብከት የቤተክርስቲያን ትልቁ የአገልግሎት ክፍል ነው፡፡</div>\n<div>✦ .ስብከት መንፈሳዊ ምግብን ለሰዎች መመገብ ማለት ሲሆን&nbsp;ለአንድ ሰው ሥጋዊ ምግብ ለመመገብ ከሚያስፈልገው ዝግጅት በላይ&nbsp;ዝግጅት ያስፈልገዋል።</div>\n<div>❖.የቤተ ክርስቲያን ተልዕኮዋ የስብከተ ወንጌል ዓላማ</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✔ ማንጻት(ያላመኑትን ማሳመን)&ldquo;<strong>ብዙኃን እለ ይቤሉ መኑ ያርእየነ ሠናይቶ&rdquo;</strong></div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✔ .ማጽናት እና</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✔ .መቀደስ ናቸው።</div>\n<h3><strong>❖.<span style=\"text-decoration: underline;\">ስብከት</span></strong></h3>\n<div>\n<ul>\n<li>ስለ እግዚአብሔር የምንመሰክርበት ነው።ዮሐ 1&divide;6፣1ኛ ዮሐ 1&divide;1፣ማቴ 10&divide;32</li>\n<li>የአምልኮ ክፍል ነው።</li>\n<li>ማምለክ፤ማመንና መዳን መሠረቱ መሰማት ነው።ሮሜ 10&divide;10-17</li>\n<li>ትእዛዘ እግዚአብሔር ነው።\"<em><strong>ለሕዝብም እንድንሰብክና በሕያዋንና በሙታን ሊፈርድ በእግዚአብሔር የተወሰነ እርሱ እንደሆነ እንመሰክር ዘንድ አዘዘን\"</strong></em>ሐዋ 10&divide;42</li>\n</ul>\n</div>\n<div><strong>✔ .አስተውሉ</strong>:-ጌታችን ኢየሱስ ክርስቶስ ደቀ መዛሙርቱን የጠራበትና የመረጠበት&nbsp;ዓላማና የመጨረሻው ትእዛዝ ስብከት ነው።።ማር 16&divide;15</div>\n<div>✦ .በአንደበታችን እውነትን ልንመሰክር ትእዛዘ እግዚአብሔርን ልንፈጽም&nbsp;ይገባል።</div>\n<div>\n<ul>\n<li>አንደበት \"<strong>ይእቲ ተዓቢ እም ሲኦል</strong>\"አንደበት ከሲኦል የከፋች ናት።</li>\n<li>\"<strong>ሞተ ዮሴፍ ነገርዎ ለዮሴፍ</strong>\"</li>\n</ul>\n</div>\n<div>✔ .ጨው ሳይሟሟ እንደማያጣፍጥ ሰውም ሳይደክም አገልግሎት&nbsp;(ስብከት) የለም።</div>\n<div>👉&ldquo;እንግዲህ ያላመኑበትን እንዴት አድርገው ይጠሩታል?ባልሰሙትስ&nbsp;እንዴት ያምናሉ? ያለ ሰባኪስ እንዴት ይሰማሉ?&rdquo;ሮሜ 10&divide;14 -15</div>\n<div>&ldquo;አንዳንዶች ተከራካሪዎችንም ውቀሱ፥ አንዳንዶችንም ከእሳት ነጥቃችሁ&nbsp;አድኑ&rdquo; ይሁዳ 1&divide;22</div>\n<div><em><strong>&ldquo;የወንጌል ሰባኪነትን ሥራ አድርግ፥ አገልግሎትህን ፈጽም</strong></em>።&rdquo; 2ኛ ጢሞ 4&divide;5</div>\n<div>👉&ldquo;በመልካም የሚያስተዳድሩ ሽማግሌዎች ይልቁንም በመስበክና&nbsp;በማስተማር የሚደክሙት እጥፍ ክብር ይገባቸዋል&rdquo;፩ኛ ጢሞ 5&divide;17</div>\n<div>👉&ldquo;ወንጌልንም ባልሰብክ ወዮልኝ&rdquo;1ኛ ቆሮ 9&divide;16</div>\n<div>👉&ldquo;ኃጢአተኛውን ኃጢአተኛ ሆይ በእርግጥ ትሞታለህ ባልሁ ጊዜ&nbsp;ኃጢአተኛውን ከመንገዱ ታስጠነቅቅ ዘንድ ባትናገር ያ ኃጢአተኛ&nbsp;በኃጢአቱ ይሞታል ደሙን ግን ከእጅህ እፈልጋለሁ&rdquo;ሕዝ 33&divide;8</div>\n<div>\n<ul>\n<li><strong>ስብከት የእግዚአብሔርን መንግስት የምንገልጥበት ነው።</strong></li>\n<li style=\"font-weight: bold;\"><strong>ስብከት መንግስተ ሰማያት እግዚአብሔርን ለሚወድና እንደፈቃዱ ለሚኖሩ የተዘጋጀቺ ናት\"🔆💡🔐</strong></li>\n</ul>\n</div>\n<div>❖&ldquo;ወንድሞቼ ሆይ ከእናንተ ማንም ከእውነት ቢስት አንዱም&nbsp;ቢመልሰው፣ኃጢአተኛን ከተሳሳተበት መንገድ የሚመልሰው ነፍሱን ከሞትእንዲያድን የኃጢአትንም ብዛት እንዲሸፍን ይወቅ\"ያዕ 5&divide;19-20</div>\n<div>✳.&ldquo;ስለ ሌላው ወንድሙ መዳን ግድ የሌለው ሰው እርሱ ይድናል ብዬ&nbsp;አላምንም፡፡&rdquo; ቅዱስ ዮሐንስ አፈወርቅ</div>\n<div>✳.\"ማንም ሳይከለክለው የእግዚአብሔርን መንግስት እየሰበከ ስለ ጌታ&nbsp;ኢየሱስ ክርስቶስ እጅግ ገልጦ ያስተምር ነበር\"ሐዋ 28&divide;31</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የስብከት ታሪክ</h2>\n<div><strong>፩ኛ.በዓለመ መላእክት:-</strong>መላእክት በተፈጠሩ በመጀመሪያ ቀን የመላእክት አለቃ የነበረ ሳጥናኤል የተፈጠረበትን ዓላማ በመሳት ክህደትንና ሐሰተኛነትን ከራሱ አፍልቆ እኔ ፈጥርኳችሁ ባለ ጊዜ ቅዱስ ገብርኤል \"ንቁም በበህላዌነ እስከ ንረክቦ ለአምላክነ\'\' በማለት መላእክትን አረጋግቷል ሰብኳል።የመጀመሪያው ስብከትም ይህ ነበር።ለበለጠ ግን ታሪኩን በሰፊው ተመልከቱ መጽሐፈ አክሲማሮስን \"<strong>ወበእንተዝ ደለወ ከመ ይጽር&nbsp;ዜናሃ ለማርያም</strong>\"ኢሳ 40&divide;1፣ምሳ 1&divide;35</div>\n<div><strong>፪ኛ.በህገ ልቡና:-</strong></div>\n<div>✦ .ከአዳም-ሙሴ&nbsp;ይሁ 14፣2ኛ ጴጥ 2&divide;5;ኩፋ 11&divide;14</div>\n<div><strong>፫ኛ.ህገ ኦሪት:-</strong></div>\n<div>✦ .ከሙሴ-መጥምቀ&nbsp;መለኮት&nbsp;ቅ/ዮሐንስ ፣ነኅ ፰&divide;፩-፰</div>\n<div><strong>፬ኛ.ዘመነ ወንጌል:-</strong></div>\n<div>✳.የዘመነ&nbsp;ወንጌል&nbsp;በር&nbsp;ከፋቺና&nbsp;መንገድ&nbsp;ጠራጊ&nbsp;መጥምቀ&nbsp;መለኮት&nbsp;ቅ/ዮሐንስ&nbsp;ነው።ማቴ 3&divide;2፣23&divide;35</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የስብከት አይነቶች</h2>\n<div>✳.ይዘትን መሠረት በማድረግ የስብከት ዓይነት በሦስት ይከፈላሉ፡፡እነርሱም:-</div>\n<div>\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 1ኛ.ትምህርት</p>\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2ኛ.ትምህርታዊ ስብከት እና</p>\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 3ኛ.ስብከት ናቸው።</p>\n</div>\n<h3>1ኛ.ትምህርት</h3>\n<div>✔ .በእውቀት ላይ የተመሠረተ</div>\n<div>✔ .ተከታታይነት ያለው</div>\n<div>✔ .በማስረጃ የተደገፈ</div>\n<div>✔ .ማብራራትን መተርጉምን፣ ማመሥጢርን የሚጠይቅ ነው።</div>\n<h3>2ኛ.ትምህርታዊ ስብከት፡-</h3>\n<div>✔ .በጥምረት የሚስጥ</div>\n<div>✔ .መነሻው ትምህርት መድርሻው ስብከት የሆነ</div>\n<div>✔ .ማስረጃ በመስጠት ሰውን ወደ ፈጣሪው የሚያቀርብ</div>\n<div>✔ .እውቀትና ሕይወት በአንድ ጊዜ የሚያስጨብጥ</div>\n<h3>3ኛ.ስብከት፡-</h3>\n<div>✔ .ቀለል ባለ አገላለጽ የሚቀርብ</div>\n<div>✔ .ማስረዳትና ማሳየት ላይ የሚያተኮር</div>\n<div>✔ .የሰውን ልቡናና አእምሮ መማረክ እና መግዛት የሚችል</div>\n<div>✳.ትምህርት አቀራረብን መሠረት በማድረግ ደግሞ በሚከተሉት&nbsp;ዘርፎች ይከፈላል።</div>\n<div><strong>❶.ነገረ ሃይማኖት:-</strong>ከስብከቶች ሁሉ ጠጣርና ከባድ የሚባለው&nbsp;የስብከት ዓይነት ነው፡፡ይህን ትምህርት ለማስተማር ሰባኪውየሚከተሉትን ነጠቦች ማስታዋል ይጠበቅበታል፡፡</div>\n<div><strong><em>ሀ.አንድ ነጥብ ላይ ብቻ ማተኮር</em></strong></div>\n<div>ለምሳሌ፡-ሀልዎተ እግዚአብሔር ፣ምሥጢረ ሥላሴ&hellip;</div>\n<div><strong>ለ.በሚገባ ማብራራት፡-</strong>ሊያስተምር የፈለገውን ነጥብ በሚገባ&nbsp;ማብራራት ይኖርበታል፡፡የሚያበራራባቸው ዘዴዎችም፡-</div>\n<div>✔ .ምሳሌዎችን በማንሳት፤</div>\n<div>✔ .ታሪክ በማስታወስ በመተረክ</div>\n<div>✔ .ለትምህርት አስረጂ ጥቅሶችን በማንሳት</div>\n<div>✔ .የሊቃውንትን ብሒል በመጠቀም</div>\n<div><strong>❷.ታሪካዊ:-</strong></div>\n<div>❖.ይህ ዘዴ አብዛኛውን ጊዜ በበዓላት ቀን የምናስተምርበት መንገድ&nbsp;ነው፡፡ በየበዓላቱ የዕለቱ ስንክሳር፣ገድል፣ድርሳን ይነበባል፣ ይተረካል፡፡ሰባኪውና የስብከቱ ቦታ የኦርቶዶክስ ቤተ ክርስቲያን እንደመሆኑ እነዚህን&nbsp;አስቀድሞ አንብቦና አጥንቶ ለምእመናን ማስተማር ይጠቅበታል፡፡</div>\n<div>❖.ሰባኪው ሕዝቡን በሚመጥንና በማያስለች መልኩ ቀላልና ግልጽ&nbsp;በሆነ አቀራረብ ሰዓት መጥኖ ርዕስ መርጦ ምእመናን ከታሪኩ ተነስተው&nbsp;በሕይወታቸው ላይ ትርጉም እንዲኖራቸው ወደ ሕይወት በመቀየር&nbsp;ማጠቃለያውን ስብከት አድርጎ መጨረስ ማለት ነው፡፡</div>\n<div><strong>❸.ባለ አንድ ሐረግ ስብከት</strong></div>\n<div><strong>❹.ቅዳሴያዊ ስብከት:-</strong>ይህ ዓይነት ስብከት በጾም ወቅት በኪዳን የጸሎት&nbsp;ሰዓት፣በንግስ ጊዜ፣በሥርዒተ ቅዲሴ መካከል የሚሰጥ ትምህርት ነው፡፡በቤተክርስቲያናችን ዋነኛው የስብከት ዘዴ ነው፡፡</div>\n<div>✔ በአጭሩ ስለ ስብከት አይነቶች ጠቅለል አድርገን ስንመለከት&nbsp;እነዚህን ነጥቦች ማየት እንቺላለን።</div>\n<div><strong>✳.ኬሪግማቲክ</strong>:-የማያምኑን አረማውያን ሰዎችን እግዚአብሔርን&nbsp;ካለማመን ወደ ማመን የምንመልስበት የስብከት ዓይነት ነው።</div>\n<div><strong>✳.ዲዳክቲክ(ዲያሌክቲክ)</strong>:-ያመኑትን፣ነገር ግን ያልጠነከሩትን አዲስ&nbsp;አማንያንን፤ንዑስ ክርስቲያንን የምንጸናበት የስብከት አይነት ነው።</div>\n<div>↪ አምነው የነበሩ፣ነገር ግን በልዩ ልዩ ምክንያት የዓለማውያን ጠባይ&nbsp;የወረሳቸውን የማነጽ የስብከት አይነት ነው።</div>\n<div><strong>✳.ፕራግማቲክ(ፕራክሎቲክ)</strong>:-አምነው&nbsp;በእምነት፤በእውቀት፤በምግባር የጸኑትን መጠበቅና ወደ ተግባራዊ&nbsp;አኗኗር የምንሸጋገርበት ለቅድስና ሕይወት የምናበቃበት የስብከት</div>\n<div>ዓይነት ነው፡፡</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የመልካም መምህር(ሰባኪ) ባህርያት</h2>\n</div>\n<h4>❶.በእምነት እና በእውቀት በመስተማር (ትምህርት)</h4>\n<div>🔆.መንፈሳዊ መምህር ማስተማር ያለበት በእምነት ነው።እምነት&nbsp;የሌለው ሰው ሌላውን ሊያሳምን አይችልም።ክህደትን ቆርጦ ለመጣል&nbsp;አስተማሪው በመጀመሪያ በእምነት መሳል አለበት።</div>\n<div>\"<strong>አመንኩ በዘነበብኩ</strong>\"መዝ 115&divide;1አመንሁ ስለዚህ ተናገር</div>\n<div>🔆.መምህር ሠወች የእግዚአብሔር ቸርነት እንዲቀምሱ የመጋበዝ&nbsp;ሀላፊነት አለበት።</div>\n<div>\"<strong>ጠአሙ ወተአይምሩ ከመ ሔር እግዚአብሔር</strong>\"መዝ 33&divide;15 ነገር ግን ያልቀመሱትን ነገር ቅመሱ ማለት አይቻልም።አንድ መምህር በእምነት ያላጣጣመውን ትምህርት ቢያስተምር ትርፉ ድካም ብቻ ነው።</div>\n<div>❖.አንድ ሰባኪ ሳይማር ሌሎችን ለማስተማር አይችልምና በቅድሚያ በሚገባ መጽሐፍ ቅዱስን የተማረ መሆን አለበት፡፡✔ .ስለዚህ አንድ ሰባኪ ከአባቶች እግር ሥር የተማረ መሆን አለበት። ከአባቶች ከሚቀዳው ምንጭ የጠጣና በትሕትና ራሱን ዝቅ በማድረግ ምስጠሩን እግዚአብሔር እንዲገልጥለት በጸሎት በመጠየቅ የተማረ መሆን አለበት፡፡</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<em><strong>\"ሳይማር የሚያስተምር ከተሳዳቢ ይቆጠራል\"</strong></em></div>\n<h4><strong>❷.መጻሕፍትን ማንበብ:-</strong></h4>\n<div>❖.አንድ ሰባኪ ወይም መምህር እንደመሆኑ መጠን ከመማሩ በተጨማሪ&nbsp;ሌሎች ተጨማሪ ይጠቅማሉ የሚላቸውን መጻሕፍቶች ዘመኑን በመዋጀት&nbsp;ማንበብ አለበት።</div>\n<div>✔ . ከሚያስተምራቸው ሰዎች በእውቀት ልቆ መገኘት አለበት፤ ካልሆነ ግን&nbsp;ቤተ ክርስቲያኗን ያስገምታታል፡፡</div>\n<div>✳.\"<strong>ለማንበብና ለመምከር ለማስተማርም ተጠንቀቅ</strong>&rdquo; 1ኛ ጢሞ 4&divide;13</div>\n<div>✳&ldquo;ሰባኪውም ጠቢብ ስለ ሆነ ለሕዝቡ እውቀትን አስተማረ፣እርሱም ብዙ&nbsp;ምሳሌዎችን መረመረና ፈላለገ፣አስማማም።&rdquo; መክ 12&divide;9-10</div>\n<div>✳.\"<strong>ለእመ ሐሰሰከ ትኩን መምህረ ኩን ገንዳሌ መጻሕፍት</strong>\"ቅ.ዮሐንስ&nbsp;አፈወርቅ</div>\n<div>➡.ሰባኪ መጻሕፍትን ካላነበበና በእውቀት ራሱን ካላካበተ የሚናገረው&nbsp;ይደናገረዋል፤ይጠፋዋል፡፡ስለዚህ ከሌሎች መምህራን፣ ከቅዱሳት መጻሕፍት፣ከምቹ አጋጣሚዎችወዘተ መማር አለበት፡፡</div>\n<div><strong>❖.አስተውሉ:</strong>-ብርጭቆ ካልሞላ አይፈስም ፤ሰባኪም ሙሉ ካልሆነ&nbsp;የምዕመናንን ልብ ማርካት አይቺልም።</div>\n<h3><strong>❸.ቀናዒነት:-</strong></h3>\n<div>💠.የክርስቶስ ወንጌል ለሁሉም ይዳረስ ዘንድ ሁሉም ይድኑ ዘንድ&nbsp;በትጋናት በቅናት ሌትና ቀን ደከመኝ ሰለቸኝ ሳይል መጋደል አለበት፡፡</div>\n<div>🔆.&ldquo;የቀረውንም ነገር ሳልቆጥር ዕለት ዕለት የሚከብድብኝ&nbsp;የአብያተ ክርስቲያናት ሁሉ አሳብ ነው&rdquo; 2ኛ ወደ ቆሮ 11&divide;28</div>\n<div>🔆. \"ለቅዱሳን አንድ ጊዜ ፈጽሞ ስለተሰጠቺ ሃይማኖት&nbsp;እንድትጋደሉ እየመከርኳችሁ እጽፍላችሁ ዘንድ ግድ ሆነብኝ\"ይሁ 1&divide;3</div>\n<h3><strong>❹.ክርስቲያናዊ ሕይወት:-</strong></h3>\n<h4><em>✔ .በፍቅር እና በትህትና የሚታወቅ</em></h4>\n<div>✳.\"ፍቅር ለዘወትር አይወድቅም\"1ኛ ቆሮ 13&divide;8</div>\n<div>✳<em><strong>.ሠናየ ሀልዩ በልብክሙ/ ለቢጽክሙ/ ተፋቀሩ በኩሉ ጊዜ ዝ ውእቱ&nbsp;ፈቃዱ ለእግዚአብሔር መንፈሰ ኢታጥፍኡ ተነብዮ ኢትመንኑ ወኩሎ&nbsp;አመክሩ ወዘሠናየ አጽንኡ</strong></em>\"በልባችሁ መልካም ነገርን አስቡ&nbsp;የእግዚአብሔር ፈቃድ እርስ በርሳችሁ እንድንፋቀሩ ነውና እርስበርሳችሁ&nbsp;ሁልጊዜ ተፋቀሩ መንፈሳዊ ነገርን አታጥፉ ትንቢትንም አትናቁ ሁሉንም&nbsp;መርምሩ የተሻለውን አጽንታችሁ ያዙ\"</div>\n<div>🔆. \"<strong>ተፋቅሮ ኢያስተፄንስ ወኢያሄሊ ተድላ ለባህቲቱ</strong> \"ፍቅር ማንንም ችግር&nbsp;ውስጥ አያስገባም የብቻ ድሎትንም አያሳስብም ወይም ብቻየን ልደሰት&nbsp;አያስብልም\"ፍቅር ከስግብግብነት ከቀናተኛነት ወጥቶ ለሌሎች መትረፍ ስለሆነ&nbsp;ብቻየን ይድላኝ አያሰኝም፡፡1ኛ ቆሮ 13&divide;5</div>\n<div><strong>✳.አስተውሉ</strong>:-ጸጋ እግዚአብሔር የሚፈሰው ዝቅ ወደአሉ ሰዎች ነው።</div>\n<h3><strong>❖.ሰባኪ መምህር ትሁት መሆን አለበት።</strong></h3>\n<div>\"ማንም ለሰርግ ቢጠራህ አስቀድመህ በከበሬታ ወንበር አትቀመጥ&nbsp;ምናልባት ከአንተ ይልቅ የከበረ ተጠርቶ ይሆናልና አንተንም እሱንም&nbsp;የጠራ ጋባዥ መጥቶ ለዚህ ስፍራ ታውለት ይልሃል ያንጊዜ እያፈርክ&nbsp;በዝቅተኛ ቦታ ትሆናለህ..\"ሉቃ 14 &divide;7-11 ብሎ በምሳሌ ጌታችን&nbsp;ያስተማረው ደቀ መዛሙረቱ ለማስተማር ሲሽቀዳደሙ በማየቱ&nbsp;እንደሆነ ነው የሚነገረው።</div>\n<div>\"ማንም ከእናንተ ታላቅ ሊሆን የሚወድ የሁሉ አገልጋይ ይሁን\"ማቴ 20&divide;26 ይህንን ትህትና ማሳየት መቻል አለበት።</div>\n<div>✔ .ማስተማርን የሥጋዊ ክብር መፈለጊያ ማድረግ አያስፈልግም ክብር&nbsp;እንደ ጥላ ሲሸሿት የምትርቅ ሲርቋት ደግሞ የምትቀርብ ናት።</div>\n<div>💠.\'\'<strong>ዘአትሐተ ርእሶ ይትሌአል ወዘ አልአለ ርእሶ ይቴሀት፤ እስመ&nbsp;ዘአዕበየ ርእሶ የሐስር ወዘአትሐተ ርእሶ ይከብር</strong>\"ማቴ 23&divide;12 -ራሱን&nbsp;ዝቅ ዝቅ የሚያደርግ ከፍ ክፍ ይላል ራሱን ከፍ ክፍ የሚያድርግ ደግሞ&nbsp;ዝቅ ዝቅ ይላል፡፡አባቶቻችን ምድር ከዚህ በታች ዝቅ የማትለው&nbsp;እስከመጨረሻው ዝቅ ስላለች ነው ይላሉ፡፡ሌላው ፀሐይ በደንብ&nbsp;የምታሞቀው ዝቅ ያለውን ነው፡፡ከፍ ሥትል ትቀዘቅዛለህ ስለዚህ&nbsp;ላለመቀዝቀዝ ራስህን ከፍ አታድርግ፡፡ከፍ አትበል በረዶ ትሆናል፡፡</div>\n<h3><strong>✔ .በክርስትና ሕይወቱ የተመሰከረለት</strong></h3>\n<div>✳.\"ወዘሰ ኢይክል ሠሪዐ ቤቱ እፎኑ ያስተሐምም ቤተ እግዚአብሔር \"ጢሞ 3&divide;5</div>\n<div>✳.በእናንተ ስበብ የእግዚአብሔር ስም ይሰደባል\"ሮሜ 2&divide;20-24</div>\n<div>➡ሃይማኖቱ የቀና፤ስነ ምግባሩ የተስተካከለ፤ከእውቀቱ ይልቅ በተግባሩ&nbsp;የሚሰብክ፤የሚጣፍጥ ጨው መልካም መዓዛ ያለው መሆን አለበት።1ኛ ቆሮ 11&divide;1</div>\n<div><em><strong>\"አንተ መዓዛህ ምንድን ነው?ክርስቶስ ክርስቶስን ነው ወይስ ዲያቢሎስ&nbsp;ዲያቢሎስን?መዓዛህ የሚታወቀው በታቀፈው ነው፤አንድ እናት የምትሸተው&nbsp;በታቀፈቺው ልጅ ነው\"<span style=\"text-decoration: underline;\">አረጋዊ መንፈሳዊ</span></strong></em></div>\n<h3><strong>❺.የማይፈራና የማያፍር መሆን</strong></h3>\n<div>✦ .ሰው ምን ይለኝ ይሆን በማለት ሳይጨናነቅ ጥበብ በተሞላበት&nbsp;በሁኔታ የእግዚአብሔርን ቃል በሚገባ ማስተላለፍ አለበት፡፡</div>\n<div>✳.&ldquo;<strong>በወንጌል አላፍርም</strong>&rdquo; ሮሜ 1&divide;16</div>\n<div>✳. &ldquo;ነገር ግን የሠራዊት ጌታ እግዚአብሔርን ቀድሱት፣ የሚያስፈራችሁና&nbsp;የሚያስደነግጣችሁም እርሱ ይሁን\"ኢሳ 8&divide;13</div>\n<h3><strong>➏ .አላስፈላጊ እንቅስቃሴ አለማድረግ</strong></h3>\n<div>✔ .እጅን ማወራጨት፤</div>\n<div>✔ .ራስን፣ . . . ማከክ፤</div>\n<div>✔ .ወዲያ ወዲህ መንጎራደድ፤</div>\n<div>✔ . አላስፈላጊ ድግግሞሽ ማድረግ የለበትም፡፡</div>\n<h3>❼.መጥኖ ማስተማር የሚቺል፤</h3>\n<div>✦ ያልተመጠነ ነገር ይጎመዝዛል ያልተመጠነ ነገር ጣእም&nbsp;አይኖረውም።ቅዱስ ጴጥሮስ በ፩ኛ መልእክቱ 4&divide;8 እና 5&divide;8 በመጠን ኑሩ ብሎ እንዳስተማረን ለሁሉም ነገር መጠንና ልክ አለው።</div>\n<div>\"<strong>ዘበልአ በአቅሙ የኃድር በሰላም</strong>\" እንዳለው ጠቢቡ ሰሎሞን ስጋዊ&nbsp;ምግብን በመጠን እንደምንመገብ ሁሉ ቃለ እግዚአብሔርንም በመጠን&nbsp;መማር ያስፈልገናል።ምእመናን መመህሩ የያዘውን ሁሉ እንዲይዙ&nbsp;የሚሞክርባቸው ቤተ ሙከራወች አይደሉም በመጠን ሰምተው&nbsp;ከህይወታቸው ጋር እንዲያዋህዱ የሚጠበቁ ናቸው እንጅ</div>\n<div>\n<p>\"<em><strong>ወበዘከመዝ አምሳል ተናገሮሙ ቃሎ በአምጣነ ይክሉ ሰሚዓ</strong></em>\" መስማት በሚችሉበት መጠን እነዚህን በሚመስል በብዙ ምሳሌ ቃሉን ይነግራችው ነበር።ማር 4&divide;33</p>\n<h3>❽.አርዓያ ክህነት(አለባበስ)</h3>\n</div>\n<div>✳በኢትዮጵያ ቤተክርስቲያን የስብከተ ወንጌል ታሪክ በጃንደረባው&nbsp;ቢጀመርም የተሟላ ሆኖ የተፈጸመውና በተግባራዊነት ዕድገት ያሳየው&nbsp;ከፍሬምናጦስ የክህነት አገልግሎት በኋላ ነው፡፡</div>\n<div>&nbsp;</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<em><strong> &nbsp;ከ34ዓ.ም-330ዓ.ም</strong></em></div>\n<div>✳ አለባበሱ አርአያ ክህነትን የጠበቀ መሆን አለበት፡፡ንጽሕናውን&nbsp;የመጠበቅና አግባብ ያለው አለባበስ መሆን አለበት።በጣም ከደረጃዉ&nbsp;የወረደ ወይም በጣም ዘመናዊ የሆነ ልብስ መልበስ የለበትም፡፡</div>\n<div><em><strong>\"ኢኃደጋ ለምድር እምቅድመ ዓለም ወእስከ ለዓለም እንበለ ካህናት&nbsp;ወዲያቆናት</strong></em>\"<strong><span style=\"text-decoration: underline;\">ቅ/ያሬድ</span></strong></div>\n<div>&nbsp;</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 1ኛ ቆሮ 15&divide;45 ተመልከቱ</div>\n<h3><strong>መምህራን፦</strong></h3>\n<ul style=\"list-style-type: square;\">\n<li>\"<em><strong>እለ ይሜህሩ ወንጌለ ለኩሉ ፍጥረት</strong></em>\"</li>\n<li>\"<strong>እስመ አርአያየ ወሀብኩክሙ</strong>\"ዮሐ 13&divide;15</li>\n</ul>\n<h3>❾.ከመስበኩ በፊት ቅድመ ዝግጅት ማድረግ</h3>\n<div>✳. ሰባኪ መጋቢ ነው፡፡ለዝግጅቱ በቂ ጊዜ በመስጠት መጻሕፍትን&nbsp;በማንበብ ማስታወሻ በመያዝ መዘጋጀት አለበት።በሚገባ ተዘጋጀቶ በመሄድ በሚገባ ቦታ የሚገባውን መልእክት&nbsp;አስተላልፎ መምጣት አለበት እንጂ በችኮላ ሳይዘጋጅ በመሄድ&nbsp;ዘበራርቆ መምጣት የለበትም፡፡</div>\n<div>✳.ለማን እንደሚሰብክ ማወቅ አለበት።የስብከት በተለያዩ ቦታዎችና&nbsp;ለተለያዩ ሰዎች ለምሳሌ፡-</div>\n<div>\n<ul style=\"list-style-type: circle;\">\n<li>በሐዘን ቤት፣</li>\n<li>በሠርግ ቤት፣</li>\n<li>በእስር ቤት&hellip;የሚሰጥ ሲሆን</li>\n</ul>\n</div>\n<div>✦ .ሰዎቹ ያሉበትን ሁኔታ</div>\n<div>✦ .ቦታውን</div>\n<div>✦ .የሰዎቹን የእውቀት ደረጃ</div>\n<div>✦ .ባህልና እድሜ&nbsp;ጠንቅቆ ማወቅ ያስፈልጋል።</div>\n<h3>❿.ራስን አለመስበክ፤</h3>\n<div>🔆.ራሱ ባለቤቱ ክርስቶስ ምንም እንኳን በሥልጣን፣ በፈቃድ፣በሕልውና፣ በባሕርይ ከአብና ከመንፈስ ቅዱስ ጋር አንድ (ትክክል)&nbsp;ቢሆንም በተዋሐደው ሥጋ ምክንያት ወልድ ከአብ ዘንድ የተላከና ለአብ&nbsp;የታዘዘ ነው።</div>\n<div><strong>\" የላከኝን ፈቃድ እንጂ ፈቃዴን ላደርግ አልሻምና\"</strong>ዮሐ 5&divide;30&nbsp;በማለት እንደተናገርው።</div>\n<div>🔆.መጥምቀ መለኮት ዮሐንስም \"ስለ ራስህ ምን ትላለህ?\"ብለው ለጠየቁት&nbsp;የሰጠው መልስ \"የጌታን መንገድ አቅኑ ብሎ በምድረ በዳ የሚጮህ ሰው&nbsp;ድምጽ እኔ ነኝ\" ብቻ ነበር ያለው፡፡ዮሐ 1&divide;23</div>\n<div><strong>❖.አስተውሉ</strong>:-ዮሐንስ የክርስቶስን ፈቃድ እንጂ የራሱን የሚያውቀውን&nbsp;እውነተኛ ታሪኩን እንኳን መናገር አልፈለገም፡፡ አንድ ሰባኪም እንዲሁ&nbsp;ሊያደርግ ይገባል።</div>\n<div>✳.የሚያደንቁት ሰባኪና ምን ልሥራ ብለው የሚጠይቁት ሰባኪ በእጅጉ&nbsp;ይለያልና ሰባኪ ራስን ከመስበክ ነጻ መሆን ይጠበቅበታል፡</div>\n<div>✳.\"ብዙ ሰዎች ቸርነታቸውን ያወራሉ የታመነውን ሰው ግን ማን&nbsp;ያገኘዋል\"ምሳ 20&divide;6</div>\n<div>✳.\"እግዚአብሔር የላክው የእግዚአብሔር ቃለ ይናገራል\"ዮሐ 3&divide;34</div>\n<div>✳.\"ልቡናዬ መልካም ነገርን አፈለቀ (አወጣ)\"ቅ/ዳዊት</div>\n<div>✳.\"እኛ ግን የተሰቀለውን ክርስቶስን እንሰብካለን\"1ኛ ቆሮ 1&divide;23</div>\n<h3>⓫.ርእሱን መጠበቅ፤</h3>\n<div>✳.አንድ ሰባኪ በግድ የለሽነት ተነስቶ ርእሱን ያልጠበቀ ስብከት&nbsp;ለአድማጮች ጥቅም የማይሰጥ ከመሆኑም ባሻገር ሰባኪውን&nbsp;ያስገምተዋል፡፡</div>\n<div>✳.ምስጢር ሳበኝ እያለ ትዝ ያለውን ሁሉ ማውራት የለበትም፡፡</div>\n<div>✳.የማያውቀውን ወይም እርግጠኛ ያልሆነበትን ነገር ለመናገር መድፈር&nbsp;የለበትም።</div>\n<div>✳.ስብከት ርዕሱ ካልተጠበቀ ውጤታማ ሊሆን አይችልም፤ ምእመናኑ&nbsp;የሚጨብጡት ነገር አይኖራቸውም ሰባኪውም ትዝብት ውስጥ&nbsp;ይወድቃል፡፡ ርዕስ መጠበቅ የሚሰጠው ትምህርት ወጥና ያልተደባለቀ&nbsp;ያደርገዋል።</div>\n<div><strong>ለምሳሌ፡</strong>- ስለ ምሥጢረ ሥላሴ ጀምሮ ስለ ጾም፤ስለ ቅዱስ ቁርባን ጀምሮ ስለ&nbsp;ሥዕል፤ስለ ክርስቶስ የባሕርይ አምላክነት ጀምሮ ስለ ታቦትየሚል ከሆነ\"አርባ ስድስት ጥዳ አንዱንም&hellip; አረረባት\" እንደተባለው ይሆናል፡፡</div>\n<div><strong>✳.አስተውሉ:-</strong> ሰዓትና ርዕስ መጠበቅ የአንድ ሰባኪ መታወቂያዎች ናቸው፡፡</div>\n<div>🔆.ሁሉ ነገር በልኩና በአግባቡ ሊሆን ይገባዋል።ነገር ሲበዛ ውጤቱና&nbsp;መጨረሻው አያምርም።</div>\n<div>✳.\"የምነግራችሁ ገና ብዙ አለኝ ነገር ግን አሁን ልትሸከሙት&nbsp;አትችሉም\"ዮሐ 16&divide;12 በማለት ተነግጿል</div>\n<div>✳.\"<em><strong>ግብር ዘአልቦ ምጣኔ ገአር ውእቱ ወለገአርኒ ይተልኦ ዝንጋኤ</strong></em>\"ልክ&nbsp;የሌለው ስራ ድካም ነው ድካምንም መዘንጋት ይከተለዋል ያልተመጠነ&nbsp;ትምህርትም ተናጋሪውንም ሰሚውንም ወደ መሰልቸት ያደርሳል።</div>\n<div>✳.መመጠን(አለማርዘም):-በመጠን ኑሩ&rdquo; 1ኛ ጴጥ 5&divide;8</div>\n<h2><strong>⓬.ድምፁን መመጠን</strong></h2>\n<div>✔ .ሰባኪው ድምጹ ለአድማጭ የሚረብሽና የሚሰቀጥጥ በጣም የሚጮኽ&nbsp;ወይም በጣም ፈዘዝ ያለ ለአድማጭ የሚሰለች መሆን የለበትም።</div>\n<div>✔ .በጣም መፍጠንም በጣም መጐተትም የለበትም፣ ትክክለኛና&nbsp;አግባብ ባለው ሁኔታ መሆን አለበት።</div>\n<h3><strong>⓭.የሰባኪውና አድማጩ ግንኙነት</strong></h3>\n<div>✳.ተረጋግተው ቦታቸውን እስኪይዙ ድረስ መጠበቅ አለበት፡፡</div>\n<div>✳.የአድማጮቹን ሁኔታ ይገምታል፡፡</div>\n<div>✳.ከዚያ በኋላ ለዕለቱ ተስማሚ በሆነ ርዕስ ትምህርቱን ይጀምራል፡፡</div>\n<div>✳.ዓይንን በአንድ ቦታ ላይ ወይም በአንድ ሰው ላይ ሳይተክሉ&nbsp;በአራቱም አቅጣጫ ቃኘት በማድረግ ሰልችቷቸው ወይም ደክመው&nbsp;እንዳይሆን ወይም አልገባቸው እያለ እንዳይሆን በዓይን ሁሉንም&nbsp;አድማጭ ለመቆጣጠር መሞከር እና በሚሰብክበት ጊዜ ጣራ ጣራ&nbsp;ወይም ወደ መሬት ማየት የለበትም፡፡</div>\n<h3><strong>⓮.ራስን መሆን</strong></h3>\n<div>✳.ሌሎችን ለመሆን መጣር የለበትም።</div>\n<h3>⓯.የተሰባክያንን ሥነ ልቡና መረዳት</h3>\n<div>✳.በመማር ማስተማር ሂደት ውስጥ የተሰባክያንን ስነ ልቡና ማወቅና መረዳት&nbsp;ለሰባኪው ከፍተኛ ጥቅምና እንደ ዋና ግብዓት ሆኖ የሚያገለግል ጉዳይ ነው።</div>\n<div>✳.ይህም ማለት የተሰባኪያንን ሥነ ልቡና መረዳት ሲባል</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>መዳን እንደሚወዱ ማወቅና ጠይቆ መረዳት፤</li>\n<li>እንደራባቸው ምግብ እንደሚያስፈልጋቸው መረዳት፤</li>\n<li>ጥያቄ ሊጠይቁ እንደፈለጉ መረዳት፤</li>\n</ul>\n</div>\n<div><strong>አስተውሉ:-</strong>እናንተን የሚጠይቋችሁ ሰዎች አራት አይነት አመለካከት&nbsp;ያላቸው መሆኑን አትዘንጉ።<strong>እነርሱም</strong>:-</div>\n<div>&nbsp;</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li><em><strong>፩ኛ.መምህራንን ለመፈተሽ የሚጠይቁ፤</strong></em></li>\n<li><em><strong>፪ኛ.ያውቀዋል ነገር ግን ሌሎች እንዲያውቁት ፈልጎ የሚጠይቅ፤</strong></em></li>\n<li><em><strong>፫ኛ.ያውቀዋል፤ነገር ግን ተጨማሪ ፈልጎ የሚጠይቅ፤</strong></em></li>\n</ul>\n<p><em><strong>፬ኛ.ምንም አያውቅም፤ስለዚህ ለማወቅ የሚጠይቅ እንዳለ መዘንጋት የለባችሁም።</strong></em></p>\n<h3><span style=\"text-decoration: underline;\"><em><strong>🔆.የተሰባኪያንን ሥነ ልቡና የመረዳት ጠቀሜታው</strong></em></span></h3>\n</div>\n<div>❶.ከአድማጩ ለመተቼት ለመዳን፤</div>\n<div>❷.ከመፍረድ ለመዳን፤</div>\n<div>❸.ከማጽደቅና ከመኮነን ለመዳን...ወዘተ.....</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;\"<em><strong>እንደካርቦን አትሁን\" ለምን ካልከኝ ካርቦን የጻፉለትን ኮፒ ያደርጋልና።</strong></em></div>\n<h3><strong>⓰.ንግግሩ ኦርቶዶክሳዊ ላህይ ያለው መሆን አለበት፡፡</strong></h3>\n<div>💠. ሰባኪው የቤተ ክርስቲያን መቃን የመታው የቤተ ክርስቲያንን&nbsp;ቋንቋ በሚገባ የሚያውቅ መሆን አለበት፡፡</div>\n<div>💠.ጸያፍ የሆኑና ኦርቶዶክሳዊ ያልሆኑ ቃላትን መጠቀም የለበትም፡፡</div>\n<div>💠.የማይመጥኑ ወይም ለአድማጩ ከባድ የሆኑ ቃላትን መጠቀም&nbsp;የለበትም።</div>\n<div>💠.ጠንከራ ስሜት ማለትም በቀላሉ የማይበርድ ስሜት ሊኖረው&nbsp;ይገባል።</div>\n<div>💠.አለምልሞ መገሰፅ የሚችል መሆን አለበት።ይህ ማለት አስተምሮ&nbsp;መምክርና መገሰፅ አለበት ማለት ነው።ጌታችን ኒቆዲሞስን&nbsp;አስተምሮ እንደገሰፀው።</div>\n<h3><strong>⓱.ቁረጠኝነት ሊኖረው ይገባል</strong></h3>\n<div>✳. &ldquo;የሎጥን ሚስት አስቧት&rdquo;ሉቃ 17&divide;32</div>\n<div>✳.ያለቆረጠ ሰው የትም መድረስ አይችልም፡፡</div>\n<div>&ldquo;በዚያን ጊዜ ኢየሱስ ለደቀ መዛሙርቱ እንዲህ አለ፦ እኔን መከተል&nbsp;የሚወድ ቢኖር ራሱን ይካድ መስቀሉንም ተሸክሞ ይከተለኝ።ነፍሱን&nbsp;ሊያድን የሚወድ ሁሉ ያጠፋታል፤ስለ እኔ ግን ነፍሱን የሚያጠፋ ሁሉ&nbsp;ያገኛታል።&rdquo; ማቴ 16&divide;24</div>\n<div>✳. \"<em><strong>መኑ የሀድገነ ፍቅሮ ለክርስቶስ</strong></em>\"ሮሜ 8 እንዳለ ቅዱስ ጳውሎስ&nbsp;ሰባኪ መምህርም ለዓላማው እስከሞት ድረስ የታመነ መሆን አለበት።</div>\n<div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የኦርቶዶክሳዊ ስብከት መለያ ጠባያት</h2>\n</div>\n<div><strong>መጽሐፋዊ፦</strong></div>\n<div>\n<ul>\n<li>✳.መጽሐፍ ቅዱስ</li>\n<li>✳.አዋልድ መጻሕፍት</li>\n<li>✳.ታሪካዊ መጻሕፍት</li>\n</ul>\n<p><strong>ነገረ መለኮታዊ፦</strong></p>\n<ul>\n<li>✳.ምሥጢራተ ቤተ ክርስቲያን</li>\n<li>✳.ሥርዓተ ቤተ ክርስቲያን</li>\n<li>✳.ሐዋርያዊ ትውፊት</li>\n<li>✳.ዶግማ</li>\n</ul>\n</div>\n<div><strong>✳.ማኅበራዊ ኑሮን በተመለከተ</strong></div>\n<div><strong>✳.ሥርአተ ቤተ ክርስቲያን</strong></div>\n<div><strong>✳.ጥምረት ያለው የስብከት አይነት አለ።</strong></div>\n<div>&nbsp;</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የስብከት ዝግጅት</h2>\n<div>💠.አንድ ስብከት ፮ ንዑሳን ዘርፎችና&nbsp;ክፍሎች አሉት።እነርሱም:-</div>\n<div>\n<ul style=\"list-style-type: circle;\">\n<li>✳.ርእስ</li>\n<li>✳.ዓላማ</li>\n<li>✳.መግቢያ</li>\n<li>✳.ዋና ክፍል</li>\n<li>✳.ምክር</li>\n<li>✳.መደምደሚያ</li>\n</ul>\n</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የስብከተ ወንጌል መንገዶች</h2>\n<div>❖.የስብከተ ወንጌል መንገዶችን በሚከተሉት መንገዶች መክፈል&nbsp;ይቻላል።እነርሱም:-</div>\n<div>\n<ul>\n<li>.ብቻ ለብቻ (ለአንድ ሰው)፣</li>\n<li>.ለጥቂት ሰዎች (ለደቀ መዛሙርት፣ ለቤተሰቦች)፣</li>\n<li>.ለሕዝብ፣</li>\n<li>.ለማኅበር፣ . . .</li>\n</ul>\n</div>\n<h3>❶.ለህዝብ:-</h3>\n<div>✳.&ldquo;ሕዝቡንም አይቶ ወደ ተራራ ወጣ፤ በተቀመጠም ጊዜ ደቀ መዛሙርቱ&nbsp;ወደ እርሱ ቀረቡ፤ አፉንም ከፍቶ አስተማራቸው እንዲህም አለ፦ . . .&rdquo;ማቴ. 5፡1-2</div>\n<h3>❷.ብቻ ለብቻ(አንድ ለአንድ):-</h3>\n<div>\n<ul style=\"list-style-type: square;\">\n<li style=\"font-weight: bold;\"><strong>✳.ኒቆዲሞስ</strong></li>\n</ul>\n</div>\n<div>&ldquo;ከእነርሱ አንዱ በሌሊት ቀድሞ ወደ እርሱ መጥቶ የነበረ ኒቆዲሞስ፡-ሕጋችን አስቀድሞ ከእርሱ ሳይሰማ ምንስ እንዳደረገ ሳያውቅ በሰው&nbsp;ይፈርዳልን? አላቸው።&rdquo; ዮሐ. 7&divide;50-51</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li style=\"font-weight: bold;\"><strong>✳.ለሳምራዊቷ ሴት</strong></li>\n</ul>\n</div>\n<div>&ldquo;ሴቲቱም፡- ያደረግሁትን ሁሉ ነገረኝ ብላ ስለ መሰከረችው ቃል ከዚያች&nbsp;ከተማ የሰማርያ ሰዎች ብዙ አመኑበት። የሰማርያ ሰዎችም ወደ እርሱ&nbsp;በመጡ ጊዜ በእነርሱ ዘንድ እንዲኖር ለመኑት፤ በዚያም ሁለት ቀን ያህል&nbsp;ኖረ።\"ስለ ቃሉ ከፊተኞች ይልቅ ብዙ ሰዎች አመኑ፤ ሴቲቱንም። አሁን&nbsp;የምናምን ስለ ቃልሽ አይደለምእኛ ራሳችን ሰምተነዋልና፤ እርሱም</div>\n<div>በእውነት ክርስቶስ የዓለም መድኃኒት እንደ ሆነ እናውቃለን ይሏት&nbsp;ነበር።&rdquo;</div>\n<h3>❸.ለጥቂት ሰዎች (ለደቀ መዛሙርት፣ለቤተሰቦች)</h3>\n<div><strong>✳.ለጵርስቅላ እና አቂላ</strong></div>\n<div>&ldquo;በክርስቶስ ኢየሱስ አብረውኝ ለሚሠሩ ለጵርስቅላና ለአቂላ ሰላምታ አቅርቡልኝ፤እነርሱም ስለ ነፍሴ ነፍሳቸውን ለሞት አቀረቡ፣የአሕዛብም አብያተ ክርስቲያናት ሁሉ የሚያመሰግኑአቸው ናቸው እንጂ እኔ ብቻ አይደለሁም፤በቤታቸውም ላለች ቤተ ክርስቲያን ሰላምታ አቅርቡልኝ። ከእስያ ለክርስቶስ በኵራት ለሆነው ለምወደው&nbsp;ለአጤኔጦን ሰላምታ አቅርቡልኝ።&rdquo;</div>\n<div>ሮሜ 16&divide;3-5</div>\n<div><strong>✳.ልድያና ቤተሰቦቿ</strong></div>\n<div>&ldquo;ከትያጥሮን ከተማም የመጣች ቀይ ሐር ሻጭ እግዚአብሔርን የምታመልክ ልድያ&nbsp;የሚሉአት አንዲት ሴት ትሰማ ነበረች፤ ጳውሎስም የሚናገረውን ታዳምጥ ዘንድ ጌታ&nbsp;ልብዋን ከፈተላት።</div>\n<div>&ldquo;እርስዋም ከቤተ ሰዎችዋ ጋር ከተጠመቀች በኋላ። በጌታ የማምን እንድሆን&nbsp;ከፈረዳችሁልኝ፥ ወደ ቤቴ ገብታችሁ ኑሩ ብላ ለመነችን፤ በግድም አለችን።&rdquo;</div>\n<div>የሐዋ.ሥራ 16&divide;14-15</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;ሐዋርያዊነት</h2>\n<div><strong>✳.ሐዋርያ</strong> የሚለው ቃል \"<strong>ሖረ</strong>\" ሄደ ከሚለው የግዕዝ ግስ የተገኘ&nbsp;ሲሆን፤ሐዋርያ ማለት የተላከ፣የተመረጠና የተጠራ ማለት ነው።</div>\n<div><strong>✳.ሐዋርያዊነት፦</strong></div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>ለአገልግሎት የሚፋጠን፣</li>\n<li>የቅዱሳንን አሠረ ፍኖት (ፈለግ) የተከተለ፣</li>\n<li>ብቁና ንቁ የሆነ፣</li>\n<li>የሐዋርያዊነትን ተልዕኮ በተግባር የሚያሳይ ማለት ነው፡፡</li>\n</ul>\n</div>\n<div>💠.ሐዋርያዊነት:-ጌታችን ኢየሱስ ክርሰቶስ በኢየሩሳሌም፤በይሁዳ፤በሰማርያም ሁሉ እስከ ምድርም ዳርቻ ድረስ ምስክሮች ትሆናላችሁ\" ብሎ&nbsp;ባዘዘው አምላካዊ ቃል መሠረት \"ሑሩ ወመሐሩ\"ያለውን በተግባር&nbsp;መፈጸም ነው፡፡ሐዋ 1&divide;8</div>\n<h2><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;ሐዋርያዊ ሊጠነቀቅባቸው የሚገቡ ጉዳዮች</strong></h2>\n<div>🔆..በሐዋርያነት መስክ የተሰማራ ማንኛውም አገልጋይ ጌታ&nbsp;እንደተናገረው \"በተራራ ላይ ያለ መብራት\" ማለት ነው፡፡በሌላ አነጋገር \"የክርስትና ባንዲራ ነው\" ምእመናን የሚያጠፋት ጥፋትና&nbsp;እርሱ የሚያጠፋው በሰውም ዘንድ በእግዚብሔርም ዘንድ በእኩል&nbsp;አይታይም አይመዘንም፡፡</div>\n<div>🔆..የጌታውን ፈቃድ አውቆ እንደ ፈቃዱ የማይሠራና የማይዘጋጅ የዚያ&nbsp;አገልጋይ ቅጣቱ ብዙ ነው\"ሉቃ 12&divide;17 ተብሎ እንደተነገረው ኃለፊነት&nbsp;ተቀብሎ አውቆ የሚያጠፋ የቅጣቱ መጠን ከባድ መሆኑን መረዳት ተገቢ&nbsp;ነው።</div>\n<h3>💠.አንድ ሐዋርያዊ ሊጠነቀቅባቸው ከሚገቡ ዓበይት ጉዳዮች መካከል:-</h3>\n<h3><strong>❶.ወገንተኝነት፡-</strong></h3>\n<ul>\n<li>የቆሮንቶስንና የፊልጵስዮስን አብያተ ክርስቲያናት ያውኳቸው ከነበሩ ጉዳዮች መካከል እንዱ ወገንተኝነት ነው፡፡</li>\n</ul>\n<div>\n<p><em><strong>&nbsp;በቆሮንቶስ ቤተ ክርስቲያን፡</strong></em>-</p>\n<ul>\n<li>እኔ የጳውሎስ ነኝ፣</li>\n<li>እኔ የኬፋ ነኝ፣</li>\n<li>እኔ የአጵሎስ ነኝ የሚል ክፍፍል ነበር ።፩ኛ ቆሮ 3&divide;1-12</li>\n</ul>\n</div>\n<div><strong>✳.ወገንተኝነት በብዙ መንገድ ይገለጣል፡-</strong></div>\n<div>✔ .የፓለቲካ ወገንተኝነት፣</div>\n<div>✔ .የቋንቋና የብሔር፣</div>\n<div>✔ .የአካባቢ ተወላጀነት፣</div>\n<div>✔ .ቡድን በመሰብሰብ፣</div>\n<h3>❷.ከንቱ ውዳሴ</h3>\n<div>🔆..አውቀውትም ሳያውቁትም ብዙዎችን ከፀጋው ዙፋን ያራቆተ፣ዓላማቸውን ያሳተ፣አቅጣጫቸውን ያሰናከለ ከባድ የሆነ የበጐ ሕሊና&nbsp;ወጥመድና እንቅፋት ነው፡፡</div>\n<div><strong>\"የታዘ</strong><em><strong>ዛችሁትን ሁሉ ባደረጋችሁ ጊዜ የማንጠቅም ባሪያዎች&nbsp;ነን፣ልናደርገው የሚገባንን አድርገናል በሉ</strong></em>\"ሉቃ 17&divide;10&nbsp;በማለት ጌታችን ደቀ መዛሙርቱን የመከረው፡፡</div>\n<div>&nbsp;</div>\n<div><strong>✳.ከንቱ ውዳሴ:-</strong></div>\n<div>✔ .ያለ እኔ ሰው የለም የሚያሰኝ፤</div>\n<div>✔ .ትዕቢትንና ትምክህትን የሚያስከትል፣</div>\n<div>✔ .ከያዘ የማይነቀል መርዛማ ሥር ነው፡፡ሉቃ 18&divide;9፣ማቴ 6&divide;2-18</div>\n<h3>❸.ለምድራዊ ጥቅም ማገልገል፡-</h3>\n<div>✳.በዚህ ዘመን ቤተክርስቲያንን በእጅጉ የተፈታተናት፣ አንዳንዶችም&nbsp;ያመኑትን ፈጣሪና የታመኑለትንና ያመነቻቸውን ቤተክርስቲያን ከመክዳት&nbsp;አልፈው የጫማ ውስጥ ጠጠርና የጭቃ ውስጥ እሾህ እንዲሆኑባት&nbsp;ያደረገው የጥቅም ፍላጐት ነው፡፡</div>\n<div>↪ በቤተክርስቲያን ታሪክ ለንዘብ ማገልገል \"<strong>ሲሞኒዝም</strong>\" ይባላል።ሐዋ 8&divide;9-25</div>\n<div><em><strong>➡.ሲሞኒዝም በዚህ ዘመን፡-</strong></em></div>\n<div><em>❖.በኑሮ ደካማ መሆንና የማኅበራዊ ኑሮ ጫና፤</em></div>\n<div><em>❖.ለገንዘብ ብቻ ሲሉ ማገልገል፤</em></div>\n<div><em>❖.ጥሩ ክፍያ ይከፍሉኛል የሚሉትን ብቻ መርጦ ማገልገል(የነፍስና የሥጋ ብለው ጉባኤያትን እስከ መክፈል ደርሰዋል)፤</em></div>\n<div><em>❖.ሀብታሞችን ብቻ ማሰባሰብ፤</em></div>\n<h3><strong>❹.ከፈተናዎች መጠበቅ</strong></h3>\n<div>✳.ከፈተናዎች መጠበቅ ሲባል</div>\n<div>\n<ul>\n<li>.ከመናፍቃንና ከአህዛብ፤</li>\n<li>.ከራስ ጋር፤ .ከወግ አጥባቂዎች፤</li>\n<li>&nbsp;.ጥቅማችን ሊነካ ይችላል ብለው ከሚያስቡ ግለሰቦች፤</li>\n<li>.ከባለስልጣናት ወዘተ ብዙ መከራና ግፍ ስለ ክርስቶስ ስም ይደርሳል።</li>\n</ul>\n<h2>ማጠቃለያ፦</h2>\n</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>&nbsp; &nbsp; &nbsp;ከላይ ከብዙዉ በጥቂቱ ለመግለጽ እንደሞከርነው በአጠቃላይ በዚህ ኮርስ የስብከት አመጣጥ ከሐዋርያት፣ሐዋርያነ አበዉ፣ዛሬም በዘመነ ሊቃዉንት እየተሰበከ ያለ ሲሆን ስለ ትክክለኛ ሐዋርያዊነት እና አገልግሎቱ&nbsp; ምን ይመስላል ትክክለኛ ሐዋርያዊነትስ ምን ይመስላል የሚለዉን የሚዳስስ ትምህርት ነው።&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</li>\n</ul>\n</div>\n<div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</h2>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;ዋቢ መጻሕፍት</h2>\n<div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>የስብከት ዘዴ&hellip;(በብጹዕ አቡነ ጎርጎርዮስ የሽዋ ሀገረ ስብከት ሊቀ ጳጳስ የነበሩ)&nbsp;</li>\n<li>ሐዋርያዊ ተልዕኮ(ሐዋተ) ...ለግቢ ጉባኤያት የተዘጋጀ(በዲ.ዳንኤል ክብረት</li>\n</ul>\n<p>&nbsp;</p>\n</div>\n</div>\n<h2>&nbsp; ስብሐት ለእግዚአብሔር ወለወላዲቱ ድንግል ወለመስቀሉ ክቡር ይቆየን!!!</h2>\n</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</div>\n<div>&nbsp;</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <strong>&nbsp; <em>አዘጋጅ፦ዲ/ን ሶፎንያስ ደመቀ(ወ/ጊዮርጊስ)&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</em></strong></div>\n<div><strong><em>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; +251927603731/+251935535937</em></strong></div>\n<div><strong><em>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 27/10/2018ዓ.ም</em></strong></div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</h2>', 'ሐዋርያዊ ተልዕኮ', 'Advanced', 'uploads/course_media/images/1782568307_caa0ff9a.jpg', '250.00', 'ዲ/ን ሶፎንያስ ደመቀ', 'uploads/course_media/pdfs/1782568307_60c6388f.pdf', '', '<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"text-decoration: underline;\"><strong>ሐዋርያዊ ተልዕኮ እና ኦርቶዶክሳዊ የስብከት ዘዴ</strong></span></h1>\n<div>❖.ስብከት የሚለው ቃል \"ሰበከ\" አስተማረ፣ አዋጀ ነገረ ከሚለው የግዕዝ&nbsp;ቃል የተገኘ ነው፡፡በግሪክ፣ኬሪግማ(kerygma) በእንግሊዝኛ sermonl&nbsp;ይባላል፡፡ ተዛማጅ /ተመሳሳይ/ የሆነ ትርጉም አለው፡፡ ማስተማር አዋጅመንገር የሚለውን ይተረጉማሉ፡፡</div>\n<div>↪ የቤተክርስቲያን ዋናው ተልዕኮዋ ሰዎችን..</div>\n<div>✦ . ከአለማመን ወደ ማመን ማምጣት፣</div>\n<div>✦ . ያመኑትን ደግሞ በእምነታቸው ማጽናት ነው፡፡</div>\n<div>\"<strong><em>በስብከት ሞኝነት የሚያምኑትን ሊያድን የእግዚአብሔር በጎ ፈቃድ&nbsp;ሆኗልና</em></strong>\"1ኛ ቆሮ 1&divide;21</div>\n<div>↪ ስብከት የቤተክርስቲያን ትልቁ የአገልግሎት ክፍል ነው፡፡</div>\n<div>✦ .ስብከት መንፈሳዊ ምግብን ለሰዎች መመገብ ማለት ሲሆን&nbsp;ለአንድ ሰው ሥጋዊ ምግብ ለመመገብ ከሚያስፈልገው ዝግጅት በላይ&nbsp;ዝግጅት ያስፈልገዋል።</div>\n<div>❖.የቤተ ክርስቲያን ተልዕኮዋ የስብከተ ወንጌል ዓላማ</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✔ ማንጻት(ያላመኑትን ማሳመን)&ldquo;<strong>ብዙኃን እለ ይቤሉ መኑ ያርእየነ ሠናይቶ&rdquo;</strong></div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✔ .ማጽናት እና</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✔ .መቀደስ ናቸው።</div>\n<h3><strong>❖.<span style=\"text-decoration: underline;\">ስብከት</span></strong></h3>\n<div>\n<ul>\n<li>ስለ እግዚአብሔር የምንመሰክርበት ነው።ዮሐ 1&divide;6፣1ኛ ዮሐ 1&divide;1፣ማቴ 10&divide;32</li>\n<li>የአምልኮ ክፍል ነው።</li>\n<li>ማምለክ፤ማመንና መዳን መሠረቱ መሰማት ነው።ሮሜ 10&divide;10-17</li>\n<li>ትእዛዘ እግዚአብሔር ነው።\"<em><strong>ለሕዝብም እንድንሰብክና በሕያዋንና በሙታን ሊፈርድ በእግዚአብሔር የተወሰነ እርሱ እንደሆነ እንመሰክር ዘንድ አዘዘን\"</strong></em>ሐዋ 10&divide;42</li>\n</ul>\n</div>\n<div><strong>✔ .አስተውሉ</strong>:-ጌታችን ኢየሱስ ክርስቶስ ደቀ መዛሙርቱን የጠራበትና የመረጠበት&nbsp;ዓላማና የመጨረሻው ትእዛዝ ስብከት ነው።።ማር 16&divide;15</div>\n<div>✦ .በአንደበታችን እውነትን ልንመሰክር ትእዛዘ እግዚአብሔርን ልንፈጽም&nbsp;ይገባል።</div>\n<div>\n<ul>\n<li>አንደበት \"<strong>ይእቲ ተዓቢ እም ሲኦል</strong>\"አንደበት ከሲኦል የከፋች ናት።</li>\n<li>\"<strong>ሞተ ዮሴፍ ነገርዎ ለዮሴፍ</strong>\"</li>\n</ul>\n</div>\n<div>✔ .ጨው ሳይሟሟ እንደማያጣፍጥ ሰውም ሳይደክም አገልግሎት&nbsp;(ስብከት) የለም።</div>\n<div>👉&ldquo;እንግዲህ ያላመኑበትን እንዴት አድርገው ይጠሩታል?ባልሰሙትስ&nbsp;እንዴት ያምናሉ? ያለ ሰባኪስ እንዴት ይሰማሉ?&rdquo;ሮሜ 10&divide;14 -15</div>\n<div>&ldquo;አንዳንዶች ተከራካሪዎችንም ውቀሱ፥ አንዳንዶችንም ከእሳት ነጥቃችሁ&nbsp;አድኑ&rdquo; ይሁዳ 1&divide;22</div>\n<div><em><strong>&ldquo;የወንጌል ሰባኪነትን ሥራ አድርግ፥ አገልግሎትህን ፈጽም</strong></em>።&rdquo; 2ኛ ጢሞ 4&divide;5</div>\n<div>👉&ldquo;በመልካም የሚያስተዳድሩ ሽማግሌዎች ይልቁንም በመስበክና&nbsp;በማስተማር የሚደክሙት እጥፍ ክብር ይገባቸዋል&rdquo;፩ኛ ጢሞ 5&divide;17</div>\n<div>👉&ldquo;ወንጌልንም ባልሰብክ ወዮልኝ&rdquo;1ኛ ቆሮ 9&divide;16</div>\n<div>👉&ldquo;ኃጢአተኛውን ኃጢአተኛ ሆይ በእርግጥ ትሞታለህ ባልሁ ጊዜ&nbsp;ኃጢአተኛውን ከመንገዱ ታስጠነቅቅ ዘንድ ባትናገር ያ ኃጢአተኛ&nbsp;በኃጢአቱ ይሞታል ደሙን ግን ከእጅህ እፈልጋለሁ&rdquo;ሕዝ 33&divide;8</div>\n<div>\n<ul>\n<li><strong>ስብከት የእግዚአብሔርን መንግስት የምንገልጥበት ነው።</strong></li>\n<li style=\"font-weight: bold;\"><strong>ስብከት መንግስተ ሰማያት እግዚአብሔርን ለሚወድና እንደፈቃዱ ለሚኖሩ የተዘጋጀቺ ናት\"🔆💡🔐</strong></li>\n</ul>\n</div>\n<div>❖&ldquo;ወንድሞቼ ሆይ ከእናንተ ማንም ከእውነት ቢስት አንዱም&nbsp;ቢመልሰው፣ኃጢአተኛን ከተሳሳተበት መንገድ የሚመልሰው ነፍሱን ከሞትእንዲያድን የኃጢአትንም ብዛት እንዲሸፍን ይወቅ\"ያዕ 5&divide;19-20</div>\n<div>✳.&ldquo;ስለ ሌላው ወንድሙ መዳን ግድ የሌለው ሰው እርሱ ይድናል ብዬ&nbsp;አላምንም፡፡&rdquo; ቅዱስ ዮሐንስ አፈወርቅ</div>\n<div>✳.\"ማንም ሳይከለክለው የእግዚአብሔርን መንግስት እየሰበከ ስለ ጌታ&nbsp;ኢየሱስ ክርስቶስ እጅግ ገልጦ ያስተምር ነበር\"ሐዋ 28&divide;31</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የስብከት ታሪክ</h2>\n<div><strong>፩ኛ.በዓለመ መላእክት:-</strong>መላእክት በተፈጠሩ በመጀመሪያ ቀን የመላእክት አለቃ የነበረ ሳጥናኤል የተፈጠረበትን ዓላማ በመሳት ክህደትንና ሐሰተኛነትን ከራሱ አፍልቆ እኔ ፈጥርኳችሁ ባለ ጊዜ ቅዱስ ገብርኤል \"ንቁም በበህላዌነ እስከ ንረክቦ ለአምላክነ\'\' በማለት መላእክትን አረጋግቷል ሰብኳል።የመጀመሪያው ስብከትም ይህ ነበር።ለበለጠ ግን ታሪኩን በሰፊው ተመልከቱ መጽሐፈ አክሲማሮስን \"<strong>ወበእንተዝ ደለወ ከመ ይጽር&nbsp;ዜናሃ ለማርያም</strong>\"ኢሳ 40&divide;1፣ምሳ 1&divide;35</div>\n<div><strong>፪ኛ.በህገ ልቡና:-</strong></div>\n<div>✦ .ከአዳም-ሙሴ&nbsp;ይሁ 14፣2ኛ ጴጥ 2&divide;5;ኩፋ 11&divide;14</div>\n<div><strong>፫ኛ.ህገ ኦሪት:-</strong></div>\n<div>✦ .ከሙሴ-መጥምቀ&nbsp;መለኮት&nbsp;ቅ/ዮሐንስ ፣ነኅ ፰&divide;፩-፰</div>\n<div><strong>፬ኛ.ዘመነ ወንጌል:-</strong></div>\n<div>✳.የዘመነ&nbsp;ወንጌል&nbsp;በር&nbsp;ከፋቺና&nbsp;መንገድ&nbsp;ጠራጊ&nbsp;መጥምቀ&nbsp;መለኮት&nbsp;ቅ/ዮሐንስ&nbsp;ነው።ማቴ 3&divide;2፣23&divide;35</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የስብከት አይነቶች</h2>\n<div>✳.ይዘትን መሠረት በማድረግ የስብከት ዓይነት በሦስት ይከፈላሉ፡፡እነርሱም:-</div>\n<div>\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 1ኛ.ትምህርት</p>\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2ኛ.ትምህርታዊ ስብከት እና</p>\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 3ኛ.ስብከት ናቸው።</p>\n</div>\n<h3>1ኛ.ትምህርት</h3>\n<div>✔ .በእውቀት ላይ የተመሠረተ</div>\n<div>✔ .ተከታታይነት ያለው</div>\n<div>✔ .በማስረጃ የተደገፈ</div>\n<div>✔ .ማብራራትን መተርጉምን፣ ማመሥጢርን የሚጠይቅ ነው።</div>\n<h3>2ኛ.ትምህርታዊ ስብከት፡-</h3>\n<div>✔ .በጥምረት የሚስጥ</div>\n<div>✔ .መነሻው ትምህርት መድርሻው ስብከት የሆነ</div>\n<div>✔ .ማስረጃ በመስጠት ሰውን ወደ ፈጣሪው የሚያቀርብ</div>\n<div>✔ .እውቀትና ሕይወት በአንድ ጊዜ የሚያስጨብጥ</div>\n<h3>3ኛ.ስብከት፡-</h3>\n<div>✔ .ቀለል ባለ አገላለጽ የሚቀርብ</div>\n<div>✔ .ማስረዳትና ማሳየት ላይ የሚያተኮር</div>\n<div>✔ .የሰውን ልቡናና አእምሮ መማረክ እና መግዛት የሚችል</div>\n<div>✳.ትምህርት አቀራረብን መሠረት በማድረግ ደግሞ በሚከተሉት&nbsp;ዘርፎች ይከፈላል።</div>\n<div><strong>❶.ነገረ ሃይማኖት:-</strong>ከስብከቶች ሁሉ ጠጣርና ከባድ የሚባለው&nbsp;የስብከት ዓይነት ነው፡፡ይህን ትምህርት ለማስተማር ሰባኪውየሚከተሉትን ነጠቦች ማስታዋል ይጠበቅበታል፡፡</div>\n<div><strong><em>ሀ.አንድ ነጥብ ላይ ብቻ ማተኮር</em></strong></div>\n<div>ለምሳሌ፡-ሀልዎተ እግዚአብሔር ፣ምሥጢረ ሥላሴ&hellip;</div>\n<div><strong>ለ.በሚገባ ማብራራት፡-</strong>ሊያስተምር የፈለገውን ነጥብ በሚገባ&nbsp;ማብራራት ይኖርበታል፡፡የሚያበራራባቸው ዘዴዎችም፡-</div>\n<div>✔ .ምሳሌዎችን በማንሳት፤</div>\n<div>✔ .ታሪክ በማስታወስ በመተረክ</div>\n<div>✔ .ለትምህርት አስረጂ ጥቅሶችን በማንሳት</div>\n<div>✔ .የሊቃውንትን ብሒል በመጠቀም</div>\n<div><strong>❷.ታሪካዊ:-</strong></div>\n<div>❖.ይህ ዘዴ አብዛኛውን ጊዜ በበዓላት ቀን የምናስተምርበት መንገድ&nbsp;ነው፡፡ በየበዓላቱ የዕለቱ ስንክሳር፣ገድል፣ድርሳን ይነበባል፣ ይተረካል፡፡ሰባኪውና የስብከቱ ቦታ የኦርቶዶክስ ቤተ ክርስቲያን እንደመሆኑ እነዚህን&nbsp;አስቀድሞ አንብቦና አጥንቶ ለምእመናን ማስተማር ይጠቅበታል፡፡</div>\n<div>❖.ሰባኪው ሕዝቡን በሚመጥንና በማያስለች መልኩ ቀላልና ግልጽ&nbsp;በሆነ አቀራረብ ሰዓት መጥኖ ርዕስ መርጦ ምእመናን ከታሪኩ ተነስተው&nbsp;በሕይወታቸው ላይ ትርጉም እንዲኖራቸው ወደ ሕይወት በመቀየር&nbsp;ማጠቃለያውን ስብከት አድርጎ መጨረስ ማለት ነው፡፡</div>\n<div><strong>❸.ባለ አንድ ሐረግ ስብከት</strong></div>\n<div><strong>❹.ቅዳሴያዊ ስብከት:-</strong>ይህ ዓይነት ስብከት በጾም ወቅት በኪዳን የጸሎት&nbsp;ሰዓት፣በንግስ ጊዜ፣በሥርዒተ ቅዲሴ መካከል የሚሰጥ ትምህርት ነው፡፡በቤተክርስቲያናችን ዋነኛው የስብከት ዘዴ ነው፡፡</div>\n<div>✔ በአጭሩ ስለ ስብከት አይነቶች ጠቅለል አድርገን ስንመለከት&nbsp;እነዚህን ነጥቦች ማየት እንቺላለን።</div>\n<div><strong>✳.ኬሪግማቲክ</strong>:-የማያምኑን አረማውያን ሰዎችን እግዚአብሔርን&nbsp;ካለማመን ወደ ማመን የምንመልስበት የስብከት ዓይነት ነው።</div>\n<div><strong>✳.ዲዳክቲክ(ዲያሌክቲክ)</strong>:-ያመኑትን፣ነገር ግን ያልጠነከሩትን አዲስ&nbsp;አማንያንን፤ንዑስ ክርስቲያንን የምንጸናበት የስብከት አይነት ነው።</div>\n<div>↪ አምነው የነበሩ፣ነገር ግን በልዩ ልዩ ምክንያት የዓለማውያን ጠባይ&nbsp;የወረሳቸውን የማነጽ የስብከት አይነት ነው።</div>\n<div><strong>✳.ፕራግማቲክ(ፕራክሎቲክ)</strong>:-አምነው&nbsp;በእምነት፤በእውቀት፤በምግባር የጸኑትን መጠበቅና ወደ ተግባራዊ&nbsp;አኗኗር የምንሸጋገርበት ለቅድስና ሕይወት የምናበቃበት የስብከት</div>\n<div>ዓይነት ነው፡፡</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የመልካም መምህር(ሰባኪ) ባህርያት</h2>\n</div>\n<h4>❶.በእምነት እና በእውቀት በመስተማር (ትምህርት)</h4>\n<div>🔆.መንፈሳዊ መምህር ማስተማር ያለበት በእምነት ነው።እምነት&nbsp;የሌለው ሰው ሌላውን ሊያሳምን አይችልም።ክህደትን ቆርጦ ለመጣል&nbsp;አስተማሪው በመጀመሪያ በእምነት መሳል አለበት።</div>\n<div>\"<strong>አመንኩ በዘነበብኩ</strong>\"መዝ 115&divide;1አመንሁ ስለዚህ ተናገር</div>\n<div>🔆.መምህር ሠወች የእግዚአብሔር ቸርነት እንዲቀምሱ የመጋበዝ&nbsp;ሀላፊነት አለበት።</div>\n<div>\"<strong>ጠአሙ ወተአይምሩ ከመ ሔር እግዚአብሔር</strong>\"መዝ 33&divide;15 ነገር ግን ያልቀመሱትን ነገር ቅመሱ ማለት አይቻልም።አንድ መምህር በእምነት ያላጣጣመውን ትምህርት ቢያስተምር ትርፉ ድካም ብቻ ነው።</div>\n<div>❖.አንድ ሰባኪ ሳይማር ሌሎችን ለማስተማር አይችልምና በቅድሚያ በሚገባ መጽሐፍ ቅዱስን የተማረ መሆን አለበት፡፡✔ .ስለዚህ አንድ ሰባኪ ከአባቶች እግር ሥር የተማረ መሆን አለበት። ከአባቶች ከሚቀዳው ምንጭ የጠጣና በትሕትና ራሱን ዝቅ በማድረግ ምስጠሩን እግዚአብሔር እንዲገልጥለት በጸሎት በመጠየቅ የተማረ መሆን አለበት፡፡</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<em><strong>\"ሳይማር የሚያስተምር ከተሳዳቢ ይቆጠራል\"</strong></em></div>\n<h4><strong>❷.መጻሕፍትን ማንበብ:-</strong></h4>\n<div>❖.አንድ ሰባኪ ወይም መምህር እንደመሆኑ መጠን ከመማሩ በተጨማሪ&nbsp;ሌሎች ተጨማሪ ይጠቅማሉ የሚላቸውን መጻሕፍቶች ዘመኑን በመዋጀት&nbsp;ማንበብ አለበት።</div>\n<div>✔ . ከሚያስተምራቸው ሰዎች በእውቀት ልቆ መገኘት አለበት፤ ካልሆነ ግን&nbsp;ቤተ ክርስቲያኗን ያስገምታታል፡፡</div>\n<div>✳.\"<strong>ለማንበብና ለመምከር ለማስተማርም ተጠንቀቅ</strong>&rdquo; 1ኛ ጢሞ 4&divide;13</div>\n<div>✳&ldquo;ሰባኪውም ጠቢብ ስለ ሆነ ለሕዝቡ እውቀትን አስተማረ፣እርሱም ብዙ&nbsp;ምሳሌዎችን መረመረና ፈላለገ፣አስማማም።&rdquo; መክ 12&divide;9-10</div>\n<div>✳.\"<strong>ለእመ ሐሰሰከ ትኩን መምህረ ኩን ገንዳሌ መጻሕፍት</strong>\"ቅ.ዮሐንስ&nbsp;አፈወርቅ</div>\n<div>➡.ሰባኪ መጻሕፍትን ካላነበበና በእውቀት ራሱን ካላካበተ የሚናገረው&nbsp;ይደናገረዋል፤ይጠፋዋል፡፡ስለዚህ ከሌሎች መምህራን፣ ከቅዱሳት መጻሕፍት፣ከምቹ አጋጣሚዎችወዘተ መማር አለበት፡፡</div>\n<div><strong>❖.አስተውሉ:</strong>-ብርጭቆ ካልሞላ አይፈስም ፤ሰባኪም ሙሉ ካልሆነ&nbsp;የምዕመናንን ልብ ማርካት አይቺልም።</div>\n<h3><strong>❸.ቀናዒነት:-</strong></h3>\n<div>💠.የክርስቶስ ወንጌል ለሁሉም ይዳረስ ዘንድ ሁሉም ይድኑ ዘንድ&nbsp;በትጋናት በቅናት ሌትና ቀን ደከመኝ ሰለቸኝ ሳይል መጋደል አለበት፡፡</div>\n<div>🔆.&ldquo;የቀረውንም ነገር ሳልቆጥር ዕለት ዕለት የሚከብድብኝ&nbsp;የአብያተ ክርስቲያናት ሁሉ አሳብ ነው&rdquo; 2ኛ ወደ ቆሮ 11&divide;28</div>\n<div>🔆. \"ለቅዱሳን አንድ ጊዜ ፈጽሞ ስለተሰጠቺ ሃይማኖት&nbsp;እንድትጋደሉ እየመከርኳችሁ እጽፍላችሁ ዘንድ ግድ ሆነብኝ\"ይሁ 1&divide;3</div>\n<h3><strong>❹.ክርስቲያናዊ ሕይወት:-</strong></h3>\n<h4><em>✔ .በፍቅር እና በትህትና የሚታወቅ</em></h4>\n<div>✳.\"ፍቅር ለዘወትር አይወድቅም\"1ኛ ቆሮ 13&divide;8</div>\n<div>✳<em><strong>.ሠናየ ሀልዩ በልብክሙ/ ለቢጽክሙ/ ተፋቀሩ በኩሉ ጊዜ ዝ ውእቱ&nbsp;ፈቃዱ ለእግዚአብሔር መንፈሰ ኢታጥፍኡ ተነብዮ ኢትመንኑ ወኩሎ&nbsp;አመክሩ ወዘሠናየ አጽንኡ</strong></em>\"በልባችሁ መልካም ነገርን አስቡ&nbsp;የእግዚአብሔር ፈቃድ እርስ በርሳችሁ እንድንፋቀሩ ነውና እርስበርሳችሁ&nbsp;ሁልጊዜ ተፋቀሩ መንፈሳዊ ነገርን አታጥፉ ትንቢትንም አትናቁ ሁሉንም&nbsp;መርምሩ የተሻለውን አጽንታችሁ ያዙ\"</div>\n<div>🔆. \"<strong>ተፋቅሮ ኢያስተፄንስ ወኢያሄሊ ተድላ ለባህቲቱ</strong> \"ፍቅር ማንንም ችግር&nbsp;ውስጥ አያስገባም የብቻ ድሎትንም አያሳስብም ወይም ብቻየን ልደሰት&nbsp;አያስብልም\"ፍቅር ከስግብግብነት ከቀናተኛነት ወጥቶ ለሌሎች መትረፍ ስለሆነ&nbsp;ብቻየን ይድላኝ አያሰኝም፡፡1ኛ ቆሮ 13&divide;5</div>\n<div><strong>✳.አስተውሉ</strong>:-ጸጋ እግዚአብሔር የሚፈሰው ዝቅ ወደአሉ ሰዎች ነው።</div>\n<h3><strong>❖.ሰባኪ መምህር ትሁት መሆን አለበት።</strong></h3>\n<div>\"ማንም ለሰርግ ቢጠራህ አስቀድመህ በከበሬታ ወንበር አትቀመጥ&nbsp;ምናልባት ከአንተ ይልቅ የከበረ ተጠርቶ ይሆናልና አንተንም እሱንም&nbsp;የጠራ ጋባዥ መጥቶ ለዚህ ስፍራ ታውለት ይልሃል ያንጊዜ እያፈርክ&nbsp;በዝቅተኛ ቦታ ትሆናለህ..\"ሉቃ 14 &divide;7-11 ብሎ በምሳሌ ጌታችን&nbsp;ያስተማረው ደቀ መዛሙረቱ ለማስተማር ሲሽቀዳደሙ በማየቱ&nbsp;እንደሆነ ነው የሚነገረው።</div>\n<div>\"ማንም ከእናንተ ታላቅ ሊሆን የሚወድ የሁሉ አገልጋይ ይሁን\"ማቴ 20&divide;26 ይህንን ትህትና ማሳየት መቻል አለበት።</div>\n<div>✔ .ማስተማርን የሥጋዊ ክብር መፈለጊያ ማድረግ አያስፈልግም ክብር&nbsp;እንደ ጥላ ሲሸሿት የምትርቅ ሲርቋት ደግሞ የምትቀርብ ናት።</div>\n<div>💠.\'\'<strong>ዘአትሐተ ርእሶ ይትሌአል ወዘ አልአለ ርእሶ ይቴሀት፤ እስመ&nbsp;ዘአዕበየ ርእሶ የሐስር ወዘአትሐተ ርእሶ ይከብር</strong>\"ማቴ 23&divide;12 -ራሱን&nbsp;ዝቅ ዝቅ የሚያደርግ ከፍ ክፍ ይላል ራሱን ከፍ ክፍ የሚያድርግ ደግሞ&nbsp;ዝቅ ዝቅ ይላል፡፡አባቶቻችን ምድር ከዚህ በታች ዝቅ የማትለው&nbsp;እስከመጨረሻው ዝቅ ስላለች ነው ይላሉ፡፡ሌላው ፀሐይ በደንብ&nbsp;የምታሞቀው ዝቅ ያለውን ነው፡፡ከፍ ሥትል ትቀዘቅዛለህ ስለዚህ&nbsp;ላለመቀዝቀዝ ራስህን ከፍ አታድርግ፡፡ከፍ አትበል በረዶ ትሆናል፡፡</div>\n<h3><strong>✔ .በክርስትና ሕይወቱ የተመሰከረለት</strong></h3>\n<div>✳.\"ወዘሰ ኢይክል ሠሪዐ ቤቱ እፎኑ ያስተሐምም ቤተ እግዚአብሔር \"ጢሞ 3&divide;5</div>\n<div>✳.በእናንተ ስበብ የእግዚአብሔር ስም ይሰደባል\"ሮሜ 2&divide;20-24</div>\n<div>➡ሃይማኖቱ የቀና፤ስነ ምግባሩ የተስተካከለ፤ከእውቀቱ ይልቅ በተግባሩ&nbsp;የሚሰብክ፤የሚጣፍጥ ጨው መልካም መዓዛ ያለው መሆን አለበት።1ኛ ቆሮ 11&divide;1</div>\n<div><em><strong>\"አንተ መዓዛህ ምንድን ነው?ክርስቶስ ክርስቶስን ነው ወይስ ዲያቢሎስ&nbsp;ዲያቢሎስን?መዓዛህ የሚታወቀው በታቀፈው ነው፤አንድ እናት የምትሸተው&nbsp;በታቀፈቺው ልጅ ነው\"<span style=\"text-decoration: underline;\">አረጋዊ መንፈሳዊ</span></strong></em></div>\n<h3><strong>❺.የማይፈራና የማያፍር መሆን</strong></h3>\n<div>✦ .ሰው ምን ይለኝ ይሆን በማለት ሳይጨናነቅ ጥበብ በተሞላበት&nbsp;በሁኔታ የእግዚአብሔርን ቃል በሚገባ ማስተላለፍ አለበት፡፡</div>\n<div>✳.&ldquo;<strong>በወንጌል አላፍርም</strong>&rdquo; ሮሜ 1&divide;16</div>\n<div>✳. &ldquo;ነገር ግን የሠራዊት ጌታ እግዚአብሔርን ቀድሱት፣ የሚያስፈራችሁና&nbsp;የሚያስደነግጣችሁም እርሱ ይሁን\"ኢሳ 8&divide;13</div>\n<h3><strong>➏ .አላስፈላጊ እንቅስቃሴ አለማድረግ</strong></h3>\n<div>✔ .እጅን ማወራጨት፤</div>\n<div>✔ .ራስን፣ . . . ማከክ፤</div>\n<div>✔ .ወዲያ ወዲህ መንጎራደድ፤</div>\n<div>✔ . አላስፈላጊ ድግግሞሽ ማድረግ የለበትም፡፡</div>\n<h3>❼.መጥኖ ማስተማር የሚቺል፤</h3>\n<div>✦ ያልተመጠነ ነገር ይጎመዝዛል ያልተመጠነ ነገር ጣእም&nbsp;አይኖረውም።ቅዱስ ጴጥሮስ በ፩ኛ መልእክቱ 4&divide;8 እና 5&divide;8 በመጠን ኑሩ ብሎ እንዳስተማረን ለሁሉም ነገር መጠንና ልክ አለው።</div>\n<div>\"<strong>ዘበልአ በአቅሙ የኃድር በሰላም</strong>\" እንዳለው ጠቢቡ ሰሎሞን ስጋዊ&nbsp;ምግብን በመጠን እንደምንመገብ ሁሉ ቃለ እግዚአብሔርንም በመጠን&nbsp;መማር ያስፈልገናል።ምእመናን መመህሩ የያዘውን ሁሉ እንዲይዙ&nbsp;የሚሞክርባቸው ቤተ ሙከራወች አይደሉም በመጠን ሰምተው&nbsp;ከህይወታቸው ጋር እንዲያዋህዱ የሚጠበቁ ናቸው እንጅ</div>\n<div>\n<p>\"<em><strong>ወበዘከመዝ አምሳል ተናገሮሙ ቃሎ በአምጣነ ይክሉ ሰሚዓ</strong></em>\" መስማት በሚችሉበት መጠን እነዚህን በሚመስል በብዙ ምሳሌ ቃሉን ይነግራችው ነበር።ማር 4&divide;33</p>\n<h3>❽.አርዓያ ክህነት(አለባበስ)</h3>\n</div>\n<div>✳በኢትዮጵያ ቤተክርስቲያን የስብከተ ወንጌል ታሪክ በጃንደረባው&nbsp;ቢጀመርም የተሟላ ሆኖ የተፈጸመውና በተግባራዊነት ዕድገት ያሳየው&nbsp;ከፍሬምናጦስ የክህነት አገልግሎት በኋላ ነው፡፡</div>\n<div>&nbsp;</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<em><strong> &nbsp;ከ34ዓ.ም-330ዓ.ም</strong></em></div>\n<div>✳ አለባበሱ አርአያ ክህነትን የጠበቀ መሆን አለበት፡፡ንጽሕናውን&nbsp;የመጠበቅና አግባብ ያለው አለባበስ መሆን አለበት።በጣም ከደረጃዉ&nbsp;የወረደ ወይም በጣም ዘመናዊ የሆነ ልብስ መልበስ የለበትም፡፡</div>\n<div><em><strong>\"ኢኃደጋ ለምድር እምቅድመ ዓለም ወእስከ ለዓለም እንበለ ካህናት&nbsp;ወዲያቆናት</strong></em>\"<strong><span style=\"text-decoration: underline;\">ቅ/ያሬድ</span></strong></div>\n<div>&nbsp;</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 1ኛ ቆሮ 15&divide;45 ተመልከቱ</div>\n<h3><strong>መምህራን፦</strong></h3>\n<ul style=\"list-style-type: square;\">\n<li>\"<em><strong>እለ ይሜህሩ ወንጌለ ለኩሉ ፍጥረት</strong></em>\"</li>\n<li>\"<strong>እስመ አርአያየ ወሀብኩክሙ</strong>\"ዮሐ 13&divide;15</li>\n</ul>\n<h3>❾.ከመስበኩ በፊት ቅድመ ዝግጅት ማድረግ</h3>\n<div>✳. ሰባኪ መጋቢ ነው፡፡ለዝግጅቱ በቂ ጊዜ በመስጠት መጻሕፍትን&nbsp;በማንበብ ማስታወሻ በመያዝ መዘጋጀት አለበት።በሚገባ ተዘጋጀቶ በመሄድ በሚገባ ቦታ የሚገባውን መልእክት&nbsp;አስተላልፎ መምጣት አለበት እንጂ በችኮላ ሳይዘጋጅ በመሄድ&nbsp;ዘበራርቆ መምጣት የለበትም፡፡</div>\n<div>✳.ለማን እንደሚሰብክ ማወቅ አለበት።የስብከት በተለያዩ ቦታዎችና&nbsp;ለተለያዩ ሰዎች ለምሳሌ፡-</div>\n<div>\n<ul style=\"list-style-type: circle;\">\n<li>በሐዘን ቤት፣</li>\n<li>በሠርግ ቤት፣</li>\n<li>በእስር ቤት&hellip;የሚሰጥ ሲሆን</li>\n</ul>\n</div>\n<div>✦ .ሰዎቹ ያሉበትን ሁኔታ</div>\n<div>✦ .ቦታውን</div>\n<div>✦ .የሰዎቹን የእውቀት ደረጃ</div>\n<div>✦ .ባህልና እድሜ&nbsp;ጠንቅቆ ማወቅ ያስፈልጋል።</div>\n<h3>❿.ራስን አለመስበክ፤</h3>\n<div>🔆.ራሱ ባለቤቱ ክርስቶስ ምንም እንኳን በሥልጣን፣ በፈቃድ፣በሕልውና፣ በባሕርይ ከአብና ከመንፈስ ቅዱስ ጋር አንድ (ትክክል)&nbsp;ቢሆንም በተዋሐደው ሥጋ ምክንያት ወልድ ከአብ ዘንድ የተላከና ለአብ&nbsp;የታዘዘ ነው።</div>\n<div><strong>\" የላከኝን ፈቃድ እንጂ ፈቃዴን ላደርግ አልሻምና\"</strong>ዮሐ 5&divide;30&nbsp;በማለት እንደተናገርው።</div>\n<div>🔆.መጥምቀ መለኮት ዮሐንስም \"ስለ ራስህ ምን ትላለህ?\"ብለው ለጠየቁት&nbsp;የሰጠው መልስ \"የጌታን መንገድ አቅኑ ብሎ በምድረ በዳ የሚጮህ ሰው&nbsp;ድምጽ እኔ ነኝ\" ብቻ ነበር ያለው፡፡ዮሐ 1&divide;23</div>\n<div><strong>❖.አስተውሉ</strong>:-ዮሐንስ የክርስቶስን ፈቃድ እንጂ የራሱን የሚያውቀውን&nbsp;እውነተኛ ታሪኩን እንኳን መናገር አልፈለገም፡፡ አንድ ሰባኪም እንዲሁ&nbsp;ሊያደርግ ይገባል።</div>\n<div>✳.የሚያደንቁት ሰባኪና ምን ልሥራ ብለው የሚጠይቁት ሰባኪ በእጅጉ&nbsp;ይለያልና ሰባኪ ራስን ከመስበክ ነጻ መሆን ይጠበቅበታል፡</div>\n<div>✳.\"ብዙ ሰዎች ቸርነታቸውን ያወራሉ የታመነውን ሰው ግን ማን&nbsp;ያገኘዋል\"ምሳ 20&divide;6</div>\n<div>✳.\"እግዚአብሔር የላክው የእግዚአብሔር ቃለ ይናገራል\"ዮሐ 3&divide;34</div>\n<div>✳.\"ልቡናዬ መልካም ነገርን አፈለቀ (አወጣ)\"ቅ/ዳዊት</div>\n<div>✳.\"እኛ ግን የተሰቀለውን ክርስቶስን እንሰብካለን\"1ኛ ቆሮ 1&divide;23</div>\n<h3>⓫.ርእሱን መጠበቅ፤</h3>\n<div>✳.አንድ ሰባኪ በግድ የለሽነት ተነስቶ ርእሱን ያልጠበቀ ስብከት&nbsp;ለአድማጮች ጥቅም የማይሰጥ ከመሆኑም ባሻገር ሰባኪውን&nbsp;ያስገምተዋል፡፡</div>\n<div>✳.ምስጢር ሳበኝ እያለ ትዝ ያለውን ሁሉ ማውራት የለበትም፡፡</div>\n<div>✳.የማያውቀውን ወይም እርግጠኛ ያልሆነበትን ነገር ለመናገር መድፈር&nbsp;የለበትም።</div>\n<div>✳.ስብከት ርዕሱ ካልተጠበቀ ውጤታማ ሊሆን አይችልም፤ ምእመናኑ&nbsp;የሚጨብጡት ነገር አይኖራቸውም ሰባኪውም ትዝብት ውስጥ&nbsp;ይወድቃል፡፡ ርዕስ መጠበቅ የሚሰጠው ትምህርት ወጥና ያልተደባለቀ&nbsp;ያደርገዋል።</div>\n<div><strong>ለምሳሌ፡</strong>- ስለ ምሥጢረ ሥላሴ ጀምሮ ስለ ጾም፤ስለ ቅዱስ ቁርባን ጀምሮ ስለ&nbsp;ሥዕል፤ስለ ክርስቶስ የባሕርይ አምላክነት ጀምሮ ስለ ታቦትየሚል ከሆነ\"አርባ ስድስት ጥዳ አንዱንም&hellip; አረረባት\" እንደተባለው ይሆናል፡፡</div>\n<div><strong>✳.አስተውሉ:-</strong> ሰዓትና ርዕስ መጠበቅ የአንድ ሰባኪ መታወቂያዎች ናቸው፡፡</div>\n<div>🔆.ሁሉ ነገር በልኩና በአግባቡ ሊሆን ይገባዋል።ነገር ሲበዛ ውጤቱና&nbsp;መጨረሻው አያምርም።</div>\n<div>✳.\"የምነግራችሁ ገና ብዙ አለኝ ነገር ግን አሁን ልትሸከሙት&nbsp;አትችሉም\"ዮሐ 16&divide;12 በማለት ተነግጿል</div>\n<div>✳.\"<em><strong>ግብር ዘአልቦ ምጣኔ ገአር ውእቱ ወለገአርኒ ይተልኦ ዝንጋኤ</strong></em>\"ልክ&nbsp;የሌለው ስራ ድካም ነው ድካምንም መዘንጋት ይከተለዋል ያልተመጠነ&nbsp;ትምህርትም ተናጋሪውንም ሰሚውንም ወደ መሰልቸት ያደርሳል።</div>\n<div>✳.መመጠን(አለማርዘም):-በመጠን ኑሩ&rdquo; 1ኛ ጴጥ 5&divide;8</div>\n<h2><strong>⓬.ድምፁን መመጠን</strong></h2>\n<div>✔ .ሰባኪው ድምጹ ለአድማጭ የሚረብሽና የሚሰቀጥጥ በጣም የሚጮኽ&nbsp;ወይም በጣም ፈዘዝ ያለ ለአድማጭ የሚሰለች መሆን የለበትም።</div>\n<div>✔ .በጣም መፍጠንም በጣም መጐተትም የለበትም፣ ትክክለኛና&nbsp;አግባብ ባለው ሁኔታ መሆን አለበት።</div>\n<h3><strong>⓭.የሰባኪውና አድማጩ ግንኙነት</strong></h3>\n<div>✳.ተረጋግተው ቦታቸውን እስኪይዙ ድረስ መጠበቅ አለበት፡፡</div>\n<div>✳.የአድማጮቹን ሁኔታ ይገምታል፡፡</div>\n<div>✳.ከዚያ በኋላ ለዕለቱ ተስማሚ በሆነ ርዕስ ትምህርቱን ይጀምራል፡፡</div>\n<div>✳.ዓይንን በአንድ ቦታ ላይ ወይም በአንድ ሰው ላይ ሳይተክሉ&nbsp;በአራቱም አቅጣጫ ቃኘት በማድረግ ሰልችቷቸው ወይም ደክመው&nbsp;እንዳይሆን ወይም አልገባቸው እያለ እንዳይሆን በዓይን ሁሉንም&nbsp;አድማጭ ለመቆጣጠር መሞከር እና በሚሰብክበት ጊዜ ጣራ ጣራ&nbsp;ወይም ወደ መሬት ማየት የለበትም፡፡</div>\n<h3><strong>⓮.ራስን መሆን</strong></h3>\n<div>✳.ሌሎችን ለመሆን መጣር የለበትም።</div>\n<h3>⓯.የተሰባክያንን ሥነ ልቡና መረዳት</h3>\n<div>✳.በመማር ማስተማር ሂደት ውስጥ የተሰባክያንን ስነ ልቡና ማወቅና መረዳት&nbsp;ለሰባኪው ከፍተኛ ጥቅምና እንደ ዋና ግብዓት ሆኖ የሚያገለግል ጉዳይ ነው።</div>\n<div>✳.ይህም ማለት የተሰባኪያንን ሥነ ልቡና መረዳት ሲባል</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>መዳን እንደሚወዱ ማወቅና ጠይቆ መረዳት፤</li>\n<li>እንደራባቸው ምግብ እንደሚያስፈልጋቸው መረዳት፤</li>\n<li>ጥያቄ ሊጠይቁ እንደፈለጉ መረዳት፤</li>\n</ul>\n</div>\n<div><strong>አስተውሉ:-</strong>እናንተን የሚጠይቋችሁ ሰዎች አራት አይነት አመለካከት&nbsp;ያላቸው መሆኑን አትዘንጉ።<strong>እነርሱም</strong>:-</div>\n<div>&nbsp;</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li><em><strong>፩ኛ.መምህራንን ለመፈተሽ የሚጠይቁ፤</strong></em></li>\n<li><em><strong>፪ኛ.ያውቀዋል ነገር ግን ሌሎች እንዲያውቁት ፈልጎ የሚጠይቅ፤</strong></em></li>\n<li><em><strong>፫ኛ.ያውቀዋል፤ነገር ግን ተጨማሪ ፈልጎ የሚጠይቅ፤</strong></em></li>\n</ul>\n<p><em><strong>፬ኛ.ምንም አያውቅም፤ስለዚህ ለማወቅ የሚጠይቅ እንዳለ መዘንጋት የለባችሁም።</strong></em></p>\n<h3><span style=\"text-decoration: underline;\"><em><strong>🔆.የተሰባኪያንን ሥነ ልቡና የመረዳት ጠቀሜታው</strong></em></span></h3>\n</div>\n<div>❶.ከአድማጩ ለመተቼት ለመዳን፤</div>\n<div>❷.ከመፍረድ ለመዳን፤</div>\n<div>❸.ከማጽደቅና ከመኮነን ለመዳን...ወዘተ.....</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;\"<em><strong>እንደካርቦን አትሁን\" ለምን ካልከኝ ካርቦን የጻፉለትን ኮፒ ያደርጋልና።</strong></em></div>\n<h3><strong>⓰.ንግግሩ ኦርቶዶክሳዊ ላህይ ያለው መሆን አለበት፡፡</strong></h3>\n<div>💠. ሰባኪው የቤተ ክርስቲያን መቃን የመታው የቤተ ክርስቲያንን&nbsp;ቋንቋ በሚገባ የሚያውቅ መሆን አለበት፡፡</div>\n<div>💠.ጸያፍ የሆኑና ኦርቶዶክሳዊ ያልሆኑ ቃላትን መጠቀም የለበትም፡፡</div>\n<div>💠.የማይመጥኑ ወይም ለአድማጩ ከባድ የሆኑ ቃላትን መጠቀም&nbsp;የለበትም።</div>\n<div>💠.ጠንከራ ስሜት ማለትም በቀላሉ የማይበርድ ስሜት ሊኖረው&nbsp;ይገባል።</div>\n<div>💠.አለምልሞ መገሰፅ የሚችል መሆን አለበት።ይህ ማለት አስተምሮ&nbsp;መምክርና መገሰፅ አለበት ማለት ነው።ጌታችን ኒቆዲሞስን&nbsp;አስተምሮ እንደገሰፀው።</div>\n<h3><strong>⓱.ቁረጠኝነት ሊኖረው ይገባል</strong></h3>\n<div>✳. &ldquo;የሎጥን ሚስት አስቧት&rdquo;ሉቃ 17&divide;32</div>\n<div>✳.ያለቆረጠ ሰው የትም መድረስ አይችልም፡፡</div>\n<div>&ldquo;በዚያን ጊዜ ኢየሱስ ለደቀ መዛሙርቱ እንዲህ አለ፦ እኔን መከተል&nbsp;የሚወድ ቢኖር ራሱን ይካድ መስቀሉንም ተሸክሞ ይከተለኝ።ነፍሱን&nbsp;ሊያድን የሚወድ ሁሉ ያጠፋታል፤ስለ እኔ ግን ነፍሱን የሚያጠፋ ሁሉ&nbsp;ያገኛታል።&rdquo; ማቴ 16&divide;24</div>\n<div>✳. \"<em><strong>መኑ የሀድገነ ፍቅሮ ለክርስቶስ</strong></em>\"ሮሜ 8 እንዳለ ቅዱስ ጳውሎስ&nbsp;ሰባኪ መምህርም ለዓላማው እስከሞት ድረስ የታመነ መሆን አለበት።</div>\n<div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የኦርቶዶክሳዊ ስብከት መለያ ጠባያት</h2>\n</div>\n<div><strong>መጽሐፋዊ፦</strong></div>\n<div>\n<ul>\n<li>✳.መጽሐፍ ቅዱስ</li>\n<li>✳.አዋልድ መጻሕፍት</li>\n<li>✳.ታሪካዊ መጻሕፍት</li>\n</ul>\n<p><strong>ነገረ መለኮታዊ፦</strong></p>\n<ul>\n<li>✳.ምሥጢራተ ቤተ ክርስቲያን</li>\n<li>✳.ሥርዓተ ቤተ ክርስቲያን</li>\n<li>✳.ሐዋርያዊ ትውፊት</li>\n<li>✳.ዶግማ</li>\n</ul>\n</div>\n<div><strong>✳.ማኅበራዊ ኑሮን በተመለከተ</strong></div>\n<div><strong>✳.ሥርአተ ቤተ ክርስቲያን</strong></div>\n<div><strong>✳.ጥምረት ያለው የስብከት አይነት አለ።</strong></div>\n<div>&nbsp;</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የስብከት ዝግጅት</h2>\n<div>💠.አንድ ስብከት ፮ ንዑሳን ዘርፎችና&nbsp;ክፍሎች አሉት።እነርሱም:-</div>\n<div>\n<ul style=\"list-style-type: circle;\">\n<li>✳.ርእስ</li>\n<li>✳.ዓላማ</li>\n<li>✳.መግቢያ</li>\n<li>✳.ዋና ክፍል</li>\n<li>✳.ምክር</li>\n<li>✳.መደምደሚያ</li>\n</ul>\n</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; የስብከተ ወንጌል መንገዶች</h2>\n<div>❖.የስብከተ ወንጌል መንገዶችን በሚከተሉት መንገዶች መክፈል&nbsp;ይቻላል።እነርሱም:-</div>\n<div>\n<ul>\n<li>.ብቻ ለብቻ (ለአንድ ሰው)፣</li>\n<li>.ለጥቂት ሰዎች (ለደቀ መዛሙርት፣ ለቤተሰቦች)፣</li>\n<li>.ለሕዝብ፣</li>\n<li>.ለማኅበር፣ . . .</li>\n</ul>\n</div>\n<h3>❶.ለህዝብ:-</h3>\n<div>✳.&ldquo;ሕዝቡንም አይቶ ወደ ተራራ ወጣ፤ በተቀመጠም ጊዜ ደቀ መዛሙርቱ&nbsp;ወደ እርሱ ቀረቡ፤ አፉንም ከፍቶ አስተማራቸው እንዲህም አለ፦ . . .&rdquo;ማቴ. 5፡1-2</div>\n<h3>❷.ብቻ ለብቻ(አንድ ለአንድ):-</h3>\n<div>\n<ul style=\"list-style-type: square;\">\n<li style=\"font-weight: bold;\"><strong>✳.ኒቆዲሞስ</strong></li>\n</ul>\n</div>\n<div>&ldquo;ከእነርሱ አንዱ በሌሊት ቀድሞ ወደ እርሱ መጥቶ የነበረ ኒቆዲሞስ፡-ሕጋችን አስቀድሞ ከእርሱ ሳይሰማ ምንስ እንዳደረገ ሳያውቅ በሰው&nbsp;ይፈርዳልን? አላቸው።&rdquo; ዮሐ. 7&divide;50-51</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li style=\"font-weight: bold;\"><strong>✳.ለሳምራዊቷ ሴት</strong></li>\n</ul>\n</div>\n<div>&ldquo;ሴቲቱም፡- ያደረግሁትን ሁሉ ነገረኝ ብላ ስለ መሰከረችው ቃል ከዚያች&nbsp;ከተማ የሰማርያ ሰዎች ብዙ አመኑበት። የሰማርያ ሰዎችም ወደ እርሱ&nbsp;በመጡ ጊዜ በእነርሱ ዘንድ እንዲኖር ለመኑት፤ በዚያም ሁለት ቀን ያህል&nbsp;ኖረ።\"ስለ ቃሉ ከፊተኞች ይልቅ ብዙ ሰዎች አመኑ፤ ሴቲቱንም። አሁን&nbsp;የምናምን ስለ ቃልሽ አይደለምእኛ ራሳችን ሰምተነዋልና፤ እርሱም</div>\n<div>በእውነት ክርስቶስ የዓለም መድኃኒት እንደ ሆነ እናውቃለን ይሏት&nbsp;ነበር።&rdquo;</div>\n<h3>❸.ለጥቂት ሰዎች (ለደቀ መዛሙርት፣ለቤተሰቦች)</h3>\n<div><strong>✳.ለጵርስቅላ እና አቂላ</strong></div>\n<div>&ldquo;በክርስቶስ ኢየሱስ አብረውኝ ለሚሠሩ ለጵርስቅላና ለአቂላ ሰላምታ አቅርቡልኝ፤እነርሱም ስለ ነፍሴ ነፍሳቸውን ለሞት አቀረቡ፣የአሕዛብም አብያተ ክርስቲያናት ሁሉ የሚያመሰግኑአቸው ናቸው እንጂ እኔ ብቻ አይደለሁም፤በቤታቸውም ላለች ቤተ ክርስቲያን ሰላምታ አቅርቡልኝ። ከእስያ ለክርስቶስ በኵራት ለሆነው ለምወደው&nbsp;ለአጤኔጦን ሰላምታ አቅርቡልኝ።&rdquo;</div>\n<div>ሮሜ 16&divide;3-5</div>\n<div><strong>✳.ልድያና ቤተሰቦቿ</strong></div>\n<div>&ldquo;ከትያጥሮን ከተማም የመጣች ቀይ ሐር ሻጭ እግዚአብሔርን የምታመልክ ልድያ&nbsp;የሚሉአት አንዲት ሴት ትሰማ ነበረች፤ ጳውሎስም የሚናገረውን ታዳምጥ ዘንድ ጌታ&nbsp;ልብዋን ከፈተላት።</div>\n<div>&ldquo;እርስዋም ከቤተ ሰዎችዋ ጋር ከተጠመቀች በኋላ። በጌታ የማምን እንድሆን&nbsp;ከፈረዳችሁልኝ፥ ወደ ቤቴ ገብታችሁ ኑሩ ብላ ለመነችን፤ በግድም አለችን።&rdquo;</div>\n<div>የሐዋ.ሥራ 16&divide;14-15</div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;ሐዋርያዊነት</h2>\n<div><strong>✳.ሐዋርያ</strong> የሚለው ቃል \"<strong>ሖረ</strong>\" ሄደ ከሚለው የግዕዝ ግስ የተገኘ&nbsp;ሲሆን፤ሐዋርያ ማለት የተላከ፣የተመረጠና የተጠራ ማለት ነው።</div>\n<div><strong>✳.ሐዋርያዊነት፦</strong></div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>ለአገልግሎት የሚፋጠን፣</li>\n<li>የቅዱሳንን አሠረ ፍኖት (ፈለግ) የተከተለ፣</li>\n<li>ብቁና ንቁ የሆነ፣</li>\n<li>የሐዋርያዊነትን ተልዕኮ በተግባር የሚያሳይ ማለት ነው፡፡</li>\n</ul>\n</div>\n<div>💠.ሐዋርያዊነት:-ጌታችን ኢየሱስ ክርሰቶስ በኢየሩሳሌም፤በይሁዳ፤በሰማርያም ሁሉ እስከ ምድርም ዳርቻ ድረስ ምስክሮች ትሆናላችሁ\" ብሎ&nbsp;ባዘዘው አምላካዊ ቃል መሠረት \"ሑሩ ወመሐሩ\"ያለውን በተግባር&nbsp;መፈጸም ነው፡፡ሐዋ 1&divide;8</div>\n<h2><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;ሐዋርያዊ ሊጠነቀቅባቸው የሚገቡ ጉዳዮች</strong></h2>\n<div>🔆..በሐዋርያነት መስክ የተሰማራ ማንኛውም አገልጋይ ጌታ&nbsp;እንደተናገረው \"በተራራ ላይ ያለ መብራት\" ማለት ነው፡፡በሌላ አነጋገር \"የክርስትና ባንዲራ ነው\" ምእመናን የሚያጠፋት ጥፋትና&nbsp;እርሱ የሚያጠፋው በሰውም ዘንድ በእግዚብሔርም ዘንድ በእኩል&nbsp;አይታይም አይመዘንም፡፡</div>\n<div>🔆..የጌታውን ፈቃድ አውቆ እንደ ፈቃዱ የማይሠራና የማይዘጋጅ የዚያ&nbsp;አገልጋይ ቅጣቱ ብዙ ነው\"ሉቃ 12&divide;17 ተብሎ እንደተነገረው ኃለፊነት&nbsp;ተቀብሎ አውቆ የሚያጠፋ የቅጣቱ መጠን ከባድ መሆኑን መረዳት ተገቢ&nbsp;ነው።</div>\n<h3>💠.አንድ ሐዋርያዊ ሊጠነቀቅባቸው ከሚገቡ ዓበይት ጉዳዮች መካከል:-</h3>\n<h3><strong>❶.ወገንተኝነት፡-</strong></h3>\n<ul>\n<li>የቆሮንቶስንና የፊልጵስዮስን አብያተ ክርስቲያናት ያውኳቸው ከነበሩ ጉዳዮች መካከል እንዱ ወገንተኝነት ነው፡፡</li>\n</ul>\n<div>\n<p><em><strong>&nbsp;በቆሮንቶስ ቤተ ክርስቲያን፡</strong></em>-</p>\n<ul>\n<li>እኔ የጳውሎስ ነኝ፣</li>\n<li>እኔ የኬፋ ነኝ፣</li>\n<li>እኔ የአጵሎስ ነኝ የሚል ክፍፍል ነበር ።፩ኛ ቆሮ 3&divide;1-12</li>\n</ul>\n</div>\n<div><strong>✳.ወገንተኝነት በብዙ መንገድ ይገለጣል፡-</strong></div>\n<div>✔ .የፓለቲካ ወገንተኝነት፣</div>\n<div>✔ .የቋንቋና የብሔር፣</div>\n<div>✔ .የአካባቢ ተወላጀነት፣</div>\n<div>✔ .ቡድን በመሰብሰብ፣</div>\n<h3>❷.ከንቱ ውዳሴ</h3>\n<div>🔆..አውቀውትም ሳያውቁትም ብዙዎችን ከፀጋው ዙፋን ያራቆተ፣ዓላማቸውን ያሳተ፣አቅጣጫቸውን ያሰናከለ ከባድ የሆነ የበጐ ሕሊና&nbsp;ወጥመድና እንቅፋት ነው፡፡</div>\n<div><strong>\"የታዘ</strong><em><strong>ዛችሁትን ሁሉ ባደረጋችሁ ጊዜ የማንጠቅም ባሪያዎች&nbsp;ነን፣ልናደርገው የሚገባንን አድርገናል በሉ</strong></em>\"ሉቃ 17&divide;10&nbsp;በማለት ጌታችን ደቀ መዛሙርቱን የመከረው፡፡</div>\n<div>&nbsp;</div>\n<div><strong>✳.ከንቱ ውዳሴ:-</strong></div>\n<div>✔ .ያለ እኔ ሰው የለም የሚያሰኝ፤</div>\n<div>✔ .ትዕቢትንና ትምክህትን የሚያስከትል፣</div>\n<div>✔ .ከያዘ የማይነቀል መርዛማ ሥር ነው፡፡ሉቃ 18&divide;9፣ማቴ 6&divide;2-18</div>\n<h3>❸.ለምድራዊ ጥቅም ማገልገል፡-</h3>\n<div>✳.በዚህ ዘመን ቤተክርስቲያንን በእጅጉ የተፈታተናት፣ አንዳንዶችም&nbsp;ያመኑትን ፈጣሪና የታመኑለትንና ያመነቻቸውን ቤተክርስቲያን ከመክዳት&nbsp;አልፈው የጫማ ውስጥ ጠጠርና የጭቃ ውስጥ እሾህ እንዲሆኑባት&nbsp;ያደረገው የጥቅም ፍላጐት ነው፡፡</div>\n<div>↪ በቤተክርስቲያን ታሪክ ለንዘብ ማገልገል \"<strong>ሲሞኒዝም</strong>\" ይባላል።ሐዋ 8&divide;9-25</div>\n<div><em><strong>➡.ሲሞኒዝም በዚህ ዘመን፡-</strong></em></div>\n<div><em>❖.በኑሮ ደካማ መሆንና የማኅበራዊ ኑሮ ጫና፤</em></div>\n<div><em>❖.ለገንዘብ ብቻ ሲሉ ማገልገል፤</em></div>\n<div><em>❖.ጥሩ ክፍያ ይከፍሉኛል የሚሉትን ብቻ መርጦ ማገልገል(የነፍስና የሥጋ ብለው ጉባኤያትን እስከ መክፈል ደርሰዋል)፤</em></div>\n<div><em>❖.ሀብታሞችን ብቻ ማሰባሰብ፤</em></div>\n<h3><strong>❹.ከፈተናዎች መጠበቅ</strong></h3>\n<div>✳.ከፈተናዎች መጠበቅ ሲባል</div>\n<div>\n<ul>\n<li>.ከመናፍቃንና ከአህዛብ፤</li>\n<li>.ከራስ ጋር፤ .ከወግ አጥባቂዎች፤</li>\n<li>&nbsp;.ጥቅማችን ሊነካ ይችላል ብለው ከሚያስቡ ግለሰቦች፤</li>\n<li>.ከባለስልጣናት ወዘተ ብዙ መከራና ግፍ ስለ ክርስቶስ ስም ይደርሳል።</li>\n</ul>\n<h2>ማጠቃለያ፦</h2>\n</div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>&nbsp; &nbsp; &nbsp;ከላይ ከብዙዉ በጥቂቱ ለመግለጽ እንደሞከርነው በአጠቃላይ በዚህ ኮርስ የስብከት አመጣጥ ከሐዋርያት፣ሐዋርያነ አበዉ፣ዛሬም በዘመነ ሊቃዉንት እየተሰበከ ያለ ሲሆን ስለ ትክክለኛ ሐዋርያዊነት እና አገልግሎቱ&nbsp; ምን ይመስላል ትክክለኛ ሐዋርያዊነትስ ምን ይመስላል የሚለዉን የሚዳስስ ትምህርት ነው።&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</li>\n</ul>\n</div>\n<div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</h2>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;ዋቢ መጻሕፍት</h2>\n<div>\n<div>\n<ul style=\"list-style-type: square;\">\n<li>የስብከት ዘዴ&hellip;(በብጹዕ አቡነ ጎርጎርዮስ የሽዋ ሀገረ ስብከት ሊቀ ጳጳስ የነበሩ)&nbsp;</li>\n<li>ሐዋርያዊ ተልዕኮ(ሐዋተ) ...ለግቢ ጉባኤያት የተዘጋጀ(በዲ.ዳንኤል ክብረት</li>\n</ul>\n<p>&nbsp;</p>\n</div>\n</div>\n<h2>&nbsp; ስብሐት ለእግዚአብሔር ወለወላዲቱ ድንግል ወለመስቀሉ ክቡር ይቆየን!!!</h2>\n</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</div>\n<div>&nbsp;</div>\n<div>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <strong>&nbsp; <em>አዘጋጅ፦ዲ/ን ሶፎንያስ ደመቀ(ወ/ጊዮርጊስ)&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</em></strong></div>\n<div><strong><em>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; +251927603731/+251935535937</em></strong></div>\n<div><strong><em>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 27/10/2018ዓ.ም</em></strong></div>\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</h2>', '', '', '', '<section class=\"builder-output-card\"><h4>ሐዋርያዊ ተልዕኮ እና ኦርቶዶክሳዊ የስብከት ዘዴ</h4><ul><li>የስብከት ምንነት እና ትርጉም</li><li>የስብከት ታሪክ</li><li>የስብከት አይነቶች</li><li>የመልካም መምህር(ሰባኪ) ባህርያት</li><li>የስብከት ዝግጅት</li><li>የስብከተ ወንጌል መንገዶች</li><li>ሐዋርያዊነት</li><li>ሐዋርያዊ ሊጠነቀቅባቸው የሚገቡ ጉዳዮች</li></ul></section><section class=\"builder-output-card\"><h4>Untitled Module</h4><p class=\"small\">No lessons added yet.</p></section>', '<article class=\"builder-output-card\"><h4>1.ከሚከተሉት ዉስጥ ለሰባኪ የማያስፈልገዉ የቱ ነው?</h4><ol><li>የስብከት ርእስ መጠበቅ</li><li>አርአያ ክህነት</li><li>ራስን መስበክ</li><li>ትምህርት</li></ol><p><strong>Answer:</strong> ራስን መስበክ</p><p class=\"small\">ሌሎች ከላይ የተዘረዘሩት ለአንድ ሰባኪ የሚያስፈልጉ ነገሮች ሲሆኑ ራስን መስበክ ግን የትክክለኛ ሰባኪ መገለጫ አይደለም።</p></article><article class=\"builder-output-card\"><h4>2.ትምህርት፣ትምህርታዊ ስብከት እና ስብከት ከሚለያዩባቸው ነገሮች መካከል ትክክል የሆነው የቱ ነው?</h4><ol><li>ትምህርታዊ ስብከት እዉቀት እና ሕይወት በአንድ ጊዜ የሚያስጨብጥ ነው።</li><li>ትምህርት ቀለል ባለ አገላለጽ የሚቀርብ ነው።</li><li>ስብከት ተከታታይነት ያለው ነው።</li><li>ሁሉም</li></ol><p><strong>Answer:</strong> ትምህርታዊ ስብከት እዉቀት እና ሕይወት በአንድ ጊዜ የሚያስጨብጥ ነው።</p><p class=\"small\">መልሱ ትምህርታዊ ስብከት እዉቀት እና ሕይወት በአንድ ጊዜ የሚያስጨብጥ ነው የሚለው ሲሆን ሌሎቹ በትክክል አልተዛመዱም።</p></article><article class=\"builder-output-card\"><h4>3.ከሁሉም የስብከት አይነቶች በደንብ ማብራራት ፣መመሰል እና ማመሳጠር የሚፈልገው የትኛው ነው?</h4><ol><li>ተዉኔታዊ ስብከት</li><li>ታሪካዊ ስብከት</li><li>ተግባራዊ ስብከት</li><li>ነገረ ሃይማኖታዊ ስብከት</li></ol><p><strong>Answer:</strong> ነገረ ሃይማኖታዊ ስብከት</p><p class=\"small\">ነገረ ሃይማኖታዊ ስብከት በተለዪ ነገረ መለኮት፣ምሥጢረ ሥላሴ እንዲሁም ምሥጠረ ሥጋዌ ከሌሎች የስብከት አይነቶች መካከል ለየት የሚያደርገው ግልጽ የሆነ ምሳሌ ማብራሪያ ምሥጢር ማመስጠርን ይጠይቃል።</p></article><article class=\"builder-output-card\"><h4>4.አንድ ሰባኪ ያስተማረዉን ትምህርት ተግባራዊ እንዲሆን መንገዱን የሚያሳዪበት፣ዕለት ከዕለት የሰማዕያኑ ሕይወት ጋር የሚያዛምድበት የስብከት ክፍል ምን ይባላል?</h4><ol><li>ሀተታ</li><li>ምክር</li><li>ዓላማ</li><li>መግቢያ</li></ol><p><strong>Answer:</strong> ምክር</p><p class=\"small\">አንድ ስብከት 6 ንዑሳን ዘርፎችና ክፍሎች ሲኖሩት ምክር የሚባለው ሰባኪ ያስተማረዉን ትምህርት ተግባራዊ እንዲሆን መንገዱን የሚያሳዪበት፣ዕለት ከዕለት የሰማዕያኑ ሕይወት ጋር የሚያዛምድበት የስብከት ክፍል ነው።</p></article>', '<article class=\"builder-output-card\"><h4>ሐዋርያዊ ተልዕኮ</h4><p>የዚህ አሳይመንት ዋና ዓላማ ተማሪዎች ስለ ሐዋርያዊ አገልግሎት እና ሕይወቱ ከዚህ ኮርስ በተጨማሪ  ሰፊ ግንዛቤ እንዲያገኙ ስለሆነ እርስዎም  እባክዎ ይህንን አሳይመንት ሲሰሩ ቅዱሳት መጻሕፍትን አንብበው ከአባቶች አሰረ ፍኖት ተምረዉ እንዲሰሩ እመክርዎታለሁ።</p><p class=\"small\">Due: የመግቢያ ቀን ማጠቃለያ ፈተና ከመውሰድዎ በፊት እንዲያስገቡ • Points: 15%</p></article>', '<p>እባክዎ ሕጋዊ ሰርተፊኬት ለመዉሰድ ኮርሶችን፣ፈተናዎችን እና አሳይመንቶችን በአግባቡ መዉሰድ እና ቢያንስ 80% ፕሮግረስ መሆን አለበት።እነዚህን ነገሮች ያላሟላ ተማሪ አቤቱታ እና ቅሬታ ቢያቀርብ ተጠያቂ አይደለሁም።</p>', '2026-06-27 16:51:47', NULL, NULL);
INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('7', 'ነገረ ቅባት', '029-1', '<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"color: rgb(132, 63, 161); font-size: 36pt;\">ቅባት(ቅብዓት)</span></h1>\r\n<h2>&nbsp;<span style=\"font-size: 18pt;\"> <span style=\"font-size: 14pt;\"><em><strong>ቅባት(ቅብዓት) ትርጉሙ ምንድን ነው❓</strong></em></span></span></h2>\r\n<div><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(224, 62, 45);\">↪ቅባት በቅዱሳት መጽሐፍት ሲተረጎም የሚከተሉት ትርጉሞች አሉት።እነርሱም:-✔</span></strong></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">1ኛ.ቅባት ማለት በቁሙ ሲፈታ ቅባት ማለት ነው</span>።</strong>ቀባ፣ለከከ፣ለቀለቀ፣ቀባ የሚል ትርጉም ያመጣል።ለዚህም ማስረጃው-\"የመገናኛውንም ድንኳን የምስክሩንም ታቦት ገበታውንም ዕቃውንም ሁሉ መቅረዙንም ዕቃውንም መሰዊያውን ሁሉ ለሚቃጠለውም መሥዋዕት ለሚሆነው መሰዊያና ዕቃውንም ሁሉ የመታጠቢያውን ሰንና&nbsp;መቀመጫውን ትቀባበታለህ\"ዘጸ 30&divide;26</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">-\"ማርያምም እጅግ ዋጋው የከበረ የጥሩ ናርዶስ ሽቱ ንጥር ወስዳ የኢየሱስን እግር ቀባች\"ዮሐ 12 &divide;3 </span><span style=\"font-size: 14pt;\">=&gt;<span style=\"text-decoration: underline; color: rgb(185, 106, 217);\">ቅባት </span></span><span style=\"text-decoration: underline; color: rgb(185, 106, 217);\"><span style=\"font-size: 14pt;\">በቁሙ ሲፈታ</span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">2ኛ.ተቀብዐ:-ከበረ ተብሎ ይተረጎማል።</span></strong>ለዚህም ማስረጃ \"<strong>እለሰ የአምኑ ርቱዓ ይሜሀሩ ከመ ተቀብዓ ቃል በስጋሁ</strong>\"ትርጓሜውም ሲቀባም የሚለውም ሲከብርም ሲዋሐድም አንድ ጊዜ ነው ሲል ነው እንጂ በቁሙ ሲቀባ ስላለ ሲቀባ ተብሎ አይተረጎምም በቁም የሚተረጉሙ አሉና!!ወዳጄ \"መጽሐፍት ትርጓሜን እንጂ ዘይቤን አይጠነቅቁም \" እሽ!!ይህ ማለት ስጋ ከቃል ጋር ሲዋሐድ መጀመሪያ ተዋሕዶ በኋላ የከበረ አይደለም:ከብሮም ሳይዋሐድ አልቀረም;ሲከብርም ሲዋሐድም አንድ ጊዜ ነው እንጂ!! አንድም ከላይ ያለውን ያነሳነውን ቃል ሊቃውንተ ቤተ ክርስቲያን እንዲህ እያሉ አቅንተው ይተረጉሙታል።ኦሪት ወነቢያት ሰበኩ በክርስቶስ ሲል \"በክርስቶስ\" ያለው ክርስቶስሀ ማለት ነው። \"<strong>በ</strong>\" አገባብ በማድረግ \"<strong>ን</strong>\"የሚል ፍቺ ይሰጡና ኦሪትና ነቢያት በክርስቶስ ሰበኩ የሚለውን በቁሙ ኦሪትና ነቢያት ክርስቶስን ሰበኩ በማለት ይገልጹታል።ማለትም ክርስቶስን ይወርዳል ይወለዳል እያሉ ሰበኩ የወንጌልን አዝመራ ዘሩ ሐዋርያትም አጨዱት ነውና ቅሉ።ስለዚህ ይህንን ቃልም በሥጋሁ የሚለውን\"በ\"ን አገባብ አድርገው \"<strong>ሥጋን</strong>\" በማለት ይተረጉሙና ስጋን ተዋሐደ ብለው ያቀኑታል።</span></li>\r\n</ul>\r\n<p><span style=\"color: rgb(230, 126, 35);\"><strong><span style=\"font-size: 14pt;\">=&gt;.ያም ሆነ ይህ ግን ይህንን ነገር ስናነሳ እነዚህን ጥያቄዎች ማሰብ ያስፈልጋል።ማለትም በቁሙ መለኮት በስጋው ከበረ ከተባለ</span></strong></span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቅድመ ተዋህዶ ቃል ክብር አልባ ነበርን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ነውስ ቃል በጊዜ ተዋህዶ የባሕርይ ክብሩን አጥቷል?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ወልድን ከመለኮታዊ ክብሩ ዝቅ አያደርገውምን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቃል(መለኮት) በስጋው ከበረ ከተባለ ስጋን የተዋሐደ ከሦስቱ አካል አንዱ አካል ወልድ(አካላዊ ቃል) ነውና ሥላሴ በማክበር ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">መለኮት በስጋው ከከበረ በመለኮትነት ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.መክበር የተፈጸመውስ መቼ ነው???በጊዜ ተዋህዶ \"ርስት\" ሰጥቶ መናገርን የትኞቱ አበውና መጽሐፍት አስተማሩን?</span></em></span></strong></li>\r\n</ul>\r\n</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">3ኛ.ተቀብዐ:-ተዋሐደ ተብሎ ይተረጎማል።</span></strong>ብዙ ወገኖቻችን ግን ቀብዓን ተዋሐደ ብለው አይተረጉሙትም።ለዚህም ማስረጃ ታላቁ ሊቁ አባ ጊዮርጊስ ዘጋስጫ በመጽሐፈ አርጋኖን ዘአርብ ዕለት\"ዘተቀባዕከ ስጋሃ ለማርያም\"ብለዋል!!ይህ ንባብ የሚተረጎመው የማርያምን ስጋ የተዋሐድክ ተብሎ ነው!!ምክንያቱም በከበረ እንዳይተረጎም የማርያምን ስጋ የተከበርክ አይባልም::በቀብዓ እንዳይተረጎም የማርያምን ስጋ የተቀባህ አይባልም ስጋ ቅብዕ ይሆናልና።ስለዚህ የተዋሐድክ ብሎ አቅንቶ መተርጎም ያስፈልጋል ወዳጄ!!!</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">➠ስለዚህ ሳጠቃልለው አንድ ቃል እንደአውዱ እንደአገባቡ የተለያየ ትርጉም ይኖረዋልና አንዲትን </span><span style=\"font-size: 14pt;\">በዘፈቀደ አንጠልጥሎ ሁሌም በዚህ ነው የሚፈታ ማለት የዕውር ክርክር ነው።ለምሳሌ \"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልክት ማኅበር ቆመ\"መዝ 81&divide;1 ይላልና ቆመ ስላለ ብቻ ቆመ ብለን ልንተረጉመው ነው??በጭራሽ</span></div>\r\n<div><span style=\"font-size: 14pt;\">ቆመ ብለን አንተረጉመውም!!ታዲያ ምን ብለን እንተረጉመዋለን ትሉኝ እንደሆነ\"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልዕክት መካከል ተገለጠ\"ብለን ነዋ!!እንደዚህም ሁሉ ተቀብዐን እንደአውዱ እንደ አገባቡ ይፈታል!!</span></div>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"color: rgb(224, 62, 45); font-size: 18pt;\"><strong>➠የቅባት ትርጉም እንደ ቅባት አስተምሮ ግን......</strong></span></h2>\r\n<div>\r\n<ul>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt; color: rgb(22, 145, 121);\">✔. ቅባት መንፈስ ቅዱስ ተብሎ ይተረጎማል!!</span></strong></li>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt;\">✔.ቅባት ሕይወት ተብሎ እንደሚተረጎም ወልደ አብ መጽሐፍ ገጽ 179 ;</span><span style=\"font-size: 14pt;\">አዕማደ ምስጢር ገጽ 22 </span><span style=\"font-size: 14pt;\">ይናገራል!!</span></strong></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">&nbsp;ከዚህ ውጭ ግን <strong><span style=\"text-decoration: underline;\">ተቀብዐን ተዋሐደ</span></strong> ብለው ተርጉመው ፈጽሞ አይናገሩም;ተዋሐደ ብለው </span><span style=\"font-size: 14pt;\">መተርጎም ስህተት ነው ይላሉ \"ተዋሐደ\"ካሉ መንፈስ ቅዱስ ቅብዕ መሆንን ያፈርስባቸዋልና!!</span><span style=\"font-size: 14pt;\">ምናልባት በነገረ ሥጋዌ ጉዳይ እመቤታችንን ተቀባትም ተዋሐዳትም ማለት ክህደት ነው </span><span style=\"font-size: 14pt;\">ሲባል ብዙ ሰዎች ግራ ይጋባሉ;ነገር ግን ጊዜ ተዋህዶ ላይ የተፈጸሙ ተግባራትን ካለማወቅ </span><span style=\"font-size: 14pt;\">የተነሳ ነው ወገኖቼ!!!በምሥጢረ ሥጋዌ ትምህርታችን ስንነጋገር እነዚህን ነገሮች </span><span style=\"font-size: 14pt;\">ካስታወሳችሁ የጥያቄያችሁ መልስ ታገኛላችሁ!!!ይኸውም ቃል በጊዜ ተዋህዶ የማይቀዳደሙ </span><span style=\"font-size: 14pt;\">፫ት ነገሮች ተከናውነዋል። እነርሱም:-</span></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መክፈል፤</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መዋሐድ እና</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">&nbsp;መክበር ናቸው።</span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">✟✔.ከፍሎ ሳይዋሐድ ቢቀር በሰው ወይም በእመቤታችን አደረ ያሰኛል።ይኼውም ኀደረ </span><span style=\"font-size: 14pt;\">በብእሲ ብሎ እንደካደው ጳውሎስ ሳምሳጢ ክህደት መግባት ነው።ተዋህዶ ሳይከፈል ቢቀር </span><span style=\"font-size: 14pt;\">እመቤታችን አምላክ ሆነቺ ያሰኛል።ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል።አካለ ቃል ክብር </span><span style=\"font-size: 14pt;\">አልባ ያሰኛል የሚሉት ናቸው።ስለዚህ ሲከፈልም፤ሲዋሐድም፤ሲከብርም(ሲቀባ) </span><span style=\"font-size: 14pt;\">አንድ ጊዜ ነው።</span></div>\r\n<div>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"font-size: 24pt; color: rgb(132, 63, 161);\">ምሥጢረ ሥጋዌ በቅባት አስተምህሮ (በወልደ አብ) ዕይታ</span></h1>\r\n<p><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 14pt;\">የኢትዮጵያ ኦርቶዶክስ ቤተ ክርስቲያን የምታስተምረው ትምህርት ከቅባት እምነት በጣም ሰፊ ልዩነት ሲኖራት የቅባት እምነት ተከታዮች ከዚህ በተለየ መልኩ ብዙ ክህደትን ሲያስተምሩ ይስተዋላሉ።ከነዚህም መካከል በጣም የጎሉትን የክህደት መንገዶ ከዚህ በታች ለማየት እንሞክራለን።&nbsp;</span></strong></span></p>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\">✔፩ኛ.እግዚአብሔር ወልድ ሁለት ልደታት አሉት እያሉ በቃል ደረጃ&nbsp;ይናገራሉ ።ነገር ግን በተግባር ደረጃ እንደጸጋ አስተምህሮ ፫ት ልደትን&nbsp;አማኝ ናቸው!!ለዚህ ማስረጃየ ወልደ አብ መጽሐፋቸው&nbsp;የመጀመሪያው ዕትም ገጽ 217 እና 218 እንዲህ ይላል!!</span></strong></div>\r\n<div style=\"padding-left: 80px;\"><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(132, 63, 161);\">\"<strong>የጌታችን ልደት ስንት ነው ቢሉ ፪ት ነው።እንዴት ፪ት ነው ቢሉ&nbsp;እምቅድመ ዓለም በመለኮቱ ተወለደ ብለናል ኋላም በማኅጸን በሰውነቱ&nbsp;ከአብ ተወለደ እንላለን ዳግም ከእመቤታችን በስጋ በጎል ተወለደ&nbsp;እንላለን</strong> \"</span></em>ወልደ አብ ገጽ ገጽ 217 ይላል!!</span></div>\r\n<div><span style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(186, 55, 42);\"><strong>↪አስተዉሉ፦</strong></span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ታዲያ ጌታችን ቅድመ ዓለም ከአብ በመለኮቱ፣ድኅረ ዓለም ከእመቤታችን በትስብእቱ፣ድኅረ ዓለም በማኅጸን በሰውነቱ ከአብ ተወለደ ከተባለ ሁለት ልደታት ማመን ከየት ይመጣል ይህ ፫ት ልደት&nbsp;አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ይህ ከሆነስ ወልደ አብ በመለኮቱ:ወልደ ማርያም በትስብእት፣አሁንም በድጋሜ በማህጸን ከወለደው እንደገና ወልደ አብ በትስብእቱ ሊባል ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ለማንኛውም \"በቃል ሁለት ልደት፣በተዘዋዋሪ በተግባር ግን ሦስት ልደት ይላሉ!!አይ ወገኔ\"አልሸሹምዞር አሉ\"ማለት ይሄ ነው እኮ ወገኔ ገባህ?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\"><strong><span style=\"font-size: 14pt; background-color: rgb(248, 202, 198);\">፪ኛ.\"ሰባቱን ሀብታተ መንፈስ ቅዱስ እርሱ በስጋ ርስት በጊዜ ፅንስ ያለምክንያት ከአብ ተቀብሎ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉሥ ሆነባቸው\"ወልደ አብ ገጽ 211 ይላል</span></strong></span></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች የነገረ ቅባትን አስተምህሮ እና ጥያቄ የሚመለሰው ብዙ ጥቅስ መዘርዘር ሳያስፈልገው ጥያቄን በጥያቄ መመለስ እና በደንድ አገናዝቦ ማስተዋል ነው።ስለዚህ ከላይ እንዳያችሁት እንዲህ ካሉ&nbsp;እስኪ በሞቴ ንገሩኝ.........</span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉስ ሆነባቸው ማለት ቀድሞውንስ የባህርይ አምላክ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ ሰው የሆነስ በአባቱ ፈቃድ በእርሱ ፈቃድ በመንፈስ ቅዱስ ፈቃድ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">ታዲያ እነማንን ነው የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸው❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በግድ ነው በኃይል የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸውስ❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በመጀመሪያ \"ሆነባቸው\"ማለት በግድ አምላክ ሆኖባቸዋልን❓የእነርሱ ፈቃድስ❓</span></strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><em><strong><span style=\"color: rgb(52, 73, 94); background-color: rgb(236, 202, 250); font-size: 18pt;\">✔፫ኛ.\"መንፈስ ቅዱስ ሠጪም ተሠጭም ነው\"ወልደ አብ ገጽ 181&nbsp;ይላል።</span><span style=\"color: rgb(52, 73, 94); font-size: 18pt;\">ይህ ከሆነ.......</span></strong></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ምንድን ነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ለማነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለው ምንን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለውስ ከማን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሌለው አለን ከሌላ የሚቀበል❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>በዓለመ ሥላሴ ነው መንፈስ ቅዱስን ሰጪም ተሰጪም ነው የምንል እንዳትሉኝ በዓለመ ሥላሴ በባህርይ በክብር በስልጣን አንድ ናቸው አንዱ ከአንዱ አያንስም አንዱ ከአንዱ አይበልጥ;ታዲያ አንዱ ከአንዱ ከአልበለጠ አንዱ ከአንዱ ካላነሰ ሰጪና ተሰጪ የሚል ከየት ይመጣል ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪና ተሰጪ ያልን ለፍጡራን ነው እንዳትሉኝ መንፈስ ቅዱስን ፍጡር እያላችሁት መሆኑ አይደለምን❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪም ተሰጪም ነውያልነው በፈጣሪና በፍጡር መካከል ነው እንዳትሉኝ መንፈስ ቅዱስ ፈጣሪ ነው ከፍጡር ይቀበላላልን❓ተሰጪ የሚለው አያፈርስባችሁምን❓ተብለዉ ሲጠየቁ መልስ የላቸዉም አፋቸዉን ይያዛሉ።</em></strong></span></li>\r\n</ul>\r\n<div><span style=\"background-color: rgb(194, 224, 244); color: rgb(52, 73, 94); font-size: 18pt;\"><em><strong>፬ኛ.አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ነው ይላሉ!!</strong></em></span></div>\r\n<div>-<em><span style=\"font-size: 14pt;\">ይህ ማለት፦</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ-አክባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ ከባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል።በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።</span></em></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><strong>↪ታዲያ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን</strong></span></p>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>&nbsp;አብ አክባሪ፣ወልድ ከባሪ መንፈስ ቅዱስ ክብር የሚል ከየት ይመጣል❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>ምሥጢረ ሥላሴ ላይ የተነገረውን ለምስጢረ ሥጋዌ መቀፀልስ ለምን አስፈለገ❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong>↪\"ሥላሴ በተለየ ግብር ሦስት ናቸው።ይኸውም መውለድ፣ማስረፅ፣መወለድ፣መስረፅ ነው\"ይላል ገጽ 53;እንደገና 133 ላይ ደግሞ\"ቅብዕ የሆነ ግን በተለየ አካሉ በተለየ ግብሩ መንፈስ&nbsp;ቅዱስ ነው\"ይላል</strong></span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለመንፈስ ቅዱስ የተለየ ግብር የተሰጠው መቼ ነው ቅብዕነት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>የመንፈስ ቅዱስ ግብር መስረፅ ከሆነ ቅብዕነት ደግሞ ለመንፈስ ቅዱስ መቼ ተጨመረለት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለወልድና ለአብስ ምን የተለየ ግብር ምን ተጨመረላቸው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp;ከዚያ ባለፈ አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ማለት </span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ➠ሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ➠ተሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ➠ስጦታ ማለት ነው።</span></em></li>\r\n</ul>\r\n<p><em><strong>↪<span style=\"font-size: 12pt;\"> ይህ ከሆነ&nbsp; &nbsp;</span></strong></em></p>\r\n</div>\r\n<div>\r\n<div>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ አለን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ ካለ ሰጪ ከተሰጪ ይበልጣል;ተሰጪ ከሰጪ ያንሳል!!ታዲያ አብ ከወልድ ከመንፈስ ቅዱስ ይበልጣልን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>ወልድስ ከአብ ከመንፈስ ቅዱስ ያንሳልን❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; color: rgb(132, 63, 161); background-color: rgb(206, 212, 217);\"><em><strong>✔፭ኛ.\"ስጋ ሲፈጠር መለኮትም ከስጋ ጋር አብሮ ተፈጠረ ካላሉ&nbsp;ይላል\"ወልደ አብ ገጽ 127</strong></em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>መለኮት(ቃል) ራሱ ፈጣሪ ነው;ራሱ ፈጣሪ ከሆነ ከስጋ ጋር አብሮ ማን ፈጠረው ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ጸሎተ ሐይማኖት ላይ\"ዘተወልደ ወአኮ ዘተገብረ\"የተወለደ እንጂ ያልተፈጠረ የምትለዋን ፋቃችኋት እንዴ ታዲያ ወገኖቼ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ፍጡር ከሆነ ታዲያ እመቤታችን ወላዲተ አምላክ ሳይሆን ወላዲተ ሰብእ ናት ልትሉ ነው እንደ ፎጢኖስ❓</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><strong><em><span style=\"color: rgb(132, 63, 161); background-color: rgb(241, 196, 15); font-size: 18pt;\">✔፮ኛ.\"እኛ የምንቀበለው የጸጋ ጌታ የሚቀበለው የባህርይ ነው ማለት&nbsp;እንዴት ነው ቢሉ እኛ በተወለድን በ፵ ቀን እናገኘዋለን በክህደት&nbsp;በኃጢአት ይነሳል ስለዚህ ስለዚህ የጸጋ ይባላል።ጌታ ግን ሲዋሐድ የባህርይ ህይወት መንፈስ ቅዱስን ከአካሉ ጋር አግኝቶታልና የባህርይ&nbsp;ይባላል\"ወልደ አብ ገጽ 188</span></em></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ጌታ የባህርይ ህይወቱን መንፈስን ከአካሉ ጋር አግኝቶታል ይላል;የመንፈስ ቅዱስን አካሉን ነው ወይስ ሀብቱን የተቀበለው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>አካሉን ከተባለ መንፈስ ቅዱስ ከስጋ ጋር ተዋህዷልን ❓</em></strong></span></li>\r\n<li style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ሀብቱን ካላችሁስ ክርስቶስ ዕሩቅ ብእሲ መሆኑ አይደለምን ❓</em></strong><em><span style=\"color: rgb(0, 0, 0);\">ብላችሁ ስትጠይቋቸው ምላሽ ያጣሉ።</span></em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp;</strong></span></p>\r\n<div><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;በነገረ ቅባት በመንፈስ ቅዱስ ከበረ ለማለት የሚነሱ ጥቅሶች</strong></span></div>\r\n<div>&nbsp;</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.የዘመኑ ቅባት ነን ባዮች በመንፈስ ቅዱስ ከበረ ለማለት በጣም በርካታ የመጽሐፍ ቅዱስ ጥቅሶችን ቢያነሱም ከብዙዉ በጥቂቱ ተደጋጋሚ ሁሌም የሚያነሷቸው የአፍ መፍቻ ጥያቄዎች የሚከተሉት ሲሆኑ ቤተክርስቲያናችን አረዳዷ ሚን ዪመስላል የሚለዉን ትርጓሜዉን እናያለን።</span></em></div>\r\n<div><strong><span style=\"background-color: rgb(194, 224, 244);\"><em><span style=\"font-size: 14pt; background-color: rgb(194, 224, 244);\"><span style=\"font-size: 18pt;\"><span style=\"color: rgb(45, 194, 107);\">1ኛ. </span>\"<span style=\"color: rgb(45, 194, 107);\">ዘአንገሦ ለሥጋ አዳም በመንፈስቅዱስ ወረሰዮ ቅዱሰ&nbsp;ወማሕየዌ ዘለብሶ ለአዳም መዋቲ</span></span>\"በመንፈስቅዱስ ህይወትነት&nbsp;የአዳምን ባህርይ ያከበረው የባህርይ አምላክ ያደረገው እርሱ ነው\"ሃይ.አበ.ዘእልመስጦአግያ ፪:፭</span></em></span></strong></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡በመጀመሪያ ያከበረው አለ እንጂ ክብር የሆነው አይልም አስተውሉ ወዳጄ!!</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>መንፈስ ቅዱስ ቅብዕ(ክብር) ከሆነው ለምን ያከበረው አለ ለምን ክብር የሆነው አላለም❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>፫ቱ በአክባሪነት አንድ አይደሉምን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም ይህ የተነገረው የመንፈስቅዱስን ህይወትነት ሥጋ ገንዘብ ማድረጉን ሲናገር ነው!!አንድም \"የአዳምን ሥጋ በመንፈስ ቅዱስ አዋሐጅነት የተዋሐደው እርሱ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም በመንፈስቅዱስ ህይወትነት ማለት በረቂቅ የሥላሴ ግብር ማለት እንጂ መንፈስ ቅዱስ ክብር ሆነው ለማለት አይደለም ወዳጄ!!የአዳምን ሥጋ በግብረ መንፈስ ቅዱስ ተዋሕዶ የባሕርይ ንጉሥ ያደረገው&nbsp;</span></em><em><span style=\"font-size: 14pt;\">እርሱ ነው!!\"<strong>ወረሰዮ ቅዱሰ ወማሕየዌ ክቡር ወሀቤ ሕይወት</strong> አምላክ ያደረገው እርሱ ነው ካለ በኋላ ዘለብሶ ለአዳም መዋቲ\"አለ;ለምን ከተባለ ስጋን የተዋሐደ በተለየ አካሉ ወልድ ነውና።ግብረ መንፈስ ቅዱስ </span></em><em><span style=\"font-size: 14pt;\">ማለት ረቂቁን ለመንፈስ ቅዱስ መስጠት ነው እንጂ በማዋሐድ፣ በመፍጠር፣ በመግዛት፣ በመንግሥት፣በክብር ሦስቱ አካላት አንድ ናቸውና በአንዲት ግብረ ባሕርይ መሆኑን እናስተውል።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(194, 224, 244);\">2ኛ. \"ለሊሁ ዘይሁብ ወለሊሁ ዘይትወሀብ\"-ጸጋውን የሚሰጥ እርሱ ነው ጸጋም ሆኖ የሚሰጥ እርሱ ነው\"</span></strong></span><span style=\"text-decoration: underline;\">አረ.መን.ድር.11</span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ይህ ቃሉ የተነገረው ለመንፈስ ቅዱስ ሳይሆን ለወልድ ነው ምክንያቱም እርሱ ለኩነተ ሥጋ ተሰጦአልና ነው ወዳጄ!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም በሰባኪ አድሮ ጸጋን ይሰጣል.በሰሚ አድሮ ይቀበላልና!!</em></span></div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em>3ኛ. \"አማን አንገለጉ በዛቲ ሀገር ላዕለ ቅዱስ ወልድከ ኢየሱስ&nbsp;ዘቀባእካሁ.ሐዋ.4&divide;27</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ከዚህ ላይ የምናስተዉለው ነገር አለ።ይኽውም፦</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>መንፈስ ቅዱስ ቅብዕ ከሆነው በቀባኸው አለ እንጂ ቅብዕ በሆንኸው ለምን አላለም❓</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>-ቅብ የሆነው መንፈስ ቅዱስ ነው ከተባለ ይህ ቃል ደግሞ የአብን ቀባዒነት የክርስቶስን&nbsp;ተቀባዒነት ይናገራል እንጂ የመንፈስቅዱስን ቅብዕነት አይናገርም እኮ!!</em></span></div>\r\n<div><span style=\"font-size: 18pt; color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em><strong>4.&nbsp;እንደእሱ አካል ባለ አካል አክብሮታልና.ዮሐ.አፈ.ወ.ድር 3&divide;100</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>➡አስተውሉ</strong>:-ሥጋን በቃል አንቀጽ ሲጠራው እንደሱ አካል አለ፤ባለአካል ብሎ ቃልን ጠራው&nbsp;አክብሮታል አለ እንጂ ክብር ሆኖታል አላለም</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም አካለቃል ከአካለሥጋ፣ባህርየ ቃል ከባህርየ ሥጋ ጋር መዋሀዳቸውን እየተናገረ ነው!!</em></span></div>\r\n<div><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>5 .\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከ እግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ\"<span style=\"font-size: 14pt;\">መዝ 44 &divide;7</span></em></span></strong></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>✔ \"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን&nbsp;ቀባህ\"</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;በመጀመሪያ እነዚህን ጥያቄዎች እንመልስ &nbsp;</em></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ቃሉ በባለቤትነት የተነገረው ለማን ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>እግዚአብሔር ሲል ከ3ቱ አካል ለአንዱ የመንፈስ ቅዱስ ስም ብቻ ነው የሦስት ስም አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ከባልንጀሮችህ ይልቅ ሲልስ ባልንጀሮቹ እነማን ናቸው ይልቅ የሚለውስ ለምን መቀጸል አስፈለገ❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>የደስታን ዘይት ቀባህ ማለት ትርጉሙ ምንድን ነው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>* በመጀመሪያ\"ጽ<strong>ድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ&nbsp;የደስታ ዘይትን ቀባህ</strong>\"በሚለውኃይለ ቃል ውስጥ \"<span style=\"text-decoration: underline;\"><strong>አንተ</strong>\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ </span></em></span><span style=\"font-size: 14pt;\"><em><span style=\"text-decoration: underline;\">እናስተውል:;ይኸውም&nbsp;\"<strong>ትስብእት\"</strong>ነው።\"ባልንጀሮችህ\"የተባሉት ደግሞ ቀደምት ነቢያት፣ካህናት ነገስታት ናቸው።</span></em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 14pt;\"><em>❓=ታዲያ \"ከባልንጀሮችህ ይልቅ\"ለምን አለ ትሉኝ እንደሆን እነርሱ ሲሾሙ የነበረው በቅብዓ ዘይት ነበርና እነ ዳዊት መመልከት ይቻላል!!ለእነርሱ ሹመት ከእግዚአብሔር የሚያገኙት የሚቀበሉት ጸጋ </em></span><span style=\"font-size: 14pt;\"><em>ጊዜያዊ የሚያልፍ ነው።የክርስቶስ ሰው መሆን የትስብእት መክበር ግን ከማንም የማይቀበለው የባህርይው በተጭና በተሰጭ መካከል የሚደረግ አይደለም ሲል ነው፣ታዲያ የስጋ መክበር እንዴት ነው ትለኝ&nbsp;</em></span><span style=\"font-size: 14pt;\"><em>እንደሆነ\"<span style=\"color: rgb(224, 62, 45);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"መለኮት ለስጋ ክብር ሆነው እርሱ ራሱ በባህርይ ክብሩ ከበረ፣ስጋ&nbsp;እርሱ ራሱ ክብሩ አምላክነቱ የባህርይ ከሆነ መለኮት ጋር ስለተዋሐደ\"እልሃለሁ ወዳጄ!!</em></span><span style=\"font-size: 14pt;\"><em>አንድም እግዚአብሔር አምላክ ብሎ ለምን አራቀቀው ትለኝ እንደሆነ\"<strong>የተዋሐደው የፈጠረውን ስጋ</strong>\"ነውና&nbsp;ማለትም\"እርሱ ራሱ የፈጠረውን ስጋ ተዋሐደ እንዲል ሊቁ!!!</em></span>\r\n<div>&nbsp;<span style=\"font-size: 14pt;\"><em>አንድም ይልቅ ማለቱ\"አምላክነት የባህርይው ስለሚሆን በጸጋ እንዳደረባቸው እንደቅዱሳኑ ሳይሆን አንተ ገንዘብህ የሚሆነውን መለኮትን ስለተዋሐድክ ነው ሲል ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን&nbsp;መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው </em></span><span style=\"font-size: 14pt;\"><em>ትለኝ እንደሆነም ሰው መሆንን ወደድህ የተባለ ቃል ነው፣ከበረ የተባለ ደግሞ ሥጋ ነው!!ሁለቱን&nbsp;መናገሩ፣በአንድ አንቀጽ ሁለቱን መናገር ነው።\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቦ ዘይቤላ በእንተ ትስብእቱ ወመለኮቱ</strong></span>\"እንዲል </em></span><span style=\"font-size: 14pt;\"><em>አንድም ሰው ማለት ክብርና መክበር ተዋህደው ክርስቶስ ነውና \"የደስታ ዘይትን (ቅብዓ ትፍስሕት)የተባለውስ ማነው ካልከኝ ወልድ(ቃል) ነው ቀባህ ሲልም&nbsp;\"አከበረህ\"ማለቱ ነው።</em></span><span style=\"font-size: 14pt;\"><em>አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቀብዐከ እግዚአብሔር አምላክከ</strong></span>\"ብሎ ባህርያዊ ግብሩን በሚገልጥ መጥራቱ አብ አብ ቀባዒ እንደሆነ በምን ያስረዳል❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ነውስ\"<span style=\"color: rgb(132, 63, 161);\"><strong>አንሰ ሶበ እቤ እግዚአብሔር እብል በእንተ አብ ወወልድ ወመንፈስ ቅዱስ</strong></span>\"-እኔ እግዚአብሔር&nbsp;ብየ በተጣራሁ ጊዜ ስለ አብ ስለወልድ ስለመንፈስ ቅዱስ መናገሬ ነው የሚለው ተዘነጋ እንዴ❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ታዲያ እግዚአብሔር ማለት የሦስት የባህርይ ግብር ለመግለጥ የምንጠቀምበት ስም ከሆነ አብን ቀባዒ&nbsp;ለማድረግ ምክንያቱ ምንድን ነው❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>&nbsp;6.ወበከመ ለአብ ቦቱ ህይወት ኀቤሁ.ዮሐ 5&divide;26</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;ለምሳሌ ክርስቶስ ከተነሣ በኃላ ሥልጣን ተሰጠኝ. ማቴ 28&divide;18 ይላልና ያን ጊዜ ሥልጣን ተሰጠው ማለት ነውን❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>ስለዚህ ህይወቱን ሰጠው ማለት፡-</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ተሰጠኝ ሲል ተሰጦት አይደለም ገንዘብ ማድረጉን ሲሻ ነው እንጂ&nbsp;</em></span>\r\n<div><span style=\"font-size: 14pt;\"><em>➠የቃል ገንዘብ ለስጋ ሲሆን ህይወትነት ለሥጋ ገንዘቡ ሆነ ማለት ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ሕይወት ያለው መንፈስ ቅዱስን አይደለም ለሚወዳቸው ህይወትን ሰጣቸው ይላልና.ዮሐ 5&divide;21</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠አንድም ስለሥጋ እንግድነት የተነገረ ነው አለዚያማ ለወልድም ህይወቱ ይሆን ዘንድ ይላልና መንፈስ ቅዱስ ከወልድ የተለየበት ጊዜ አለ ያሰኛል።</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>ከሁሉ አስቀድሞ ግን የረሳሁት ነገር......</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ተቀብዓን ህይወት ተብሎ ከተተረጎመና ለስጋ ክብር የሆነው መንፈስ ቅዱስ ነው የምንለው የባህርይ ህይወቱ ስለሆነ ነው&nbsp;ከተባለ አብም የባህርይ ልቡ ነውና ምን እንበለው እሽ ወገኖቼ ❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250);\"><em><span style=\"font-size: 18pt; color: rgb(52, 73, 94); background-color: rgb(236, 202, 250);\"><strong>7.\"እነሆ ናዝራዊው ኢየሱስ ቅባትን ተቀብቶ የመቀባትን&nbsp;መንግስት ተቀበለ፣አምላክ ሲሆን ስለሰውነቱም የመለኮትን ቅባት&nbsp;ተቀብቶ ሰው ሆነ እግዚአብሔር ሰው ለመሆን ወረደ ሰውም&nbsp;እግዚአብሔር ለመሆን ከፍ ከፍ አለ\"<span style=\"font-size: 14pt;\">መ.ምሥጢር ገጽ 214</span></strong></span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ በመጀመሪያ ናዝራዊው ኢየሱስየሚለው ከሁለት አካል አንድ አካል ከሁለት ባህርይ አንድ ባህርይ ሲሆን&nbsp;የወጣለት የተዋህዶ ስም ነው!!ትርጓሜውም መሲህ፣የተቀባ፣የተሾመ ማለት ነው።የተቀባ የተሾመ ሲባል ግን ለእርሱ ቀቢ ሿሚ ኖሮት አይደለም።ቀቢውም ሿሚውም ተሿሚውም አንድ&nbsp;እርሱ ነው እንጂ!!ዮሐ 4&divide;25 -30 ማለትም<span style=\"color: rgb(132, 63, 161);\"><strong>\"ለሊየ እቄድስ ርእስየ\" </strong></span>እንዲል ይህ ሲባል ኢየሱስ ክርስቶስ ቅባትን ተቀብቶ ሲል አንቀጹ ለትስብእት ነው።ማለትም መለኮት&nbsp;ለተዋሐደው ስጋ ክብር ሁኗል;አንድም ቅድመ ተዋህዶ ትስብእት ትሑት፣ህፁፅ ስለሆነ ተለዓለ ተብሎ ተነገረለት።ማለትም ያ ህፀፅ ንዴት የነበረበት ትስብእት ከቃል ጋር ሲዋሐድ ቃል ለተዋሐደው ስጋ ክብር&nbsp;ሆነው\"<span style=\"color: rgb(132, 63, 161);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"እንዲል ቅዱስ ቄርሎስ &nbsp;የቃል ገንዘብ በተዋህዶ ለስጋ ገንዘቡ ሲሆን ከበረ አምላክ ሆነ፣የባህርይ ልጅ ሆነ ሲል የመቀባትን መንግስት ተቀበለ አለ።ማለትም ስጋ ከተዋህዶ በኋላ የመለኮት ገንዘብን ገንዘቡ አድርጓልና\"\"<span style=\"color: rgb(132, 63, 161);\"><strong>እንቲአሁ ለቃል ኮነ ለስጋ ወእንቲአሁ ለስጋ ኮነ ለቃል</strong></span>\"እንዲል ቅዱስ ቄርሎስ!አንድም ስጋ ልዕልናን ግብረ አምላካዊውን ባህርይው ረቂቅባህርየ መለኮትን ገንዘቡ አደረገ።ማለትም&nbsp;የሚሞት ሲሆን የማይሞት ሆነ፣\"ምድራዊ ሲሆን ከልዕልና በላይ ያለ ልዕልናን ገንዘቡ አደረገ በአጠቃላይ የማይመረመር ጌትነትን አገኘ።አንድም በዚያው አጋጣሚ ነስአ ተወክፈ አይሉም እንባለለን;ነገር ግን ስንተረጉምና ስንል&nbsp;እመንገለ ሥጋሁ እንጂ እመንገለ መለኮቱ አንልም።ምክንያቱም በመለኮቱ በኩል&nbsp;ብንል \"ኢይጽሕቅ ቅብዓተ በህላዌ በመለኮቱ\"ማለትም በመለኮቱ መቀባትን(ክብርን)አይሻል!!ከዚህ በተጨማሪ እግዚአብሔር ሰው ለመሆን ወረደ ሲል የሰውን ባህርይ ባህርይው ለማድረግ ማለትም&nbsp;የማይራበው እንዲራብ መሆኑ፣ባእለ ጸጋ የነበረው ባህርይውን ሳይለቅ በተዓቅቦ ነዳይ መሆኑ የንጉሶች ንጉሥ ሲሆን የጌቶች ጌታ ሲሆን በአይሁድ ፊት መገረፉ በአጠቃላይ ራሱን በሰው መልክና አርዓያ መምጣቱን&nbsp;ያመለክታል። ምክንያቱም\"ነገር ግን የባህርይን መልክን ይዞ በሠውም ምሳሌ ሆኖ ራሱን ባዶ አደረገ&nbsp;በምስሉም እንደሰው ተገኝቶ ራሱን አዋረደ\"እንዲል ፊል 2&divide;8</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ሕቀ አሕጸጽኮ እምመላእክቲከ</strong></span>\"-ከመላእክት እጅግ ጥቂት አሳነስኸው\"መዝ 8&divide;5 እንዲል&nbsp;አንድም \"ሰውም እግዚአብሔርን ለመሆን ከፍ ከፍ አለ ሲል በተዋህዶ የመለኮትን ገንዘብ ገንዘቡ </em></span><span style=\"font-size: 14pt;\"><em>ስለሚያደርግ የስጋ በአምላክነት መክበር መቀባት ተብሎ ተነግሯል።አምላክነቱ የባህርይው ስለሚሆን በጸጋ&nbsp;እንዳደረባቸው ቅዱሳን አይደለም ሲል ነው።አንድም ቅዱስ ዮሐንስ አፈወርቅ እንደገለጸው </em></span><span style=\"font-size: 14pt;\"><em>ትስብእት ከመለኮት ጋር በመዋሐዱ ያገኘውን የክብር መጠን ሲያብራራ እንዲህ በማለት በሰፊው&nbsp;አብራርቷል!!\"ወዴት ስፍራ እንዳወጣው ዕወቅ:ከፍጡራን ሁሉ ከመላእክትም ሁሉ በላይ አደረገው\"አለ።ረቂቅ </em></span><span style=\"font-size: 14pt;\"><em>እውቀትን እንዲገልጽልህ ከወደድክ በእግዚአብሔር ባህርይና በሰው ባህርይ መካከል ያለ ልዩነት ምን ያህል እንደሆነ አንተ እወቅ፣ማንም ሊናገረው ወደማይቺለው ክብረ መለኮት ትስብእትን ከፍ ከፍ </em></span><span style=\"font-size: 14pt;\"><em>አደረገው፣ከልዑላን መላእክት ሁሉ በላይ አደረገው\"ሃይ.አበው 67 ክፍል 16 &divide;23 ስለዚህ ተለዓለ መባሉ ስለዚህ ነው።</em></span></div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244); color: rgb(224, 62, 45);\"><em><strong>8. \"ዘቀብኦ እግዚአብሔር መንፈሰ ቅዱሰ ወኃይለ\"ሐዋ 10&divide;38</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡\"እግዚአብሔርም የናዝሪቱን ኢየሱስን በኃይል በመንፈስ ቅዱስ ቀባው\" ሲል </em></span><span style=\"font-size: 14pt;\"><em>በመንፈስ ቅዱስ ማለት በግብረ መንፈስ ቅዱስ(በረቂቅ ምሥጢር)ሥጋን አከበርኸው ማለት ነው!!</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>&nbsp;እንደዚህማ ባይሆን ኖሮ ሐዋርያው ቅዱስ ጴጥሮስ</em></span></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>\"እግዚአብሔር የናዝሬንቱን ኢየሱስን ከሙታን መካከል ለይቶ አስነሳው\"ሲል በመንፈስ ቅዱስ ወይም </em><em>በአብ ስልጣን ነው የተነሳ በራሱ ስልጣን የተነሳ አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>በራሱ ስልጣን ካልተነሳ \"እንዴት አልዓዛርን ከመቃብር አስነሳው\"ለራሱ የሌለው ለሰው </em><em>ያበድራልን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም በመንፈስቅዱስ በቀባኸው አለ እንጂ ቅብዕ በሆነው አይልም!!</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(224, 62, 45); font-size: 18pt; background-color: rgb(251, 238, 184);\"><strong><em>9.\"መንፈሰ እግዚአብሔር ላእሌየ ዘበእንቲአሁ ቀብዐኒ\"ኢሳ 61</em><em>&divide;1</em></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp; ↪ የእግዚአብሔር መንፈስ ሲል መንፈስ ቅዱስ ነው፣እኔ ያለው ደግሞ ባለቤቱ ወልድ ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>☝በእኔ ላይ ማለቱም መንፈስ ቅዱስ በእኔ በወልድ ህልው ነው ማለቱ ነው!!</em></span><span style=\"font-size: 14pt;\"><em>ቀባኝ ማለቱም አዋሐደኝ ሲል ነው!!</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>\"ስለዚህ የእግዚአብሔር መንፈስ በእኔ ህልው ነው፣ስለዚህ ነገር አዋሐደኝ ሲል በኢሳያስ የተነገረለትን የባህርይ ህይወቱን መንፈስ ቅዱስን እርሱ ገንዘብ እንዳደረገ ሊነገር ይገባል።ስለዚህ በባህርይ ገንዘቤ&nbsp;የሚሆን መንፈስ ቅዱስ በህልውናየ ጸና ብሎ ብሎ አስተማረ\"ሃይ.አበው ዘሳዊሮስ 87 ክፍል 17-18</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;&nbsp;***አዋሐደኝ ማለቱም የአምላክ ሰው መሆን በፈቃደ አብ፣በፈቃደ ወልድ፣በፈቃደ መምፈስ ቅዱስ የሆነ ማለት ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ በሌላ አነጋገር </em></span><span style=\"font-size: 14pt;\"><em>አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ከተባለ ታዲያ ከዚህ ጥቅስ ላይ </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>በእኔ ላይ ያለ የእግዚአብሔር መንፈስ ቀባኝ ሲል ቀባዒው ማነው❓</em></span></li>\r\n<li><em style=\"font-size: 14pt;\">በዚህ ጥቅስ ቀባዒው አብ መሆኑ አይደለምን❓</em></li>\r\n<li><em style=\"font-size: 14pt;\">ታዲያ መንፈስ ቅዱስ ቅብዕ የሚል ከየት ይመጣል❓</em></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h1><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><em><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የዘመኑ ቅባት ነን ባዮች የሚያነሷቸው ጥያቄዎችና መልሶቻቸው</strong></em></span></h1>\r\n<div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(45, 194, 107); background-color: rgb(241, 196, 15);\"><em>=&gt;.እኛ የተዋህዶ ልጆች ትሥብእት ወይም ሥጋ ከባሪ መለኮት(ቃል) ክብር ስንል አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርጋችሁ ስትናገሩ መለኮት የመለኮትን ሥራ ይሰራል ሥጋም የሥጋን ሥራ ይሰራል </em><em>ከሚሉት መለካዊያን በምን ትለያላችሁ?ይሉናል።</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.ቅባት ወገኖቻችን ሆይ እኛ አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርገን እናንተ እንደምትሉት ያለ&nbsp;ፍልስፍና ላይ አልተሰማራንም በሉልኝማ የተዋህዶ ልጆች። ከበረ፣ አከበረ የምንለው በጊዜ ተዋሕዶ ላይ </em></span><span style=\"font-size: 14pt;\"><em>ያለን ጊዜ ብቻ ናት። መክበር ይሻ የነበረን ሥጋ አካላዊ ቃል በአምላክነት ክብሩ አከበረው። ይች እመቤታችን&nbsp;\"<span style=\"color: rgb(132, 63, 161);\"><strong>ይኩነኒ በከመ ትቤለኒ</strong></span>\"ባለችው ጊዜ የተፈጸመች ድንቅ ምስጢር ናት። ከዚህ ጊዜ በኋላ መለኮትና ትስብእት&nbsp;አንድ ስለኾኑ ከባሪና አክባሪ የለም።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ ወልድ አምላክ ነውና በአምላክነት ክብሩ ያከብራል ስንል ወልድ ማክበር አይችልም ካላችሁን </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\"><em>\"በመንፈስ ቅዱስ ከበረ\"ስትሉ መንፈስ ቅዱስስ ማክበር የብቻው ግብሩ ነው ብላችሁ ነውን? </em></span></strong></span></li>\r\n<li><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\">አዎ ካላችሁ ለመንፈስ ቅዱስ ከመሥረጽ ውጭ ሌላ አካላዊ ግብር እንዳለው ከየት ተማራችሁት? </span></strong></span>ማስረጃችሁ ምንድን ነው ወገኖቼ?ብላችሁ ጠይቁልኝ!!</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.አንዱ አካል አክባሪ ያሉ ቃልን አንዱ አካል ከባሪ የሚሉን ደግሞ ትስብእትን ለማለት ፈልጋችሁ ነው። እናንተ \"<span style=\"text-decoration: underline;\"><strong>በመንፈስ ቅዱስ ከበረ\"</strong></span> የምትሉት ሥግው ቃልን ነው።ታዲያ ሥግዉ ቃልን ከሆነስ</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ሥግው ቃል አምላክ ነው ወይስ አይደለም?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>&nbsp;ሥግው ቃል እስከሚከብር ድረስ የአብ የመንፈስ ቅዱስ ቃላቸው ማን ነበር?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ትስብእት አምላክ የኾነው በቅብዐተ መንፈስ ቅዱስ ከኾነ ሥግው ቃል እስኪከብር ድረስ አብና መንፈስ ቅዱስ ዲዳ ነበሩ (ሎቱ ስብሐት)?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(22, 145, 121); background-color: rgb(194, 224, 244);\"><em><strong><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244);\">=&gt;&ldquo;እራሱ(አብ) አክብሮ አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ አለው&rdquo; ዮሐንስ አፈ ወርቅ ድር 8&divide;69 ብሎ አብ ወልድን እንዳከበረው እየተናገረ ለምን እራሱን በራሱ አከበረ ለማለት ደፈራችሁ? ምን ምስክርስ አላችሁ?ይሉናል።</span></strong></em></span></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✔. አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ የሚለው ቃል መነሻው ዳዊት ነው። ይህን የጻፈው ዳዊት 2&divide;7 ላይ ነው።ማክበር አምላካዊ ግብር እንደመኾኑ መጠን በአብ በወልድ በመንፈስ ቅዱስ ሊነገር ይችላል። ይህ </span><span style=\"font-size: 14pt;\">ችግር ነው ብለን አናውቅም። በመጀመሪያ</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ማክበር የማን ግብር ነው ብለው ያስባሉ?</em></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ግብርነቱስ የአካል ነው ወይስ የአምላክነት?የሚሉትን ጥያቄዎች ማጤን ያስፈልጋል።</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.እኛ ወልድ ዋህድ በተዋህዶ ከበረ ብለን የምናምን እርሱ ራሱን እንዳከበረ መጽሐፍትን አብነት አድርገን&nbsp;እንናገራለን።ይኸውም&laquo;ዳግመኛ ክርስቶስስ ክብር መሻት ኖሮበት አልከበረም እርሱ ራሱ አክባሪ ነው እንጂ ሰው ቢኾንም በባሕርይ&nbsp;ክብሩ ከበረ እርሱ ራሱ እግዚአብሔር አምላክ ነው ሥጋ ትሁት ሕጹጽ ነዳይ ስለኾነ ተለዐለ ተብሎ ተነገረለት ከኹሉ በላይ የኾነ ስምንም እርሱ ራሱ ሰጠው ተባለ ይህም የኾነ በባሕርይ ተዋሕዶ ነው አምላክ እንደኾነ&nbsp;እኛንም እርሱ ወደ አለበት ያቀርበን ዘንድ&raquo; ሊቁ ቅዱስ ቄርሎስ በሃይማኖተ አበው ስምዐት 124 &divide;34 ላይ ይላል።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ታላቁ ሊቅ ቅዱስ ዮሐንስ አፈወርቅም በሃይማኖተ አበው 66 &divide;18 -19&nbsp;ላይ አካላዊ ቃል የተዋሐደውን የእኛን ሥጋ እንዳከበረው በመደነቅ እንዲህ ይላል፡-</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;ክብሩ ተለይቶ የነበረ ሥጋን ክቡር አምላክ ሊያደርገው የጸጋ ገዥነትን አጥቶ የነበረ ሥጋንም የባሕርይ ገዥ&nbsp;ሊያደርገው ወደደ አዳም ከእኛ እንደ አንዱ ኾነ ያለውንም ሰው በመኾን ሊገልጠው ወደደ። ስለዚህ ሥጋዬን&nbsp;ተዋሐደ። ወንጌልን ሲያስተምር እሰማው ዘንድ ሥጋዬን በተዋሕዶ ገንዘብ አደረገ፤ መንፈስ ቅዱስን ሰጠኝ ሰጠሁ ተቀበልኩ ለእኔም ፍጹም ሕይወትን ገንዘብ አደረግሁ። እርሱ ያከብረው ዘንድ ሥጋዬን ተዋሐደው። የሚያድነኝ መንፈስ ቅዱስን ሰጠኝ&raquo;በዚህ አነጋገር መሠረት <strong><span style=\"text-decoration: underline;\">እርሱ የተባለው አካላዊ ቃል ነው</span></strong>። አንዳንድ የቅብዐት እምነት ተከታዮች ግን እርሱ የሚለውን ለመንፈስ ቅዱስ ቀጽለው በመንፈስ ቅዱስ ከበረ ለሚለው ኑፋቄያቸው ደጋፊ ጥቅስ አድርገው ይጠቅሱታል። እርሱ የሚለውን ለመንፈስ ቅዱስ ከቀጸሉት ሥጋዬን የተዋሐደው መንፈስ ቅዱስ ነው ያሰኛልና ፍጹም ክህደት ነው። መንፈስ ቅዱስ ሥጋዬን ተዋሕዶ ሰው ኾነ የሚያሰኝ ክፉ መንገድ ነው። በተዋሕዶ ከበረ&nbsp;ብለው ላለማመን ወደ ሌላ ስህተት ሲያመሩ ይታያሉ። ሊቁ እንደጻፈው ግን እርሱ የሚለው ለአካላዊ ቃል የተነገረ ነው። ስለዚህም እርሱ መንፈስ ቅዱስን ሰጠኝ ሲል አካላዊ ቃል ለተዋሐደው ሥጋ የባሕርይ ሕይወቱ&nbsp;መንፈስ ቅዱስን መስጠቱንና ሥጋ የመንፈስ ቅዱስን ሕይወትነት ገንዘቡ ማድረጉን መናገር ነው። ይህ የተደረገው ደግሞ <span style=\"text-decoration: underline;\"><strong>በተዋሕዶ</strong></span> ብቻ ነው።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች&nbsp;የሊቁን ትምህርት በማስተዋል ተመልከቱና ከሰፊው የምስጢር ባሕር ውስጥ ገብታችሁ የምሥጢሩን ጥልቀት የትምህርቱን ርቀት (ቀ ይጠብቃል) አድንቁ ከዚህ በላይ ምን ማስረጃ አለ??</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;<span style=\"color: rgb(186, 55, 42);\"><strong>ወከመዝ ነአምሮ ለሊሁ ተቀብዐ ከመ ሥርዓተ ትስብእት ወዳእሙ ውእቱ ዘይቀብዕ ርእሶ በ</strong></span><span style=\"color: rgb(186, 55, 42);\"><strong>መንፈሱ ባሕቲቱ</strong></span>\"በተዋሕዶ እንደከበረ እናውቃለን ግን በገዛ ሥልጣኑ ራሱን የሚያከብር እርሱ ነው&raquo; ሃይማኖተ አበው ስምዓት 124 &divide;14 ይላል።</span></em><em><span style=\"font-size: 14pt;\">ወንጌላዊው ዮሐንስም በወንጌሉ ዮሐ 17&divide;19 ላይ &laquo;<strong><span style=\"color: rgb(186, 55, 42);\">አነ እቄድስ ርእስየ </span></strong>-እኔ ራሴን አከብራለሁ&raquo; ብሎ ጌታ የተናገረውን ጽፎት እናገኛለን። እኔ ራሴን አከብራለሁ ሲል በተዋሕዶ ማለቱ ነው። እኔ ሲልም በቃል ርስት ኾኖ ነው በሥጋ ርስትማ ይህን አይናገርም። ሥጋማ እንኳንስ ሊያከብር የጸጋ ልጅነትን እንኳ ያጣ ነበርና። ቃል ሲዋሐደው ግን ክቡር አምላክ ኾነ ይባላል። እኔ ብሎ አምላክነቱን (አክባሪነቱን) ራሴን ብሎ ሰውነቱን (ከባሪነቱን) ይናገራል። እርሱ ራሱ አክባሪ ነው እርሱ ራሱም ከባሪ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>↪\"እምቅድመ ቅብዓትሰ ነበሩ መላእክትከመ ህፃናት በዝንጋዔ ወሶበ ተቀብዑ መል', '<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"color: rgb(132, 63, 161); font-size: 36pt;\">ቅባት(ቅብዓት)</span></h1>\r\n<h2>&nbsp;<span style=\"font-size: 18pt;\"> <span style=\"font-size: 14pt;\"><em><strong>ቅባት(ቅብዓት) ትርጉሙ ምንድን ነው❓</strong></em></span></span></h2>\r\n<div><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(224, 62, 45);\">↪ቅባት በቅዱሳት መጽሐፍት ሲተረጎም የሚከተሉት ትርጉሞች አሉት።እነርሱም:-✔</span></strong></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">1ኛ.ቅባት ማለት በቁሙ ሲፈታ ቅባት ማለት ነው</span>።</strong>ቀባ፣ለከከ፣ለቀለቀ፣ቀባ የሚል ትርጉም ያመጣል።ለዚህም ማስረጃው-\"የመገናኛውንም ድንኳን የምስክሩንም ታቦት ገበታውንም ዕቃውንም ሁሉ መቅረዙንም ዕቃውንም መሰዊያውን ሁሉ ለሚቃጠለውም መሥዋዕት ለሚሆነው መሰዊያና ዕቃውንም ሁሉ የመታጠቢያውን ሰንና&nbsp;መቀመጫውን ትቀባበታለህ\"ዘጸ 30&divide;26</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">-\"ማርያምም እጅግ ዋጋው የከበረ የጥሩ ናርዶስ ሽቱ ንጥር ወስዳ የኢየሱስን እግር ቀባች\"ዮሐ 12 &divide;3 </span><span style=\"font-size: 14pt;\">=&gt;<span style=\"text-decoration: underline; color: rgb(185, 106, 217);\">ቅባት </span></span><span style=\"text-decoration: underline; color: rgb(185, 106, 217);\"><span style=\"font-size: 14pt;\">በቁሙ ሲፈታ</span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">2ኛ.ተቀብዐ:-ከበረ ተብሎ ይተረጎማል።</span></strong>ለዚህም ማስረጃ \"<strong>እለሰ የአምኑ ርቱዓ ይሜሀሩ ከመ ተቀብዓ ቃል በስጋሁ</strong>\"ትርጓሜውም ሲቀባም የሚለውም ሲከብርም ሲዋሐድም አንድ ጊዜ ነው ሲል ነው እንጂ በቁሙ ሲቀባ ስላለ ሲቀባ ተብሎ አይተረጎምም በቁም የሚተረጉሙ አሉና!!ወዳጄ \"መጽሐፍት ትርጓሜን እንጂ ዘይቤን አይጠነቅቁም \" እሽ!!ይህ ማለት ስጋ ከቃል ጋር ሲዋሐድ መጀመሪያ ተዋሕዶ በኋላ የከበረ አይደለም:ከብሮም ሳይዋሐድ አልቀረም;ሲከብርም ሲዋሐድም አንድ ጊዜ ነው እንጂ!! አንድም ከላይ ያለውን ያነሳነውን ቃል ሊቃውንተ ቤተ ክርስቲያን እንዲህ እያሉ አቅንተው ይተረጉሙታል።ኦሪት ወነቢያት ሰበኩ በክርስቶስ ሲል \"በክርስቶስ\" ያለው ክርስቶስሀ ማለት ነው። \"<strong>በ</strong>\" አገባብ በማድረግ \"<strong>ን</strong>\"የሚል ፍቺ ይሰጡና ኦሪትና ነቢያት በክርስቶስ ሰበኩ የሚለውን በቁሙ ኦሪትና ነቢያት ክርስቶስን ሰበኩ በማለት ይገልጹታል።ማለትም ክርስቶስን ይወርዳል ይወለዳል እያሉ ሰበኩ የወንጌልን አዝመራ ዘሩ ሐዋርያትም አጨዱት ነውና ቅሉ።ስለዚህ ይህንን ቃልም በሥጋሁ የሚለውን\"በ\"ን አገባብ አድርገው \"<strong>ሥጋን</strong>\" በማለት ይተረጉሙና ስጋን ተዋሐደ ብለው ያቀኑታል።</span></li>\r\n</ul>\r\n<p><span style=\"color: rgb(230, 126, 35);\"><strong><span style=\"font-size: 14pt;\">=&gt;.ያም ሆነ ይህ ግን ይህንን ነገር ስናነሳ እነዚህን ጥያቄዎች ማሰብ ያስፈልጋል።ማለትም በቁሙ መለኮት በስጋው ከበረ ከተባለ</span></strong></span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቅድመ ተዋህዶ ቃል ክብር አልባ ነበርን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ነውስ ቃል በጊዜ ተዋህዶ የባሕርይ ክብሩን አጥቷል?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ወልድን ከመለኮታዊ ክብሩ ዝቅ አያደርገውምን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቃል(መለኮት) በስጋው ከበረ ከተባለ ስጋን የተዋሐደ ከሦስቱ አካል አንዱ አካል ወልድ(አካላዊ ቃል) ነውና ሥላሴ በማክበር ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">መለኮት በስጋው ከከበረ በመለኮትነት ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.መክበር የተፈጸመውስ መቼ ነው???በጊዜ ተዋህዶ \"ርስት\" ሰጥቶ መናገርን የትኞቱ አበውና መጽሐፍት አስተማሩን?</span></em></span></strong></li>\r\n</ul>\r\n</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">3ኛ.ተቀብዐ:-ተዋሐደ ተብሎ ይተረጎማል።</span></strong>ብዙ ወገኖቻችን ግን ቀብዓን ተዋሐደ ብለው አይተረጉሙትም።ለዚህም ማስረጃ ታላቁ ሊቁ አባ ጊዮርጊስ ዘጋስጫ በመጽሐፈ አርጋኖን ዘአርብ ዕለት\"ዘተቀባዕከ ስጋሃ ለማርያም\"ብለዋል!!ይህ ንባብ የሚተረጎመው የማርያምን ስጋ የተዋሐድክ ተብሎ ነው!!ምክንያቱም በከበረ እንዳይተረጎም የማርያምን ስጋ የተከበርክ አይባልም::በቀብዓ እንዳይተረጎም የማርያምን ስጋ የተቀባህ አይባልም ስጋ ቅብዕ ይሆናልና።ስለዚህ የተዋሐድክ ብሎ አቅንቶ መተርጎም ያስፈልጋል ወዳጄ!!!</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">➠ስለዚህ ሳጠቃልለው አንድ ቃል እንደአውዱ እንደአገባቡ የተለያየ ትርጉም ይኖረዋልና አንዲትን </span><span style=\"font-size: 14pt;\">በዘፈቀደ አንጠልጥሎ ሁሌም በዚህ ነው የሚፈታ ማለት የዕውር ክርክር ነው።ለምሳሌ \"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልክት ማኅበር ቆመ\"መዝ 81&divide;1 ይላልና ቆመ ስላለ ብቻ ቆመ ብለን ልንተረጉመው ነው??በጭራሽ</span></div>\r\n<div><span style=\"font-size: 14pt;\">ቆመ ብለን አንተረጉመውም!!ታዲያ ምን ብለን እንተረጉመዋለን ትሉኝ እንደሆነ\"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልዕክት መካከል ተገለጠ\"ብለን ነዋ!!እንደዚህም ሁሉ ተቀብዐን እንደአውዱ እንደ አገባቡ ይፈታል!!</span></div>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"color: rgb(224, 62, 45); font-size: 18pt;\"><strong>➠የቅባት ትርጉም እንደ ቅባት አስተምሮ ግን......</strong></span></h2>\r\n<div>\r\n<ul>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt; color: rgb(22, 145, 121);\">✔. ቅባት መንፈስ ቅዱስ ተብሎ ይተረጎማል!!</span></strong></li>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span><span style=\"font-size: 14pt;\">✔.ቅባት ሕይወት ተብሎ እንደሚተረጎም ወልደ አብ መጽሐፍ ገጽ 179 ;</span><span style=\"font-size: 14pt;\">አዕማደ ምስጢር ገጽ 22 </span><span style=\"font-size: 14pt;\">ይናገራል!!</span></span></strong></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">&nbsp;ከዚህ ውጭ ግን <strong><span style=\"text-decoration: underline;\">ተቀብዐን ተዋሐደ</span></strong> ብለው ተርጉመው ፈጽሞ አይናገሩም;ተዋሐደ ብለው </span><span style=\"font-size: 14pt;\">መተርጎም ስህተት ነው ይላሉ \"ተዋሐደ\"ካሉ መንፈስ ቅዱስ ቅብዕ መሆንን ያፈርስባቸዋልና!!</span><span style=\"font-size: 14pt;\">ምናልባት በነገረ ሥጋዌ ጉዳይ እመቤታችንን ተቀባትም ተዋሐዳትም ማለት ክህደት ነው </span><span style=\"font-size: 14pt;\">ሲባል ብዙ ሰዎች ግራ ይጋባሉ;ነገር ግን ጊዜ ተዋህዶ ላይ የተፈጸሙ ተግባራትን ካለማወቅ </span><span style=\"font-size: 14pt;\">የተነሳ ነው ወገኖቼ!!!በምሥጢረ ሥጋዌ ትምህርታችን ስንነጋገር እነዚህን ነገሮች </span><span style=\"font-size: 14pt;\">ካስታወሳችሁ የጥያቄያችሁ መልስ ታገኛላችሁ!!!ይኸውም ቃል በጊዜ ተዋህዶ የማይቀዳደሙ </span><span style=\"font-size: 14pt;\">፫ት ነገሮች ተከናውነዋል። እነርሱም:-</span></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መክፈል፤</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መዋሐድ እና</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">&nbsp;መክበር ናቸው።</span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">✟✔.ከፍሎ ሳይዋሐድ ቢቀር በሰው ወይም በእመቤታችን አደረ ያሰኛል።ይኼውም ኀደረ </span><span style=\"font-size: 14pt;\">በብእሲ ብሎ እንደካደው ጳውሎስ ሳምሳጢ ክህደት መግባት ነው።ተዋህዶ ሳይከፈል ቢቀር </span><span style=\"font-size: 14pt;\">እመቤታችን አምላክ ሆነቺ ያሰኛል።ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል።አካለ ቃል ክብር </span><span style=\"font-size: 14pt;\">አልባ ያሰኛል የሚሉት ናቸው።ስለዚህ ሲከፈልም፤ሲዋሐድም፤ሲከብርም(ሲቀባ) </span><span style=\"font-size: 14pt;\">አንድ ጊዜ ነው።</span></div>\r\n<div>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"font-size: 24pt; color: rgb(132, 63, 161);\">ምሥጢረ ሥጋዌ በቅባት አስተምህሮ (በወልደ አብ) ዕይታ</span></h1>\r\n<p><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 14pt;\">የኢትዮጵያ ኦርቶዶክስ ቤተ ክርስቲያን የምታስተምረው ትምህርት ከቅባት እምነት በጣም ሰፊ ልዩነት ሲኖራት የቅባት እምነት ተከታዮች ከዚህ በተለየ መልኩ ብዙ ክህደትን ሲያስተምሩ ይስተዋላሉ።ከነዚህም መካከል በጣም የጎሉትን የክህደት መንገዶ ከዚህ በታች ለማየት እንሞክራለን።&nbsp;</span></strong></span></p>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\">✔፩ኛ.እግዚአብሔር ወልድ ሁለት ልደታት አሉት እያሉ በቃል ደረጃ&nbsp;ይናገራሉ ።ነገር ግን በተግባር ደረጃ እንደጸጋ አስተምህሮ ፫ት ልደትን&nbsp;አማኝ ናቸው!!ለዚህ ማስረጃየ ወልደ አብ መጽሐፋቸው&nbsp;የመጀመሪያው ዕትም ገጽ 217 እና 218 እንዲህ ይላል!!</span></strong></div>\r\n<div style=\"padding-left: 80px;\"><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(132, 63, 161);\">\"<strong>የጌታችን ልደት ስንት ነው ቢሉ ፪ት ነው።እንዴት ፪ት ነው ቢሉ&nbsp;እምቅድመ ዓለም በመለኮቱ ተወለደ ብለናል ኋላም በማኅጸን በሰውነቱ&nbsp;ከአብ ተወለደ እንላለን ዳግም ከእመቤታችን በስጋ በጎል ተወለደ&nbsp;እንላለን</strong> \"</span></em>ወልደ አብ ገጽ ገጽ 217 ይላል!!</span></div>\r\n<div><span style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(186, 55, 42);\"><strong>↪አስተዉሉ፦</strong></span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ታዲያ ጌታችን ቅድመ ዓለም ከአብ በመለኮቱ፣ድኅረ ዓለም ከእመቤታችን በትስብእቱ፣ድኅረ ዓለም በማኅጸን በሰውነቱ ከአብ ተወለደ ከተባለ ሁለት ልደታት ማመን ከየት ይመጣል ይህ ፫ት ልደት&nbsp;አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ይህ ከሆነስ ወልደ አብ በመለኮቱ:ወልደ ማርያም በትስብእት፣አሁንም በድጋሜ በማህጸን ከወለደው እንደገና ወልደ አብ በትስብእቱ ሊባል ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ለማንኛውም \"በቃል ሁለት ልደት፣በተዘዋዋሪ በተግባር ግን ሦስት ልደት ይላሉ!!አይ ወገኔ\"አልሸሹምዞር አሉ\"ማለት ይሄ ነው እኮ ወገኔ ገባህ?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\"><strong><span style=\"font-size: 14pt; background-color: rgb(248, 202, 198);\">፪ኛ.\"ሰባቱን ሀብታተ መንፈስ ቅዱስ እርሱ በስጋ ርስት በጊዜ ፅንስ ያለምክንያት ከአብ ተቀብሎ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉሥ ሆነባቸው\"ወልደ አብ ገጽ 211 ይላል</span></strong></span></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች የነገረ ቅባትን አስተምህሮ እና ጥያቄ የሚመለሰው ብዙ ጥቅስ መዘርዘር ሳያስፈልገው ጥያቄን በጥያቄ መመለስ እና በደንድ አገናዝቦ ማስተዋል ነው።ስለዚህ ከላይ እንዳያችሁት እንዲህ ካሉ&nbsp;እስኪ በሞቴ ንገሩኝ.........</span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉስ ሆነባቸው ማለት ቀድሞውንስ የባህርይ አምላክ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ ሰው የሆነስ በአባቱ ፈቃድ በእርሱ ፈቃድ በመንፈስ ቅዱስ ፈቃድ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">ታዲያ እነማንን ነው የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸው❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በግድ ነው በኃይል የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸውስ❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በመጀመሪያ \"ሆነባቸው\"ማለት በግድ አምላክ ሆኖባቸዋልን❓የእነርሱ ፈቃድስ❓</span></strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><em><strong><span style=\"color: rgb(52, 73, 94); background-color: rgb(236, 202, 250); font-size: 18pt;\">✔፫ኛ.\"መንፈስ ቅዱስ ሠጪም ተሠጭም ነው\"ወልደ አብ ገጽ 181&nbsp;ይላል።</span><span style=\"color: rgb(52, 73, 94); font-size: 18pt;\">ይህ ከሆነ.......</span></strong></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ምንድን ነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ለማነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለው ምንን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለውስ ከማን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሌለው አለን ከሌላ የሚቀበል❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>በዓለመ ሥላሴ ነው መንፈስ ቅዱስን ሰጪም ተሰጪም ነው የምንል እንዳትሉኝ በዓለመ ሥላሴ በባህርይ በክብር በስልጣን አንድ ናቸው አንዱ ከአንዱ አያንስም አንዱ ከአንዱ አይበልጥ;ታዲያ አንዱ ከአንዱ ከአልበለጠ አንዱ ከአንዱ ካላነሰ ሰጪና ተሰጪ የሚል ከየት ይመጣል ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪና ተሰጪ ያልን ለፍጡራን ነው እንዳትሉኝ መንፈስ ቅዱስን ፍጡር እያላችሁት መሆኑ አይደለምን❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪም ተሰጪም ነውያልነው በፈጣሪና በፍጡር መካከል ነው እንዳትሉኝ መንፈስ ቅዱስ ፈጣሪ ነው ከፍጡር ይቀበላላልን❓ተሰጪ የሚለው አያፈርስባችሁምን❓ተብለዉ ሲጠየቁ መልስ የላቸዉም አፋቸዉን ይያዛሉ።</em></strong></span></li>\r\n</ul>\r\n<div><span style=\"background-color: rgb(194, 224, 244); color: rgb(52, 73, 94); font-size: 18pt;\"><em><strong>፬ኛ.አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ነው ይላሉ!!</strong></em></span></div>\r\n<div>-<em><span style=\"font-size: 14pt;\">ይህ ማለት፦</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ-አክባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ ከባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል።በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።</span></em></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><strong>↪ታዲያ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን</strong></span></p>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>&nbsp;አብ አክባሪ፣ወልድ ከባሪ መንፈስ ቅዱስ ክብር የሚል ከየት ይመጣል❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>ምሥጢረ ሥላሴ ላይ የተነገረውን ለምስጢረ ሥጋዌ መቀፀልስ ለምን አስፈለገ❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong>↪\"ሥላሴ በተለየ ግብር ሦስት ናቸው።ይኸውም መውለድ፣ማስረፅ፣መወለድ፣መስረፅ ነው\"ይላል ገጽ 53;እንደገና 133 ላይ ደግሞ\"ቅብዕ የሆነ ግን በተለየ አካሉ በተለየ ግብሩ መንፈስ&nbsp;ቅዱስ ነው\"ይላል</strong></span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለመንፈስ ቅዱስ የተለየ ግብር የተሰጠው መቼ ነው ቅብዕነት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>የመንፈስ ቅዱስ ግብር መስረፅ ከሆነ ቅብዕነት ደግሞ ለመንፈስ ቅዱስ መቼ ተጨመረለት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለወልድና ለአብስ ምን የተለየ ግብር ምን ተጨመረላቸው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp;ከዚያ ባለፈ አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ማለት </span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ➠ሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ➠ተሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ➠ስጦታ ማለት ነው።</span></em></li>\r\n</ul>\r\n<p><em><strong>↪<span style=\"font-size: 12pt;\"> ይህ ከሆነ&nbsp; &nbsp;</span></strong></em></p>\r\n</div>\r\n<div>\r\n<div>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ አለን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ ካለ ሰጪ ከተሰጪ ይበልጣል;ተሰጪ ከሰጪ ያንሳል!!ታዲያ አብ ከወልድ ከመንፈስ ቅዱስ ይበልጣልን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>ወልድስ ከአብ ከመንፈስ ቅዱስ ያንሳልን❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; color: rgb(132, 63, 161); background-color: rgb(206, 212, 217);\"><em><strong>✔፭ኛ.\"ስጋ ሲፈጠር መለኮትም ከስጋ ጋር አብሮ ተፈጠረ ካላሉ&nbsp;ይላል\"ወልደ አብ ገጽ 127</strong></em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>መለኮት(ቃል) ራሱ ፈጣሪ ነው;ራሱ ፈጣሪ ከሆነ ከስጋ ጋር አብሮ ማን ፈጠረው ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ጸሎተ ሐይማኖት ላይ\"ዘተወልደ ወአኮ ዘተገብረ\"የተወለደ እንጂ ያልተፈጠረ የምትለዋን ፋቃችኋት እንዴ ታዲያ ወገኖቼ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ፍጡር ከሆነ ታዲያ እመቤታችን ወላዲተ አምላክ ሳይሆን ወላዲተ ሰብእ ናት ልትሉ ነው እንደ ፎጢኖስ❓</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><strong><em><span style=\"color: rgb(132, 63, 161); background-color: rgb(241, 196, 15); font-size: 18pt;\">✔፮ኛ.\"እኛ የምንቀበለው የጸጋ ጌታ የሚቀበለው የባህርይ ነው ማለት&nbsp;እንዴት ነው ቢሉ እኛ በተወለድን በ፵ ቀን እናገኘዋለን በክህደት&nbsp;በኃጢአት ይነሳል ስለዚህ ስለዚህ የጸጋ ይባላል።ጌታ ግን ሲዋሐድ የባህርይ ህይወት መንፈስ ቅዱስን ከአካሉ ጋር አግኝቶታልና የባህርይ&nbsp;ይባላል\"ወልደ አብ ገጽ 188</span></em></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ጌታ የባህርይ ህይወቱን መንፈስን ከአካሉ ጋር አግኝቶታል ይላል;የመንፈስ ቅዱስን አካሉን ነው ወይስ ሀብቱን የተቀበለው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>አካሉን ከተባለ መንፈስ ቅዱስ ከስጋ ጋር ተዋህዷልን ❓</em></strong></span></li>\r\n<li style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ሀብቱን ካላችሁስ ክርስቶስ ዕሩቅ ብእሲ መሆኑ አይደለምን ❓</em></strong><em><span style=\"color: rgb(0, 0, 0);\">ብላችሁ ስትጠይቋቸው ምላሽ ያጣሉ።</span></em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp;</strong></span></p>\r\n<div><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;በነገረ ቅባት በመንፈስ ቅዱስ ከበረ ለማለት የሚነሱ ጥቅሶች</strong></span></div>\r\n<div>&nbsp;</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.የዘመኑ ቅባት ነን ባዮች በመንፈስ ቅዱስ ከበረ ለማለት በጣም በርካታ የመጽሐፍ ቅዱስ ጥቅሶችን ቢያነሱም ከብዙዉ በጥቂቱ ተደጋጋሚ ሁሌም የሚያነሷቸው የአፍ መፍቻ ጥያቄዎች የሚከተሉት ሲሆኑ ቤተክርስቲያናችን አረዳዷ ሚን ዪመስላል የሚለዉን ትርጓሜዉን እናያለን።</span></em></div>\r\n<div><strong><span style=\"background-color: rgb(194, 224, 244);\"><em><span style=\"font-size: 14pt; background-color: rgb(194, 224, 244);\"><span style=\"font-size: 18pt;\"><span style=\"color: rgb(45, 194, 107);\">1ኛ. </span>\"<span style=\"color: rgb(45, 194, 107);\">ዘአንገሦ ለሥጋ አዳም በመንፈስቅዱስ ወረሰዮ ቅዱሰ&nbsp;ወማሕየዌ ዘለብሶ ለአዳም መዋቲ</span></span>\"በመንፈስቅዱስ ህይወትነት&nbsp;የአዳምን ባህርይ ያከበረው የባህርይ አምላክ ያደረገው እርሱ ነው\"ሃይ.አበ.ዘእልመስጦአግያ ፪:፭</span></em></span></strong></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡በመጀመሪያ ያከበረው አለ እንጂ ክብር የሆነው አይልም አስተውሉ ወዳጄ!!</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>መንፈስ ቅዱስ ቅብዕ(ክብር) ከሆነው ለምን ያከበረው አለ ለምን ክብር የሆነው አላለም❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>፫ቱ በአክባሪነት አንድ አይደሉምን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም ይህ የተነገረው የመንፈስቅዱስን ህይወትነት ሥጋ ገንዘብ ማድረጉን ሲናገር ነው!!አንድም \"የአዳምን ሥጋ በመንፈስ ቅዱስ አዋሐጅነት የተዋሐደው እርሱ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም በመንፈስቅዱስ ህይወትነት ማለት በረቂቅ የሥላሴ ግብር ማለት እንጂ መንፈስ ቅዱስ ክብር ሆነው ለማለት አይደለም ወዳጄ!!የአዳምን ሥጋ በግብረ መንፈስ ቅዱስ ተዋሕዶ የባሕርይ ንጉሥ ያደረገው&nbsp;</span></em><em><span style=\"font-size: 14pt;\">እርሱ ነው!!\"<strong>ወረሰዮ ቅዱሰ ወማሕየዌ ክቡር ወሀቤ ሕይወት</strong> አምላክ ያደረገው እርሱ ነው ካለ በኋላ ዘለብሶ ለአዳም መዋቲ\"አለ;ለምን ከተባለ ስጋን የተዋሐደ በተለየ አካሉ ወልድ ነውና።ግብረ መንፈስ ቅዱስ </span></em><em><span style=\"font-size: 14pt;\">ማለት ረቂቁን ለመንፈስ ቅዱስ መስጠት ነው እንጂ በማዋሐድ፣ በመፍጠር፣ በመግዛት፣ በመንግሥት፣በክብር ሦስቱ አካላት አንድ ናቸውና በአንዲት ግብረ ባሕርይ መሆኑን እናስተውል።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(194, 224, 244);\">2ኛ. \"ለሊሁ ዘይሁብ ወለሊሁ ዘይትወሀብ\"-ጸጋውን የሚሰጥ እርሱ ነው ጸጋም ሆኖ የሚሰጥ እርሱ ነው\"</span></strong></span><span style=\"text-decoration: underline;\">አረ.መን.ድር.11</span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ይህ ቃሉ የተነገረው ለመንፈስ ቅዱስ ሳይሆን ለወልድ ነው ምክንያቱም እርሱ ለኩነተ ሥጋ ተሰጦአልና ነው ወዳጄ!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም በሰባኪ አድሮ ጸጋን ይሰጣል.በሰሚ አድሮ ይቀበላልና!!</em></span></div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em>3ኛ. \"አማን አንገለጉ በዛቲ ሀገር ላዕለ ቅዱስ ወልድከ ኢየሱስ&nbsp;ዘቀባእካሁ.ሐዋ.4&divide;27</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ከዚህ ላይ የምናስተዉለው ነገር አለ።ይኽውም፦</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>መንፈስ ቅዱስ ቅብዕ ከሆነው በቀባኸው አለ እንጂ ቅብዕ በሆንኸው ለምን አላለም❓</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>-ቅብ የሆነው መንፈስ ቅዱስ ነው ከተባለ ይህ ቃል ደግሞ የአብን ቀባዒነት የክርስቶስን&nbsp;ተቀባዒነት ይናገራል እንጂ የመንፈስቅዱስን ቅብዕነት አይናገርም እኮ!!</em></span></div>\r\n<div><span style=\"font-size: 18pt; color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em><strong>4.&nbsp;እንደእሱ አካል ባለ አካል አክብሮታልና.ዮሐ.አፈ.ወ.ድር 3&divide;100</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>➡አስተውሉ</strong>:-ሥጋን በቃል አንቀጽ ሲጠራው እንደሱ አካል አለ፤ባለአካል ብሎ ቃልን ጠራው&nbsp;አክብሮታል አለ እንጂ ክብር ሆኖታል አላለም</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም አካለቃል ከአካለሥጋ፣ባህርየ ቃል ከባህርየ ሥጋ ጋር መዋሀዳቸውን እየተናገረ ነው!!</em></span></div>\r\n<div><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>5 .\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከ እግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ\"<span style=\"font-size: 14pt;\">መዝ 44 &divide;7</span></em></span></strong></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>✔ \"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን&nbsp;ቀባህ\"</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;በመጀመሪያ እነዚህን ጥያቄዎች እንመልስ &nbsp;</em></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ቃሉ በባለቤትነት የተነገረው ለማን ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>እግዚአብሔር ሲል ከ3ቱ አካል ለአንዱ የመንፈስ ቅዱስ ስም ብቻ ነው የሦስት ስም አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ከባልንጀሮችህ ይልቅ ሲልስ ባልንጀሮቹ እነማን ናቸው ይልቅ የሚለውስ ለምን መቀጸል አስፈለገ❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>የደስታን ዘይት ቀባህ ማለት ትርጉሙ ምንድን ነው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>* በመጀመሪያ\"ጽ<strong>ድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ&nbsp;የደስታ ዘይትን ቀባህ</strong>\"በሚለውኃይለ ቃል ውስጥ \"<span style=\"text-decoration: underline;\"><strong>አንተ</strong>\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ </span></em></span><span style=\"font-size: 14pt;\"><em><span style=\"text-decoration: underline;\">እናስተውል:;ይኸውም&nbsp;\"<strong>ትስብእት\"</strong>ነው።\"ባልንጀሮችህ\"የተባሉት ደግሞ ቀደምት ነቢያት፣ካህናት ነገስታት ናቸው።</span></em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 14pt;\"><em>❓=ታዲያ \"ከባልንጀሮችህ ይልቅ\"ለምን አለ ትሉኝ እንደሆን እነርሱ ሲሾሙ የነበረው በቅብዓ ዘይት ነበርና እነ ዳዊት መመልከት ይቻላል!!ለእነርሱ ሹመት ከእግዚአብሔር የሚያገኙት የሚቀበሉት ጸጋ </em></span><span style=\"font-size: 14pt;\"><em>ጊዜያዊ የሚያልፍ ነው።የክርስቶስ ሰው መሆን የትስብእት መክበር ግን ከማንም የማይቀበለው የባህርይው በተጭና በተሰጭ መካከል የሚደረግ አይደለም ሲል ነው፣ታዲያ የስጋ መክበር እንዴት ነው ትለኝ&nbsp;</em></span><span style=\"font-size: 14pt;\"><em>እንደሆነ\"<span style=\"color: rgb(224, 62, 45);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"መለኮት ለስጋ ክብር ሆነው እርሱ ራሱ በባህርይ ክብሩ ከበረ፣ስጋ&nbsp;እርሱ ራሱ ክብሩ አምላክነቱ የባህርይ ከሆነ መለኮት ጋር ስለተዋሐደ\"እልሃለሁ ወዳጄ!!</em></span><span style=\"font-size: 14pt;\"><em>አንድም እግዚአብሔር አምላክ ብሎ ለምን አራቀቀው ትለኝ እንደሆነ\"<strong>የተዋሐደው የፈጠረውን ስጋ</strong>\"ነውና&nbsp;ማለትም\"እርሱ ራሱ የፈጠረውን ስጋ ተዋሐደ እንዲል ሊቁ!!!</em></span>\r\n<div>&nbsp;<span style=\"font-size: 14pt;\"><em>አንድም ይልቅ ማለቱ\"አምላክነት የባህርይው ስለሚሆን በጸጋ እንዳደረባቸው እንደቅዱሳኑ ሳይሆን አንተ ገንዘብህ የሚሆነውን መለኮትን ስለተዋሐድክ ነው ሲል ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን&nbsp;መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው </em></span><span style=\"font-size: 14pt;\"><em>ትለኝ እንደሆነም ሰው መሆንን ወደድህ የተባለ ቃል ነው፣ከበረ የተባለ ደግሞ ሥጋ ነው!!ሁለቱን&nbsp;መናገሩ፣በአንድ አንቀጽ ሁለቱን መናገር ነው።\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቦ ዘይቤላ በእንተ ትስብእቱ ወመለኮቱ</strong></span>\"እንዲል </em></span><span style=\"font-size: 14pt;\"><em>አንድም ሰው ማለት ክብርና መክበር ተዋህደው ክርስቶስ ነውና \"የደስታ ዘይትን (ቅብዓ ትፍስሕት)የተባለውስ ማነው ካልከኝ ወልድ(ቃል) ነው ቀባህ ሲልም&nbsp;\"አከበረህ\"ማለቱ ነው።</em></span><span style=\"font-size: 14pt;\"><em>አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቀብዐከ እግዚአብሔር አምላክከ</strong></span>\"ብሎ ባህርያዊ ግብሩን በሚገልጥ መጥራቱ አብ አብ ቀባዒ እንደሆነ በምን ያስረዳል❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ነውስ\"<span style=\"color: rgb(132, 63, 161);\"><strong>አንሰ ሶበ እቤ እግዚአብሔር እብል በእንተ አብ ወወልድ ወመንፈስ ቅዱስ</strong></span>\"-እኔ እግዚአብሔር&nbsp;ብየ በተጣራሁ ጊዜ ስለ አብ ስለወልድ ስለመንፈስ ቅዱስ መናገሬ ነው የሚለው ተዘነጋ እንዴ❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ታዲያ እግዚአብሔር ማለት የሦስት የባህርይ ግብር ለመግለጥ የምንጠቀምበት ስም ከሆነ አብን ቀባዒ&nbsp;ለማድረግ ምክንያቱ ምንድን ነው❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>&nbsp;6.ወበከመ ለአብ ቦቱ ህይወት ኀቤሁ.ዮሐ 5&divide;26</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;ለምሳሌ ክርስቶስ ከተነሣ በኃላ ሥልጣን ተሰጠኝ. ማቴ 28&divide;18 ይላልና ያን ጊዜ ሥልጣን ተሰጠው ማለት ነውን❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>ስለዚህ ህይወቱን ሰጠው ማለት፡-</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ተሰጠኝ ሲል ተሰጦት አይደለም ገንዘብ ማድረጉን ሲሻ ነው እንጂ&nbsp;</em></span>\r\n<div><span style=\"font-size: 14pt;\"><em>➠የቃል ገንዘብ ለስጋ ሲሆን ህይወትነት ለሥጋ ገንዘቡ ሆነ ማለት ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ሕይወት ያለው መንፈስ ቅዱስን አይደለም ለሚወዳቸው ህይወትን ሰጣቸው ይላልና.ዮሐ 5&divide;21</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠አንድም ስለሥጋ እንግድነት የተነገረ ነው አለዚያማ ለወልድም ህይወቱ ይሆን ዘንድ ይላልና መንፈስ ቅዱስ ከወልድ የተለየበት ጊዜ አለ ያሰኛል።</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>ከሁሉ አስቀድሞ ግን የረሳሁት ነገር......</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ተቀብዓን ህይወት ተብሎ ከተተረጎመና ለስጋ ክብር የሆነው መንፈስ ቅዱስ ነው የምንለው የባህርይ ህይወቱ ስለሆነ ነው&nbsp;ከተባለ አብም የባህርይ ልቡ ነውና ምን እንበለው እሽ ወገኖቼ ❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250);\"><em><span style=\"font-size: 18pt; color: rgb(52, 73, 94); background-color: rgb(236, 202, 250);\"><strong>7.\"እነሆ ናዝራዊው ኢየሱስ ቅባትን ተቀብቶ የመቀባትን&nbsp;መንግስት ተቀበለ፣አምላክ ሲሆን ስለሰውነቱም የመለኮትን ቅባት&nbsp;ተቀብቶ ሰው ሆነ እግዚአብሔር ሰው ለመሆን ወረደ ሰውም&nbsp;እግዚአብሔር ለመሆን ከፍ ከፍ አለ\"<span style=\"font-size: 14pt;\">መ.ምሥጢር ገጽ 214</span></strong></span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ በመጀመሪያ ናዝራዊው ኢየሱስየሚለው ከሁለት አካል አንድ አካል ከሁለት ባህርይ አንድ ባህርይ ሲሆን&nbsp;የወጣለት የተዋህዶ ስም ነው!!ትርጓሜውም መሲህ፣የተቀባ፣የተሾመ ማለት ነው።የተቀባ የተሾመ ሲባል ግን ለእርሱ ቀቢ ሿሚ ኖሮት አይደለም።ቀቢውም ሿሚውም ተሿሚውም አንድ&nbsp;እርሱ ነው እንጂ!!ዮሐ 4&divide;25 -30 ማለትም<span style=\"color: rgb(132, 63, 161);\"><strong>\"ለሊየ እቄድስ ርእስየ\" </strong></span>እንዲል ይህ ሲባል ኢየሱስ ክርስቶስ ቅባትን ተቀብቶ ሲል አንቀጹ ለትስብእት ነው።ማለትም መለኮት&nbsp;ለተዋሐደው ስጋ ክብር ሁኗል;አንድም ቅድመ ተዋህዶ ትስብእት ትሑት፣ህፁፅ ስለሆነ ተለዓለ ተብሎ ተነገረለት።ማለትም ያ ህፀፅ ንዴት የነበረበት ትስብእት ከቃል ጋር ሲዋሐድ ቃል ለተዋሐደው ስጋ ክብር&nbsp;ሆነው\"<span style=\"color: rgb(132, 63, 161);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"እንዲል ቅዱስ ቄርሎስ &nbsp;የቃል ገንዘብ በተዋህዶ ለስጋ ገንዘቡ ሲሆን ከበረ አምላክ ሆነ፣የባህርይ ልጅ ሆነ ሲል የመቀባትን መንግስት ተቀበለ አለ።ማለትም ስጋ ከተዋህዶ በኋላ የመለኮት ገንዘብን ገንዘቡ አድርጓልና\"\"<span style=\"color: rgb(132, 63, 161);\"><strong>እንቲአሁ ለቃል ኮነ ለስጋ ወእንቲአሁ ለስጋ ኮነ ለቃል</strong></span>\"እንዲል ቅዱስ ቄርሎስ!አንድም ስጋ ልዕልናን ግብረ አምላካዊውን ባህርይው ረቂቅባህርየ መለኮትን ገንዘቡ አደረገ።ማለትም&nbsp;የሚሞት ሲሆን የማይሞት ሆነ፣\"ምድራዊ ሲሆን ከልዕልና በላይ ያለ ልዕልናን ገንዘቡ አደረገ በአጠቃላይ የማይመረመር ጌትነትን አገኘ።አንድም በዚያው አጋጣሚ ነስአ ተወክፈ አይሉም እንባለለን;ነገር ግን ስንተረጉምና ስንል&nbsp;እመንገለ ሥጋሁ እንጂ እመንገለ መለኮቱ አንልም።ምክንያቱም በመለኮቱ በኩል&nbsp;ብንል \"ኢይጽሕቅ ቅብዓተ በህላዌ በመለኮቱ\"ማለትም በመለኮቱ መቀባትን(ክብርን)አይሻል!!ከዚህ በተጨማሪ እግዚአብሔር ሰው ለመሆን ወረደ ሲል የሰውን ባህርይ ባህርይው ለማድረግ ማለትም&nbsp;የማይራበው እንዲራብ መሆኑ፣ባእለ ጸጋ የነበረው ባህርይውን ሳይለቅ በተዓቅቦ ነዳይ መሆኑ የንጉሶች ንጉሥ ሲሆን የጌቶች ጌታ ሲሆን በአይሁድ ፊት መገረፉ በአጠቃላይ ራሱን በሰው መልክና አርዓያ መምጣቱን&nbsp;ያመለክታል። ምክንያቱም\"ነገር ግን የባህርይን መልክን ይዞ በሠውም ምሳሌ ሆኖ ራሱን ባዶ አደረገ&nbsp;በምስሉም እንደሰው ተገኝቶ ራሱን አዋረደ\"እንዲል ፊል 2&divide;8</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ሕቀ አሕጸጽኮ እምመላእክቲከ</strong></span>\"-ከመላእክት እጅግ ጥቂት አሳነስኸው\"መዝ 8&divide;5 እንዲል&nbsp;አንድም \"ሰውም እግዚአብሔርን ለመሆን ከፍ ከፍ አለ ሲል በተዋህዶ የመለኮትን ገንዘብ ገንዘቡ </em></span><span style=\"font-size: 14pt;\"><em>ስለሚያደርግ የስጋ በአምላክነት መክበር መቀባት ተብሎ ተነግሯል።አምላክነቱ የባህርይው ስለሚሆን በጸጋ&nbsp;እንዳደረባቸው ቅዱሳን አይደለም ሲል ነው።አንድም ቅዱስ ዮሐንስ አፈወርቅ እንደገለጸው </em></span><span style=\"font-size: 14pt;\"><em>ትስብእት ከመለኮት ጋር በመዋሐዱ ያገኘውን የክብር መጠን ሲያብራራ እንዲህ በማለት በሰፊው&nbsp;አብራርቷል!!\"ወዴት ስፍራ እንዳወጣው ዕወቅ:ከፍጡራን ሁሉ ከመላእክትም ሁሉ በላይ አደረገው\"አለ።ረቂቅ </em></span><span style=\"font-size: 14pt;\"><em>እውቀትን እንዲገልጽልህ ከወደድክ በእግዚአብሔር ባህርይና በሰው ባህርይ መካከል ያለ ልዩነት ምን ያህል እንደሆነ አንተ እወቅ፣ማንም ሊናገረው ወደማይቺለው ክብረ መለኮት ትስብእትን ከፍ ከፍ </em></span><span style=\"font-size: 14pt;\"><em>አደረገው፣ከልዑላን መላእክት ሁሉ በላይ አደረገው\"ሃይ.አበው 67 ክፍል 16 &divide;23 ስለዚህ ተለዓለ መባሉ ስለዚህ ነው።</em></span></div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244); color: rgb(224, 62, 45);\"><em><strong>8. \"ዘቀብኦ እግዚአብሔር መንፈሰ ቅዱሰ ወኃይለ\"ሐዋ 10&divide;38</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡\"እግዚአብሔርም የናዝሪቱን ኢየሱስን በኃይል በመንፈስ ቅዱስ ቀባው\" ሲል </em></span><span style=\"font-size: 14pt;\"><em>በመንፈስ ቅዱስ ማለት በግብረ መንፈስ ቅዱስ(በረቂቅ ምሥጢር)ሥጋን አከበርኸው ማለት ነው!!</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>&nbsp;እንደዚህማ ባይሆን ኖሮ ሐዋርያው ቅዱስ ጴጥሮስ</em></span></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>\"እግዚአብሔር የናዝሬንቱን ኢየሱስን ከሙታን መካከል ለይቶ አስነሳው\"ሲል በመንፈስ ቅዱስ ወይም </em><em>በአብ ስልጣን ነው የተነሳ በራሱ ስልጣን የተነሳ አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>በራሱ ስልጣን ካልተነሳ \"እንዴት አልዓዛርን ከመቃብር አስነሳው\"ለራሱ የሌለው ለሰው </em><em>ያበድራልን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም በመንፈስቅዱስ በቀባኸው አለ እንጂ ቅብዕ በሆነው አይልም!!</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(224, 62, 45); font-size: 18pt; background-color: rgb(251, 238, 184);\"><strong><em>9.\"መንፈሰ እግዚአብሔር ላእሌየ ዘበእንቲአሁ ቀብዐኒ\"ኢሳ 61</em><em>&divide;1</em></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp; ↪ የእግዚአብሔር መንፈስ ሲል መንፈስ ቅዱስ ነው፣እኔ ያለው ደግሞ ባለቤቱ ወልድ ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>☝በእኔ ላይ ማለቱም መንፈስ ቅዱስ በእኔ በወልድ ህልው ነው ማለቱ ነው!!</em></span><span style=\"font-size: 14pt;\"><em>ቀባኝ ማለቱም አዋሐደኝ ሲል ነው!!</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>\"ስለዚህ የእግዚአብሔር መንፈስ በእኔ ህልው ነው፣ስለዚህ ነገር አዋሐደኝ ሲል በኢሳያስ የተነገረለትን የባህርይ ህይወቱን መንፈስ ቅዱስን እርሱ ገንዘብ እንዳደረገ ሊነገር ይገባል።ስለዚህ በባህርይ ገንዘቤ&nbsp;የሚሆን መንፈስ ቅዱስ በህልውናየ ጸና ብሎ ብሎ አስተማረ\"ሃይ.አበው ዘሳዊሮስ 87 ክፍል 17-18</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;&nbsp;***አዋሐደኝ ማለቱም የአምላክ ሰው መሆን በፈቃደ አብ፣በፈቃደ ወልድ፣በፈቃደ መምፈስ ቅዱስ የሆነ ማለት ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ በሌላ አነጋገር </em></span><span style=\"font-size: 14pt;\"><em>አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ከተባለ ታዲያ ከዚህ ጥቅስ ላይ </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>በእኔ ላይ ያለ የእግዚአብሔር መንፈስ ቀባኝ ሲል ቀባዒው ማነው❓</em></span></li>\r\n<li><em style=\"font-size: 14pt;\">በዚህ ጥቅስ ቀባዒው አብ መሆኑ አይደለምን❓</em></li>\r\n<li><em style=\"font-size: 14pt;\">ታዲያ መንፈስ ቅዱስ ቅብዕ የሚል ከየት ይመጣል❓</em></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h1><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><em><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የዘመኑ ቅባት ነን ባዮች የሚያነሷቸው ጥያቄዎችና መልሶቻቸው</strong></em></span></h1>\r\n<div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(45, 194, 107); background-color: rgb(241, 196, 15);\"><em>=&gt;.እኛ የተዋህዶ ልጆች ትሥብእት ወይም ሥጋ ከባሪ መለኮት(ቃል) ክብር ስንል አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርጋችሁ ስትናገሩ መለኮት የመለኮትን ሥራ ይሰራል ሥጋም የሥጋን ሥራ ይሰራል </em><em>ከሚሉት መለካዊያን በምን ትለያላችሁ?ይሉናል።</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.ቅባት ወገኖቻችን ሆይ እኛ አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርገን እናንተ እንደምትሉት ያለ&nbsp;ፍልስፍና ላይ አልተሰማራንም በሉልኝማ የተዋህዶ ልጆች። ከበረ፣ አከበረ የምንለው በጊዜ ተዋሕዶ ላይ </em></span><span style=\"font-size: 14pt;\"><em>ያለን ጊዜ ብቻ ናት። መክበር ይሻ የነበረን ሥጋ አካላዊ ቃል በአምላክነት ክብሩ አከበረው። ይች እመቤታችን&nbsp;\"<span style=\"color: rgb(132, 63, 161);\"><strong>ይኩነኒ በከመ ትቤለኒ</strong></span>\"ባለችው ጊዜ የተፈጸመች ድንቅ ምስጢር ናት። ከዚህ ጊዜ በኋላ መለኮትና ትስብእት&nbsp;አንድ ስለኾኑ ከባሪና አክባሪ የለም።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ ወልድ አምላክ ነውና በአምላክነት ክብሩ ያከብራል ስንል ወልድ ማክበር አይችልም ካላችሁን </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\"><em>\"በመንፈስ ቅዱስ ከበረ\"ስትሉ መንፈስ ቅዱስስ ማክበር የብቻው ግብሩ ነው ብላችሁ ነውን? </em></span></strong></span></li>\r\n<li><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\">አዎ ካላችሁ ለመንፈስ ቅዱስ ከመሥረጽ ውጭ ሌላ አካላዊ ግብር እንዳለው ከየት ተማራችሁት? </span></strong></span>ማስረጃችሁ ምንድን ነው ወገኖቼ?ብላችሁ ጠይቁልኝ!!</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.አንዱ አካል አክባሪ ያሉ ቃልን አንዱ አካል ከባሪ የሚሉን ደግሞ ትስብእትን ለማለት ፈልጋችሁ ነው። እናንተ \"<span style=\"text-decoration: underline;\"><strong>በመንፈስ ቅዱስ ከበረ\"</strong></span> የምትሉት ሥግው ቃልን ነው።ታዲያ ሥግዉ ቃልን ከሆነስ</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ሥግው ቃል አምላክ ነው ወይስ አይደለም?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>&nbsp;ሥግው ቃል እስከሚከብር ድረስ የአብ የመንፈስ ቅዱስ ቃላቸው ማን ነበር?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ትስብእት አምላክ የኾነው በቅብዐተ መንፈስ ቅዱስ ከኾነ ሥግው ቃል እስኪከብር ድረስ አብና መንፈስ ቅዱስ ዲዳ ነበሩ (ሎቱ ስብሐት)?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(22, 145, 121); background-color: rgb(194, 224, 244);\"><em><strong><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244);\">=&gt;&ldquo;እራሱ(አብ) አክብሮ አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ አለው&rdquo; ዮሐንስ አፈ ወርቅ ድር 8&divide;69 ብሎ አብ ወልድን እንዳከበረው እየተናገረ ለምን እራሱን በራሱ አከበረ ለማለት ደፈራችሁ? ምን ምስክርስ አላችሁ?ይሉናል።</span></strong></em></span></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✔. አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ የሚለው ቃል መነሻው ዳዊት ነው። ይህን የጻፈው ዳዊት 2&divide;7 ላይ ነው።ማክበር አምላካዊ ግብር እንደመኾኑ መጠን በአብ በወልድ በመንፈስ ቅዱስ ሊነገር ይችላል። ይህ </span><span style=\"font-size: 14pt;\">ችግር ነው ብለን አናውቅም። በመጀመሪያ</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ማክበር የማን ግብር ነው ብለው ያስባሉ?</em></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ግብርነቱስ የአካል ነው ወይስ የአምላክነት?የሚሉትን ጥያቄዎች ማጤን ያስፈልጋል።</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.እኛ ወልድ ዋህድ በተዋህዶ ከበረ ብለን የምናምን እርሱ ራሱን እንዳከበረ መጽሐፍትን አብነት አድርገን&nbsp;እንናገራለን።ይኸውም&laquo;ዳግመኛ ክርስቶስስ ክብር መሻት ኖሮበት አልከበረም እርሱ ራሱ አክባሪ ነው እንጂ ሰው ቢኾንም በባሕርይ&nbsp;ክብሩ ከበረ እርሱ ራሱ እግዚአብሔር አምላክ ነው ሥጋ ትሁት ሕጹጽ ነዳይ ስለኾነ ተለዐለ ተብሎ ተነገረለት ከኹሉ በላይ የኾነ ስምንም እርሱ ራሱ ሰጠው ተባለ ይህም የኾነ በባሕርይ ተዋሕዶ ነው አምላክ እንደኾነ&nbsp;እኛንም እርሱ ወደ አለበት ያቀርበን ዘንድ&raquo; ሊቁ ቅዱስ ቄርሎስ በሃይማኖተ አበው ስምዐት 124 &divide;34 ላይ ይላል።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ታላቁ ሊቅ ቅዱስ ዮሐንስ አፈወርቅም በሃይማኖተ አበው 66 &divide;18 -19&nbsp;ላይ አካላዊ ቃል የተዋሐደውን የእኛን ሥጋ እንዳከበረው በመደነቅ እንዲህ ይላል፡-</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;ክብሩ ተለይቶ የነበረ ሥጋን ክቡር አምላክ ሊያደርገው የጸጋ ገዥነትን አጥቶ የነበረ ሥጋንም የባሕርይ ገዥ&nbsp;ሊያደርገው ወደደ አዳም ከእኛ እንደ አንዱ ኾነ ያለውንም ሰው በመኾን ሊገልጠው ወደደ። ስለዚህ ሥጋዬን&nbsp;ተዋሐደ። ወንጌልን ሲያስተምር እሰማው ዘንድ ሥጋዬን በተዋሕዶ ገንዘብ አደረገ፤ መንፈስ ቅዱስን ሰጠኝ ሰጠሁ ተቀበልኩ ለእኔም ፍጹም ሕይወትን ገንዘብ አደረግሁ። እርሱ ያከብረው ዘንድ ሥጋዬን ተዋሐደው። የሚያድነኝ መንፈስ ቅዱስን ሰጠኝ&raquo;በዚህ አነጋገር መሠረት <strong><span style=\"text-decoration: underline;\">እርሱ የተባለው አካላዊ ቃል ነው</span></strong>። አንዳንድ የቅብዐት እምነት ተከታዮች ግን እርሱ የሚለውን ለመንፈስ ቅዱስ ቀጽለው በመንፈስ ቅዱስ ከበረ ለሚለው ኑፋቄያቸው ደጋፊ ጥቅስ አድርገው ይጠቅሱታል። እርሱ የሚለውን ለመንፈስ ቅዱስ ከቀጸሉት ሥጋዬን የተዋሐደው መንፈስ ቅዱስ ነው ያሰኛልና ፍጹም ክህደት ነው። መንፈስ ቅዱስ ሥጋዬን ተዋሕዶ ሰው ኾነ የሚያሰኝ ክፉ መንገድ ነው። በተዋሕዶ ከበረ&nbsp;ብለው ላለማመን ወደ ሌላ ስህተት ሲያመሩ ይታያሉ። ሊቁ እንደጻፈው ግን እርሱ የሚለው ለአካላዊ ቃል የተነገረ ነው። ስለዚህም እርሱ መንፈስ ቅዱስን ሰጠኝ ሲል አካላዊ ቃል ለተዋሐደው ሥጋ የባሕርይ ሕይወቱ&nbsp;መንፈስ ቅዱስን መስጠቱንና ሥጋ የመንፈስ ቅዱስን ሕይወትነት ገንዘቡ ማድረጉን መናገር ነው። ይህ የተደረገው ደግሞ <span style=\"text-decoration: underline;\"><strong>በተዋሕዶ</strong></span> ብቻ ነው።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች&nbsp;የሊቁን ትምህርት በማስተዋል ተመልከቱና ከሰፊው የምስጢር ባሕር ውስጥ ገብታችሁ የምሥጢሩን ጥልቀት የትምህርቱን ርቀት (ቀ ይጠብቃል) አድንቁ ከዚህ በላይ ምን ማስረጃ አለ??</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;<span style=\"color: rgb(186, 55, 42);\"><strong>ወከመዝ ነአምሮ ለሊሁ ተቀብዐ ከመ ሥርዓተ ትስብእት ወዳእሙ ውእቱ ዘይቀብዕ ርእሶ በ</strong></span><span style=\"color: rgb(186, 55, 42);\"><strong>መንፈሱ ባሕቲቱ</strong></span>\"በተዋሕዶ እንደከበረ እናውቃለን ግን በገዛ ሥልጣኑ ራሱን የሚያከብር እርሱ ነው&raquo; ሃይማኖተ አበው ስምዓት 124 &divide;14 ይላል።</span></em><em><span style=\"font-size: 14pt;\">ወንጌላዊው ዮሐንስም በወንጌሉ ዮሐ 17&divide;19 ላይ &laquo;<strong><span style=\"color: rgb(186, 55, 42);\">አነ እቄድስ ርእስየ </span></strong>-እኔ ራሴን አከብራለሁ&raquo; ብሎ ጌታ የተናገረውን ጽፎት እናገኛለን። እኔ ራሴን አከብራለሁ ሲል በተዋሕዶ ማለቱ ነው። እኔ ሲልም በቃል ርስት ኾኖ ነው በሥጋ ርስትማ ይህን አይናገርም። ሥጋማ እንኳንስ ሊያከብር የጸጋ ልጅነትን እንኳ ያጣ ነበርና። ቃል ሲዋሐደው ግን ክቡር አምላክ ኾነ ይባላል። እኔ ብሎ አምላክነቱን (አክባሪነቱን) ራሴን ብሎ ሰውነቱን (ከባሪነቱን) ይናገራል። እርሱ ራሱ አክባሪ ነው እርሱ ራሱም ከባሪ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>↪\"እምቅድመ ቅብዓትሰ ነበሩ መላእክትከመ ህፃናት በዝንጋዔ ወሶበ ተቀብዑ መልዓ ላዕሌሆ', 'ቅባት ወተዋህዶ', 'Advanced', 'uploads/course_media/images/1782774026_285b3e12.jpg', '300.00', 'ዲ/ን ሶፎንያስ ደመቀ', '', '', '<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"color: rgb(132, 63, 161); font-size: 36pt;\">ቅባት(ቅብዓት)</span></h1>\r\n<h2>&nbsp;<span style=\"font-size: 18pt;\"> <span style=\"font-size: 14pt;\"><em><strong>ቅባት(ቅብዓት) ትርጉሙ ምንድን ነው❓</strong></em></span></span></h2>\r\n<div><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(224, 62, 45);\">↪ቅባት በቅዱሳት መጽሐፍት ሲተረጎም የሚከተሉት ትርጉሞች አሉት።እነርሱም:-✔</span></strong></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">1ኛ.ቅባት ማለት በቁሙ ሲፈታ ቅባት ማለት ነው</span>።</strong>ቀባ፣ለከከ፣ለቀለቀ፣ቀባ የሚል ትርጉም ያመጣል።ለዚህም ማስረጃው-\"የመገናኛውንም ድንኳን የምስክሩንም ታቦት ገበታውንም ዕቃውንም ሁሉ መቅረዙንም ዕቃውንም መሰዊያውን ሁሉ ለሚቃጠለውም መሥዋዕት ለሚሆነው መሰዊያና ዕቃውንም ሁሉ የመታጠቢያውን ሰንና&nbsp;መቀመጫውን ትቀባበታለህ\"ዘጸ 30&divide;26</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">-\"ማርያምም እጅግ ዋጋው የከበረ የጥሩ ናርዶስ ሽቱ ንጥር ወስዳ የኢየሱስን እግር ቀባች\"ዮሐ 12 &divide;3 </span><span style=\"font-size: 14pt;\">=&gt;<span style=\"text-decoration: underline; color: rgb(185, 106, 217);\">ቅባት </span></span><span style=\"text-decoration: underline; color: rgb(185, 106, 217);\"><span style=\"font-size: 14pt;\">በቁሙ ሲፈታ</span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">2ኛ.ተቀብዐ:-ከበረ ተብሎ ይተረጎማል።</span></strong>ለዚህም ማስረጃ \"<strong>እለሰ የአምኑ ርቱዓ ይሜሀሩ ከመ ተቀብዓ ቃል በስጋሁ</strong>\"ትርጓሜውም ሲቀባም የሚለውም ሲከብርም ሲዋሐድም አንድ ጊዜ ነው ሲል ነው እንጂ በቁሙ ሲቀባ ስላለ ሲቀባ ተብሎ አይተረጎምም በቁም የሚተረጉሙ አሉና!!ወዳጄ \"መጽሐፍት ትርጓሜን እንጂ ዘይቤን አይጠነቅቁም \" እሽ!!ይህ ማለት ስጋ ከቃል ጋር ሲዋሐድ መጀመሪያ ተዋሕዶ በኋላ የከበረ አይደለም:ከብሮም ሳይዋሐድ አልቀረም;ሲከብርም ሲዋሐድም አንድ ጊዜ ነው እንጂ!! አንድም ከላይ ያለውን ያነሳነውን ቃል ሊቃውንተ ቤተ ክርስቲያን እንዲህ እያሉ አቅንተው ይተረጉሙታል።ኦሪት ወነቢያት ሰበኩ በክርስቶስ ሲል \"በክርስቶስ\" ያለው ክርስቶስሀ ማለት ነው። \"<strong>በ</strong>\" አገባብ በማድረግ \"<strong>ን</strong>\"የሚል ፍቺ ይሰጡና ኦሪትና ነቢያት በክርስቶስ ሰበኩ የሚለውን በቁሙ ኦሪትና ነቢያት ክርስቶስን ሰበኩ በማለት ይገልጹታል።ማለትም ክርስቶስን ይወርዳል ይወለዳል እያሉ ሰበኩ የወንጌልን አዝመራ ዘሩ ሐዋርያትም አጨዱት ነውና ቅሉ።ስለዚህ ይህንን ቃልም በሥጋሁ የሚለውን\"በ\"ን አገባብ አድርገው \"<strong>ሥጋን</strong>\" በማለት ይተረጉሙና ስጋን ተዋሐደ ብለው ያቀኑታል።</span></li>\r\n</ul>\r\n<p><span style=\"color: rgb(230, 126, 35);\"><strong><span style=\"font-size: 14pt;\">=&gt;.ያም ሆነ ይህ ግን ይህንን ነገር ስናነሳ እነዚህን ጥያቄዎች ማሰብ ያስፈልጋል።ማለትም በቁሙ መለኮት በስጋው ከበረ ከተባለ</span></strong></span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቅድመ ተዋህዶ ቃል ክብር አልባ ነበርን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ነውስ ቃል በጊዜ ተዋህዶ የባሕርይ ክብሩን አጥቷል?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ወልድን ከመለኮታዊ ክብሩ ዝቅ አያደርገውምን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቃል(መለኮት) በስጋው ከበረ ከተባለ ስጋን የተዋሐደ ከሦስቱ አካል አንዱ አካል ወልድ(አካላዊ ቃል) ነውና ሥላሴ በማክበር ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">መለኮት በስጋው ከከበረ በመለኮትነት ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.መክበር የተፈጸመውስ መቼ ነው???በጊዜ ተዋህዶ \"ርስት\" ሰጥቶ መናገርን የትኞቱ አበውና መጽሐፍት አስተማሩን?</span></em></span></strong></li>\r\n</ul>\r\n</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">3ኛ.ተቀብዐ:-ተዋሐደ ተብሎ ይተረጎማል።</span></strong>ብዙ ወገኖቻችን ግን ቀብዓን ተዋሐደ ብለው አይተረጉሙትም።ለዚህም ማስረጃ ታላቁ ሊቁ አባ ጊዮርጊስ ዘጋስጫ በመጽሐፈ አርጋኖን ዘአርብ ዕለት\"ዘተቀባዕከ ስጋሃ ለማርያም\"ብለዋል!!ይህ ንባብ የሚተረጎመው የማርያምን ስጋ የተዋሐድክ ተብሎ ነው!!ምክንያቱም በከበረ እንዳይተረጎም የማርያምን ስጋ የተከበርክ አይባልም::በቀብዓ እንዳይተረጎም የማርያምን ስጋ የተቀባህ አይባልም ስጋ ቅብዕ ይሆናልና።ስለዚህ የተዋሐድክ ብሎ አቅንቶ መተርጎም ያስፈልጋል ወዳጄ!!!</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">➠ስለዚህ ሳጠቃልለው አንድ ቃል እንደአውዱ እንደአገባቡ የተለያየ ትርጉም ይኖረዋልና አንዲትን </span><span style=\"font-size: 14pt;\">በዘፈቀደ አንጠልጥሎ ሁሌም በዚህ ነው የሚፈታ ማለት የዕውር ክርክር ነው።ለምሳሌ \"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልክት ማኅበር ቆመ\"መዝ 81&divide;1 ይላልና ቆመ ስላለ ብቻ ቆመ ብለን ልንተረጉመው ነው??በጭራሽ</span></div>\r\n<div><span style=\"font-size: 14pt;\">ቆመ ብለን አንተረጉመውም!!ታዲያ ምን ብለን እንተረጉመዋለን ትሉኝ እንደሆነ\"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልዕክት መካከል ተገለጠ\"ብለን ነዋ!!እንደዚህም ሁሉ ተቀብዐን እንደአውዱ እንደ አገባቡ ይፈታል!!</span></div>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"color: rgb(224, 62, 45); font-size: 18pt;\"><strong>➠የቅባት ትርጉም እንደ ቅባት አስተምሮ ግን......</strong></span></h2>\r\n<div>\r\n<ul>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt; color: rgb(22, 145, 121);\">✔. ቅባት መንፈስ ቅዱስ ተብሎ ይተረጎማል!!</span></strong></li>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span><span style=\"font-size: 14pt;\">✔.ቅባት ሕይወት ተብሎ እንደሚተረጎም ወልደ አብ መጽሐፍ ገጽ 179 ;</span><span style=\"font-size: 14pt;\">አዕማደ ምስጢር ገጽ 22 </span><span style=\"font-size: 14pt;\">ይናገራል!!</span></span></strong></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">&nbsp;ከዚህ ውጭ ግን <strong><span style=\"text-decoration: underline;\">ተቀብዐን ተዋሐደ</span></strong> ብለው ተርጉመው ፈጽሞ አይናገሩም;ተዋሐደ ብለው </span><span style=\"font-size: 14pt;\">መተርጎም ስህተት ነው ይላሉ \"ተዋሐደ\"ካሉ መንፈስ ቅዱስ ቅብዕ መሆንን ያፈርስባቸዋልና!!</span><span style=\"font-size: 14pt;\">ምናልባት በነገረ ሥጋዌ ጉዳይ እመቤታችንን ተቀባትም ተዋሐዳትም ማለት ክህደት ነው </span><span style=\"font-size: 14pt;\">ሲባል ብዙ ሰዎች ግራ ይጋባሉ;ነገር ግን ጊዜ ተዋህዶ ላይ የተፈጸሙ ተግባራትን ካለማወቅ </span><span style=\"font-size: 14pt;\">የተነሳ ነው ወገኖቼ!!!በምሥጢረ ሥጋዌ ትምህርታችን ስንነጋገር እነዚህን ነገሮች </span><span style=\"font-size: 14pt;\">ካስታወሳችሁ የጥያቄያችሁ መልስ ታገኛላችሁ!!!ይኸውም ቃል በጊዜ ተዋህዶ የማይቀዳደሙ </span><span style=\"font-size: 14pt;\">፫ት ነገሮች ተከናውነዋል። እነርሱም:-</span></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መክፈል፤</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መዋሐድ እና</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">&nbsp;መክበር ናቸው።</span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">✟✔.ከፍሎ ሳይዋሐድ ቢቀር በሰው ወይም በእመቤታችን አደረ ያሰኛል።ይኼውም ኀደረ </span><span style=\"font-size: 14pt;\">በብእሲ ብሎ እንደካደው ጳውሎስ ሳምሳጢ ክህደት መግባት ነው።ተዋህዶ ሳይከፈል ቢቀር </span><span style=\"font-size: 14pt;\">እመቤታችን አምላክ ሆነቺ ያሰኛል።ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል።አካለ ቃል ክብር </span><span style=\"font-size: 14pt;\">አልባ ያሰኛል የሚሉት ናቸው።ስለዚህ ሲከፈልም፤ሲዋሐድም፤ሲከብርም(ሲቀባ) </span><span style=\"font-size: 14pt;\">አንድ ጊዜ ነው።</span></div>\r\n<div>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"font-size: 24pt; color: rgb(132, 63, 161);\">ምሥጢረ ሥጋዌ በቅባት አስተምህሮ (በወልደ አብ) ዕይታ</span></h1>\r\n<p><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 14pt;\">የኢትዮጵያ ኦርቶዶክስ ቤተ ክርስቲያን የምታስተምረው ትምህርት ከቅባት እምነት በጣም ሰፊ ልዩነት ሲኖራት የቅባት እምነት ተከታዮች ከዚህ በተለየ መልኩ ብዙ ክህደትን ሲያስተምሩ ይስተዋላሉ።ከነዚህም መካከል በጣም የጎሉትን የክህደት መንገዶ ከዚህ በታች ለማየት እንሞክራለን።&nbsp;</span></strong></span></p>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\">✔፩ኛ.እግዚአብሔር ወልድ ሁለት ልደታት አሉት እያሉ በቃል ደረጃ&nbsp;ይናገራሉ ።ነገር ግን በተግባር ደረጃ እንደጸጋ አስተምህሮ ፫ት ልደትን&nbsp;አማኝ ናቸው!!ለዚህ ማስረጃየ ወልደ አብ መጽሐፋቸው&nbsp;የመጀመሪያው ዕትም ገጽ 217 እና 218 እንዲህ ይላል!!</span></strong></div>\r\n<div style=\"padding-left: 80px;\"><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(132, 63, 161);\">\"<strong>የጌታችን ልደት ስንት ነው ቢሉ ፪ት ነው።እንዴት ፪ት ነው ቢሉ&nbsp;እምቅድመ ዓለም በመለኮቱ ተወለደ ብለናል ኋላም በማኅጸን በሰውነቱ&nbsp;ከአብ ተወለደ እንላለን ዳግም ከእመቤታችን በስጋ በጎል ተወለደ&nbsp;እንላለን</strong> \"</span></em>ወልደ አብ ገጽ ገጽ 217 ይላል!!</span></div>\r\n<div><span style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(186, 55, 42);\"><strong>↪አስተዉሉ፦</strong></span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ታዲያ ጌታችን ቅድመ ዓለም ከአብ በመለኮቱ፣ድኅረ ዓለም ከእመቤታችን በትስብእቱ፣ድኅረ ዓለም በማኅጸን በሰውነቱ ከአብ ተወለደ ከተባለ ሁለት ልደታት ማመን ከየት ይመጣል ይህ ፫ት ልደት&nbsp;አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ይህ ከሆነስ ወልደ አብ በመለኮቱ:ወልደ ማርያም በትስብእት፣አሁንም በድጋሜ በማህጸን ከወለደው እንደገና ወልደ አብ በትስብእቱ ሊባል ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ለማንኛውም \"በቃል ሁለት ልደት፣በተዘዋዋሪ በተግባር ግን ሦስት ልደት ይላሉ!!አይ ወገኔ\"አልሸሹምዞር አሉ\"ማለት ይሄ ነው እኮ ወገኔ ገባህ?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\"><strong><span style=\"font-size: 14pt; background-color: rgb(248, 202, 198);\">፪ኛ.\"ሰባቱን ሀብታተ መንፈስ ቅዱስ እርሱ በስጋ ርስት በጊዜ ፅንስ ያለምክንያት ከአብ ተቀብሎ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉሥ ሆነባቸው\"ወልደ አብ ገጽ 211 ይላል</span></strong></span></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች የነገረ ቅባትን አስተምህሮ እና ጥያቄ የሚመለሰው ብዙ ጥቅስ መዘርዘር ሳያስፈልገው ጥያቄን በጥያቄ መመለስ እና በደንድ አገናዝቦ ማስተዋል ነው።ስለዚህ ከላይ እንዳያችሁት እንዲህ ካሉ&nbsp;እስኪ በሞቴ ንገሩኝ.........</span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉስ ሆነባቸው ማለት ቀድሞውንስ የባህርይ አምላክ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ ሰው የሆነስ በአባቱ ፈቃድ በእርሱ ፈቃድ በመንፈስ ቅዱስ ፈቃድ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">ታዲያ እነማንን ነው የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸው❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በግድ ነው በኃይል የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸውስ❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በመጀመሪያ \"ሆነባቸው\"ማለት በግድ አምላክ ሆኖባቸዋልን❓የእነርሱ ፈቃድስ❓</span></strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><em><strong><span style=\"color: rgb(52, 73, 94); background-color: rgb(236, 202, 250); font-size: 18pt;\">✔፫ኛ.\"መንፈስ ቅዱስ ሠጪም ተሠጭም ነው\"ወልደ አብ ገጽ 181&nbsp;ይላል።</span><span style=\"color: rgb(52, 73, 94); font-size: 18pt;\">ይህ ከሆነ.......</span></strong></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ምንድን ነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ለማነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለው ምንን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለውስ ከማን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሌለው አለን ከሌላ የሚቀበል❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>በዓለመ ሥላሴ ነው መንፈስ ቅዱስን ሰጪም ተሰጪም ነው የምንል እንዳትሉኝ በዓለመ ሥላሴ በባህርይ በክብር በስልጣን አንድ ናቸው አንዱ ከአንዱ አያንስም አንዱ ከአንዱ አይበልጥ;ታዲያ አንዱ ከአንዱ ከአልበለጠ አንዱ ከአንዱ ካላነሰ ሰጪና ተሰጪ የሚል ከየት ይመጣል ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪና ተሰጪ ያልን ለፍጡራን ነው እንዳትሉኝ መንፈስ ቅዱስን ፍጡር እያላችሁት መሆኑ አይደለምን❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪም ተሰጪም ነውያልነው በፈጣሪና በፍጡር መካከል ነው እንዳትሉኝ መንፈስ ቅዱስ ፈጣሪ ነው ከፍጡር ይቀበላላልን❓ተሰጪ የሚለው አያፈርስባችሁምን❓ተብለዉ ሲጠየቁ መልስ የላቸዉም አፋቸዉን ይያዛሉ።</em></strong></span></li>\r\n</ul>\r\n<div><span style=\"background-color: rgb(194, 224, 244); color: rgb(52, 73, 94); font-size: 18pt;\"><em><strong>፬ኛ.አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ነው ይላሉ!!</strong></em></span></div>\r\n<div>-<em><span style=\"font-size: 14pt;\">ይህ ማለት፦</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ-አክባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ ከባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል።በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።</span></em></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><strong>↪ታዲያ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን</strong></span></p>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>&nbsp;አብ አክባሪ፣ወልድ ከባሪ መንፈስ ቅዱስ ክብር የሚል ከየት ይመጣል❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>ምሥጢረ ሥላሴ ላይ የተነገረውን ለምስጢረ ሥጋዌ መቀፀልስ ለምን አስፈለገ❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong>↪\"ሥላሴ በተለየ ግብር ሦስት ናቸው።ይኸውም መውለድ፣ማስረፅ፣መወለድ፣መስረፅ ነው\"ይላል ገጽ 53;እንደገና 133 ላይ ደግሞ\"ቅብዕ የሆነ ግን በተለየ አካሉ በተለየ ግብሩ መንፈስ&nbsp;ቅዱስ ነው\"ይላል</strong></span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለመንፈስ ቅዱስ የተለየ ግብር የተሰጠው መቼ ነው ቅብዕነት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>የመንፈስ ቅዱስ ግብር መስረፅ ከሆነ ቅብዕነት ደግሞ ለመንፈስ ቅዱስ መቼ ተጨመረለት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለወልድና ለአብስ ምን የተለየ ግብር ምን ተጨመረላቸው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp;ከዚያ ባለፈ አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ማለት </span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ➠ሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ➠ተሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ➠ስጦታ ማለት ነው።</span></em></li>\r\n</ul>\r\n<p><em><strong>↪<span style=\"font-size: 12pt;\"> ይህ ከሆነ&nbsp; &nbsp;</span></strong></em></p>\r\n</div>\r\n<div>\r\n<div>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ አለን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ ካለ ሰጪ ከተሰጪ ይበልጣል;ተሰጪ ከሰጪ ያንሳል!!ታዲያ አብ ከወልድ ከመንፈስ ቅዱስ ይበልጣልን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>ወልድስ ከአብ ከመንፈስ ቅዱስ ያንሳልን❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; color: rgb(132, 63, 161); background-color: rgb(206, 212, 217);\"><em><strong>✔፭ኛ.\"ስጋ ሲፈጠር መለኮትም ከስጋ ጋር አብሮ ተፈጠረ ካላሉ&nbsp;ይላል\"ወልደ አብ ገጽ 127</strong></em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>መለኮት(ቃል) ራሱ ፈጣሪ ነው;ራሱ ፈጣሪ ከሆነ ከስጋ ጋር አብሮ ማን ፈጠረው ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ጸሎተ ሐይማኖት ላይ\"ዘተወልደ ወአኮ ዘተገብረ\"የተወለደ እንጂ ያልተፈጠረ የምትለዋን ፋቃችኋት እንዴ ታዲያ ወገኖቼ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ፍጡር ከሆነ ታዲያ እመቤታችን ወላዲተ አምላክ ሳይሆን ወላዲተ ሰብእ ናት ልትሉ ነው እንደ ፎጢኖስ❓</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><strong><em><span style=\"color: rgb(132, 63, 161); background-color: rgb(241, 196, 15); font-size: 18pt;\">✔፮ኛ.\"እኛ የምንቀበለው የጸጋ ጌታ የሚቀበለው የባህርይ ነው ማለት&nbsp;እንዴት ነው ቢሉ እኛ በተወለድን በ፵ ቀን እናገኘዋለን በክህደት&nbsp;በኃጢአት ይነሳል ስለዚህ ስለዚህ የጸጋ ይባላል።ጌታ ግን ሲዋሐድ የባህርይ ህይወት መንፈስ ቅዱስን ከአካሉ ጋር አግኝቶታልና የባህርይ&nbsp;ይባላል\"ወልደ አብ ገጽ 188</span></em></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ጌታ የባህርይ ህይወቱን መንፈስን ከአካሉ ጋር አግኝቶታል ይላል;የመንፈስ ቅዱስን አካሉን ነው ወይስ ሀብቱን የተቀበለው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>አካሉን ከተባለ መንፈስ ቅዱስ ከስጋ ጋር ተዋህዷልን ❓</em></strong></span></li>\r\n<li style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ሀብቱን ካላችሁስ ክርስቶስ ዕሩቅ ብእሲ መሆኑ አይደለምን ❓</em></strong><em><span style=\"color: rgb(0, 0, 0);\">ብላችሁ ስትጠይቋቸው ምላሽ ያጣሉ።</span></em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp;</strong></span></p>\r\n<div><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;በነገረ ቅባት በመንፈስ ቅዱስ ከበረ ለማለት የሚነሱ ጥቅሶች</strong></span></div>\r\n<div>&nbsp;</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.የዘመኑ ቅባት ነን ባዮች በመንፈስ ቅዱስ ከበረ ለማለት በጣም በርካታ የመጽሐፍ ቅዱስ ጥቅሶችን ቢያነሱም ከብዙዉ በጥቂቱ ተደጋጋሚ ሁሌም የሚያነሷቸው የአፍ መፍቻ ጥያቄዎች የሚከተሉት ሲሆኑ ቤተክርስቲያናችን አረዳዷ ሚን ዪመስላል የሚለዉን ትርጓሜዉን እናያለን።</span></em></div>\r\n<div><strong><span style=\"background-color: rgb(194, 224, 244);\"><em><span style=\"font-size: 14pt; background-color: rgb(194, 224, 244);\"><span style=\"font-size: 18pt;\"><span style=\"color: rgb(45, 194, 107);\">1ኛ. </span>\"<span style=\"color: rgb(45, 194, 107);\">ዘአንገሦ ለሥጋ አዳም በመንፈስቅዱስ ወረሰዮ ቅዱሰ&nbsp;ወማሕየዌ ዘለብሶ ለአዳም መዋቲ</span></span>\"በመንፈስቅዱስ ህይወትነት&nbsp;የአዳምን ባህርይ ያከበረው የባህርይ አምላክ ያደረገው እርሱ ነው\"ሃይ.አበ.ዘእልመስጦአግያ ፪:፭</span></em></span></strong></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡በመጀመሪያ ያከበረው አለ እንጂ ክብር የሆነው አይልም አስተውሉ ወዳጄ!!</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>መንፈስ ቅዱስ ቅብዕ(ክብር) ከሆነው ለምን ያከበረው አለ ለምን ክብር የሆነው አላለም❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>፫ቱ በአክባሪነት አንድ አይደሉምን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም ይህ የተነገረው የመንፈስቅዱስን ህይወትነት ሥጋ ገንዘብ ማድረጉን ሲናገር ነው!!አንድም \"የአዳምን ሥጋ በመንፈስ ቅዱስ አዋሐጅነት የተዋሐደው እርሱ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም በመንፈስቅዱስ ህይወትነት ማለት በረቂቅ የሥላሴ ግብር ማለት እንጂ መንፈስ ቅዱስ ክብር ሆነው ለማለት አይደለም ወዳጄ!!የአዳምን ሥጋ በግብረ መንፈስ ቅዱስ ተዋሕዶ የባሕርይ ንጉሥ ያደረገው&nbsp;</span></em><em><span style=\"font-size: 14pt;\">እርሱ ነው!!\"<strong>ወረሰዮ ቅዱሰ ወማሕየዌ ክቡር ወሀቤ ሕይወት</strong> አምላክ ያደረገው እርሱ ነው ካለ በኋላ ዘለብሶ ለአዳም መዋቲ\"አለ;ለምን ከተባለ ስጋን የተዋሐደ በተለየ አካሉ ወልድ ነውና።ግብረ መንፈስ ቅዱስ </span></em><em><span style=\"font-size: 14pt;\">ማለት ረቂቁን ለመንፈስ ቅዱስ መስጠት ነው እንጂ በማዋሐድ፣ በመፍጠር፣ በመግዛት፣ በመንግሥት፣በክብር ሦስቱ አካላት አንድ ናቸውና በአንዲት ግብረ ባሕርይ መሆኑን እናስተውል።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(194, 224, 244);\">2ኛ. \"ለሊሁ ዘይሁብ ወለሊሁ ዘይትወሀብ\"-ጸጋውን የሚሰጥ እርሱ ነው ጸጋም ሆኖ የሚሰጥ እርሱ ነው\"</span></strong></span><span style=\"text-decoration: underline;\">አረ.መን.ድር.11</span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ይህ ቃሉ የተነገረው ለመንፈስ ቅዱስ ሳይሆን ለወልድ ነው ምክንያቱም እርሱ ለኩነተ ሥጋ ተሰጦአልና ነው ወዳጄ!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም በሰባኪ አድሮ ጸጋን ይሰጣል.በሰሚ አድሮ ይቀበላልና!!</em></span></div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em>3ኛ. \"አማን አንገለጉ በዛቲ ሀገር ላዕለ ቅዱስ ወልድከ ኢየሱስ&nbsp;ዘቀባእካሁ.ሐዋ.4&divide;27</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ከዚህ ላይ የምናስተዉለው ነገር አለ።ይኽውም፦</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>መንፈስ ቅዱስ ቅብዕ ከሆነው በቀባኸው አለ እንጂ ቅብዕ በሆንኸው ለምን አላለም❓</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>-ቅብ የሆነው መንፈስ ቅዱስ ነው ከተባለ ይህ ቃል ደግሞ የአብን ቀባዒነት የክርስቶስን&nbsp;ተቀባዒነት ይናገራል እንጂ የመንፈስቅዱስን ቅብዕነት አይናገርም እኮ!!</em></span></div>\r\n<div><span style=\"font-size: 18pt; color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em><strong>4.&nbsp;እንደእሱ አካል ባለ አካል አክብሮታልና.ዮሐ.አፈ.ወ.ድር 3&divide;100</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>➡አስተውሉ</strong>:-ሥጋን በቃል አንቀጽ ሲጠራው እንደሱ አካል አለ፤ባለአካል ብሎ ቃልን ጠራው&nbsp;አክብሮታል አለ እንጂ ክብር ሆኖታል አላለም</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም አካለቃል ከአካለሥጋ፣ባህርየ ቃል ከባህርየ ሥጋ ጋር መዋሀዳቸውን እየተናገረ ነው!!</em></span></div>\r\n<div><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>5 .\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከ እግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ\"<span style=\"font-size: 14pt;\">መዝ 44 &divide;7</span></em></span></strong></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>✔ \"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን&nbsp;ቀባህ\"</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;በመጀመሪያ እነዚህን ጥያቄዎች እንመልስ &nbsp;</em></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ቃሉ በባለቤትነት የተነገረው ለማን ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>እግዚአብሔር ሲል ከ3ቱ አካል ለአንዱ የመንፈስ ቅዱስ ስም ብቻ ነው የሦስት ስም አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ከባልንጀሮችህ ይልቅ ሲልስ ባልንጀሮቹ እነማን ናቸው ይልቅ የሚለውስ ለምን መቀጸል አስፈለገ❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>የደስታን ዘይት ቀባህ ማለት ትርጉሙ ምንድን ነው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>* በመጀመሪያ\"ጽ<strong>ድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ&nbsp;የደስታ ዘይትን ቀባህ</strong>\"በሚለውኃይለ ቃል ውስጥ \"<span style=\"text-decoration: underline;\"><strong>አንተ</strong>\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ </span></em></span><span style=\"font-size: 14pt;\"><em><span style=\"text-decoration: underline;\">እናስተውል:;ይኸውም&nbsp;\"<strong>ትስብእት\"</strong>ነው።\"ባልንጀሮችህ\"የተባሉት ደግሞ ቀደምት ነቢያት፣ካህናት ነገስታት ናቸው።</span></em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 14pt;\"><em>❓=ታዲያ \"ከባልንጀሮችህ ይልቅ\"ለምን አለ ትሉኝ እንደሆን እነርሱ ሲሾሙ የነበረው በቅብዓ ዘይት ነበርና እነ ዳዊት መመልከት ይቻላል!!ለእነርሱ ሹመት ከእግዚአብሔር የሚያገኙት የሚቀበሉት ጸጋ </em></span><span style=\"font-size: 14pt;\"><em>ጊዜያዊ የሚያልፍ ነው።የክርስቶስ ሰው መሆን የትስብእት መክበር ግን ከማንም የማይቀበለው የባህርይው በተጭና በተሰጭ መካከል የሚደረግ አይደለም ሲል ነው፣ታዲያ የስጋ መክበር እንዴት ነው ትለኝ&nbsp;</em></span><span style=\"font-size: 14pt;\"><em>እንደሆነ\"<span style=\"color: rgb(224, 62, 45);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"መለኮት ለስጋ ክብር ሆነው እርሱ ራሱ በባህርይ ክብሩ ከበረ፣ስጋ&nbsp;እርሱ ራሱ ክብሩ አምላክነቱ የባህርይ ከሆነ መለኮት ጋር ስለተዋሐደ\"እልሃለሁ ወዳጄ!!</em></span><span style=\"font-size: 14pt;\"><em>አንድም እግዚአብሔር አምላክ ብሎ ለምን አራቀቀው ትለኝ እንደሆነ\"<strong>የተዋሐደው የፈጠረውን ስጋ</strong>\"ነውና&nbsp;ማለትም\"እርሱ ራሱ የፈጠረውን ስጋ ተዋሐደ እንዲል ሊቁ!!!</em></span>\r\n<div>&nbsp;<span style=\"font-size: 14pt;\"><em>አንድም ይልቅ ማለቱ\"አምላክነት የባህርይው ስለሚሆን በጸጋ እንዳደረባቸው እንደቅዱሳኑ ሳይሆን አንተ ገንዘብህ የሚሆነውን መለኮትን ስለተዋሐድክ ነው ሲል ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን&nbsp;መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው </em></span><span style=\"font-size: 14pt;\"><em>ትለኝ እንደሆነም ሰው መሆንን ወደድህ የተባለ ቃል ነው፣ከበረ የተባለ ደግሞ ሥጋ ነው!!ሁለቱን&nbsp;መናገሩ፣በአንድ አንቀጽ ሁለቱን መናገር ነው።\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቦ ዘይቤላ በእንተ ትስብእቱ ወመለኮቱ</strong></span>\"እንዲል </em></span><span style=\"font-size: 14pt;\"><em>አንድም ሰው ማለት ክብርና መክበር ተዋህደው ክርስቶስ ነውና \"የደስታ ዘይትን (ቅብዓ ትፍስሕት)የተባለውስ ማነው ካልከኝ ወልድ(ቃል) ነው ቀባህ ሲልም&nbsp;\"አከበረህ\"ማለቱ ነው።</em></span><span style=\"font-size: 14pt;\"><em>አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቀብዐከ እግዚአብሔር አምላክከ</strong></span>\"ብሎ ባህርያዊ ግብሩን በሚገልጥ መጥራቱ አብ አብ ቀባዒ እንደሆነ በምን ያስረዳል❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ነውስ\"<span style=\"color: rgb(132, 63, 161);\"><strong>አንሰ ሶበ እቤ እግዚአብሔር እብል በእንተ አብ ወወልድ ወመንፈስ ቅዱስ</strong></span>\"-እኔ እግዚአብሔር&nbsp;ብየ በተጣራሁ ጊዜ ስለ አብ ስለወልድ ስለመንፈስ ቅዱስ መናገሬ ነው የሚለው ተዘነጋ እንዴ❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ታዲያ እግዚአብሔር ማለት የሦስት የባህርይ ግብር ለመግለጥ የምንጠቀምበት ስም ከሆነ አብን ቀባዒ&nbsp;ለማድረግ ምክንያቱ ምንድን ነው❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>&nbsp;6.ወበከመ ለአብ ቦቱ ህይወት ኀቤሁ.ዮሐ 5&divide;26</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;ለምሳሌ ክርስቶስ ከተነሣ በኃላ ሥልጣን ተሰጠኝ. ማቴ 28&divide;18 ይላልና ያን ጊዜ ሥልጣን ተሰጠው ማለት ነውን❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>ስለዚህ ህይወቱን ሰጠው ማለት፡-</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ተሰጠኝ ሲል ተሰጦት አይደለም ገንዘብ ማድረጉን ሲሻ ነው እንጂ&nbsp;</em></span>\r\n<div><span style=\"font-size: 14pt;\"><em>➠የቃል ገንዘብ ለስጋ ሲሆን ህይወትነት ለሥጋ ገንዘቡ ሆነ ማለት ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ሕይወት ያለው መንፈስ ቅዱስን አይደለም ለሚወዳቸው ህይወትን ሰጣቸው ይላልና.ዮሐ 5&divide;21</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠አንድም ስለሥጋ እንግድነት የተነገረ ነው አለዚያማ ለወልድም ህይወቱ ይሆን ዘንድ ይላልና መንፈስ ቅዱስ ከወልድ የተለየበት ጊዜ አለ ያሰኛል።</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>ከሁሉ አስቀድሞ ግን የረሳሁት ነገር......</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ተቀብዓን ህይወት ተብሎ ከተተረጎመና ለስጋ ክብር የሆነው መንፈስ ቅዱስ ነው የምንለው የባህርይ ህይወቱ ስለሆነ ነው&nbsp;ከተባለ አብም የባህርይ ልቡ ነውና ምን እንበለው እሽ ወገኖቼ ❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250);\"><em><span style=\"font-size: 18pt; color: rgb(52, 73, 94); background-color: rgb(236, 202, 250);\"><strong>7.\"እነሆ ናዝራዊው ኢየሱስ ቅባትን ተቀብቶ የመቀባትን&nbsp;መንግስት ተቀበለ፣አምላክ ሲሆን ስለሰውነቱም የመለኮትን ቅባት&nbsp;ተቀብቶ ሰው ሆነ እግዚአብሔር ሰው ለመሆን ወረደ ሰውም&nbsp;እግዚአብሔር ለመሆን ከፍ ከፍ አለ\"<span style=\"font-size: 14pt;\">መ.ምሥጢር ገጽ 214</span></strong></span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ በመጀመሪያ ናዝራዊው ኢየሱስየሚለው ከሁለት አካል አንድ አካል ከሁለት ባህርይ አንድ ባህርይ ሲሆን&nbsp;የወጣለት የተዋህዶ ስም ነው!!ትርጓሜውም መሲህ፣የተቀባ፣የተሾመ ማለት ነው።የተቀባ የተሾመ ሲባል ግን ለእርሱ ቀቢ ሿሚ ኖሮት አይደለም።ቀቢውም ሿሚውም ተሿሚውም አንድ&nbsp;እርሱ ነው እንጂ!!ዮሐ 4&divide;25 -30 ማለትም<span style=\"color: rgb(132, 63, 161);\"><strong>\"ለሊየ እቄድስ ርእስየ\" </strong></span>እንዲል ይህ ሲባል ኢየሱስ ክርስቶስ ቅባትን ተቀብቶ ሲል አንቀጹ ለትስብእት ነው።ማለትም መለኮት&nbsp;ለተዋሐደው ስጋ ክብር ሁኗል;አንድም ቅድመ ተዋህዶ ትስብእት ትሑት፣ህፁፅ ስለሆነ ተለዓለ ተብሎ ተነገረለት።ማለትም ያ ህፀፅ ንዴት የነበረበት ትስብእት ከቃል ጋር ሲዋሐድ ቃል ለተዋሐደው ስጋ ክብር&nbsp;ሆነው\"<span style=\"color: rgb(132, 63, 161);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"እንዲል ቅዱስ ቄርሎስ &nbsp;የቃል ገንዘብ በተዋህዶ ለስጋ ገንዘቡ ሲሆን ከበረ አምላክ ሆነ፣የባህርይ ልጅ ሆነ ሲል የመቀባትን መንግስት ተቀበለ አለ።ማለትም ስጋ ከተዋህዶ በኋላ የመለኮት ገንዘብን ገንዘቡ አድርጓልና\"\"<span style=\"color: rgb(132, 63, 161);\"><strong>እንቲአሁ ለቃል ኮነ ለስጋ ወእንቲአሁ ለስጋ ኮነ ለቃል</strong></span>\"እንዲል ቅዱስ ቄርሎስ!አንድም ስጋ ልዕልናን ግብረ አምላካዊውን ባህርይው ረቂቅባህርየ መለኮትን ገንዘቡ አደረገ።ማለትም&nbsp;የሚሞት ሲሆን የማይሞት ሆነ፣\"ምድራዊ ሲሆን ከልዕልና በላይ ያለ ልዕልናን ገንዘቡ አደረገ በአጠቃላይ የማይመረመር ጌትነትን አገኘ።አንድም በዚያው አጋጣሚ ነስአ ተወክፈ አይሉም እንባለለን;ነገር ግን ስንተረጉምና ስንል&nbsp;እመንገለ ሥጋሁ እንጂ እመንገለ መለኮቱ አንልም።ምክንያቱም በመለኮቱ በኩል&nbsp;ብንል \"ኢይጽሕቅ ቅብዓተ በህላዌ በመለኮቱ\"ማለትም በመለኮቱ መቀባትን(ክብርን)አይሻል!!ከዚህ በተጨማሪ እግዚአብሔር ሰው ለመሆን ወረደ ሲል የሰውን ባህርይ ባህርይው ለማድረግ ማለትም&nbsp;የማይራበው እንዲራብ መሆኑ፣ባእለ ጸጋ የነበረው ባህርይውን ሳይለቅ በተዓቅቦ ነዳይ መሆኑ የንጉሶች ንጉሥ ሲሆን የጌቶች ጌታ ሲሆን በአይሁድ ፊት መገረፉ በአጠቃላይ ራሱን በሰው መልክና አርዓያ መምጣቱን&nbsp;ያመለክታል። ምክንያቱም\"ነገር ግን የባህርይን መልክን ይዞ በሠውም ምሳሌ ሆኖ ራሱን ባዶ አደረገ&nbsp;በምስሉም እንደሰው ተገኝቶ ራሱን አዋረደ\"እንዲል ፊል 2&divide;8</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ሕቀ አሕጸጽኮ እምመላእክቲከ</strong></span>\"-ከመላእክት እጅግ ጥቂት አሳነስኸው\"መዝ 8&divide;5 እንዲል&nbsp;አንድም \"ሰውም እግዚአብሔርን ለመሆን ከፍ ከፍ አለ ሲል በተዋህዶ የመለኮትን ገንዘብ ገንዘቡ </em></span><span style=\"font-size: 14pt;\"><em>ስለሚያደርግ የስጋ በአምላክነት መክበር መቀባት ተብሎ ተነግሯል።አምላክነቱ የባህርይው ስለሚሆን በጸጋ&nbsp;እንዳደረባቸው ቅዱሳን አይደለም ሲል ነው።አንድም ቅዱስ ዮሐንስ አፈወርቅ እንደገለጸው </em></span><span style=\"font-size: 14pt;\"><em>ትስብእት ከመለኮት ጋር በመዋሐዱ ያገኘውን የክብር መጠን ሲያብራራ እንዲህ በማለት በሰፊው&nbsp;አብራርቷል!!\"ወዴት ስፍራ እንዳወጣው ዕወቅ:ከፍጡራን ሁሉ ከመላእክትም ሁሉ በላይ አደረገው\"አለ።ረቂቅ </em></span><span style=\"font-size: 14pt;\"><em>እውቀትን እንዲገልጽልህ ከወደድክ በእግዚአብሔር ባህርይና በሰው ባህርይ መካከል ያለ ልዩነት ምን ያህል እንደሆነ አንተ እወቅ፣ማንም ሊናገረው ወደማይቺለው ክብረ መለኮት ትስብእትን ከፍ ከፍ </em></span><span style=\"font-size: 14pt;\"><em>አደረገው፣ከልዑላን መላእክት ሁሉ በላይ አደረገው\"ሃይ.አበው 67 ክፍል 16 &divide;23 ስለዚህ ተለዓለ መባሉ ስለዚህ ነው።</em></span></div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244); color: rgb(224, 62, 45);\"><em><strong>8. \"ዘቀብኦ እግዚአብሔር መንፈሰ ቅዱሰ ወኃይለ\"ሐዋ 10&divide;38</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡\"እግዚአብሔርም የናዝሪቱን ኢየሱስን በኃይል በመንፈስ ቅዱስ ቀባው\" ሲል </em></span><span style=\"font-size: 14pt;\"><em>በመንፈስ ቅዱስ ማለት በግብረ መንፈስ ቅዱስ(በረቂቅ ምሥጢር)ሥጋን አከበርኸው ማለት ነው!!</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>&nbsp;እንደዚህማ ባይሆን ኖሮ ሐዋርያው ቅዱስ ጴጥሮስ</em></span></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>\"እግዚአብሔር የናዝሬንቱን ኢየሱስን ከሙታን መካከል ለይቶ አስነሳው\"ሲል በመንፈስ ቅዱስ ወይም </em><em>በአብ ስልጣን ነው የተነሳ በራሱ ስልጣን የተነሳ አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>በራሱ ስልጣን ካልተነሳ \"እንዴት አልዓዛርን ከመቃብር አስነሳው\"ለራሱ የሌለው ለሰው </em><em>ያበድራልን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም በመንፈስቅዱስ በቀባኸው አለ እንጂ ቅብዕ በሆነው አይልም!!</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(224, 62, 45); font-size: 18pt; background-color: rgb(251, 238, 184);\"><strong><em>9.\"መንፈሰ እግዚአብሔር ላእሌየ ዘበእንቲአሁ ቀብዐኒ\"ኢሳ 61</em><em>&divide;1</em></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp; ↪ የእግዚአብሔር መንፈስ ሲል መንፈስ ቅዱስ ነው፣እኔ ያለው ደግሞ ባለቤቱ ወልድ ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>☝በእኔ ላይ ማለቱም መንፈስ ቅዱስ በእኔ በወልድ ህልው ነው ማለቱ ነው!!</em></span><span style=\"font-size: 14pt;\"><em>ቀባኝ ማለቱም አዋሐደኝ ሲል ነው!!</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>\"ስለዚህ የእግዚአብሔር መንፈስ በእኔ ህልው ነው፣ስለዚህ ነገር አዋሐደኝ ሲል በኢሳያስ የተነገረለትን የባህርይ ህይወቱን መንፈስ ቅዱስን እርሱ ገንዘብ እንዳደረገ ሊነገር ይገባል።ስለዚህ በባህርይ ገንዘቤ&nbsp;የሚሆን መንፈስ ቅዱስ በህልውናየ ጸና ብሎ ብሎ አስተማረ\"ሃይ.አበው ዘሳዊሮስ 87 ክፍል 17-18</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;&nbsp;***አዋሐደኝ ማለቱም የአምላክ ሰው መሆን በፈቃደ አብ፣በፈቃደ ወልድ፣በፈቃደ መምፈስ ቅዱስ የሆነ ማለት ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ በሌላ አነጋገር </em></span><span style=\"font-size: 14pt;\"><em>አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ከተባለ ታዲያ ከዚህ ጥቅስ ላይ </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>በእኔ ላይ ያለ የእግዚአብሔር መንፈስ ቀባኝ ሲል ቀባዒው ማነው❓</em></span></li>\r\n<li><em style=\"font-size: 14pt;\">በዚህ ጥቅስ ቀባዒው አብ መሆኑ አይደለምን❓</em></li>\r\n<li><em style=\"font-size: 14pt;\">ታዲያ መንፈስ ቅዱስ ቅብዕ የሚል ከየት ይመጣል❓</em></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h1><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><em><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የዘመኑ ቅባት ነን ባዮች የሚያነሷቸው ጥያቄዎችና መልሶቻቸው</strong></em></span></h1>\r\n<div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(45, 194, 107); background-color: rgb(241, 196, 15);\"><em>=&gt;.እኛ የተዋህዶ ልጆች ትሥብእት ወይም ሥጋ ከባሪ መለኮት(ቃል) ክብር ስንል አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርጋችሁ ስትናገሩ መለኮት የመለኮትን ሥራ ይሰራል ሥጋም የሥጋን ሥራ ይሰራል </em><em>ከሚሉት መለካዊያን በምን ትለያላችሁ?ይሉናል።</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.ቅባት ወገኖቻችን ሆይ እኛ አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርገን እናንተ እንደምትሉት ያለ&nbsp;ፍልስፍና ላይ አልተሰማራንም በሉልኝማ የተዋህዶ ልጆች። ከበረ፣ አከበረ የምንለው በጊዜ ተዋሕዶ ላይ </em></span><span style=\"font-size: 14pt;\"><em>ያለን ጊዜ ብቻ ናት። መክበር ይሻ የነበረን ሥጋ አካላዊ ቃል በአምላክነት ክብሩ አከበረው። ይች እመቤታችን&nbsp;\"<span style=\"color: rgb(132, 63, 161);\"><strong>ይኩነኒ በከመ ትቤለኒ</strong></span>\"ባለችው ጊዜ የተፈጸመች ድንቅ ምስጢር ናት። ከዚህ ጊዜ በኋላ መለኮትና ትስብእት&nbsp;አንድ ስለኾኑ ከባሪና አክባሪ የለም።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ ወልድ አምላክ ነውና በአምላክነት ክብሩ ያከብራል ስንል ወልድ ማክበር አይችልም ካላችሁን </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\"><em>\"በመንፈስ ቅዱስ ከበረ\"ስትሉ መንፈስ ቅዱስስ ማክበር የብቻው ግብሩ ነው ብላችሁ ነውን? </em></span></strong></span></li>\r\n<li><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\">አዎ ካላችሁ ለመንፈስ ቅዱስ ከመሥረጽ ውጭ ሌላ አካላዊ ግብር እንዳለው ከየት ተማራችሁት? </span></strong></span>ማስረጃችሁ ምንድን ነው ወገኖቼ?ብላችሁ ጠይቁልኝ!!</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.አንዱ አካል አክባሪ ያሉ ቃልን አንዱ አካል ከባሪ የሚሉን ደግሞ ትስብእትን ለማለት ፈልጋችሁ ነው። እናንተ \"<span style=\"text-decoration: underline;\"><strong>በመንፈስ ቅዱስ ከበረ\"</strong></span> የምትሉት ሥግው ቃልን ነው።ታዲያ ሥግዉ ቃልን ከሆነስ</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ሥግው ቃል አምላክ ነው ወይስ አይደለም?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>&nbsp;ሥግው ቃል እስከሚከብር ድረስ የአብ የመንፈስ ቅዱስ ቃላቸው ማን ነበር?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ትስብእት አምላክ የኾነው በቅብዐተ መንፈስ ቅዱስ ከኾነ ሥግው ቃል እስኪከብር ድረስ አብና መንፈስ ቅዱስ ዲዳ ነበሩ (ሎቱ ስብሐት)?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(22, 145, 121); background-color: rgb(194, 224, 244);\"><em><strong><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244);\">=&gt;&ldquo;እራሱ(አብ) አክብሮ አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ አለው&rdquo; ዮሐንስ አፈ ወርቅ ድር 8&divide;69 ብሎ አብ ወልድን እንዳከበረው እየተናገረ ለምን እራሱን በራሱ አከበረ ለማለት ደፈራችሁ? ምን ምስክርስ አላችሁ?ይሉናል።</span></strong></em></span></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✔. አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ የሚለው ቃል መነሻው ዳዊት ነው። ይህን የጻፈው ዳዊት 2&divide;7 ላይ ነው።ማክበር አምላካዊ ግብር እንደመኾኑ መጠን በአብ በወልድ በመንፈስ ቅዱስ ሊነገር ይችላል። ይህ </span><span style=\"font-size: 14pt;\">ችግር ነው ብለን አናውቅም። በመጀመሪያ</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ማክበር የማን ግብር ነው ብለው ያስባሉ?</em></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ግብርነቱስ የአካል ነው ወይስ የአምላክነት?የሚሉትን ጥያቄዎች ማጤን ያስፈልጋል።</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.እኛ ወልድ ዋህድ በተዋህዶ ከበረ ብለን የምናምን እርሱ ራሱን እንዳከበረ መጽሐፍትን አብነት አድርገን&nbsp;እንናገራለን።ይኸውም&laquo;ዳግመኛ ክርስቶስስ ክብር መሻት ኖሮበት አልከበረም እርሱ ራሱ አክባሪ ነው እንጂ ሰው ቢኾንም በባሕርይ&nbsp;ክብሩ ከበረ እርሱ ራሱ እግዚአብሔር አምላክ ነው ሥጋ ትሁት ሕጹጽ ነዳይ ስለኾነ ተለዐለ ተብሎ ተነገረለት ከኹሉ በላይ የኾነ ስምንም እርሱ ራሱ ሰጠው ተባለ ይህም የኾነ በባሕርይ ተዋሕዶ ነው አምላክ እንደኾነ&nbsp;እኛንም እርሱ ወደ አለበት ያቀርበን ዘንድ&raquo; ሊቁ ቅዱስ ቄርሎስ በሃይማኖተ አበው ስምዐት 124 &divide;34 ላይ ይላል።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ታላቁ ሊቅ ቅዱስ ዮሐንስ አፈወርቅም በሃይማኖተ አበው 66 &divide;18 -19&nbsp;ላይ አካላዊ ቃል የተዋሐደውን የእኛን ሥጋ እንዳከበረው በመደነቅ እንዲህ ይላል፡-</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;ክብሩ ተለይቶ የነበረ ሥጋን ክቡር አምላክ ሊያደርገው የጸጋ ገዥነትን አጥቶ የነበረ ሥጋንም የባሕርይ ገዥ&nbsp;ሊያደርገው ወደደ አዳም ከእኛ እንደ አንዱ ኾነ ያለውንም ሰው በመኾን ሊገልጠው ወደደ። ስለዚህ ሥጋዬን&nbsp;ተዋሐደ። ወንጌልን ሲያስተምር እሰማው ዘንድ ሥጋዬን በተዋሕዶ ገንዘብ አደረገ፤ መንፈስ ቅዱስን ሰጠኝ ሰጠሁ ተቀበልኩ ለእኔም ፍጹም ሕይወትን ገንዘብ አደረግሁ። እርሱ ያከብረው ዘንድ ሥጋዬን ተዋሐደው። የሚያድነኝ መንፈስ ቅዱስን ሰጠኝ&raquo;በዚህ አነጋገር መሠረት <strong><span style=\"text-decoration: underline;\">እርሱ የተባለው አካላዊ ቃል ነው</span></strong>። አንዳንድ የቅብዐት እምነት ተከታዮች ግን እርሱ የሚለውን ለመንፈስ ቅዱስ ቀጽለው በመንፈስ ቅዱስ ከበረ ለሚለው ኑፋቄያቸው ደጋፊ ጥቅስ አድርገው ይጠቅሱታል። እርሱ የሚለውን ለመንፈስ ቅዱስ ከቀጸሉት ሥጋዬን የተዋሐደው መንፈስ ቅዱስ ነው ያሰኛልና ፍጹም ክህደት ነው። መንፈስ ቅዱስ ሥጋዬን ተዋሕዶ ሰው ኾነ የሚያሰኝ ክፉ መንገድ ነው። በተዋሕዶ ከበረ&nbsp;ብለው ላለማመን ወደ ሌላ ስህተት ሲያመሩ ይታያሉ። ሊቁ እንደጻፈው ግን እርሱ የሚለው ለአካላዊ ቃል የተነገረ ነው። ስለዚህም እርሱ መንፈስ ቅዱስን ሰጠኝ ሲል አካላዊ ቃል ለተዋሐደው ሥጋ የባሕርይ ሕይወቱ&nbsp;መንፈስ ቅዱስን መስጠቱንና ሥጋ የመንፈስ ቅዱስን ሕይወትነት ገንዘቡ ማድረጉን መናገር ነው። ይህ የተደረገው ደግሞ <span style=\"text-decoration: underline;\"><strong>በተዋሕዶ</strong></span> ብቻ ነው።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች&nbsp;የሊቁን ትምህርት በማስተዋል ተመልከቱና ከሰፊው የምስጢር ባሕር ውስጥ ገብታችሁ የምሥጢሩን ጥልቀት የትምህርቱን ርቀት (ቀ ይጠብቃል) አድንቁ ከዚህ በላይ ምን ማስረጃ አለ??</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;<span style=\"color: rgb(186, 55, 42);\"><strong>ወከመዝ ነአምሮ ለሊሁ ተቀብዐ ከመ ሥርዓተ ትስብእት ወዳእሙ ውእቱ ዘይቀብዕ ርእሶ በ</strong></span><span style=\"color: rgb(186, 55, 42);\"><strong>መንፈሱ ባሕቲቱ</strong></span>\"በተዋሕዶ እንደከበረ እናውቃለን ግን በገዛ ሥልጣኑ ራሱን የሚያከብር እርሱ ነው&raquo; ሃይማኖተ አበው ስምዓት 124 &divide;14 ይላል።</span></em><em><span style=\"font-size: 14pt;\">ወንጌላዊው ዮሐንስም በወንጌሉ ዮሐ 17&divide;19 ላይ &laquo;<strong><span style=\"color: rgb(186, 55, 42);\">አነ እቄድስ ርእስየ </span></strong>-እኔ ራሴን አከብራለሁ&raquo; ብሎ ጌታ የተናገረውን ጽፎት እናገኛለን። እኔ ራሴን አከብራለሁ ሲል በተዋሕዶ ማለቱ ነው። እኔ ሲልም በቃል ርስት ኾኖ ነው በሥጋ ርስትማ ይህን አይናገርም። ሥጋማ እንኳንስ ሊያከብር የጸጋ ልጅነትን እንኳ ያጣ ነበርና። ቃል ሲዋሐደው ግን ክቡር አምላክ ኾነ ይባላል። እኔ ብሎ አምላክነቱን (አክባሪነቱን) ራሴን ብሎ ሰውነቱን (ከባሪነቱን) ይናገራል። እርሱ ራሱ አክባሪ ነው እርሱ ራሱም ከባሪ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>↪\"እምቅድመ ቅብዓትሰ ነበሩ መላእክትከመ ህፃናት በዝንጋዔ ወሶበ ተቀብዑ መልዓ ላዕሌሆ', '', '', '', 'Module: ነገረ ቅባት\n- Lesson: ቅባት(ቅብዓት)\n- Lesson: ቅባት(ቅብዓት) ትርጉሙ ምንድን ነው❓\n- Lesson: ቅባት በቅዱሳት መጽሐፍት ሲተረጎም\n- Lesson: የቅባት ትርጉም እንደ ቅባት አስተምሮ .....\n- Lesson: ምሥጢረ ሥጋዌ በቅባት አስተምህሮ (በወልደ አብ) ዕይታ\n- Lesson: በነገረ ቅባት በመንፈስ ቅዱስ ከበረ ለማለት የሚነሱ ጥቅሶች\n- Lesson: የዘመኑ ቅባት ነን ባዮች የሚያነሷቸው ጥያቄዎችና መልሶቻቸው', '<article class=\"builder-output-card\"><h4>Question 1</h4><ol></ol></article>', '<article class=\"builder-output-card\"><h4>የቤተ ገብርኤል አሳይመንት</h4><p>ይህ አሳይመንት ነገረ ቅባት ዙሪያ የሚያትት ሲሆን እባክዎ መልስዎትን በግልጽ ማብራሪያ እና በማያሻማ ቃል በማስረጃ ይግለጹ።</p><p class=\"small\">Due: አሳይመንቱ የሚገባበት ቀን ከማጠቃለያ ፈታና በፊት • Points: 15%</p></article>', '<p><strong><em>ዉድ የዲ/ን ሶፎንያስ ደመቀ ቤተ ገብርኤል ዌቭሣይት ኦንላይን ተማሪዎች ህጋዊ ሠርተፊኬት ለማግኘት ቢያንስ 80% አሰስመንት ከኩይዝ ጀምሮ አጋማሽ ፈተና፣የማተቃለያ ፈተና እና አሳይመንት በሰአቱ ተገኝቶ መዉሰድ እና ሱብሚት አድርገው ያስገቡ መሆን እንዳለብዎ እንዳዪዘነጉ።አሰስመንት ሳያሟላ ለሚመጣ ተማሪ ተጠያቄ አይደለንም ኃላፊነቱን ራሱ ይወስዳል።</em></strong></p>', '2026-06-30 02:00:26', '', '');
INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('8', 'ነገረ ሃይማኖት', '072', '', '<h1><span style=\"color: rgb(22, 145, 121);\"><em><span style=\"font-size: 36pt;\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ምዕራፍ አንድ</strong></span></em></span></h1>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"font-size: 36pt; color: rgb(132, 63, 161);\"><strong>የአዕማደ ምሥጢራት መግቢያ</strong></span></h1>\r\n<div>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>የቅድመ ምንባብ ጥያቄዎች፦</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አዕማደ ምሥጢር ማለት ምን ማለት ነው?</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አዕማድ ምንድን ነው??ምሥጢር ማለትስ?</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✔ .የኢትዮጵያ ኦርቶዶክስ ተዋህዶ ሃይማኖት መፍቻ ቁልፍ የግእዝ ቋንቋ&nbsp;እንደ መሆኑ መጠን በተለይም በቤተክርስቲያን ጥቅም ላይ የሚውሉ&nbsp;ቃላት ምንጫቸው ግእዝ ነው፡፡ስለዚህ በመጀመሪያ አዕማደ ምሥጢር የሚለው ቃል አዕማድ እና&nbsp;ምሥጢር ከሚሉ ሁለት ቃላት የተገኘ ነው።</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">➠ \"<strong>አዕማድ</strong>\" :-የሚለውም ቃል መገኛው \"አምድ\" የሚለው የግዕዝ ቃል ነው፡፡\"<strong>አምድ</strong>\" የሚለው ቃል የነጠላ ቁጥርን የሚገልፅ ሲሆን \"አዕማድ\" ሲሆን ደግሞ&nbsp;ብዙ ቁጥርን ይገልፃል፡፡ ትርጉሙም በቃላዊ ፍቺው ለቤት ሲሆን ምሰሶ ማለት&nbsp;ነው፡፡ምሰሶ ቤትን ደግፎ እና አቅንቶ እንደሚይዝ ሁሉ አምስቱ አዕማደ ምሥጢራትም የኦርቶዶክስ ተዋህዶ ሃይማኖትን አቅንተውና ደግፈው&nbsp;ስለሚይዙ የተሰጠ ስያሜ ነው፡፡ ዐምድ ለጽሕፈትም ይውላል፡፡ የገጽ&nbsp;ስፋትንም በመክፈል ለንባብ መመጠኛነት ያገለግላል፡፡ በዚህ ፍቺም ባህርየ&nbsp;ሥላሴን ከልክ አልፈን እንዳንመረምር የተሰጠ ስያሜ ነው፡፡</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp;</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .አምድ በቁሙ ምሰሶ ብለን የምንጠራው እና ቤቱ እንዳይዘም ወይም ወደ አንድ ጎን እንዳያዘነብል፤ ሚዛኑን እና ልኩን ጠብቆ እንዲቆም የሚያደርግ ነው። በአምድ የተሠራ ቤት አይዛባም ያለዓምድ የተሠራ ቤት ግን ይፈርሳል አይጸናም፡፡ ቤት በአምድ (በኮለም) እንደሚጸና ሃይማኖትም በእነዚህ አዕማደ ምሥጢራት ተጠቃሎ ይገለጻል፤ ምዕመናንም እነዚህን ምሥጢራት በመማር ጸንተው ይኖራሉ። እንደዚህም ሁሉ ቅድስት ቤተ ክርስቲያናችን አዕማድ የተባሉ ምሥጢራት ይዞ የተገኘ ሰው ልቡናው በፍቅረ እግዚአብሔር በተስፋ መንግስተ ሰማያት ይጸናል፡፡ እነዚህን አምስቱን ምሥጢራት ሳይዝ የተገኘ ልቡናው በፍቅረ እግዚአብሔር በተስፋ መንግስተ ሰማያት አይጸናም፡፡</span></em></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">በቅድስት ተዋህዶ ቤተክርስቲያናችን አስተምህሮ ምሰሶዎች አንድን&nbsp;ቤት ደግፈው እንደሚይዙት ሁሉ የኦርቶዶክስ ተዋህዶ ሃይማኖትንም ቀጥ አድርገው የሚይዙ ምሰሶዎች አምስቱ አዕማደ ምስጢራት ናቸው፡፡የቤተ ክርስቲያን ሊቃውንት እንደሚያስተምሩት ከሆነ አንድ ሰው&nbsp;አምስቱን አዕማደ ምስጢራት በጥንቃቄ ካወቀ የኑፋቄ ማዕበል&nbsp;አይጥለውም፡፡ከእምነቱም አይናወጽም፡፡በህይወቱ የተለያዩ መከራዎች&nbsp;ቢመጡበትም በእነዚህ ትምህርቶች በኩል ራሱን ያፀናል፡፡እነዚህን&nbsp;አዕማድ ያላወቀ በሙሉ ልቡ የኦርቶዶክስ ተዋሕዶ አማኝ ነኝ ማለት&nbsp;አይችልም፡፡በዚህም ምክንያት እነዚህን ጠንቅቆ ማወቅ ያስፈልጋል፡፡</span></em></li>\r\n</ul>\r\n<div><em><span style=\"font-size: 14pt;\">➠<strong>ምሥጢር:</strong>-የሚለው ቃል &lsquo;&rsquo;<strong>አመሥጠረ</strong>&rsquo;&rsquo; አመሠጠረ፣አረቀቀ፣ሰወረ፣ሸሸገ፣ደበቀ\" ከሚለው የግዕዝ ሥርወ ቃል የተገኘ ሲሆን&nbsp;ትርጉሙም \"የማይታወቅ ረቂቅ ሥውር ሽሽግ ድብቅ\" ማለት&nbsp;ነው።</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">➠.ምሥጢር ሁለት ወገን ነው።እነርሱም:-</span></em></div>\r\n<div>\r\n<p><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;1ኛ.ምሥጢረ ፍጡራን እና</span></em></p>\r\n<p><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;2ኛ.ምሥጢረ ፈጣሪ ናቸው።</span></em></p>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><span style=\"color: rgb(35, 111, 161);\"><strong>1ኛ.ምሥጢረ ፍጡራን:</strong></span>-ምሥጢረ ፍጡራን ማለት በፍጡራን ውስጥ ያለ&nbsp;የማይታወቅ ነገር ነው። እርሱ ሦስት ወገን ነው።እነርሱም:-</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምሥጢረ ሰማይ ወምድር፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምሥጢረ ሰብእ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምሥጢረ መላእክት ናቸው።</span></em></li>\r\n</ul>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>ሀ.ምሥጢረ ሰማይ ወምድር:-</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የሰማይ ያለባላ መቆም፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የሰማይ መጠነ ሥፍሐት፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የሰማይ መጠነ ርሕቀት፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የምድር በውሃ ላይ መጽናት፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የምድር መጠነ ሥፍሐት በሰው አእምሮ ከመታወቅ በላይ ስለሆነ ምሥጢር ይባላል።</span></em></div>\r\n<div>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>ለ.ምሥጢረ ሰብእ:-</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .አራቱ መሥተጻርራን ባሕርያት በውስጡ ተስማምተው መኖራቸው፤</span></em></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ልደቱ፣</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ነጽሮቱ፣</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">. ሰሚኦቱ፣</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ነቢቦቱ፣</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong>✦ .ተዋሕዶቱ፦</strong> .የሥጋ ህዋሳቱ እንቅስቃሴና ተግባር፤የነፍሱ የከዊን ምስጢር፤የኅሊናው&nbsp;ምጥቀት፤የልቡናው ተመስጦ፤የመንፈሱ ዕድገት ወ.ዘ.ተ ነው፡፡ይህ ምስጢር በሰው ተፈጥሮ ውስጥ ያለ ከፈጠረው በቀር ሙሉውን ማወቅ ለሰው ለራሱ የማይቻል ስውር የሆነው የሰው የነፍሱና የሥጋው ውሕደት&nbsp;እንዲሁም የተሰጠውና የሚሰጠው ፀጋ ነው፡፡እነዚህ ከላይ የተዘረዘሩት ነገሮች&nbsp;እንዴት እንደተከናወኑ እና እንዴት እንደሚከናወኑ በሰው አእምሮ ከመታወቅ&nbsp;በላይ ስለሆኑ <strong>ምሥጢር</strong> ይባላሉ።</span></em></div>\r\n<div>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>ሐ.ምሥጢረ መላእክት :-</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .የመላእክት ቅርጸ አካላቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .መንፈስነታቸው</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .መጠነ ቁመታቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .ኃያልነታቸው</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .ኅብረ መልክዓቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .ክብራቸው እና ሙሉ ጸጋቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ . ሥርዓተ ሕልውናቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ . መጠነ ብዛታቸው፤በሰው አእምሮ ከመታወቅ በላይ ስለሆነ ምሥጢር ይባላል።</span></em></div>\r\n<div>\r\n<div><span style=\"color: rgb(35, 111, 161);\"><em><span style=\"font-size: 14pt;\"><strong>2ኛ.ምሥጢረ ፈጣሪ(እግዚአብሔር) :-</strong></span></em></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ዓለምን እምኀበ አልቦ መፍጠሩ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.አንድ ሲሆን ሦስት፤ሦስት ሲሆኑ አንድ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ቀዳማዊነቱ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ርቀቱ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምልዓቱ፤</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔ .በአጭሩ እግዚአብሔር ይህንን ዓለም <strong>እምኀበ አልቦ ኀበ ቦ ከኢምንት&nbsp;ኀበ ምንት</strong> ሲያመጣው እንዴት እንዳመጣው ከራሱ በቀር የሚያውቅ&nbsp;አለመኖሩ፤የእግዚአብሔር ምልዓት በፍጡር አእምሮ ከመታወቅ በላይ</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">መሆኑ፤ እግዚአብሔር በዚህ ጊዜ ተገኘ በዚህ ጊዜ ያልፋል ብሎ ልብ&nbsp;ሊመረምረው አንደበት ሊናገረው አይችልምና ቀዳማዊነቱ ምሥጢር ይባላል። ምክንያቱም&lsquo;&rsquo;<span style=\"color: rgb(22, 145, 121);\"><strong>አልቦቱ ጥንት ለክዋኔሁ ወኢ ተፍጻሜት ለህላዌሁ</strong></span>&rsquo;&rsquo;</span></em><em><span style=\"font-size: 14pt;\">እንዲል</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">ማጠቃለያ</span>፦</strong>ሳጠቃልለው አምስቱ አዕማደ ምሥጢር በዋናነት በሁለት ተመድበው ሊታዩ ይችላሉ፡፡</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\"><strong>. በእግዚአብሔር ብቻ ያለ</strong>:-ምሥጢረ ሥላሴና ምሥጢረ ሥጋዌ ናቸው፡፡ይህንም ፍጡር በሃይማኖትና በሱታፌ ይጠቀምበታል፡፡</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\"><strong>. በሰዎች የሚፈጸሙ</strong>:-ጥምቀት፣ቁርባን፣ትንሣኤ ሲሆኑ ሰዎች በሃይማኖትም&nbsp;በገቢርም ይፈጽሙታል፡፡</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">👉የኦርቶዶክሳዊት ተዋሕዶ ቤተክርስቲያን የእምነትና የሃይማኖት መሠረት&nbsp;የሆኑት አምስቱ አዕማደ ምስጢራት ናቸው፡፡ሃይማኖት የሚባለውም እነዚህን&nbsp;ምሥጢራት ተቀብሎ ሁሉን ማድረግ ከሚችል ከእግዚአብሔር ጋር መኖር&nbsp;ነው፡፡</span></em></div>\r\n<div>\r\n<h1><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"font-size: 36pt; color: rgb(132, 63, 161);\"><strong>&nbsp;አዕማደ ምስጢራት ለምን አምስት ሆኑ?</strong></span></span></em></h1>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">*አዕማደ ምሥጢራት አምስት የሆኑበት ዓበይት ምክንንያት፦</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-weight: bold;\"><strong><em><span style=\"font-size: 14pt;\">&nbsp;<span style=\"color: rgb(186, 55, 42);\">.የአምስቱ መጻሕፍተ ሙሴ መጽሐፍት ምሳሌ ነው፣</span></span></em></strong></li>\r\n<li><em><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(186, 55, 42);\">የቤተ ሳይዳ ምሳሌ ነው።</span></strong>ለምን ቢሉ ቤተ ሳይዳ አምስት እርከኖች </span></em><em><span style=\"font-size: 14pt;\">ነበሯት።ያቺ ቤተ ሳይዳ መጠመቂያዋ ለድኅነት ስጋ ነበረች።አማናዊቷ የኖኅ </span></em><em><span style=\"font-size: 14pt;\">መርከብ ስንዱዋ እመቤት ቅድስት ቤተ ክርስቲያን ግን አምስቱን አዕማደ </span></em><em><span style=\"font-size: 14pt;\">ምሥጢር በመስራት ለልጆቿ ድኅነተ ስጋ እና ድኅነተ ነፍስ ትሠጣለቺ ለማለት </span></em><em><span style=\"font-size: 14pt;\">ነው።ዮሐ 5፡1</span></em></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>&nbsp;አንድም አዕማደ ምሥጢራት አምስት መሆናቸው የምን ምሳሌ ነው ቢሉ <span style=\"color: rgb(186, 55, 42);\"><strong>የአራቱ ባህርያተ ስጋ(እሳት፣ውሃ፣መሬት፣ነፋስ)እና የአምስተኛ ባህርየ ነፍስ (ለባዊት፣ህያዊት፣ነባቢት) ድምር ውጤት ነው ሲል ነው።</strong></span> -አንድም ሐዋርያው&nbsp;ቅዱስ ጳውሎስ \"<span style=\"color: rgb(22, 145, 121);\"><strong>ወባህቱ በቤተ ክርስቲያን እፈቅድ ኀምስተ ቃላተ እንገር በልብየ ከመ ለባዕዳንሂ እምህር ዘይኄይስ እም አእላፍ ቃል በነገረ በሐውርት</strong></span>\"ነገር ግን ሌላዎችን አስተምር ዘንድ በማኅበር እልፍ ቃላት በልሳን ከመናገር ይልቅ አምስት ቃላት በአእምሮዬ ላስብ እወዳለሁ\"1ኛ ቆሮ 14 &divide;19 ያለው ነው!!!</em></span></li>\r\n<li style=\"color: rgb(186, 55, 42); font-weight: bold; font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong><span style=\"color: rgb(186, 55, 42);\">.በሌላ አነጋገር የአምስቱ ሕዋሳት ምሳሌም ይሆናል፡፡</span></strong></em></span></li>\r\n</ul>\r\n<div><span style=\"font-size: 24pt;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em>&nbsp; &nbsp; &nbsp;አምስቱ አዕማደ ምስጢራት &ldquo;ምሥጢር&rdquo; የተባሉበት ምክንያት ምንድን ነው?</em></span></strong></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>አምስቱ አዕማደ ምስጢራት &ldquo;ምስጢር&rdquo; የተባሉበት ምክንያት</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>1ኛ</strong>.ቤተክርስቲያን ለአማንያን ብቻ የምትነግረው እና የምታስተምረው በመሆኑ ነው።ለማያምኑ የማይገለጥ፣ለሚያምኑ ግን በእውነተኛው&nbsp;መንፈሳዊና ሃይማኖታዊ የእውቀት ቁልፍ ከፍተው በዚያው በፍፁም ብርሃን </em></span><span style=\"font-size: 14pt;\"><em>ካዩት በኋላ አክብረው የሚጠብቁት &ldquo;<strong>የማይጠፋ ዕንቁ</strong>&rdquo; በመሆኑ ነው።ማቴ&nbsp;7&divide;6 ፤ማቴ 13&divide;11</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>2ኛ</strong>.ረቂቅ እና ስውር ስለሆነው አምላክ የሚናገሩ አስተምህሮቶች ስለሆኑ ነው።የእግዚአብሔርን የአንድነትና የሦስትነት ነገር፣ ቀጥሎ ከሦስቱ አካላት አንዱ&nbsp;ሰው የመሆኑ ነገር፣ እንዲሁም ሰው ከእግዚአብሔር በመንፈስ የመወለዱን ነገር፣ደግሞም ሰው የሆነውን አምላክ ሥጋውን በመብላትና ደሙን በመጠጣት&nbsp; በእግዚአብሔር&nbsp; መንግስት ለዘለአለም ሕያው ሆኖ የመኖርን ነገርና በመጨረሻም ሰው ለዘላለማዊው ህይወት ወይም ሞት በማይበሰብስ አዲስ አካል እንደገና&nbsp;የመነሳቱን ነገር የሚያስረዳ ጥልቅ የሆነ መንፈሳዊና ሃይማኖታዊ ትምህርት&nbsp;የሚያስረዱ በመሆኑ ነው።</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>3ኛ</strong>. ትምህርቶቹን በሥጋዊ ጥበብ ለመረዳት የማይቻል በመሆኑ ነው።ትምህርቱና እውቀቱ እንደሥጋዊ ትምህርትና እውቀት ተፅፎ የሚቀርብና&nbsp;ተነቦ የሚጠና፣ በሥጋዊው ቁሳቁስ ግዙፍ ማስረጃነት እየተደገፈ የሚሰጥ ሳይሆን በአንድ ወገን ከሃይማኖታዊና መንፈሳዊ ልቦና በእውነተኛ አምልኮ&nbsp;ፈልቆ የሚናገሩትና የሚያስተምሩት፣ በሌላው ወገን ደግሞ በእውነተኛ&nbsp;ፍላጎት በተመሰረት ሃይማኖታዊና መንፈሳዊ ልቦና ሆነው የሚሰሙትና&nbsp;የሚማሩት ረቂቅ የእግዚአብሔር ነገር ስለሆነ ነው።</em></span></div>\r\n<h1><span style=\"font-size: 14pt;\"><em>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<strong> <span style=\"color: rgb(132, 63, 161); font-size: 36pt;\">&nbsp;ምዕራፍ ሁለት</span></strong></em></span></h1>\r\n<span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(22, 145, 121);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"font-size: 24pt; color: rgb(22, 145, 121);\">&nbsp; &nbsp; &nbsp; &nbsp; ምሥጢረ ሥላሴ</span></strong></span></em></span>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ከላይ በምዕራፍ አንድ ለመግለጽ እንደሞከርኩት የኦርቶዶክሳዊት ተዋሕዶ ቤተ&nbsp;ክርስቲያን የእምነትና የሃይማኖት መሠረት የሆኑት አምስቱ አዕማደ&nbsp;ምስጢራት ናቸው።</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 14pt;\"><em>*አምስቱ አዕማደ ምሥጢራት&nbsp;</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምስጢረ-ሥላሴ፣</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ሥጋዌ</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ጥምቀት</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ቁርባን</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ትንሳኤ ሙታን ናቸው።</em></span></li>\r\n</ul>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;</em></span></div>\r\n<h2><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(35, 111, 161);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"font-size: 24pt;\">ምሥጢረ-ሥላሴ</span></strong></span></em></span></h2>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ሥላሴ የሚለው ቃል \"<strong>ሠለሰ</strong>\" ከሚለው ከግዕዝ ቃል የተገኘ ሲሆን&nbsp;ሦስትነት ማለት ነው።ሦስትነት ስንል ልዩ ሦስትነት ነው።ለዚያም ነው&nbsp;ቅድስት ብለን የምንቀጽል;ለምን ከተባለ አንድ ሲሆን ሦስት፤ሦስት ሲሆኑ&nbsp;አንድ ናቸውና።ቅድሰት ሥላሴ ሲልም ልዩ ሦስትነት ማለት ሲሆን አንድነት&nbsp;ያለው ሦስትነት የሚያሳይ አነጋገር ነው፡፡</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ ምሥጢረ ሥላሴም ማለት የእግዚአብሔርን አንድነት ሦስትነት የምንማርበት ረቂቅ ምሥጢር ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp; &nbsp; &nbsp;&nbsp;</em></span>\r\n<div><span style=\"font-size: 14pt;\"><em>\"<span style=\"color: rgb(35, 111, 161);\"><strong>መቅድመ ኵሉ ንሰብክ ሥላሴ ዕሩየ ወቅዱሰ ዘውእቶሙ አብ&nbsp;ወወልድ ወመንፈስ ቅዱስ ሥላሴ በተዋሕዶተ መለኮት ዘኢይትሌለይ&nbsp;ወአካላትሰ ለለ ፩ዱ አካል ፍጹም ውእቱ በበገጹ ወበበመልክዑ እንዘ&nbsp;ኢይትሌለይ በመለኮት</strong></span>\" ሃ.አበው ዘጎርጎርዮስ 60፣2&nbsp;</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>ሥላሴ በ፫ ነገር ሦስት ይሆናሉ በዋናነት።እነርሱም:-</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በስም፣</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በአካልና፣</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በግብር ነው።</em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><em>ሥላሴ በስም በአካል፤በግብር ሦስት ሲሆኑ በመለከት፤በአገዛዝ፤ በባህርይ፤በስልጣን ፤በፈቃድ፤በመንግሥት ፤በአገዛዝ ወዘተረፈ አንድ ናቸው።በአጠቃላይ አንድነታቸው በባህርይ ህልውና አንድ ናቸው።</em></span></p>\r\n<div><span style=\"font-size: 18pt;\"><em><span style=\"color: rgb(132, 63, 161);\"><strong>የሥላሴ የአካላት ፫ነት፦</strong></span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉 በመጀመሪያ አካል ማለት ምን ማለት ነው?</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ <strong>አካል</strong>:-ማለት ከራስ ጠጉር እስከ እግር ጥፍር በአጥንት፤በጅማት፤በስጋና በቁርበት የተያያዘ ፍጹም ገጽ ፍጹም መልክ ያለው ነፍስ የተዋሐደቺው የባህርይ፣የስም፣የግብር ባለቤት ነው።መድሎተ አሚን ተመልከት</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ <strong>አካል</strong>፡-አካልን አካለ ፈጣሪ እና አካለ ፍጡራን ብለን በሁለት መንገድ&nbsp;ከፍለን እናያለን፡፡</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong>&nbsp;.አካለ ፍጡራን</strong>:- የምንለው በቦታና በጊዜ አጥር ውስጥ የሚኖር በሁሉ የተገደበ ደኃራዊ ውሱን አካል ነው፡፡</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>&nbsp;.<strong>አካለ እግዚአብሔር</strong>፦የእግዚአብሔር አካል ረቂቅ፤ስፉሕ ፤ምሉዕ ነው።\"<span style=\"color: rgb(35, 111, 161);\"><strong>እስመ አግዚአብሔር መንፈስ ውእቱ</strong></span>\"ዮሐ 4፣24 እንዲል የፍጡራንን ርቀት ሁሉ ያስገኘና የሚለካው ርቀት ደግሞ ይህ ርቀተ አካለ- እግዚአብሔር ነው፡፡\"<strong>እግዚአ መናፍስት</strong>\"እንዲል ሄኖክ</em></span></li>\r\n</ul>\r\n<div><span style=\"font-size: 14pt;\"><em>👉<span style=\"color: rgb(132, 63, 161);\"><strong> የሥላሴ የአካላት ሦስትነት</strong>፦</span>ሥላሴ በአካላት ፫ት ናቸው።ይሄውም አብ በህልውና ከወልድና ከመንፈስ ቅዱስ ጋር የሚያገናዝበው የራሱ የሆነ ፍጹም መልክ፤ፍጹም አካል፤ፍጹም ገጽ አለው።ለወልድም በህልውና ከአብና ከመንፈስ ቅዱስ ጋር የሚያገናዝበው የራሱ የሆነ ፍጹም መልክ፤ፍጹም አካል፤ፍጹም ገጽ አለው።ለመንፈስ ቅዱስም በህልውና ከአብና ከወልድና ጋር የሚያገናዝበው የራሱ የሆነ ፍጹም መልክ፣ፍጹም አካል፣ፍጹም ገጽ አለው።\"<span style=\"color: rgb(22, 145, 121);\"><strong>አብኒ በአካሉ ወበመልክዑ ወበገጹ ፍፁም ውእቱ፤ወልድኒ በአካሉ&nbsp;ወበመልክዑ ወበገጹ ፍፁም ውእቱ፤መንፈስ ቅዱስኒ በአካሉ ወበመልክዑ&nbsp;ወበገጹ ፍፁም ውእቱ</strong></span>\"እንዲል ሊቁ!!\"<span style=\"color: rgb(45, 194, 107);\"><strong>ወነአምን ከመ እሙንቱ ሠለስቱ አካላት ፍጹማን በገጻት</strong></span>\"ሃይ. አበው 52፥3</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ሦስት አካላት ስንል ፍጹማን(ጉደለት የሌለባቸው)፣ቀዋምያን (በየአካላቸው የሚኖሩ)፣ ጽኑዓን፣ሊሉያን (የተለዩ አካላት)፣ሁነው የሚኖሩ አካላት ማለታችን ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>*የአካላት ፫ነት ሲባል መጠቅለል ሳይኖርባቸው በራሳቸው የቆሙ ናቸው።አካልን&nbsp;የሚያገናዝበው ባህርየ ሥላሴ ይባላል።እርሱም መለኮታዊ ባህርይ ይባላል።አካለ&nbsp;ባህርይን የምታገናዝበዋ ባህርየ ሥላሴ 3 ከዊን አላት።አንድም &ldquo;<span style=\"color: rgb(132, 63, 161);\"><strong>ወአካላትሰ ለለአሐዱ አካል ፍጹም ውእቱ በበገጹ ወበበመልክዑ&nbsp;እንዘ ኢይትሌለይ በመለኮት</strong></span>\"ሃይ.አበው 60፥2</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ <span style=\"color: rgb(132, 63, 161);\"><strong>&ldquo;<span style=\"color: rgb(186, 55, 42);\">አብ አሐዱ ፍጹም በአካሉ ወወልድ አሐዱ ፍጹም በአካሉ ወመንፈስ ቅዱስ አሐዱ ፍጹም በአካሉ ወአኮ እሉ ከመ መዓርገ መንግሥት አላ አሐዱ መለኮቶሙ ወአሐዱ ምኵናኖሙ ወአሐዱ ሥምረቶሙ</span></strong></span>\" ሃይ. አበው 71 ፥2 ብሏል።</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ሥላሴ በአካል ሦስት ናቸው ለማለት ብዙ የመጽሐፍ ቅዱስ ማስረጃ</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>አለ።ለአብነትም ያህል.....</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(230, 126, 35);\"><strong>\"ዘአነ እፌኑ ለክሙ እም ኀበ አብ መንፈሰ ጽድቅ ዘይወጽእ እምኀበ አብ&nbsp;ውእቱ ሰማዕትየ</strong></span>\" ዮሐ 15 ፣26፣ኢሳ 6&divide;3፣ዘፍ 1&divide;26፣ዘፍ 18 &divide;1 ለበለጠ መረጃ ተመልከቱ!!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦&nbsp;</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉 <span style=\"color: rgb(22, 145, 121);\"><strong>ሥላሴን በአካል 3 ስንል ልብ ልንላቸው የሚገቡ ነገሮች እነማን ናቸው?</strong></span></em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦&nbsp;</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>3 አካል ብንልም እንኳን 3 እግዚአብሔር የማንል መሆኑን፤<span style=\"color: rgb(132, 63, 161);\"><strong>\"መቅድመ ኩሉ ንእመን በአሐዱ አምላክ ዘቦቱ ሠለስቱ አካላት</strong></span>\"ከሁሉ&nbsp;አስቀድመን ሦስት አካላት ባለው አንድ አምላክ ልናምን ይገባል\"ሃይ.አበው ባስልዮስ ዘቂሳርያ 34 &divide;2 \"<span style=\"color: rgb(22, 145, 121);\"><strong>ሠለስቱ ህላዌ በአካላት፣ወአሐዱ ህላዌ በመለኮት</strong></span>\"ሃይ.አበው 34 &divide;2</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ሦስት አካል ብንልም እያንዳንዳቸው ልብ፣ቃል፣እስትንፋስ የላቸውም።በሰፊው ኩነት ላይ የምናየው ይሆናል....</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ሦስት አካል ብንልም አንዱ አካል ከሌላው አካል ተለይቶ የተገኘበት ዘመን የለም ወደፊትም አይኖርም።</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በሰው ባህርይ ሦስት አካል ተደርድረውበት እንዲሞሉ በሥላሴ ዘንድ ግን እንዲህ አይደለም።አካል የሌለው ባህርይ፤ባህርይ የሌለው አካል አካል ስለሌለ በእያንዳንዳቸው ባህርይ አላቸው የማንል መሆኑን፤</em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(186, 55, 42);\"><strong><span style=\"color: rgb(224, 62, 45);\">✦. </span>ባህርይ፦</strong></span></em></span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ማለት የአካል መገኛ(ስር) ማለት ነው።አንድም አካል ስራውን የሚሰራበት መሳሪያ ነው።<span style=\"color: rgb(230, 126, 35);\"><strong>\"ኢይደሉ ይኩን ህላዌ ዘእንበለ አካል ወኢይደሉ ይትረከብ አካል ዘእንበለ&nbsp;አምሳሉ ለአካል ዘውእቱ አርዓያሁ\"</strong></span> ባህርይ ያለ አካል፣አካልም ያለ ባህርይ ብቻ ሊገኝ አይችልም ነውና ነገሩ ወዳጄ አስተውል!!ከላይ ያየነውን በምሳሌ እንመልከት በጣም ቀለል ለማድረግ አካል ያለ ባህርይ፤ባህር ያለ አካል እንደማይገኝ:-ውሃ አካልም ባህርይም አለው።አካሉ \"<strong><span style=\"text-decoration: underline;\">በእጅ ባይጨበጥም፣ በጥርስ&nbsp;ባይላመጥም</span></strong>\" ሲፈስ ወይም <span style=\"text-decoration: underline;\"><strong>\"በቀላይ ተዘርግቶ፤በማድጋ ተቀድቶ</strong></span>\"ይታያል።ባህርዩም እርጥበት ነው።ይህ ባህርዩ የሆነው እርጥበት አካሉ በደረሰበት ሁሉ ይገኛል እንጂ አካሉ በሌለበት ብቻው ሊገኝ አይችልም።</em></span>\r\n<div>\r\n<h2 style=\"font-size: 14pt;\">&nbsp;</h2>\r\n<div>\r\n<h2 style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"color: rgb(35, 111, 161); font-size: 24pt;\">ህልውና አካላት እንዴት ይታያል?</span></strong></em></span></h2>\r\n<div style=\"font-size: 14pt;\">\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(224, 62, 45);\"><strong>✦ ህልውና:-</strong></span>ማለት አንዱ አካል በአንዱ አካል መኖር ማለት ነው።ይህም&nbsp;ሲባል አብ በወልድ በመንፈስ ቅዱስ ህልው ነው።ወልድም በአብ በመንፈስ&nbsp;ቅዱስ ህልው ነው።መንፈስ ቅዱስም በአብ በወልድ ህልው ነው። <span style=\"text-decoration: underline;\">ውሕደት&nbsp;ግን አይደለም።ምክንያቱም ረቂቅ ከረቂቅ ህላዌን እንጂ ውሕደትን&nbsp;አይፈጥርም።</span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>አስተውሉ፦</strong></em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong><span style=\"color: rgb(35, 111, 161);\">ውህደት ለባህርይ እንጂ ለአካላት አይነገርም።ውህደት የሚነገር\"ለቃል ስጋ ኮነ\"ነው።ዮሐ 1&divide;14</span></strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉&ldquo;<strong><span style=\"color: rgb(230, 126, 35);\">ሥላሴ በተዋሕዶ ፍጹም ወተዋሕዶ በሥላሴ ፍጹም</span></strong>- አንድነት በፍጹም&nbsp;ሦስትነት ሦስትነትም በፍጹም አንድነት አለ&rdquo; ሃይ. አበው 108፥2።<span style=\"color: rgb(22, 145, 121);\"><strong>\"ነአምን ከመ አብ በወልድ ወበመንፈስ ቅዱስ ወወልድ በአብ ወበመንፈስ&nbsp;ቅዱስ ወመንፈስ ቅዱስ በአብ ወበወልድ ዛቲ ሥላሴ ዕሪት እንበለ ፍልጠት&nbsp;በሠለስቱ አካል ወአሐዱ መለኮት\"</strong></span>ሃይ. አበው 11 ፥5</em></span></div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 24pt; color: rgb(186, 55, 42);\"><strong>አብ በሁሉ የመላ ከሆነ ወልድና መንፈስ ቅዱስ በምን ይመላሉ?</strong></span></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div>✦ .አካላት በአካላት ህልዋነ አካላት ምሉዓነ አካላት ናቸው።&ldquo;<span style=\"color: rgb(230, 126, 35);\"><strong>ዘውእቱ አሐዱ ብርሃን ዘይሠርቅ እምኔሁ ሥላሴ ወይመልእ ኵሎ ፍጥረታተ </strong></span><span style=\"color: rgb(230, 126, 35);\"><strong>ወያበርህ ለእለ መትሕተ ምድር በከመ ጽሑፍ እስመ አነ እመልእ ሰማየ&nbsp;ወምድረ ወእለ ሀለዉ ውስተ መትሕተ ሲኦል ርእዩ ስብሓትየ</strong></span>-ሃይ. አበው&nbsp;ዘአግናጥዮስ 11፥9።</div>\r\n<div>👉ፍጡራን በፈጣሪ ዓለምነት ይኖራሉ።ጫጩት እንቊላሉ እስኪፈለፈል ድረስ&nbsp;በእንቊላሏ ውስጥ ይኖራል።ዶሮም እንቊላሏን ብትታቀፍ ከእንቊላሏ ውጪ&nbsp;እንጂ በእንቊላሏ ውስጥ መኖር አትችልም። ፍጡር በያዘው ላይ መኖር&nbsp;አይችልም።ለአብነትም ያህል ለፍጡር ስንናገር ለምሳሌ ለሰው ልጅ ሰው በቤቱ&nbsp;ይኖራል፤ቤቱ ግን በሰው ላይ አይኖርም።በዓለመ ሥላሴ ግን እንዲህ&nbsp;አይደለም።ምክንያቱም በፈጠሩት ፍጥረት እና ከፈጠሩት ፍጥረት በአፍኣ</div>\r\n<div>ይኖራሉ።መገፋፋትም የለባቸውም። ለዚህም ማስረጃ በአንድ ቤት ያሉ&nbsp;አምፖሎችን ብርሐን እንደማይገፋፉ መመልከት በቂ ነው።\"<span style=\"color: rgb(45, 194, 107);\"><strong>ዓለማተ ዓለም ሥላሴ ዘአልብክሙ ዓለም\"</strong></span>- የዓለማተ ዓለም ፈጣሪ ለእነርሱ&nbsp;ዓላም አላቸው ተብሎ አይነገርላቸውም።</div>\r\n<div>✦ ሳጠቃልለው &ldquo;<span style=\"color: rgb(35, 111, 161);\"><strong>አልብነ ጠፈር ወአልብነ መሠረት ንሕነ ጠፈር ወንሕነ&nbsp;መሠረት አልቦ ዘይክል ርእዮተነ ወአልቦ ዘየአምር ዘከመ እፎ ህላዌነ ንሕነ&nbsp;ነአምሮ ለኩሉ ወንሕነ ንጤይቆ ለኩሉ ነአትቶ ለልጹቅ ወናቀርቦ ለርኁቅ</strong></span> -ሠለስቱ ምእት ቁጥር 42 ሠለስቱ ምእቱ</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">&nbsp;</span>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 24pt; color: rgb(186, 55, 42);\"><strong>የስም ሦስትነት:-</strong></span></div>\r\n<div style=\"font-size: 14pt;\">👉የሥላሴ የስም አይነቶች 4ት ናቸው።እነርሱም፦</div>\r\n<div style=\"font-size: 14pt;\">\r\n<ul>\r\n<li>&nbsp;.ስመ አካል፣</li>\r\n<li>.ስመ ግብር፣</li>\r\n<li>ስመ ከዊን፣</li>\r\n<li>ስመ ተዋሕዶ(አንድነት) ናቸው፡፡</li>\r\n</ul>\r\n</div>\r\n<div style=\"font-size: 14pt;\"><strong>አስተውሉ:</strong>-እዚህ ላይ የምናየው ግን ስመ አካልን ነው።</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(53, 152, 219);\"><strong>✦.የስም ሦስትነት:</strong></span>-ሥላሴ በስም አብ፤ወልድ፤መንፈስ ቅዱስ ናቸው።የስም ተፋልሶ የለም።\"<span style=\"color: rgb(35, 111, 161);\"><strong>ኢይፈልስ አብ ለከዊነ ወልድ ወመንፈስ ቅዱስ ወኢወልድ ለከዊነ አብ ወመንፈስ ቅዱስ ወኢመንፈስ ቅዱስ ለከዊነ አብ ወወልድ እሉ ፫ቱ አካላት ፍጹማን ዲበ መንበረ ስብሐት እኁዛን በጽፍረተ አሐዱ መለኮት</strong></span> \"(ሃ.አበው ዘአግናጥዮስ 11&divide;8) በማለት በአስደናቂ ቃል ተናግሮታል።ማለትም አብ አብ ተብሎ ቢጠራ እንጂ ወልድ መንፈስ ቅዱስ ተብሎ አይጠራም፤ ወልድም ወልድ ተብሎ ቢጠራ እንጂ አብ መንፈስ ቅዱስ ወደመባል አይለወጥም፣መንፈስ ቅዱስም መንፈስ ቅዱስ ቢባል እንጂ አብ ወልድ ተብሎ ሊጠራ አይቺልም።እነኚህ ሦስቱ አካላት በጌትነት በክብር ፍጹማን ናቸው በአንድ መለኮት&nbsp;አንድነትም አንድ ናቸው።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\">\"<span style=\"color: rgb(22, 145, 121);\"><strong>ሑሩ ወመሐሩ ኩሎ አህዛበ እንዘ ታጠምቅዎሙ በስመ አብ ወወልድ&nbsp;ወመንፈስ ቅዱስ</strong></span>\" ማቴ 28-20 አንድም&nbsp;\"<span style=\"color: rgb(186, 55, 42);\"><strong>ስመ አብ ብከ ወስመ ወልድ ለሊከ ወስመ መንፈስ ቅዱስ ሕልው&nbsp;ውስቴትከ</strong></span>\"-የአብ ስም በአባትነት ገንዘብህ ነው፣ወልድ የሚለውም ያንተ ስም ነው፤ስመ መንፈስ ቅዱስም በህልውናህ አለ\"እንዲል ትርጓሜ ወንጌል</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"background-color: rgb(35, 111, 161);\"><strong><span style=\"color: rgb(236, 240, 241);\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><strong>👉 በስመ አብ ወወልድ ወመንፈስ ቅዱስ ብሎ በመጀመር ፈንታ ወልድ&nbsp;አብ መንፈስ ቅዱስ ማለት ይቻላል?ተፋልሶ አያመጣም ?</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"background-color: rgb(35, 111, 161);\"><strong><span style=\"color: rgb(236, 240, 241);\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></strong></span></div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(52, 73, 94);\">&nbsp;<strong>በስመ አብ ወወልድ ወመንፈስ ቅዱስ ብሎ በመጀመር ፈንታ ወልድ&nbsp;አብ መንፈስ ቅዱስ ማለት ይቻላል </strong></span><strong>ተፋልሶ አያመጣም</strong>; ምክንያቱም ሥላሴ በቅድምና አንድ&nbsp;ናቸውና።ማስረጃውም....</div>\r\n<div style=\"font-size: 14pt;\">\r\n<ul>\r\n<li>\"<span style=\"color: rgb(230, 126, 35);\"><strong>ሐይማኖትሰ እንተ እምኀበ አብ ተፈጥረት፤ኀበ ወልድ ታበጽሕ፤ወበኀ&nbsp;መንፈስ ቅዱስ ትትፌጸም</strong></span>\"እንዲል ሊቁ ቅ/ያሬድ</li>\r\n<li>\"<span style=\"color: rgb(186, 55, 42);\"><strong>ጸጋሁ ለእግእዚነ ኢየሱስ ክርስቶስ ወፍቅረ እግዚአብሔር ወሱታፌ መንፈስ ቅዱስ የሀሉ ምስሌክሙ</strong></span>\"-የጌታችን የኢየሱስ ክርስቶስ ጸጋው</li>\r\n</ul>\r\n</div>\r\n<div style=\"font-size: 14pt;\">የእግዚአብሔር ፍቅር የመንፈስ ቅዱስ ሕብረት አንድነት ከእናንተ ጋር ይሁን\"፪ኛ ቆሮ 13&divide;13 እንዳለ ቅ/ጳውሎስ</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(53, 152, 219);\"><strong>✦.</strong></span>አንድም ይህ አብ ወልድ መንፈስ ቅዱስ የሚለው ስም የምሉዓን የፍጹማን አካላት የሥላሴ የአካል ተጸውዖ ግል ስም ነው።</div>\r\n<div style=\"font-size: 14pt;\">\"<span style=\"color: rgb(132, 63, 161);\"><strong>ለአብ ቦቱ ስብሐት ወስመ አብና ወለወልድ ቦቱ ስብሐት ወስመ ወልድና&nbsp;ወለመንፈስ ቅዱስ ቦቱ ስብሐት ወስመ መንፈስ ቅድስና</strong></span>\" - ለአብ የአባትነት</div>\r\n<div style=\"font-size: 14pt;\">ስም የአባትነት ክብር አለው።ለወልድም በባሕርይ ክብሩ ከአብ ሳያንስ&nbsp;የልጅነት ስም የልጅነት ክብር አለው።መንፈስ ቅዱስም እንዲሁ በክብር</div>\r\n<div style=\"font-size: 14pt;\">አይለያይም።ነገር ግን ተለውጦ አብ ወልድ መንፈስ ቅዱስም አይባልም&rdquo;ሃይ. አበው ጎርጎርዮስ ዘእንዚናዙ 60&divide;3 ይላል።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\">✔ .የእያንዳንዳቸው ስማቸው ፍፁም ክብር ያለው ኖሮ ኖሮ ያልወጣ ስም&nbsp;መሆኑን መረዳት ያስፈልጋል ወገኖቼ። ስለምን ቢባል አካል ያልቀደመው የአካል&nbsp;ስም ነውና። ስለዚህ ሥላሴ ስማቸው አይቀድማቸውም። አካላቸውም&nbsp;ስማቸውን አይቀድምም። አካል ከስም፤ስም ከአካል ተቀዳድሞ አይገኝም።</div>\r\n<div style=\"font-size: 14pt;\">&ldquo;<span style=\"color: rgb(35, 111, 161);\"><strong>ወናሁ ንቤ ካዕበ አብ ወወልድ ወመንፈስቅዱስ ወአኮ እሉ አስማት ዘቦኡ&nbsp;ላዕሌሆሙ ድኅረ እላ እሙንቱ ስመ አካላት</strong></span>\"-አሁን ደግሞ አብ ወልድ መንፈስ</div>\r\n<div style=\"font-size: 14pt;\">ቅዱስ እንላለን። እነዚህ ስምች ግን የአካላት ስሞች ናቸው እንጂ አካላት&nbsp;ቀድመው ተገኝተው በኋላ የተጠሩባቸው አይደለም&rdquo; ሰው መባልም ሰው</div>\r\n<div style=\"font-size: 14pt;\">ከመሆን በኋላ የመጣ ስም አይደለም። (ጎርጎርዮስ ገባሬ ተአምራት ዘቀጰዶቅያ&nbsp;13 &divide;4) እንዲል።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(53, 152, 219);\"><strong>✦.</strong></span>ሳጠቃልለው ስም አካልን፤አካልም ስምን ሳይቀድመው የሚጠሩበት ስም ነውና በዚህ ስም በየግላቸው በግል ስማቸው ይጠሩበታል።</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(224, 62, 45);\"><strong>&ldquo;ወንሰምዮሙ በሠለስቱ አስማት ዘውእቶሙ አብ ወወልድ ወመንፈስ ቅዱስ </strong></span><span style=\"color: rgb(224, 62, 45);\"><strong>አሐዱ መለኮት ወአሐዱ ኃይል እንዘ ሠለስቱ አካላት</strong></span>- በስም ሦስት ናቸው</div>\r\n<div style=\"font-size: 14pt;\">እንላለን። አብ ወልድ መንፈስ ቅዱስ ሦስት አካላት ሲሆኑ አንድ ባህርይ&nbsp;አንድ ሥልጣን ናቸው&rdquo; (ጎርጎርዮስ ዘእንዚናዙ ነባቤ መለኮት 60&divide;7)</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161); font-size: 18pt;\"><strong>ማጠቃለያ:</strong></span>-<strong>በአጠቃላይ የስም የእነኚህ ስም መገለጫዎች</strong></div>\r\n<div>\r\n<ul style=\"font-size: 14pt;\">\r\n<li style=\"font-weight: bold;\"><strong>&nbsp;ዘኢይፈልስ፣</strong></li>\r\n<li style=\"font-weight: bold;\"><strong>ብሑትነት፣</strong></li>\r\n<li style=\"font-weight: bold;\"><strong>ቀዋሚነት፣</strong></li>\r\n<li style=\"font-weight: bold;\"><strong>ኢደኃራዊነት ናቸው።</strong></li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 18pt;\"><strong>የግብር ሦስትነት:-</strong></span></div>\r\n<div style=\"font-size: 14pt;\">👉ሥላሴ በአካል የሚጠሩበት ስም እንዳላቸው እንደተመለከትን ከዚህ&nbsp;ደግሞ በግብር የሚጠሩበትን ስም በአጭሩ እንመለከታለን የግብር ስም</div>\r\n<div style=\"font-size: 14pt;\">ማለት አንድ አካል ስለ ሥራው የሚጠራበት ስም ማለት ነው፡፡</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><span style=\"font-size: 18pt;\"><strong>✦.</strong></span><strong>እንደዋናነት የግብር አይነቶች ሁለት ናቸው።እነርሱም</strong></span><strong>፦</strong></div>\r\n<div style=\"font-size: 14pt;\">\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-weight: bold;\"><strong>አፍአዊ ግብር(ግብረ ዋህድና) እና</strong></li>\r\n</ul>\r\n</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-weight: bold;\"><strong>ውሳጣዊ ግብር(ግብረ ሥላሴ) ናቸው።</strong></li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>✦ .ግብረ -ዋህድና፦</strong></span>አፍአዊ ሥራ የመፍጠር፣የመመገብ ፣የማሳለፍ ወዘተ...</div>\r\n<div style=\"font-size: 14pt;\">ምሳሌ፦\"<span style=\"color: rgb(22, 145, 121);\"><strong>ንግበር ሰብአ በአርአያነ ወበአምሳሊነ</strong></span>\"</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>✦ .ግብረ- ሥላሴ(ውሳጣዊ ሥራ)፦</strong></span>በዓለመ ሥላሴ ብቻ የሚነገር ወላዲ፤ተዋላዲ፤ሠራፂ የሚባሉት ናቸው።ይህ የአንደኛውን ግብር ለሌላኛው</div>\r\n<div style=\"font-size: 14pt;\">አድሎ መስጠት አይቻልም።</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 18pt;\">የግብር ሦስትነት:</span>-</strong></span>አብ በተለየ አካሉ በተለየ ግብሩ ወላዲ&nbsp;አስራፂ፤ወልድ በተለየ አካሉበተለየ ግብሩ ተወላዲ፤መንፈስ ቅዱስ</div>\r\n<div style=\"font-size: 14pt;\">በተለየ አካሉ በተለየ ግብሩ ሠራፂ ነው።</div>\r\n<div style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp;\"<span style=\"color: rgb(186, 55, 42);\"><strong>በስመ አብ ወላዲ ወኢተወላዲ ወኢሠራጺ ወልድኒ ተወላዲ&nbsp;ወኢወላዲ ወኢሠራጺ ወመንፈስ ቅዱስኒ ሠራጺ ወኢወላዲ&nbsp;ወኢተወላዲ\"</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt;\"><strong>አስተውሉ፦</strong></span>ባህርይን በፍጡራን ደረጃ በሁለት ከፍለን ማየት&nbsp;እንቺላለን።ይኸውም</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li>ስመ ባህርይ፣</li>\r\n<li>ስመ ግብር ነው።</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><strong>✦ .ስመ ባህርይ:</strong></span>-አካል ስምን ሳይቀድመው፤ስምም አካልን ሳይቀድመው&nbsp;የሚገኝ ነው።</div>\r\n<div style=\"font-size: 14pt;\"><strong>ምሳሌ፦</strong>ሰው ከአራቱ ባህርያተ ስጋ ስለተገኘ ሰው ተባለ።</div>\r\n<div style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">✦.ስመ ግብር፦</span></strong>ለሰው ሲሆን ሰዓሊ፤ጸሐፊ፤ደራሲ እንደሚባለው ያለ ነው።በአጭሩ ስመ ግብር ማለት በግብር የሚጠሩበት ስም አለ ማለት ነው አብ</div>\r\n<div style=\"font-size: 14pt;\">ቢወልድ ወላዲ ተባለ እንጂ አብ አልተባለም፤ወልድ ቢወለድ ተወላዲ ተባለ&nbsp;አንጂ ወልድ አልተባለም፤መንፈስ ቅዱስ ቢሠርጽ ሠራጺ ተባለ እንጂ መንፈስ</div>\r\n<div style=\"font-size: 14pt;\">ቅዱስ አልተባለም ማለት ነው።ይህም በግበር ብቻ የሚጠሩበት ነው ወደ&nbsp;አካል ወደከዊን አይፋለስም ሥላሴን ፍሉጣን ከሚያስብላቸው ዋነኛውም</div>\r\n<div style=\"font-size: 14pt;\">ይህ ነው፡፡</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong>*የአካል ተጸውዖ ስም፦</strong>አብርሐም፤ይስሐቅ፤ያዕቆብ እንደሚለው አይነት ነው።ነገር ግን አንድ የምናስተውለው ነገር ምንድን ነው ካላችሁኝ:-</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(230, 126, 35);\"><strong>አንድ ሰው በሚያስተምር ጊዜ መምህር ይባላል።አንድ ሰው ሀኪም በሆነ&nbsp;ጊዜ ዶክተር ይባላል።ማስተማሩን ቢያቆም(ቢተው)ግን መምህር ነበር እንጂ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(230, 126, 35);\"><strong>ነው አይባልለትም።ዶክተሩም እንዲሁ ነው።</strong></span></div>\r\n<div style=\"font-size: 14pt;\">✔ .በዓለመ ሥላሴ ግን አብ ዘወትር አባት ወላዲ አስራፂ፤ወልድ ልጅ&nbsp;ተወላዲ፤መንፈስ ቅዱስ ሠራፂ ሲባሉ ይኖራሉ እንጂ ዘመን የሚሽረው</div>\r\n<div style=\"font-size: 14pt;\">ወይም የሚለወጥ አይደለም።</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(22, 145, 121);\"><strong>&nbsp; &nbsp; \"አብሰ ኢተወልደ አላ ወላዴ ወልድ ውእቱ እምቅድመ ኩሉ ዓለም ወልድኒ ተወልድ እም እግዚአብሔር አብ እምቅድመ ኩሉ ዓለም መንፈስ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(22, 145, 121);\"><strong>&nbsp; &nbsp; &nbsp; ቅዱስኒ ሠረጸ እምእግዚአብሔረ አብ እምቅድመ ኩሉ ዓለም</strong></span>\"እንዲል ሃይ.አበው አትናቴዎስ</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">✦.</span></strong>የወልድ ልደቱ አልተፈጸመም፤የአብ ወላዲነቱ አስራፂነቱ አልተፈጸመም፤የመንፈስ ቅዱስ ሠራፂነቱም አልተፈጸመም።ማለትም ቀዳማዊ ወላዲ አስራፂ</div>\r\n<div style=\"font-size: 14pt;\">አብ መውለዱ ማስረጹ የሚፈጸም የሚያልቅ አይደለም;ምክንያቱም ቢያልቅ&nbsp;ቢፈጸም ኖሮ ግን አብ ወልድን የወለደበትና መንፈስ ቅዱስን ያሰረጸበት ዘመንና&nbsp;ጊዜ በታወቀ ነበር።ወልድም ልደቱ ዘኢይኀልቅ(ዘወትር ወልድ ሲባል ይኖራል)&nbsp;ነው።</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"color: rgb(186, 55, 42);\">\"<strong>ወኢተፈጸመ ልደቱ አላ ውእቱ ወትረ ይትወለድ እምኔሁ ኩሎ ጊዜ\"</strong></span>-ዘወትር ሁልጊዜ ሲወለድ ይኖራል እንጂ ልደቱ አልተፈጸመም ፣ለበለጠ መረጃ ምሥጢረ ምሥጢራት ገጽ 226 አንብቡ</li>\r\n<li>\"<span style=\"color: rgb(35, 111, 161);\"><strong>ወኢትሰአለኒ ዘከመእፎ ልደቱ ለወልድ ዋህድ እም አብ\"</strong></span>-ወልድ ዋህድ ከአብ መወለዱ እንዴት እንደሆነ አትጠይቀኝ\"-ሀ.አበው ቴዎዶጥስ 53&divide;16 እንዳለ</li>\r\n<li>\r\n<div>-\"<span style=\"color: rgb(185, 106, 217);\"><strong>ልደተ ወልድ ወጸዓተ መንፈስ ቅዱስ ኢይትነገር አላ ይትነከር</strong></span>\"-የወልድ&nbsp;መወለድ የመንፈስ ቅዱስ መስረጽ ይደነቃል እንጂ አይነገርም\"ሃይ.አበው</div>\r\n<div>ዘዲዮናስዮስ 10&divide;12</div>\r\n</li>\r\n<li>\r\n<div><span style=\"color: rgb(22, 145, 121);\"><strong>\"ሥላሴ ትትረም ወትትነከር\"</strong></span>-ሥላሴ ትደነቃለቺ እንጂ አትነገርም።</div>\r\n</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\"><strong>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><strong>&nbsp;<span style=\"font-size: 18pt;\"><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"color: rgb(22, 145, 121);\">አብ ስለወለደ ወልድ ደግሞ ተወለደ መንፈስ ቅዱስ ደግሞ ሠረፀ ስላልን<span style=\"font-size: 14pt;\"> ማነስ መበላለጥ መቀዳደም በሥላሴ ዘንድ አለ?</span></span></span></strong></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42); background-color: rgb(251, 238, 184);\"><strong>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦<span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>&nbsp;✦ ✦ ✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦ ✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦ ✦<span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦</span> ✦ ✦ ✦&nbsp;</strong></span></div>\r\n<p style=\"font-size: 14pt;\"><strong>&nbsp;<span style=\"font-size: 18pt;\"><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span></span></strong><span style=\"color: rgb(0, 0, 0);\"><span style=\"font-size: 18pt;\"><span style=\"font-size: 14pt;\">አብ ስለወለደ ወልድ ደግሞ ተወለደ መንፈስ ቅዱስ ደግሞ ሠረፀ ስላልን </span></span>በስላሴ መበላለጥና መቀዳደም የለም።</span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li>\"<span style=\"color: rgb(186, 55, 42);\"><strong>ወሶ ንቤ ከመ አብ ኢተወልደ ወወልድሂ ተወልደ ወመንፈስ ቅዱስሂ ወጽአ&nbsp;እምኔሁ ኢትኀሊ ከመ ወልድ ይሐጽጽ እም አብ ወመንፈስ ቅዱስሂ እም&nbsp;ወልድ\"</strong></span>-አብ አልተወለደም ስላልን ወልድ ግን ተወለደ መንፈስ ቅዱስ ከአብ&nbsp;ሠረፀ ስላልን ወልድ ከአብ እንደሚያስ አታስብ መንፈስ ቅዱስም ከወልድ&nbsp;እንደሚያንስ አታስብ\"ሃይ.አበው ዮሐንስ ዘአንጾኪያ 107&divide;3</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><em><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp; በዓለመ ፍጡራን አባት ልጁን ቀድሞ ይገኛል።በዓለመ ሥላሴስ መቀዳደም አለ?</strong></span></em></div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">✦.</span></strong>በዓለመ ሥላሴ መቀዳደም የለም!!ሥላሴ በቅድምና አንድ ናቸው።ይህንንም የሚያስረዳ:-ቅዱስ ጴጥሮስ \"ጌታዬ ሆይ አነዋወርህ&nbsp;እንደምን ነው ቢለው\"<span style=\"color: rgb(186, 55, 42);\"><strong>አቡየ ፀሐይ ወአነ ብርሐኑ ወመንፈስ ቅዱስ ዋዕዩ\"</strong></span>አብ&nbsp;ፀሐይ ነው፤እኔ ብርሐኑ ነኝ፤መንፈስ ቅዱስ ሙቀቱ ነው\"መጽሐፈ ቀለምኒጦስ፣</div>\r\n<div style=\"font-size: 14pt;\">➡.ይህ ማለት ፀሐይ ስትወጣ ክበቧ ብርሐኗ ሙቀቷ ይገለጻል።ብርሐኑና ሙቀቱ ከፀሐይ ይገኛል።ክበቡ የብርሐኑና የሙቀቱ አስገኝ በመሆኑ&nbsp;ከብርሐንና ከሙቀት የምትቀድምበት ጊዜ ቀድማ የኖረችበትም ጊዜ አለ&nbsp;አይባልም።ምክንያቱም ያለ ብርሐንና ሙቀት ከነበረች የኖረችበትም ጊዜ ካለ&nbsp;ፀሐይ ሳትሆን ሌላ ነት።ምክንያቱም አታበራም አታቃጥልም።ይህ ሲባል&nbsp;ብርሐኑ፣ሙቀቱ፣ክበቡ 3ት ቢሆንም የምንለው ግን አንድ ፀሐይ ነው።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\">👉 .ይህንንም ሊቁ አባ ሕርያቆስ በመጽሐፈ ቀለምኒጦስ ያለውን በደንብ&nbsp;አብራርቶታል።ቃሉም እንዲህ ይላል \"<span style=\"color: rgb(35, 111, 161);\"><strong>አብ ፀሐይ ወልድ ፀሐይ መንፈስ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(35, 111, 161);\"><strong>ቅዱስ ፀሐይ አሐዱ ውእቱ ፀሐየ ጽድቅ ዘላዕለ ኩሉ</strong></span>\"-አብ ፀሐይ ነው ወልድ&nbsp;ፀሐይ ነው መንፈስ ቅዱስ ፀሐይ ነው አንድ የህይወት ፀሐይ ነው።</div>\r\n<div style=\"font-size: 14pt;\">*ስለዚህ በፀሐይ ግብር ተቀድም ተድኅሮ እንዳልሰጠነው በሥላሴ ግብርም&nbsp;ተቀድሞ ተድኅሮ(መቀዳደም) አንሰጠውም።</div>\r\n<div style=\"font-size: 14pt;\">👉 <strong>አስተውሉ፦</strong>የአብ ወላዲነት አስራፂነት ፣የወልድ ተወላዲነት፣የመንፈስቅዱስ ሰራፂነት ዘለዓለማዊ ነው፡፡</div>\r\n<div style=\"font-size: 14pt;\">\"<span style=\"color: rgb(132, 63, 161);\"><strong>ወቃለ እግዚአብሔር ህልው በአካሉ እምህላዌ ልዑል ወፅኑእ ወውእቱ&nbsp;ቀዳማዊ ብሉየ መዋእል ህልው ምስሌሁ እምቀዲሙ ወኢይትፈለጥ እምኔሁ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><strong>ወኢየሀልቅ ልደቱ እምኔሁ አላ ውእቱ ብሉየ መዋእል ምስሌሁ በኩሉ ጊዜ&nbsp;ዘእንበለ ፍልጠት\"</strong></span>ሃይ አበ 13 &divide;24</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>ማጠቃለያ፦</strong></span>ግብር የሚለውንና የግብር አይነቶችን ስንመለከት ከላይ ያለው&nbsp;እንዳለ ሁኖ ለበለጠ እውቀትና ሕይወት እነዚህን ነጥቦች እናንተ በሰፊው</div>\r\n<div style=\"font-size: 14pt;\">ተመልከቷቸው።</div>\r\n<div style=\"font-size: 14pt;\">👉 <span style=\"color: rgb(22, 145, 121);\"><strong>የግብር አይነቶች:-</strong></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li>ውሳጣዊ አካላዊ ግላዊ ግብር፣</li>\r\n<li>ውሳጣዊ አካላዊ ባሕርያዊ፣</li>\r\n<li>ከዊናዊ ተገናዛቢ ግል ግብር፣</li>\r\n<li>አፍኣዊ አካላዊ የባሕርይ ግብር፣</li>\r\n<li>ግብረ ሥጋዌ ዘወልድ፣</li>\r\n<li>ግብረ ሀብት ዘመንፈስ ቅዱስ ናቸው።</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161); font-size: 18pt;\"><strong>የኩነት ሦስትነት</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><strong>➡የኩነት ሦስትነት:</strong>-ኩነት ማለት መባል መሆን ሁኔታ ማለት ነው።ሥላሴ በኩነት አብ፤ወልድ ቃል፤መንፈስ ቅዱስ እሥትንፋስ(ሕይወት)&nbsp;ነው። ይኸውም፦አካላት በሕልውና የሚገናዘቡበት የባህርይ ከዊን ስም ነው።ተፈልጦ ተከፍሎ&nbsp;በሌለበት በአንዲት ባህርይ ያለ የከዊን ስም ነው።ከዊነ ልብ በአብ መሠረትነት ለራሱ አሳቢ ሁኖ ለወልድና ለመንፈስ ቅዱስ&nbsp;እውቀት መሆን ነው።ወልድም በአብ መሠረትነት ለራሱ(ነባቢ) ቃል ሆኖ ለአብና&nbsp;ለመንፈስ ቅዱስ ንባብ(መነጋገሪያ)መሆን ነው።መንፈስ ቅዱስም በአብ&nbsp;መሠረትነት ህያው ሆኖ ለአብና ለወልድ ህይወት መሆን ነው።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong>አስተውሉ፦</strong>እንዲህ ስላልን ግን አንዲትን መለኮታዊ ባህርይ ከ፫ አይከፍላትም።ስለዚህ ኩነታት በተለየ ባልተለየ እያልን እንናገራለን።በተለየ&nbsp;ስንል እያንዳንዳቸው አብ ልብ፤ወልድ ቃል፤መንፈስ ቅዱስ እሥትንፋስ&nbsp;መባል ሲሆን ባልተለየ ስንል ደግሞ ተገናዝቦ አቸውንና የእያንዳንዳቸው&nbsp;ልብ፤ ቃል፤እሥትንፋስ አለመኖሩ ነው።ስለዚህ ከዊንን አንድነት ሳለበት&nbsp;ልዩነት፤ልዩነት ሳለበት አንድነት ነው።</div>\r\n<div style=\"font-size: 14pt;\"><strong>በአጭሩ፦</strong>\"ልዩነቱ በ', 'ነገረ መለኮት', 'Advanced', '', '500.00', 'ዲ/ን ሶፎንያስ ደመቀ', '', '', '<h1><span style=\"color: rgb(22, 145, 121);\"><em><span style=\"font-size: 36pt;\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ምዕራፍ አንድ</strong></span></em></span></h1>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"font-size: 36pt; color: rgb(132, 63, 161);\"><strong>የአዕማደ ምሥጢራት መግቢያ</strong></span></h1>\r\n<div>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>የቅድመ ምንባብ ጥያቄዎች፦</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አዕማደ ምሥጢር ማለት ምን ማለት ነው?</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አዕማድ ምንድን ነው??ምሥጢር ማለትስ?</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✔ .የኢትዮጵያ ኦርቶዶክስ ተዋህዶ ሃይማኖት መፍቻ ቁልፍ የግእዝ ቋንቋ&nbsp;እንደ መሆኑ መጠን በተለይም በቤተክርስቲያን ጥቅም ላይ የሚውሉ&nbsp;ቃላት ምንጫቸው ግእዝ ነው፡፡ስለዚህ በመጀመሪያ አዕማደ ምሥጢር የሚለው ቃል አዕማድ እና&nbsp;ምሥጢር ከሚሉ ሁለት ቃላት የተገኘ ነው።</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">➠ \"<strong>አዕማድ</strong>\" :-የሚለውም ቃል መገኛው \"አምድ\" የሚለው የግዕዝ ቃል ነው፡፡\"<strong>አምድ</strong>\" የሚለው ቃል የነጠላ ቁጥርን የሚገልፅ ሲሆን \"አዕማድ\" ሲሆን ደግሞ&nbsp;ብዙ ቁጥርን ይገልፃል፡፡ ትርጉሙም በቃላዊ ፍቺው ለቤት ሲሆን ምሰሶ ማለት&nbsp;ነው፡፡ምሰሶ ቤትን ደግፎ እና አቅንቶ እንደሚይዝ ሁሉ አምስቱ አዕማደ ምሥጢራትም የኦርቶዶክስ ተዋህዶ ሃይማኖትን አቅንተውና ደግፈው&nbsp;ስለሚይዙ የተሰጠ ስያሜ ነው፡፡ ዐምድ ለጽሕፈትም ይውላል፡፡ የገጽ&nbsp;ስፋትንም በመክፈል ለንባብ መመጠኛነት ያገለግላል፡፡ በዚህ ፍቺም ባህርየ&nbsp;ሥላሴን ከልክ አልፈን እንዳንመረምር የተሰጠ ስያሜ ነው፡፡</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp;</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .አምድ በቁሙ ምሰሶ ብለን የምንጠራው እና ቤቱ እንዳይዘም ወይም ወደ አንድ ጎን እንዳያዘነብል፤ ሚዛኑን እና ልኩን ጠብቆ እንዲቆም የሚያደርግ ነው። በአምድ የተሠራ ቤት አይዛባም ያለዓምድ የተሠራ ቤት ግን ይፈርሳል አይጸናም፡፡ ቤት በአምድ (በኮለም) እንደሚጸና ሃይማኖትም በእነዚህ አዕማደ ምሥጢራት ተጠቃሎ ይገለጻል፤ ምዕመናንም እነዚህን ምሥጢራት በመማር ጸንተው ይኖራሉ። እንደዚህም ሁሉ ቅድስት ቤተ ክርስቲያናችን አዕማድ የተባሉ ምሥጢራት ይዞ የተገኘ ሰው ልቡናው በፍቅረ እግዚአብሔር በተስፋ መንግስተ ሰማያት ይጸናል፡፡ እነዚህን አምስቱን ምሥጢራት ሳይዝ የተገኘ ልቡናው በፍቅረ እግዚአብሔር በተስፋ መንግስተ ሰማያት አይጸናም፡፡</span></em></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">በቅድስት ተዋህዶ ቤተክርስቲያናችን አስተምህሮ ምሰሶዎች አንድን&nbsp;ቤት ደግፈው እንደሚይዙት ሁሉ የኦርቶዶክስ ተዋህዶ ሃይማኖትንም ቀጥ አድርገው የሚይዙ ምሰሶዎች አምስቱ አዕማደ ምስጢራት ናቸው፡፡የቤተ ክርስቲያን ሊቃውንት እንደሚያስተምሩት ከሆነ አንድ ሰው&nbsp;አምስቱን አዕማደ ምስጢራት በጥንቃቄ ካወቀ የኑፋቄ ማዕበል&nbsp;አይጥለውም፡፡ከእምነቱም አይናወጽም፡፡በህይወቱ የተለያዩ መከራዎች&nbsp;ቢመጡበትም በእነዚህ ትምህርቶች በኩል ራሱን ያፀናል፡፡እነዚህን&nbsp;አዕማድ ያላወቀ በሙሉ ልቡ የኦርቶዶክስ ተዋሕዶ አማኝ ነኝ ማለት&nbsp;አይችልም፡፡በዚህም ምክንያት እነዚህን ጠንቅቆ ማወቅ ያስፈልጋል፡፡</span></em></li>\r\n</ul>\r\n<div><em><span style=\"font-size: 14pt;\">➠<strong>ምሥጢር:</strong>-የሚለው ቃል &lsquo;&rsquo;<strong>አመሥጠረ</strong>&rsquo;&rsquo; አመሠጠረ፣አረቀቀ፣ሰወረ፣ሸሸገ፣ደበቀ\" ከሚለው የግዕዝ ሥርወ ቃል የተገኘ ሲሆን&nbsp;ትርጉሙም \"የማይታወቅ ረቂቅ ሥውር ሽሽግ ድብቅ\" ማለት&nbsp;ነው።</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">➠.ምሥጢር ሁለት ወገን ነው።እነርሱም:-</span></em></div>\r\n<div>\r\n<p><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;1ኛ.ምሥጢረ ፍጡራን እና</span></em></p>\r\n<p><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;2ኛ.ምሥጢረ ፈጣሪ ናቸው።</span></em></p>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><span style=\"color: rgb(35, 111, 161);\"><strong>1ኛ.ምሥጢረ ፍጡራን:</strong></span>-ምሥጢረ ፍጡራን ማለት በፍጡራን ውስጥ ያለ&nbsp;የማይታወቅ ነገር ነው። እርሱ ሦስት ወገን ነው።እነርሱም:-</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምሥጢረ ሰማይ ወምድር፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምሥጢረ ሰብእ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምሥጢረ መላእክት ናቸው።</span></em></li>\r\n</ul>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>ሀ.ምሥጢረ ሰማይ ወምድር:-</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የሰማይ ያለባላ መቆም፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የሰማይ መጠነ ሥፍሐት፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የሰማይ መጠነ ርሕቀት፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የምድር በውሃ ላይ መጽናት፣</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;✦ .የምድር መጠነ ሥፍሐት በሰው አእምሮ ከመታወቅ በላይ ስለሆነ ምሥጢር ይባላል።</span></em></div>\r\n<div>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>ለ.ምሥጢረ ሰብእ:-</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .አራቱ መሥተጻርራን ባሕርያት በውስጡ ተስማምተው መኖራቸው፤</span></em></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ልደቱ፣</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ነጽሮቱ፣</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">. ሰሚኦቱ፣</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ነቢቦቱ፣</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong>✦ .ተዋሕዶቱ፦</strong> .የሥጋ ህዋሳቱ እንቅስቃሴና ተግባር፤የነፍሱ የከዊን ምስጢር፤የኅሊናው&nbsp;ምጥቀት፤የልቡናው ተመስጦ፤የመንፈሱ ዕድገት ወ.ዘ.ተ ነው፡፡ይህ ምስጢር በሰው ተፈጥሮ ውስጥ ያለ ከፈጠረው በቀር ሙሉውን ማወቅ ለሰው ለራሱ የማይቻል ስውር የሆነው የሰው የነፍሱና የሥጋው ውሕደት&nbsp;እንዲሁም የተሰጠውና የሚሰጠው ፀጋ ነው፡፡እነዚህ ከላይ የተዘረዘሩት ነገሮች&nbsp;እንዴት እንደተከናወኑ እና እንዴት እንደሚከናወኑ በሰው አእምሮ ከመታወቅ&nbsp;በላይ ስለሆኑ <strong>ምሥጢር</strong> ይባላሉ።</span></em></div>\r\n<div>\r\n<div><em><span style=\"color: rgb(186, 55, 42); font-size: 14pt;\"><strong>ሐ.ምሥጢረ መላእክት :-</strong></span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .የመላእክት ቅርጸ አካላቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .መንፈስነታቸው</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .መጠነ ቁመታቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .ኃያልነታቸው</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .ኅብረ መልክዓቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ .ክብራቸው እና ሙሉ ጸጋቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ . ሥርዓተ ሕልውናቸው፤</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">✦ . መጠነ ብዛታቸው፤በሰው አእምሮ ከመታወቅ በላይ ስለሆነ ምሥጢር ይባላል።</span></em></div>\r\n<div>\r\n<div><span style=\"color: rgb(35, 111, 161);\"><em><span style=\"font-size: 14pt;\"><strong>2ኛ.ምሥጢረ ፈጣሪ(እግዚአብሔር) :-</strong></span></em></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ዓለምን እምኀበ አልቦ መፍጠሩ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.አንድ ሲሆን ሦስት፤ሦስት ሲሆኑ አንድ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ቀዳማዊነቱ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ርቀቱ፤</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">.ምልዓቱ፤</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔ .በአጭሩ እግዚአብሔር ይህንን ዓለም <strong>እምኀበ አልቦ ኀበ ቦ ከኢምንት&nbsp;ኀበ ምንት</strong> ሲያመጣው እንዴት እንዳመጣው ከራሱ በቀር የሚያውቅ&nbsp;አለመኖሩ፤የእግዚአብሔር ምልዓት በፍጡር አእምሮ ከመታወቅ በላይ</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">መሆኑ፤ እግዚአብሔር በዚህ ጊዜ ተገኘ በዚህ ጊዜ ያልፋል ብሎ ልብ&nbsp;ሊመረምረው አንደበት ሊናገረው አይችልምና ቀዳማዊነቱ ምሥጢር ይባላል። ምክንያቱም&lsquo;&rsquo;<span style=\"color: rgb(22, 145, 121);\"><strong>አልቦቱ ጥንት ለክዋኔሁ ወኢ ተፍጻሜት ለህላዌሁ</strong></span>&rsquo;&rsquo;</span></em><em><span style=\"font-size: 14pt;\">እንዲል</span></em></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">ማጠቃለያ</span>፦</strong>ሳጠቃልለው አምስቱ አዕማደ ምሥጢር በዋናነት በሁለት ተመድበው ሊታዩ ይችላሉ፡፡</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\"><strong>. በእግዚአብሔር ብቻ ያለ</strong>:-ምሥጢረ ሥላሴና ምሥጢረ ሥጋዌ ናቸው፡፡ይህንም ፍጡር በሃይማኖትና በሱታፌ ይጠቀምበታል፡፡</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\"><strong>. በሰዎች የሚፈጸሙ</strong>:-ጥምቀት፣ቁርባን፣ትንሣኤ ሲሆኑ ሰዎች በሃይማኖትም&nbsp;በገቢርም ይፈጽሙታል፡፡</span></em></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">👉የኦርቶዶክሳዊት ተዋሕዶ ቤተክርስቲያን የእምነትና የሃይማኖት መሠረት&nbsp;የሆኑት አምስቱ አዕማደ ምስጢራት ናቸው፡፡ሃይማኖት የሚባለውም እነዚህን&nbsp;ምሥጢራት ተቀብሎ ሁሉን ማድረግ ከሚችል ከእግዚአብሔር ጋር መኖር&nbsp;ነው፡፡</span></em></div>\r\n<div>\r\n<h1><em><span style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"font-size: 36pt; color: rgb(132, 63, 161);\"><strong>&nbsp;አዕማደ ምስጢራት ለምን አምስት ሆኑ?</strong></span></span></em></h1>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">*አዕማደ ምሥጢራት አምስት የሆኑበት ዓበይት ምክንንያት፦</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-weight: bold;\"><strong><em><span style=\"font-size: 14pt;\">&nbsp;<span style=\"color: rgb(186, 55, 42);\">.የአምስቱ መጻሕፍተ ሙሴ መጽሐፍት ምሳሌ ነው፣</span></span></em></strong></li>\r\n<li><em><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(186, 55, 42);\">የቤተ ሳይዳ ምሳሌ ነው።</span></strong>ለምን ቢሉ ቤተ ሳይዳ አምስት እርከኖች </span></em><em><span style=\"font-size: 14pt;\">ነበሯት።ያቺ ቤተ ሳይዳ መጠመቂያዋ ለድኅነት ስጋ ነበረች።አማናዊቷ የኖኅ </span></em><em><span style=\"font-size: 14pt;\">መርከብ ስንዱዋ እመቤት ቅድስት ቤተ ክርስቲያን ግን አምስቱን አዕማደ </span></em><em><span style=\"font-size: 14pt;\">ምሥጢር በመስራት ለልጆቿ ድኅነተ ስጋ እና ድኅነተ ነፍስ ትሠጣለቺ ለማለት </span></em><em><span style=\"font-size: 14pt;\">ነው።ዮሐ 5፡1</span></em></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>&nbsp;አንድም አዕማደ ምሥጢራት አምስት መሆናቸው የምን ምሳሌ ነው ቢሉ <span style=\"color: rgb(186, 55, 42);\"><strong>የአራቱ ባህርያተ ስጋ(እሳት፣ውሃ፣መሬት፣ነፋስ)እና የአምስተኛ ባህርየ ነፍስ (ለባዊት፣ህያዊት፣ነባቢት) ድምር ውጤት ነው ሲል ነው።</strong></span> -አንድም ሐዋርያው&nbsp;ቅዱስ ጳውሎስ \"<span style=\"color: rgb(22, 145, 121);\"><strong>ወባህቱ በቤተ ክርስቲያን እፈቅድ ኀምስተ ቃላተ እንገር በልብየ ከመ ለባዕዳንሂ እምህር ዘይኄይስ እም አእላፍ ቃል በነገረ በሐውርት</strong></span>\"ነገር ግን ሌላዎችን አስተምር ዘንድ በማኅበር እልፍ ቃላት በልሳን ከመናገር ይልቅ አምስት ቃላት በአእምሮዬ ላስብ እወዳለሁ\"1ኛ ቆሮ 14 &divide;19 ያለው ነው!!!</em></span></li>\r\n<li style=\"color: rgb(186, 55, 42); font-weight: bold; font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong><span style=\"color: rgb(186, 55, 42);\">.በሌላ አነጋገር የአምስቱ ሕዋሳት ምሳሌም ይሆናል፡፡</span></strong></em></span></li>\r\n</ul>\r\n<div><span style=\"font-size: 24pt;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em>&nbsp; &nbsp; &nbsp;አምስቱ አዕማደ ምስጢራት &ldquo;ምሥጢር&rdquo; የተባሉበት ምክንያት ምንድን ነው?</em></span></strong></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>አምስቱ አዕማደ ምስጢራት &ldquo;ምስጢር&rdquo; የተባሉበት ምክንያት</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>1ኛ</strong>.ቤተክርስቲያን ለአማንያን ብቻ የምትነግረው እና የምታስተምረው በመሆኑ ነው።ለማያምኑ የማይገለጥ፣ለሚያምኑ ግን በእውነተኛው&nbsp;መንፈሳዊና ሃይማኖታዊ የእውቀት ቁልፍ ከፍተው በዚያው በፍፁም ብርሃን </em></span><span style=\"font-size: 14pt;\"><em>ካዩት በኋላ አክብረው የሚጠብቁት &ldquo;<strong>የማይጠፋ ዕንቁ</strong>&rdquo; በመሆኑ ነው።ማቴ&nbsp;7&divide;6 ፤ማቴ 13&divide;11</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>2ኛ</strong>.ረቂቅ እና ስውር ስለሆነው አምላክ የሚናገሩ አስተምህሮቶች ስለሆኑ ነው።የእግዚአብሔርን የአንድነትና የሦስትነት ነገር፣ ቀጥሎ ከሦስቱ አካላት አንዱ&nbsp;ሰው የመሆኑ ነገር፣ እንዲሁም ሰው ከእግዚአብሔር በመንፈስ የመወለዱን ነገር፣ደግሞም ሰው የሆነውን አምላክ ሥጋውን በመብላትና ደሙን በመጠጣት&nbsp; በእግዚአብሔር&nbsp; መንግስት ለዘለአለም ሕያው ሆኖ የመኖርን ነገርና በመጨረሻም ሰው ለዘላለማዊው ህይወት ወይም ሞት በማይበሰብስ አዲስ አካል እንደገና&nbsp;የመነሳቱን ነገር የሚያስረዳ ጥልቅ የሆነ መንፈሳዊና ሃይማኖታዊ ትምህርት&nbsp;የሚያስረዱ በመሆኑ ነው።</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>3ኛ</strong>. ትምህርቶቹን በሥጋዊ ጥበብ ለመረዳት የማይቻል በመሆኑ ነው።ትምህርቱና እውቀቱ እንደሥጋዊ ትምህርትና እውቀት ተፅፎ የሚቀርብና&nbsp;ተነቦ የሚጠና፣ በሥጋዊው ቁሳቁስ ግዙፍ ማስረጃነት እየተደገፈ የሚሰጥ ሳይሆን በአንድ ወገን ከሃይማኖታዊና መንፈሳዊ ልቦና በእውነተኛ አምልኮ&nbsp;ፈልቆ የሚናገሩትና የሚያስተምሩት፣ በሌላው ወገን ደግሞ በእውነተኛ&nbsp;ፍላጎት በተመሰረት ሃይማኖታዊና መንፈሳዊ ልቦና ሆነው የሚሰሙትና&nbsp;የሚማሩት ረቂቅ የእግዚአብሔር ነገር ስለሆነ ነው።</em></span></div>\r\n<h1><span style=\"font-size: 14pt;\"><em>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<strong> <span style=\"color: rgb(132, 63, 161); font-size: 36pt;\">&nbsp;ምዕራፍ ሁለት</span></strong></em></span></h1>\r\n<span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(22, 145, 121);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"font-size: 24pt; color: rgb(22, 145, 121);\">&nbsp; &nbsp; &nbsp; &nbsp; ምሥጢረ ሥላሴ</span></strong></span></em></span>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ከላይ በምዕራፍ አንድ ለመግለጽ እንደሞከርኩት የኦርቶዶክሳዊት ተዋሕዶ ቤተ&nbsp;ክርስቲያን የእምነትና የሃይማኖት መሠረት የሆኑት አምስቱ አዕማደ&nbsp;ምስጢራት ናቸው።</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 14pt;\"><em>*አምስቱ አዕማደ ምሥጢራት&nbsp;</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምስጢረ-ሥላሴ፣</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ሥጋዌ</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ጥምቀት</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ቁርባን</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ምሥጢረ ትንሳኤ ሙታን ናቸው።</em></span></li>\r\n</ul>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;</em></span></div>\r\n<h2><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(35, 111, 161);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"font-size: 24pt;\">ምሥጢረ-ሥላሴ</span></strong></span></em></span></h2>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ሥላሴ የሚለው ቃል \"<strong>ሠለሰ</strong>\" ከሚለው ከግዕዝ ቃል የተገኘ ሲሆን&nbsp;ሦስትነት ማለት ነው።ሦስትነት ስንል ልዩ ሦስትነት ነው።ለዚያም ነው&nbsp;ቅድስት ብለን የምንቀጽል;ለምን ከተባለ አንድ ሲሆን ሦስት፤ሦስት ሲሆኑ&nbsp;አንድ ናቸውና።ቅድሰት ሥላሴ ሲልም ልዩ ሦስትነት ማለት ሲሆን አንድነት&nbsp;ያለው ሦስትነት የሚያሳይ አነጋገር ነው፡፡</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ ምሥጢረ ሥላሴም ማለት የእግዚአብሔርን አንድነት ሦስትነት የምንማርበት ረቂቅ ምሥጢር ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp; &nbsp; &nbsp;&nbsp;</em></span>\r\n<div><span style=\"font-size: 14pt;\"><em>\"<span style=\"color: rgb(35, 111, 161);\"><strong>መቅድመ ኵሉ ንሰብክ ሥላሴ ዕሩየ ወቅዱሰ ዘውእቶሙ አብ&nbsp;ወወልድ ወመንፈስ ቅዱስ ሥላሴ በተዋሕዶተ መለኮት ዘኢይትሌለይ&nbsp;ወአካላትሰ ለለ ፩ዱ አካል ፍጹም ውእቱ በበገጹ ወበበመልክዑ እንዘ&nbsp;ኢይትሌለይ በመለኮት</strong></span>\" ሃ.አበው ዘጎርጎርዮስ 60፣2&nbsp;</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>ሥላሴ በ፫ ነገር ሦስት ይሆናሉ በዋናነት።እነርሱም:-</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በስም፣</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በአካልና፣</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በግብር ነው።</em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><em>ሥላሴ በስም በአካል፤በግብር ሦስት ሲሆኑ በመለከት፤በአገዛዝ፤ በባህርይ፤በስልጣን ፤በፈቃድ፤በመንግሥት ፤በአገዛዝ ወዘተረፈ አንድ ናቸው።በአጠቃላይ አንድነታቸው በባህርይ ህልውና አንድ ናቸው።</em></span></p>\r\n<div><span style=\"font-size: 18pt;\"><em><span style=\"color: rgb(132, 63, 161);\"><strong>የሥላሴ የአካላት ፫ነት፦</strong></span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉 በመጀመሪያ አካል ማለት ምን ማለት ነው?</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ <strong>አካል</strong>:-ማለት ከራስ ጠጉር እስከ እግር ጥፍር በአጥንት፤በጅማት፤በስጋና በቁርበት የተያያዘ ፍጹም ገጽ ፍጹም መልክ ያለው ነፍስ የተዋሐደቺው የባህርይ፣የስም፣የግብር ባለቤት ነው።መድሎተ አሚን ተመልከት</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ <strong>አካል</strong>፡-አካልን አካለ ፈጣሪ እና አካለ ፍጡራን ብለን በሁለት መንገድ&nbsp;ከፍለን እናያለን፡፡</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong>&nbsp;.አካለ ፍጡራን</strong>:- የምንለው በቦታና በጊዜ አጥር ውስጥ የሚኖር በሁሉ የተገደበ ደኃራዊ ውሱን አካል ነው፡፡</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>&nbsp;.<strong>አካለ እግዚአብሔር</strong>፦የእግዚአብሔር አካል ረቂቅ፤ስፉሕ ፤ምሉዕ ነው።\"<span style=\"color: rgb(35, 111, 161);\"><strong>እስመ አግዚአብሔር መንፈስ ውእቱ</strong></span>\"ዮሐ 4፣24 እንዲል የፍጡራንን ርቀት ሁሉ ያስገኘና የሚለካው ርቀት ደግሞ ይህ ርቀተ አካለ- እግዚአብሔር ነው፡፡\"<strong>እግዚአ መናፍስት</strong>\"እንዲል ሄኖክ</em></span></li>\r\n</ul>\r\n<div><span style=\"font-size: 14pt;\"><em>👉<span style=\"color: rgb(132, 63, 161);\"><strong> የሥላሴ የአካላት ሦስትነት</strong>፦</span>ሥላሴ በአካላት ፫ት ናቸው።ይሄውም አብ በህልውና ከወልድና ከመንፈስ ቅዱስ ጋር የሚያገናዝበው የራሱ የሆነ ፍጹም መልክ፤ፍጹም አካል፤ፍጹም ገጽ አለው።ለወልድም በህልውና ከአብና ከመንፈስ ቅዱስ ጋር የሚያገናዝበው የራሱ የሆነ ፍጹም መልክ፤ፍጹም አካል፤ፍጹም ገጽ አለው።ለመንፈስ ቅዱስም በህልውና ከአብና ከወልድና ጋር የሚያገናዝበው የራሱ የሆነ ፍጹም መልክ፣ፍጹም አካል፣ፍጹም ገጽ አለው።\"<span style=\"color: rgb(22, 145, 121);\"><strong>አብኒ በአካሉ ወበመልክዑ ወበገጹ ፍፁም ውእቱ፤ወልድኒ በአካሉ&nbsp;ወበመልክዑ ወበገጹ ፍፁም ውእቱ፤መንፈስ ቅዱስኒ በአካሉ ወበመልክዑ&nbsp;ወበገጹ ፍፁም ውእቱ</strong></span>\"እንዲል ሊቁ!!\"<span style=\"color: rgb(45, 194, 107);\"><strong>ወነአምን ከመ እሙንቱ ሠለስቱ አካላት ፍጹማን በገጻት</strong></span>\"ሃይ. አበው 52፥3</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ሦስት አካላት ስንል ፍጹማን(ጉደለት የሌለባቸው)፣ቀዋምያን (በየአካላቸው የሚኖሩ)፣ ጽኑዓን፣ሊሉያን (የተለዩ አካላት)፣ሁነው የሚኖሩ አካላት ማለታችን ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>*የአካላት ፫ነት ሲባል መጠቅለል ሳይኖርባቸው በራሳቸው የቆሙ ናቸው።አካልን&nbsp;የሚያገናዝበው ባህርየ ሥላሴ ይባላል።እርሱም መለኮታዊ ባህርይ ይባላል።አካለ&nbsp;ባህርይን የምታገናዝበዋ ባህርየ ሥላሴ 3 ከዊን አላት።አንድም &ldquo;<span style=\"color: rgb(132, 63, 161);\"><strong>ወአካላትሰ ለለአሐዱ አካል ፍጹም ውእቱ በበገጹ ወበበመልክዑ&nbsp;እንዘ ኢይትሌለይ በመለኮት</strong></span>\"ሃይ.አበው 60፥2</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ <span style=\"color: rgb(132, 63, 161);\"><strong>&ldquo;<span style=\"color: rgb(186, 55, 42);\">አብ አሐዱ ፍጹም በአካሉ ወወልድ አሐዱ ፍጹም በአካሉ ወመንፈስ ቅዱስ አሐዱ ፍጹም በአካሉ ወአኮ እሉ ከመ መዓርገ መንግሥት አላ አሐዱ መለኮቶሙ ወአሐዱ ምኵናኖሙ ወአሐዱ ሥምረቶሙ</span></strong></span>\" ሃይ. አበው 71 ፥2 ብሏል።</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉ሥላሴ በአካል ሦስት ናቸው ለማለት ብዙ የመጽሐፍ ቅዱስ ማስረጃ</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>አለ።ለአብነትም ያህል.....</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(230, 126, 35);\"><strong>\"ዘአነ እፌኑ ለክሙ እም ኀበ አብ መንፈሰ ጽድቅ ዘይወጽእ እምኀበ አብ&nbsp;ውእቱ ሰማዕትየ</strong></span>\" ዮሐ 15 ፣26፣ኢሳ 6&divide;3፣ዘፍ 1&divide;26፣ዘፍ 18 &divide;1 ለበለጠ መረጃ ተመልከቱ!!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦&nbsp;</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉 <span style=\"color: rgb(22, 145, 121);\"><strong>ሥላሴን በአካል 3 ስንል ልብ ልንላቸው የሚገቡ ነገሮች እነማን ናቸው?</strong></span></em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦&nbsp;</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>3 አካል ብንልም እንኳን 3 እግዚአብሔር የማንል መሆኑን፤<span style=\"color: rgb(132, 63, 161);\"><strong>\"መቅድመ ኩሉ ንእመን በአሐዱ አምላክ ዘቦቱ ሠለስቱ አካላት</strong></span>\"ከሁሉ&nbsp;አስቀድመን ሦስት አካላት ባለው አንድ አምላክ ልናምን ይገባል\"ሃይ.አበው ባስልዮስ ዘቂሳርያ 34 &divide;2 \"<span style=\"color: rgb(22, 145, 121);\"><strong>ሠለስቱ ህላዌ በአካላት፣ወአሐዱ ህላዌ በመለኮት</strong></span>\"ሃይ.አበው 34 &divide;2</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ሦስት አካል ብንልም እያንዳንዳቸው ልብ፣ቃል፣እስትንፋስ የላቸውም።በሰፊው ኩነት ላይ የምናየው ይሆናል....</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ሦስት አካል ብንልም አንዱ አካል ከሌላው አካል ተለይቶ የተገኘበት ዘመን የለም ወደፊትም አይኖርም።</em></span></li>\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>በሰው ባህርይ ሦስት አካል ተደርድረውበት እንዲሞሉ በሥላሴ ዘንድ ግን እንዲህ አይደለም።አካል የሌለው ባህርይ፤ባህርይ የሌለው አካል አካል ስለሌለ በእያንዳንዳቸው ባህርይ አላቸው የማንል መሆኑን፤</em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(186, 55, 42);\"><strong><span style=\"color: rgb(224, 62, 45);\">✦. </span>ባህርይ፦</strong></span></em></span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em>ማለት የአካል መገኛ(ስር) ማለት ነው።አንድም አካል ስራውን የሚሰራበት መሳሪያ ነው።<span style=\"color: rgb(230, 126, 35);\"><strong>\"ኢይደሉ ይኩን ህላዌ ዘእንበለ አካል ወኢይደሉ ይትረከብ አካል ዘእንበለ&nbsp;አምሳሉ ለአካል ዘውእቱ አርዓያሁ\"</strong></span> ባህርይ ያለ አካል፣አካልም ያለ ባህርይ ብቻ ሊገኝ አይችልም ነውና ነገሩ ወዳጄ አስተውል!!ከላይ ያየነውን በምሳሌ እንመልከት በጣም ቀለል ለማድረግ አካል ያለ ባህርይ፤ባህር ያለ አካል እንደማይገኝ:-ውሃ አካልም ባህርይም አለው።አካሉ \"<strong><span style=\"text-decoration: underline;\">በእጅ ባይጨበጥም፣ በጥርስ&nbsp;ባይላመጥም</span></strong>\" ሲፈስ ወይም <span style=\"text-decoration: underline;\"><strong>\"በቀላይ ተዘርግቶ፤በማድጋ ተቀድቶ</strong></span>\"ይታያል።ባህርዩም እርጥበት ነው።ይህ ባህርዩ የሆነው እርጥበት አካሉ በደረሰበት ሁሉ ይገኛል እንጂ አካሉ በሌለበት ብቻው ሊገኝ አይችልም።</em></span>\r\n<div>\r\n<h2 style=\"font-size: 14pt;\">&nbsp;</h2>\r\n<div>\r\n<h2 style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"color: rgb(35, 111, 161); font-size: 24pt;\">ህልውና አካላት እንዴት ይታያል?</span></strong></em></span></h2>\r\n<div style=\"font-size: 14pt;\">\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(224, 62, 45);\"><strong>✦ ህልውና:-</strong></span>ማለት አንዱ አካል በአንዱ አካል መኖር ማለት ነው።ይህም&nbsp;ሲባል አብ በወልድ በመንፈስ ቅዱስ ህልው ነው።ወልድም በአብ በመንፈስ&nbsp;ቅዱስ ህልው ነው።መንፈስ ቅዱስም በአብ በወልድ ህልው ነው። <span style=\"text-decoration: underline;\">ውሕደት&nbsp;ግን አይደለም።ምክንያቱም ረቂቅ ከረቂቅ ህላዌን እንጂ ውሕደትን&nbsp;አይፈጥርም።</span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>አስተውሉ፦</strong></em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-size: 14pt;\"><span style=\"font-size: 14pt;\"><em><strong><span style=\"color: rgb(35, 111, 161);\">ውህደት ለባህርይ እንጂ ለአካላት አይነገርም።ውህደት የሚነገር\"ለቃል ስጋ ኮነ\"ነው።ዮሐ 1&divide;14</span></strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>👉&ldquo;<strong><span style=\"color: rgb(230, 126, 35);\">ሥላሴ በተዋሕዶ ፍጹም ወተዋሕዶ በሥላሴ ፍጹም</span></strong>- አንድነት በፍጹም&nbsp;ሦስትነት ሦስትነትም በፍጹም አንድነት አለ&rdquo; ሃይ. አበው 108፥2።<span style=\"color: rgb(22, 145, 121);\"><strong>\"ነአምን ከመ አብ በወልድ ወበመንፈስ ቅዱስ ወወልድ በአብ ወበመንፈስ&nbsp;ቅዱስ ወመንፈስ ቅዱስ በአብ ወበወልድ ዛቲ ሥላሴ ዕሪት እንበለ ፍልጠት&nbsp;በሠለስቱ አካል ወአሐዱ መለኮት\"</strong></span>ሃይ. አበው 11 ፥5</em></span></div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 24pt; color: rgb(186, 55, 42);\"><strong>አብ በሁሉ የመላ ከሆነ ወልድና መንፈስ ቅዱስ በምን ይመላሉ?</strong></span></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div>✦ .አካላት በአካላት ህልዋነ አካላት ምሉዓነ አካላት ናቸው።&ldquo;<span style=\"color: rgb(230, 126, 35);\"><strong>ዘውእቱ አሐዱ ብርሃን ዘይሠርቅ እምኔሁ ሥላሴ ወይመልእ ኵሎ ፍጥረታተ </strong></span><span style=\"color: rgb(230, 126, 35);\"><strong>ወያበርህ ለእለ መትሕተ ምድር በከመ ጽሑፍ እስመ አነ እመልእ ሰማየ&nbsp;ወምድረ ወእለ ሀለዉ ውስተ መትሕተ ሲኦል ርእዩ ስብሓትየ</strong></span>-ሃይ. አበው&nbsp;ዘአግናጥዮስ 11፥9።</div>\r\n<div>👉ፍጡራን በፈጣሪ ዓለምነት ይኖራሉ።ጫጩት እንቊላሉ እስኪፈለፈል ድረስ&nbsp;በእንቊላሏ ውስጥ ይኖራል።ዶሮም እንቊላሏን ብትታቀፍ ከእንቊላሏ ውጪ&nbsp;እንጂ በእንቊላሏ ውስጥ መኖር አትችልም። ፍጡር በያዘው ላይ መኖር&nbsp;አይችልም።ለአብነትም ያህል ለፍጡር ስንናገር ለምሳሌ ለሰው ልጅ ሰው በቤቱ&nbsp;ይኖራል፤ቤቱ ግን በሰው ላይ አይኖርም።በዓለመ ሥላሴ ግን እንዲህ&nbsp;አይደለም።ምክንያቱም በፈጠሩት ፍጥረት እና ከፈጠሩት ፍጥረት በአፍኣ</div>\r\n<div>ይኖራሉ።መገፋፋትም የለባቸውም። ለዚህም ማስረጃ በአንድ ቤት ያሉ&nbsp;አምፖሎችን ብርሐን እንደማይገፋፉ መመልከት በቂ ነው።\"<span style=\"color: rgb(45, 194, 107);\"><strong>ዓለማተ ዓለም ሥላሴ ዘአልብክሙ ዓለም\"</strong></span>- የዓለማተ ዓለም ፈጣሪ ለእነርሱ&nbsp;ዓላም አላቸው ተብሎ አይነገርላቸውም።</div>\r\n<div>✦ ሳጠቃልለው &ldquo;<span style=\"color: rgb(35, 111, 161);\"><strong>አልብነ ጠፈር ወአልብነ መሠረት ንሕነ ጠፈር ወንሕነ&nbsp;መሠረት አልቦ ዘይክል ርእዮተነ ወአልቦ ዘየአምር ዘከመ እፎ ህላዌነ ንሕነ&nbsp;ነአምሮ ለኩሉ ወንሕነ ንጤይቆ ለኩሉ ነአትቶ ለልጹቅ ወናቀርቦ ለርኁቅ</strong></span> -ሠለስቱ ምእት ቁጥር 42 ሠለስቱ ምእቱ</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">&nbsp;</span>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 24pt; color: rgb(186, 55, 42);\"><strong>የስም ሦስትነት:-</strong></span></div>\r\n<div style=\"font-size: 14pt;\">👉የሥላሴ የስም አይነቶች 4ት ናቸው።እነርሱም፦</div>\r\n<div style=\"font-size: 14pt;\">\r\n<ul>\r\n<li>&nbsp;.ስመ አካል፣</li>\r\n<li>.ስመ ግብር፣</li>\r\n<li>ስመ ከዊን፣</li>\r\n<li>ስመ ተዋሕዶ(አንድነት) ናቸው፡፡</li>\r\n</ul>\r\n</div>\r\n<div style=\"font-size: 14pt;\"><strong>አስተውሉ:</strong>-እዚህ ላይ የምናየው ግን ስመ አካልን ነው።</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(53, 152, 219);\"><strong>✦.የስም ሦስትነት:</strong></span>-ሥላሴ በስም አብ፤ወልድ፤መንፈስ ቅዱስ ናቸው።የስም ተፋልሶ የለም።\"<span style=\"color: rgb(35, 111, 161);\"><strong>ኢይፈልስ አብ ለከዊነ ወልድ ወመንፈስ ቅዱስ ወኢወልድ ለከዊነ አብ ወመንፈስ ቅዱስ ወኢመንፈስ ቅዱስ ለከዊነ አብ ወወልድ እሉ ፫ቱ አካላት ፍጹማን ዲበ መንበረ ስብሐት እኁዛን በጽፍረተ አሐዱ መለኮት</strong></span> \"(ሃ.አበው ዘአግናጥዮስ 11&divide;8) በማለት በአስደናቂ ቃል ተናግሮታል።ማለትም አብ አብ ተብሎ ቢጠራ እንጂ ወልድ መንፈስ ቅዱስ ተብሎ አይጠራም፤ ወልድም ወልድ ተብሎ ቢጠራ እንጂ አብ መንፈስ ቅዱስ ወደመባል አይለወጥም፣መንፈስ ቅዱስም መንፈስ ቅዱስ ቢባል እንጂ አብ ወልድ ተብሎ ሊጠራ አይቺልም።እነኚህ ሦስቱ አካላት በጌትነት በክብር ፍጹማን ናቸው በአንድ መለኮት&nbsp;አንድነትም አንድ ናቸው።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\">\"<span style=\"color: rgb(22, 145, 121);\"><strong>ሑሩ ወመሐሩ ኩሎ አህዛበ እንዘ ታጠምቅዎሙ በስመ አብ ወወልድ&nbsp;ወመንፈስ ቅዱስ</strong></span>\" ማቴ 28-20 አንድም&nbsp;\"<span style=\"color: rgb(186, 55, 42);\"><strong>ስመ አብ ብከ ወስመ ወልድ ለሊከ ወስመ መንፈስ ቅዱስ ሕልው&nbsp;ውስቴትከ</strong></span>\"-የአብ ስም በአባትነት ገንዘብህ ነው፣ወልድ የሚለውም ያንተ ስም ነው፤ስመ መንፈስ ቅዱስም በህልውናህ አለ\"እንዲል ትርጓሜ ወንጌል</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"background-color: rgb(35, 111, 161);\"><strong><span style=\"color: rgb(236, 240, 241);\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><strong>👉 በስመ አብ ወወልድ ወመንፈስ ቅዱስ ብሎ በመጀመር ፈንታ ወልድ&nbsp;አብ መንፈስ ቅዱስ ማለት ይቻላል?ተፋልሶ አያመጣም ?</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"background-color: rgb(35, 111, 161);\"><strong><span style=\"color: rgb(236, 240, 241);\">✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥✥</span></strong></span></div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(52, 73, 94);\">&nbsp;<strong>በስመ አብ ወወልድ ወመንፈስ ቅዱስ ብሎ በመጀመር ፈንታ ወልድ&nbsp;አብ መንፈስ ቅዱስ ማለት ይቻላል </strong></span><strong>ተፋልሶ አያመጣም</strong>; ምክንያቱም ሥላሴ በቅድምና አንድ&nbsp;ናቸውና።ማስረጃውም....</div>\r\n<div style=\"font-size: 14pt;\">\r\n<ul>\r\n<li>\"<span style=\"color: rgb(230, 126, 35);\"><strong>ሐይማኖትሰ እንተ እምኀበ አብ ተፈጥረት፤ኀበ ወልድ ታበጽሕ፤ወበኀ&nbsp;መንፈስ ቅዱስ ትትፌጸም</strong></span>\"እንዲል ሊቁ ቅ/ያሬድ</li>\r\n<li>\"<span style=\"color: rgb(186, 55, 42);\"><strong>ጸጋሁ ለእግእዚነ ኢየሱስ ክርስቶስ ወፍቅረ እግዚአብሔር ወሱታፌ መንፈስ ቅዱስ የሀሉ ምስሌክሙ</strong></span>\"-የጌታችን የኢየሱስ ክርስቶስ ጸጋው</li>\r\n</ul>\r\n</div>\r\n<div style=\"font-size: 14pt;\">የእግዚአብሔር ፍቅር የመንፈስ ቅዱስ ሕብረት አንድነት ከእናንተ ጋር ይሁን\"፪ኛ ቆሮ 13&divide;13 እንዳለ ቅ/ጳውሎስ</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(53, 152, 219);\"><strong>✦.</strong></span>አንድም ይህ አብ ወልድ መንፈስ ቅዱስ የሚለው ስም የምሉዓን የፍጹማን አካላት የሥላሴ የአካል ተጸውዖ ግል ስም ነው።</div>\r\n<div style=\"font-size: 14pt;\">\"<span style=\"color: rgb(132, 63, 161);\"><strong>ለአብ ቦቱ ስብሐት ወስመ አብና ወለወልድ ቦቱ ስብሐት ወስመ ወልድና&nbsp;ወለመንፈስ ቅዱስ ቦቱ ስብሐት ወስመ መንፈስ ቅድስና</strong></span>\" - ለአብ የአባትነት</div>\r\n<div style=\"font-size: 14pt;\">ስም የአባትነት ክብር አለው።ለወልድም በባሕርይ ክብሩ ከአብ ሳያንስ&nbsp;የልጅነት ስም የልጅነት ክብር አለው።መንፈስ ቅዱስም እንዲሁ በክብር</div>\r\n<div style=\"font-size: 14pt;\">አይለያይም።ነገር ግን ተለውጦ አብ ወልድ መንፈስ ቅዱስም አይባልም&rdquo;ሃይ. አበው ጎርጎርዮስ ዘእንዚናዙ 60&divide;3 ይላል።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\">✔ .የእያንዳንዳቸው ስማቸው ፍፁም ክብር ያለው ኖሮ ኖሮ ያልወጣ ስም&nbsp;መሆኑን መረዳት ያስፈልጋል ወገኖቼ። ስለምን ቢባል አካል ያልቀደመው የአካል&nbsp;ስም ነውና። ስለዚህ ሥላሴ ስማቸው አይቀድማቸውም። አካላቸውም&nbsp;ስማቸውን አይቀድምም። አካል ከስም፤ስም ከአካል ተቀዳድሞ አይገኝም።</div>\r\n<div style=\"font-size: 14pt;\">&ldquo;<span style=\"color: rgb(35, 111, 161);\"><strong>ወናሁ ንቤ ካዕበ አብ ወወልድ ወመንፈስቅዱስ ወአኮ እሉ አስማት ዘቦኡ&nbsp;ላዕሌሆሙ ድኅረ እላ እሙንቱ ስመ አካላት</strong></span>\"-አሁን ደግሞ አብ ወልድ መንፈስ</div>\r\n<div style=\"font-size: 14pt;\">ቅዱስ እንላለን። እነዚህ ስምች ግን የአካላት ስሞች ናቸው እንጂ አካላት&nbsp;ቀድመው ተገኝተው በኋላ የተጠሩባቸው አይደለም&rdquo; ሰው መባልም ሰው</div>\r\n<div style=\"font-size: 14pt;\">ከመሆን በኋላ የመጣ ስም አይደለም። (ጎርጎርዮስ ገባሬ ተአምራት ዘቀጰዶቅያ&nbsp;13 &divide;4) እንዲል።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(53, 152, 219);\"><strong>✦.</strong></span>ሳጠቃልለው ስም አካልን፤አካልም ስምን ሳይቀድመው የሚጠሩበት ስም ነውና በዚህ ስም በየግላቸው በግል ስማቸው ይጠሩበታል።</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(224, 62, 45);\"><strong>&ldquo;ወንሰምዮሙ በሠለስቱ አስማት ዘውእቶሙ አብ ወወልድ ወመንፈስ ቅዱስ </strong></span><span style=\"color: rgb(224, 62, 45);\"><strong>አሐዱ መለኮት ወአሐዱ ኃይል እንዘ ሠለስቱ አካላት</strong></span>- በስም ሦስት ናቸው</div>\r\n<div style=\"font-size: 14pt;\">እንላለን። አብ ወልድ መንፈስ ቅዱስ ሦስት አካላት ሲሆኑ አንድ ባህርይ&nbsp;አንድ ሥልጣን ናቸው&rdquo; (ጎርጎርዮስ ዘእንዚናዙ ነባቤ መለኮት 60&divide;7)</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161); font-size: 18pt;\"><strong>ማጠቃለያ:</strong></span>-<strong>በአጠቃላይ የስም የእነኚህ ስም መገለጫዎች</strong></div>\r\n<div>\r\n<ul style=\"font-size: 14pt;\">\r\n<li style=\"font-weight: bold;\"><strong>&nbsp;ዘኢይፈልስ፣</strong></li>\r\n<li style=\"font-weight: bold;\"><strong>ብሑትነት፣</strong></li>\r\n<li style=\"font-weight: bold;\"><strong>ቀዋሚነት፣</strong></li>\r\n<li style=\"font-weight: bold;\"><strong>ኢደኃራዊነት ናቸው።</strong></li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 18pt;\"><strong>የግብር ሦስትነት:-</strong></span></div>\r\n<div style=\"font-size: 14pt;\">👉ሥላሴ በአካል የሚጠሩበት ስም እንዳላቸው እንደተመለከትን ከዚህ&nbsp;ደግሞ በግብር የሚጠሩበትን ስም በአጭሩ እንመለከታለን የግብር ስም</div>\r\n<div style=\"font-size: 14pt;\">ማለት አንድ አካል ስለ ሥራው የሚጠራበት ስም ማለት ነው፡፡</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><span style=\"font-size: 18pt;\"><strong>✦.</strong></span><strong>እንደዋናነት የግብር አይነቶች ሁለት ናቸው።እነርሱም</strong></span><strong>፦</strong></div>\r\n<div style=\"font-size: 14pt;\">\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-weight: bold;\"><strong>አፍአዊ ግብር(ግብረ ዋህድና) እና</strong></li>\r\n</ul>\r\n</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-weight: bold;\"><strong>ውሳጣዊ ግብር(ግብረ ሥላሴ) ናቸው።</strong></li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>✦ .ግብረ -ዋህድና፦</strong></span>አፍአዊ ሥራ የመፍጠር፣የመመገብ ፣የማሳለፍ ወዘተ...</div>\r\n<div style=\"font-size: 14pt;\">ምሳሌ፦\"<span style=\"color: rgb(22, 145, 121);\"><strong>ንግበር ሰብአ በአርአያነ ወበአምሳሊነ</strong></span>\"</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>✦ .ግብረ- ሥላሴ(ውሳጣዊ ሥራ)፦</strong></span>በዓለመ ሥላሴ ብቻ የሚነገር ወላዲ፤ተዋላዲ፤ሠራፂ የሚባሉት ናቸው።ይህ የአንደኛውን ግብር ለሌላኛው</div>\r\n<div style=\"font-size: 14pt;\">አድሎ መስጠት አይቻልም።</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 18pt;\">የግብር ሦስትነት:</span>-</strong></span>አብ በተለየ አካሉ በተለየ ግብሩ ወላዲ&nbsp;አስራፂ፤ወልድ በተለየ አካሉበተለየ ግብሩ ተወላዲ፤መንፈስ ቅዱስ</div>\r\n<div style=\"font-size: 14pt;\">በተለየ አካሉ በተለየ ግብሩ ሠራፂ ነው።</div>\r\n<div style=\"font-size: 14pt;\">&nbsp; &nbsp; &nbsp;\"<span style=\"color: rgb(186, 55, 42);\"><strong>በስመ አብ ወላዲ ወኢተወላዲ ወኢሠራጺ ወልድኒ ተወላዲ&nbsp;ወኢወላዲ ወኢሠራጺ ወመንፈስ ቅዱስኒ ሠራጺ ወኢወላዲ&nbsp;ወኢተወላዲ\"</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"font-size: 18pt;\"><strong>አስተውሉ፦</strong></span>ባህርይን በፍጡራን ደረጃ በሁለት ከፍለን ማየት&nbsp;እንቺላለን።ይኸውም</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li>ስመ ባህርይ፣</li>\r\n<li>ስመ ግብር ነው።</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><strong>✦ .ስመ ባህርይ:</strong></span>-አካል ስምን ሳይቀድመው፤ስምም አካልን ሳይቀድመው&nbsp;የሚገኝ ነው።</div>\r\n<div style=\"font-size: 14pt;\"><strong>ምሳሌ፦</strong>ሰው ከአራቱ ባህርያተ ስጋ ስለተገኘ ሰው ተባለ።</div>\r\n<div style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">✦.ስመ ግብር፦</span></strong>ለሰው ሲሆን ሰዓሊ፤ጸሐፊ፤ደራሲ እንደሚባለው ያለ ነው።በአጭሩ ስመ ግብር ማለት በግብር የሚጠሩበት ስም አለ ማለት ነው አብ</div>\r\n<div style=\"font-size: 14pt;\">ቢወልድ ወላዲ ተባለ እንጂ አብ አልተባለም፤ወልድ ቢወለድ ተወላዲ ተባለ&nbsp;አንጂ ወልድ አልተባለም፤መንፈስ ቅዱስ ቢሠርጽ ሠራጺ ተባለ እንጂ መንፈስ</div>\r\n<div style=\"font-size: 14pt;\">ቅዱስ አልተባለም ማለት ነው።ይህም በግበር ብቻ የሚጠሩበት ነው ወደ&nbsp;አካል ወደከዊን አይፋለስም ሥላሴን ፍሉጣን ከሚያስብላቸው ዋነኛውም</div>\r\n<div style=\"font-size: 14pt;\">ይህ ነው፡፡</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong>*የአካል ተጸውዖ ስም፦</strong>አብርሐም፤ይስሐቅ፤ያዕቆብ እንደሚለው አይነት ነው።ነገር ግን አንድ የምናስተውለው ነገር ምንድን ነው ካላችሁኝ:-</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(230, 126, 35);\"><strong>አንድ ሰው በሚያስተምር ጊዜ መምህር ይባላል።አንድ ሰው ሀኪም በሆነ&nbsp;ጊዜ ዶክተር ይባላል።ማስተማሩን ቢያቆም(ቢተው)ግን መምህር ነበር እንጂ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(230, 126, 35);\"><strong>ነው አይባልለትም።ዶክተሩም እንዲሁ ነው።</strong></span></div>\r\n<div style=\"font-size: 14pt;\">✔ .በዓለመ ሥላሴ ግን አብ ዘወትር አባት ወላዲ አስራፂ፤ወልድ ልጅ&nbsp;ተወላዲ፤መንፈስ ቅዱስ ሠራፂ ሲባሉ ይኖራሉ እንጂ ዘመን የሚሽረው</div>\r\n<div style=\"font-size: 14pt;\">ወይም የሚለወጥ አይደለም።</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(22, 145, 121);\"><strong>&nbsp; &nbsp; \"አብሰ ኢተወልደ አላ ወላዴ ወልድ ውእቱ እምቅድመ ኩሉ ዓለም ወልድኒ ተወልድ እም እግዚአብሔር አብ እምቅድመ ኩሉ ዓለም መንፈስ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(22, 145, 121);\"><strong>&nbsp; &nbsp; &nbsp; ቅዱስኒ ሠረጸ እምእግዚአብሔረ አብ እምቅድመ ኩሉ ዓለም</strong></span>\"እንዲል ሃይ.አበው አትናቴዎስ</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">✦.</span></strong>የወልድ ልደቱ አልተፈጸመም፤የአብ ወላዲነቱ አስራፂነቱ አልተፈጸመም፤የመንፈስ ቅዱስ ሠራፂነቱም አልተፈጸመም።ማለትም ቀዳማዊ ወላዲ አስራፂ</div>\r\n<div style=\"font-size: 14pt;\">አብ መውለዱ ማስረጹ የሚፈጸም የሚያልቅ አይደለም;ምክንያቱም ቢያልቅ&nbsp;ቢፈጸም ኖሮ ግን አብ ወልድን የወለደበትና መንፈስ ቅዱስን ያሰረጸበት ዘመንና&nbsp;ጊዜ በታወቀ ነበር።ወልድም ልደቱ ዘኢይኀልቅ(ዘወትር ወልድ ሲባል ይኖራል)&nbsp;ነው።</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"color: rgb(186, 55, 42);\">\"<strong>ወኢተፈጸመ ልደቱ አላ ውእቱ ወትረ ይትወለድ እምኔሁ ኩሎ ጊዜ\"</strong></span>-ዘወትር ሁልጊዜ ሲወለድ ይኖራል እንጂ ልደቱ አልተፈጸመም ፣ለበለጠ መረጃ ምሥጢረ ምሥጢራት ገጽ 226 አንብቡ</li>\r\n<li>\"<span style=\"color: rgb(35, 111, 161);\"><strong>ወኢትሰአለኒ ዘከመእፎ ልደቱ ለወልድ ዋህድ እም አብ\"</strong></span>-ወልድ ዋህድ ከአብ መወለዱ እንዴት እንደሆነ አትጠይቀኝ\"-ሀ.አበው ቴዎዶጥስ 53&divide;16 እንዳለ</li>\r\n<li>\r\n<div>-\"<span style=\"color: rgb(185, 106, 217);\"><strong>ልደተ ወልድ ወጸዓተ መንፈስ ቅዱስ ኢይትነገር አላ ይትነከር</strong></span>\"-የወልድ&nbsp;መወለድ የመንፈስ ቅዱስ መስረጽ ይደነቃል እንጂ አይነገርም\"ሃይ.አበው</div>\r\n<div>ዘዲዮናስዮስ 10&divide;12</div>\r\n</li>\r\n<li>\r\n<div><span style=\"color: rgb(22, 145, 121);\"><strong>\"ሥላሴ ትትረም ወትትነከር\"</strong></span>-ሥላሴ ትደነቃለቺ እንጂ አትነገርም።</div>\r\n</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\"><strong>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><strong>&nbsp;<span style=\"font-size: 18pt;\"><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span><span style=\"color: rgb(22, 145, 121);\">አብ ስለወለደ ወልድ ደግሞ ተወለደ መንፈስ ቅዱስ ደግሞ ሠረፀ ስላልን<span style=\"font-size: 14pt;\"> ማነስ መበላለጥ መቀዳደም በሥላሴ ዘንድ አለ?</span></span></span></strong></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42); background-color: rgb(251, 238, 184);\"><strong>✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦ ✦<span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>&nbsp;✦ ✦ ✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦ ✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦ ✦ ✦✦ ✦ ✦ <span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span>✦ ✦ ✦ ✦ ✦<span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦</span> ✦ ✦ ✦&nbsp;</strong></span></div>\r\n<p style=\"font-size: 14pt;\"><strong>&nbsp;<span style=\"font-size: 18pt;\"><span style=\"background-color: rgb(251, 238, 184); color: rgb(132, 63, 161);\">✦ </span></span></strong><span style=\"color: rgb(0, 0, 0);\"><span style=\"font-size: 18pt;\"><span style=\"font-size: 14pt;\">አብ ስለወለደ ወልድ ደግሞ ተወለደ መንፈስ ቅዱስ ደግሞ ሠረፀ ስላልን </span></span>በስላሴ መበላለጥና መቀዳደም የለም።</span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li>\"<span style=\"color: rgb(186, 55, 42);\"><strong>ወሶ ንቤ ከመ አብ ኢተወልደ ወወልድሂ ተወልደ ወመንፈስ ቅዱስሂ ወጽአ&nbsp;እምኔሁ ኢትኀሊ ከመ ወልድ ይሐጽጽ እም አብ ወመንፈስ ቅዱስሂ እም&nbsp;ወልድ\"</strong></span>-አብ አልተወለደም ስላልን ወልድ ግን ተወለደ መንፈስ ቅዱስ ከአብ&nbsp;ሠረፀ ስላልን ወልድ ከአብ እንደሚያስ አታስብ መንፈስ ቅዱስም ከወልድ&nbsp;እንደሚያንስ አታስብ\"ሃይ.አበው ዮሐንስ ዘአንጾኪያ 107&divide;3</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div style=\"font-size: 14pt;\"><em><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp; በዓለመ ፍጡራን አባት ልጁን ቀድሞ ይገኛል።በዓለመ ሥላሴስ መቀዳደም አለ?</strong></span></em></div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(132, 63, 161);\">✦.</span></strong>በዓለመ ሥላሴ መቀዳደም የለም!!ሥላሴ በቅድምና አንድ ናቸው።ይህንንም የሚያስረዳ:-ቅዱስ ጴጥሮስ \"ጌታዬ ሆይ አነዋወርህ&nbsp;እንደምን ነው ቢለው\"<span style=\"color: rgb(186, 55, 42);\"><strong>አቡየ ፀሐይ ወአነ ብርሐኑ ወመንፈስ ቅዱስ ዋዕዩ\"</strong></span>አብ&nbsp;ፀሐይ ነው፤እኔ ብርሐኑ ነኝ፤መንፈስ ቅዱስ ሙቀቱ ነው\"መጽሐፈ ቀለምኒጦስ፣</div>\r\n<div style=\"font-size: 14pt;\">➡.ይህ ማለት ፀሐይ ስትወጣ ክበቧ ብርሐኗ ሙቀቷ ይገለጻል።ብርሐኑና ሙቀቱ ከፀሐይ ይገኛል።ክበቡ የብርሐኑና የሙቀቱ አስገኝ በመሆኑ&nbsp;ከብርሐንና ከሙቀት የምትቀድምበት ጊዜ ቀድማ የኖረችበትም ጊዜ አለ&nbsp;አይባልም።ምክንያቱም ያለ ብርሐንና ሙቀት ከነበረች የኖረችበትም ጊዜ ካለ&nbsp;ፀሐይ ሳትሆን ሌላ ነት።ምክንያቱም አታበራም አታቃጥልም።ይህ ሲባል&nbsp;ብርሐኑ፣ሙቀቱ፣ክበቡ 3ት ቢሆንም የምንለው ግን አንድ ፀሐይ ነው።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\">👉 .ይህንንም ሊቁ አባ ሕርያቆስ በመጽሐፈ ቀለምኒጦስ ያለውን በደንብ&nbsp;አብራርቶታል።ቃሉም እንዲህ ይላል \"<span style=\"color: rgb(35, 111, 161);\"><strong>አብ ፀሐይ ወልድ ፀሐይ መንፈስ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(35, 111, 161);\"><strong>ቅዱስ ፀሐይ አሐዱ ውእቱ ፀሐየ ጽድቅ ዘላዕለ ኩሉ</strong></span>\"-አብ ፀሐይ ነው ወልድ&nbsp;ፀሐይ ነው መንፈስ ቅዱስ ፀሐይ ነው አንድ የህይወት ፀሐይ ነው።</div>\r\n<div style=\"font-size: 14pt;\">*ስለዚህ በፀሐይ ግብር ተቀድም ተድኅሮ እንዳልሰጠነው በሥላሴ ግብርም&nbsp;ተቀድሞ ተድኅሮ(መቀዳደም) አንሰጠውም።</div>\r\n<div style=\"font-size: 14pt;\">👉 <strong>አስተውሉ፦</strong>የአብ ወላዲነት አስራፂነት ፣የወልድ ተወላዲነት፣የመንፈስቅዱስ ሰራፂነት ዘለዓለማዊ ነው፡፡</div>\r\n<div style=\"font-size: 14pt;\">\"<span style=\"color: rgb(132, 63, 161);\"><strong>ወቃለ እግዚአብሔር ህልው በአካሉ እምህላዌ ልዑል ወፅኑእ ወውእቱ&nbsp;ቀዳማዊ ብሉየ መዋእል ህልው ምስሌሁ እምቀዲሙ ወኢይትፈለጥ እምኔሁ</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161);\"><strong>ወኢየሀልቅ ልደቱ እምኔሁ አላ ውእቱ ብሉየ መዋእል ምስሌሁ በኩሉ ጊዜ&nbsp;ዘእንበለ ፍልጠት\"</strong></span>ሃይ አበ 13 &divide;24</div>\r\n<div style=\"font-size: 14pt;\">&nbsp;</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>ማጠቃለያ፦</strong></span>ግብር የሚለውንና የግብር አይነቶችን ስንመለከት ከላይ ያለው&nbsp;እንዳለ ሁኖ ለበለጠ እውቀትና ሕይወት እነዚህን ነጥቦች እናንተ በሰፊው</div>\r\n<div style=\"font-size: 14pt;\">ተመልከቷቸው።</div>\r\n<div style=\"font-size: 14pt;\">👉 <span style=\"color: rgb(22, 145, 121);\"><strong>የግብር አይነቶች:-</strong></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li>ውሳጣዊ አካላዊ ግላዊ ግብር፣</li>\r\n<li>ውሳጣዊ አካላዊ ባሕርያዊ፣</li>\r\n<li>ከዊናዊ ተገናዛቢ ግል ግብር፣</li>\r\n<li>አፍኣዊ አካላዊ የባሕርይ ግብር፣</li>\r\n<li>ግብረ ሥጋዌ ዘወልድ፣</li>\r\n<li>ግብረ ሀብት ዘመንፈስ ቅዱስ ናቸው።</li>\r\n</ul>\r\n<div style=\"font-size: 14pt;\"><span style=\"color: rgb(132, 63, 161); font-size: 18pt;\"><strong>የኩነት ሦስትነት</strong></span></div>\r\n<div style=\"font-size: 14pt;\"><strong>➡የኩነት ሦስትነት:</strong>-ኩነት ማለት መባል መሆን ሁኔታ ማለት ነው።ሥላሴ በኩነት አብ፤ወልድ ቃል፤መንፈስ ቅዱስ እሥትንፋስ(ሕይወት)&nbsp;ነው። ይኸውም፦አካላት በሕልውና የሚገናዘቡበት የባህርይ ከዊን ስም ነው።ተፈልጦ ተከፍሎ&nbsp;በሌለበት በአንዲት ባህርይ ያለ የከዊን ስም ነው።ከዊነ ልብ በአብ መሠረትነት ለራሱ አሳቢ ሁኖ ለወልድና ለመንፈስ ቅዱስ&nbsp;እውቀት መሆን ነው።ወልድም በአብ መሠረትነት ለራሱ(ነባቢ) ቃል ሆኖ ለአብና&nbsp;ለመንፈስ ቅዱስ ንባብ(መነጋገሪያ)መሆን ነው።መንፈስ ቅዱስም በአብ&nbsp;መሠረትነት ህያው ሆኖ ለአብና ለወልድ ህይወት መሆን ነው።</div>\r\n<div>\r\n<div style=\"font-size: 14pt;\"><strong>አስተውሉ፦</strong>እንዲህ ስላልን ግን አንዲትን መለኮታዊ ባህርይ ከ፫ አይከፍላትም።ስለዚህ ኩነታት በተለየ ባልተለየ እያልን እንናገራለን።በተለየ&nbsp;ስንል እያንዳንዳቸው አብ ልብ፤ወልድ ቃል፤መንፈስ ቅዱስ እሥትንፋስ&nbsp;መባል ሲሆን ባልተለየ ስንል ደግሞ ተገናዝቦ አቸውንና የእያንዳንዳቸው&nbsp;ልብ፤ ቃል፤እሥትንፋስ አለመኖሩ ነው።ስለዚህ ከዊንን አንድነት ሳለበት&nbsp;ልዩነት፤ልዩነት ሳለበት አንድነት ነው።</div>\r\n<div style=\"font-size: 14pt;\"><strong>በአጭሩ፦</strong>\"ልዩነቱ በ', '', '', '', 'Module: ነገረ ሃይማኖት\n- Lesson: የነገረ ሃይማኖት መግቢያ\n- Lesson: ሃይማኖት ማለት ምን ማለት ነው?ሐይማኖት መቼ ተገለጠ?በማን ተገለጠ?\n- Lesson: አዕማደ ምሥጢራት\n- Lesson: አዕማድ ማለት ምን ማለት ነው?\n- Lesson: ለምን ምስጢራት ተባሉ? .', '<article class=\"builder-output-card\"><h4>1.የቃል እና ስጋን ተዋህዶ በብረት እና በእሳት ተዋሕዶ መስሎ የተናገረዉ ሊቅ ማን ነው?</h4><ol><li>ቅዱስ አትናቴዎስ</li><li>ቅዱስ ቄርሎስ</li><li>ቅዱስ ሄሬኔዎስ</li><li>ቅዱስ ጳውሎስ</li></ol><p><strong>Answer:</strong> ቅዱስ ቄርሎስ</p></article><article class=\"builder-output-card\"><h4>2.ለለባዊ አፍአዊ ግብር &quot;አለባዊ&quot; ካልን ለሕያው  አፍአዊ  ግብር ምን እንላለን?</h4><ol><li>ሕያው</li><li>ንባብ</li><li>ሕይወት</li><li>ማኅየዊ</li></ol><p><strong>Answer:</strong> ማኅየዊ</p></article><article class=\"builder-output-card\"><h4>ቅብነት መሆን የመንፈስ ቅዱስ አካላዊ ዉሳጣዊ ግብር ነው</h4><ol><li>እዉነት</li><li>ሀሰት</li><li>ሀ እና ለ</li><li>አይባልም</li></ol><p><strong>Answer:</strong> ሀሰት</p></article>', '<article class=\"builder-output-card\"><h4>የቤተ ገብርኤል ነገረ ሃይማኖት አሳይመንት</h4><p>እባክዎ ይህንን አሳይመንት ለሕይወት ብለዉ ከቅዱሳት መጻሕፍት አገላብጠው መምህራንን ጠይቀው ለመስራት ይሞክሩ።</p><p class=\"small\">Due: አሳይመንት የሚገባበት ቀን ከማጠቃለያ ፈተና ከመዉሰድዎ በፊት ነው • Points: 15%</p></article>', '', '2026-07-02 05:47:40', '', '');
INSERT INTO `courses` (`id`, `course_name`, `course_code`, `short_description`, `description`, `category`, `level`, `thumbnail`, `price`, `instructor`, `pdf_file`, `tutorial_topic`, `tutorial_text`, `tutorial_image`, `tutorial_audio`, `tutorial_video`, `modules`, `quiz`, `assignment`, `certificate_requirements`, `created_at`, `instructor_bio`, `instructor_image`) VALUES ('10', 'ነገረ ቅባት', '02929', '', '<h1>&nbsp;</h1>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"color: rgb(132, 63, 161); font-size: 36pt;\">ቅባት(ቅብዓት)</span></h1>\r\n<h2>&nbsp;<span style=\"font-size: 18pt;\"> <span style=\"font-size: 14pt;\"><em><strong>ቅባት(ቅብዓት) ትርጉሙ ምንድን ነው❓</strong></em></span></span></h2>\r\n<div><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(224, 62, 45);\">↪ቅባት በቅዱሳት መጽሐፍት ሲተረጎም የሚከተሉት ትርጉሞች አሉት።እነርሱም:-✔</span></strong></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">1ኛ.ቅባት ማለት በቁሙ ሲፈታ ቅባት ማለት ነው</span>።</strong>ቀባ፣ለከከ፣ለቀለቀ፣ቀባ የሚል ትርጉም ያመጣል።ለዚህም ማስረጃው-\"የመገናኛውንም ድንኳን የምስክሩንም ታቦት ገበታውንም ዕቃውንም ሁሉ መቅረዙንም ዕቃውንም መሰዊያውን ሁሉ ለሚቃጠለውም መሥዋዕት ለሚሆነው መሰዊያና ዕቃውንም ሁሉ የመታጠቢያውን ሰንና&nbsp;መቀመጫውን ትቀባበታለህ\"ዘጸ 30&divide;26</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">-\"ማርያምም እጅግ ዋጋው የከበረ የጥሩ ናርዶስ ሽቱ ንጥር ወስዳ የኢየሱስን እግር ቀባች\"ዮሐ 12 &divide;3 </span><span style=\"font-size: 14pt;\">=&gt;<span style=\"text-decoration: underline; color: rgb(185, 106, 217);\">ቅባት </span></span><span style=\"text-decoration: underline; color: rgb(185, 106, 217);\"><span style=\"font-size: 14pt;\">በቁሙ ሲፈታ</span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">2ኛ.ተቀብዐ:-ከበረ ተብሎ ይተረጎማል።</span></strong>ለዚህም ማስረጃ \"<strong>እለሰ የአምኑ ርቱዓ ይሜሀሩ ከመ ተቀብዓ ቃል በስጋሁ</strong>\"ትርጓሜውም ሲቀባም የሚለውም ሲከብርም ሲዋሐድም አንድ ጊዜ ነው ሲል ነው እንጂ በቁሙ ሲቀባ ስላለ ሲቀባ ተብሎ አይተረጎምም በቁም የሚተረጉሙ አሉና!!ወዳጄ \"መጽሐፍት ትርጓሜን እንጂ ዘይቤን አይጠነቅቁም \" እሽ!!ይህ ማለት ስጋ ከቃል ጋር ሲዋሐድ መጀመሪያ ተዋሕዶ በኋላ የከበረ አይደለም:ከብሮም ሳይዋሐድ አልቀረም;ሲከብርም ሲዋሐድም አንድ ጊዜ ነው እንጂ!! አንድም ከላይ ያለውን ያነሳነውን ቃል ሊቃውንተ ቤተ ክርስቲያን እንዲህ እያሉ አቅንተው ይተረጉሙታል።ኦሪት ወነቢያት ሰበኩ በክርስቶስ ሲል \"በክርስቶስ\" ያለው ክርስቶስሀ ማለት ነው። \"<strong>በ</strong>\" አገባብ በማድረግ \"<strong>ን</strong>\"የሚል ፍቺ ይሰጡና ኦሪትና ነቢያት በክርስቶስ ሰበኩ የሚለውን በቁሙ ኦሪትና ነቢያት ክርስቶስን ሰበኩ በማለት ይገልጹታል።ማለትም ክርስቶስን ይወርዳል ይወለዳል እያሉ ሰበኩ የወንጌልን አዝመራ ዘሩ ሐዋርያትም አጨዱት ነውና ቅሉ።ስለዚህ ይህንን ቃልም በሥጋሁ የሚለውን\"በ\"ን አገባብ አድርገው \"<strong>ሥጋን</strong>\" በማለት ይተረጉሙና ስጋን ተዋሐደ ብለው ያቀኑታል።</span></li>\r\n</ul>\r\n<p><span style=\"color: rgb(230, 126, 35);\"><strong><span style=\"font-size: 14pt;\">=&gt;.ያም ሆነ ይህ ግን ይህንን ነገር ስናነሳ እነዚህን ጥያቄዎች ማሰብ ያስፈልጋል።ማለትም በቁሙ መለኮት በስጋው ከበረ ከተባለ</span></strong></span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቅድመ ተዋህዶ ቃል ክብር አልባ ነበርን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ነውስ ቃል በጊዜ ተዋህዶ የባሕርይ ክብሩን አጥቷል?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ወልድን ከመለኮታዊ ክብሩ ዝቅ አያደርገውምን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቃል(መለኮት) በስጋው ከበረ ከተባለ ስጋን የተዋሐደ ከሦስቱ አካል አንዱ አካል ወልድ(አካላዊ ቃል) ነውና ሥላሴ በማክበር ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">መለኮት በስጋው ከከበረ በመለኮትነት ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.መክበር የተፈጸመውስ መቼ ነው???በጊዜ ተዋህዶ \"ርስት\" ሰጥቶ መናገርን የትኞቱ አበውና መጽሐፍት አስተማሩን?</span></em></span></strong></li>\r\n</ul>\r\n</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">3ኛ.ተቀብዐ:-ተዋሐደ ተብሎ ይተረጎማል።</span></strong>ብዙ ወገኖቻችን ግን ቀብዓን ተዋሐደ ብለው አይተረጉሙትም።ለዚህም ማስረጃ ታላቁ ሊቁ አባ ጊዮርጊስ ዘጋስጫ በመጽሐፈ አርጋኖን ዘአርብ ዕለት\"ዘተቀባዕከ ስጋሃ ለማርያም\"ብለዋል!!ይህ ንባብ የሚተረጎመው የማርያምን ስጋ የተዋሐድክ ተብሎ ነው!!ምክንያቱም በከበረ እንዳይተረጎም የማርያምን ስጋ የተከበርክ አይባልም::በቀብዓ እንዳይተረጎም የማርያምን ስጋ የተቀባህ አይባልም ስጋ ቅብዕ ይሆናልና።ስለዚህ የተዋሐድክ ብሎ አቅንቶ መተርጎም ያስፈልጋል ወዳጄ!!!</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">➠ስለዚህ ሳጠቃልለው አንድ ቃል እንደአውዱ እንደአገባቡ የተለያየ ትርጉም ይኖረዋልና አንዲትን </span><span style=\"font-size: 14pt;\">በዘፈቀደ አንጠልጥሎ ሁሌም በዚህ ነው የሚፈታ ማለት የዕውር ክርክር ነው።ለምሳሌ \"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልክት ማኅበር ቆመ\"መዝ 81&divide;1 ይላልና ቆመ ስላለ ብቻ ቆመ ብለን ልንተረጉመው ነው??በጭራሽ</span></div>\r\n<div><span style=\"font-size: 14pt;\">ቆመ ብለን አንተረጉመውም!!ታዲያ ምን ብለን እንተረጉመዋለን ትሉኝ እንደሆነ\"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልዕክት መካከል ተገለጠ\"ብለን ነዋ!!እንደዚህም ሁሉ ተቀብዐን እንደአውዱ እንደ አገባቡ ይፈታል!!</span></div>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"color: rgb(224, 62, 45); font-size: 18pt;\"><strong>➠የቅባት ትርጉም እንደ ቅባት አስተምሮ ግን......</strong></span></h2>\r\n<div>\r\n<ul>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt; color: rgb(22, 145, 121);\">✔. ቅባት መንፈስ ቅዱስ ተብሎ ይተረጎማል!!</span></strong></li>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt;\">✔.ቅባት ሕይወት ተብሎ እንደሚተረጎም ወልደ አብ መጽሐፍ ገጽ 179 ;</span><span style=\"font-size: 14pt;\">አዕማደ ምስጢር ገጽ 22 </span><span style=\"font-size: 14pt;\">ይናገራል!!</span></strong></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">&nbsp;ከዚህ ውጭ ግን <strong><span style=\"text-decoration: underline;\">ተቀብዐን ተዋሐደ</span></strong> ብለው ተርጉመው ፈጽሞ አይናገሩም;ተዋሐደ ብለው </span><span style=\"font-size: 14pt;\">መተርጎም ስህተት ነው ይላሉ \"ተዋሐደ\"ካሉ መንፈስ ቅዱስ ቅብዕ መሆንን ያፈርስባቸዋልና!!</span><span style=\"font-size: 14pt;\">ምናልባት በነገረ ሥጋዌ ጉዳይ እመቤታችንን ተቀባትም ተዋሐዳትም ማለት ክህደት ነው </span><span style=\"font-size: 14pt;\">ሲባል ብዙ ሰዎች ግራ ይጋባሉ;ነገር ግን ጊዜ ተዋህዶ ላይ የተፈጸሙ ተግባራትን ካለማወቅ </span><span style=\"font-size: 14pt;\">የተነሳ ነው ወገኖቼ!!!በምሥጢረ ሥጋዌ ትምህርታችን ስንነጋገር እነዚህን ነገሮች </span><span style=\"font-size: 14pt;\">ካስታወሳችሁ የጥያቄያችሁ መልስ ታገኛላችሁ!!!ይኸውም ቃል በጊዜ ተዋህዶ የማይቀዳደሙ </span><span style=\"font-size: 14pt;\">፫ት ነገሮች ተከናውነዋል። እነርሱም:-</span></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መክፈል፤</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መዋሐድ እና</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">&nbsp;መክበር ናቸው።</span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">✟✔.ከፍሎ ሳይዋሐድ ቢቀር በሰው ወይም በእመቤታችን አደረ ያሰኛል።ይኼውም ኀደረ </span><span style=\"font-size: 14pt;\">በብእሲ ብሎ እንደካደው ጳውሎስ ሳምሳጢ ክህደት መግባት ነው።ተዋህዶ ሳይከፈል ቢቀር </span><span style=\"font-size: 14pt;\">እመቤታችን አምላክ ሆነቺ ያሰኛል።ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል።አካለ ቃል ክብር </span><span style=\"font-size: 14pt;\">አልባ ያሰኛል የሚሉት ናቸው።ስለዚህ ሲከፈልም፤ሲዋሐድም፤ሲከብርም(ሲቀባ) </span><span style=\"font-size: 14pt;\">አንድ ጊዜ ነው።</span></div>\r\n<div>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"font-size: 24pt; color: rgb(132, 63, 161);\">ምሥጢረ ሥጋዌ በቅባት አስተምህሮ (በወልደ አብ) ዕይታ</span></h1>\r\n<p><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 14pt;\">የኢትዮጵያ ኦርቶዶክስ ቤተ ክርስቲያን የምታስተምረው ትምህርት ከቅባት እምነት በጣም ሰፊ ልዩነት ሲኖራት የቅባት እምነት ተከታዮች ከዚህ በተለየ መልኩ ብዙ ክህደትን ሲያስተምሩ ይስተዋላሉ።ከነዚህም መካከል በጣም የጎሉትን የክህደት መንገዶ ከዚህ በታች ለማየት እንሞክራለን።&nbsp;</span></strong></span></p>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\">✔፩ኛ.እግዚአብሔር ወልድ ሁለት ልደታት አሉት እያሉ በቃል ደረጃ&nbsp;ይናገራሉ ።ነገር ግን በተግባር ደረጃ እንደጸጋ አስተምህሮ ፫ት ልደትን&nbsp;አማኝ ናቸው!!ለዚህ ማስረጃየ ወልደ አብ መጽሐፋቸው&nbsp;የመጀመሪያው ዕትም ገጽ 217 እና 218 እንዲህ ይላል!!</span></strong></div>\r\n<div style=\"padding-left: 80px;\"><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(132, 63, 161);\">\"<strong>የጌታችን ልደት ስንት ነው ቢሉ ፪ት ነው።እንዴት ፪ት ነው ቢሉ&nbsp;እምቅድመ ዓለም በመለኮቱ ተወለደ ብለናል ኋላም በማኅጸን በሰውነቱ&nbsp;ከአብ ተወለደ እንላለን ዳግም ከእመቤታችን በስጋ በጎል ተወለደ&nbsp;እንላለን</strong> \"</span></em>ወልደ አብ ገጽ ገጽ 217 ይላል!!</span></div>\r\n<div><span style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(186, 55, 42);\"><strong>↪አስተዉሉ፦</strong></span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ታዲያ ጌታችን ቅድመ ዓለም ከአብ በመለኮቱ፣ድኅረ ዓለም ከእመቤታችን በትስብእቱ፣ድኅረ ዓለም በማኅጸን በሰውነቱ ከአብ ተወለደ ከተባለ ሁለት ልደታት ማመን ከየት ይመጣል ይህ ፫ት ልደት&nbsp;አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ይህ ከሆነስ ወልደ አብ በመለኮቱ:ወልደ ማርያም በትስብእት፣አሁንም በድጋሜ በማህጸን ከወለደው እንደገና ወልደ አብ በትስብእቱ ሊባል ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ለማንኛውም \"በቃል ሁለት ልደት፣በተዘዋዋሪ በተግባር ግን ሦስት ልደት ይላሉ!!አይ ወገኔ\"አልሸሹምዞር አሉ\"ማለት ይሄ ነው እኮ ወገኔ ገባህ?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\"><strong><span style=\"font-size: 14pt; background-color: rgb(248, 202, 198);\">፪ኛ.\"ሰባቱን ሀብታተ መንፈስ ቅዱስ እርሱ በስጋ ርስት በጊዜ ፅንስ ያለምክንያት ከአብ ተቀብሎ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉሥ ሆነባቸው\"ወልደ አብ ገጽ 211 ይላል</span></strong></span></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች የነገረ ቅባትን አስተምህሮ እና ጥያቄ የሚመለሰው ብዙ ጥቅስ መዘርዘር ሳያስፈልገው ጥያቄን በጥያቄ መመለስ እና በደንድ አገናዝቦ ማስተዋል ነው።ስለዚህ ከላይ እንዳያችሁት እንዲህ ካሉ&nbsp;እስኪ በሞቴ ንገሩኝ.........</span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉስ ሆነባቸው ማለት ቀድሞውንስ የባህርይ አምላክ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ ሰው የሆነስ በአባቱ ፈቃድ በእርሱ ፈቃድ በመንፈስ ቅዱስ ፈቃድ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">ታዲያ እነማንን ነው የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸው❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በግድ ነው በኃይል የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸውስ❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በመጀመሪያ \"ሆነባቸው\"ማለት በግድ አምላክ ሆኖባቸዋልን❓የእነርሱ ፈቃድስ❓</span></strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><em><strong><span style=\"color: rgb(52, 73, 94); background-color: rgb(236, 202, 250); font-size: 18pt;\">✔፫ኛ.\"መንፈስ ቅዱስ ሠጪም ተሠጭም ነው\"ወልደ አብ ገጽ 181&nbsp;ይላል።</span><span style=\"color: rgb(52, 73, 94); font-size: 18pt;\">ይህ ከሆነ.......</span></strong></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ምንድን ነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ለማነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለው ምንን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለውስ ከማን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሌለው አለን ከሌላ የሚቀበል❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>በዓለመ ሥላሴ ነው መንፈስ ቅዱስን ሰጪም ተሰጪም ነው የምንል እንዳትሉኝ በዓለመ ሥላሴ በባህርይ በክብር በስልጣን አንድ ናቸው አንዱ ከአንዱ አያንስም አንዱ ከአንዱ አይበልጥ;ታዲያ አንዱ ከአንዱ ከአልበለጠ አንዱ ከአንዱ ካላነሰ ሰጪና ተሰጪ የሚል ከየት ይመጣል ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪና ተሰጪ ያልን ለፍጡራን ነው እንዳትሉኝ መንፈስ ቅዱስን ፍጡር እያላችሁት መሆኑ አይደለምን❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪም ተሰጪም ነውያልነው በፈጣሪና በፍጡር መካከል ነው እንዳትሉኝ መንፈስ ቅዱስ ፈጣሪ ነው ከፍጡር ይቀበላላልን❓ተሰጪ የሚለው አያፈርስባችሁምን❓ተብለዉ ሲጠየቁ መልስ የላቸዉም አፋቸዉን ይያዛሉ።</em></strong></span></li>\r\n</ul>\r\n<div><span style=\"background-color: rgb(194, 224, 244); color: rgb(52, 73, 94); font-size: 18pt;\"><em><strong>፬ኛ.አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ነው ይላሉ!!</strong></em></span></div>\r\n<div>-<em><span style=\"font-size: 14pt;\">ይህ ማለት፦</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ-አክባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ ከባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል።በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።</span></em></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><strong>↪ታዲያ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን</strong></span></p>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>&nbsp;አብ አክባሪ፣ወልድ ከባሪ መንፈስ ቅዱስ ክብር የሚል ከየት ይመጣል❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>ምሥጢረ ሥላሴ ላይ የተነገረውን ለምስጢረ ሥጋዌ መቀፀልስ ለምን አስፈለገ❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong>↪\"ሥላሴ በተለየ ግብር ሦስት ናቸው።ይኸውም መውለድ፣ማስረፅ፣መወለድ፣መስረፅ ነው\"ይላል ገጽ 53;እንደገና 133 ላይ ደግሞ\"ቅብዕ የሆነ ግን በተለየ አካሉ በተለየ ግብሩ መንፈስ&nbsp;ቅዱስ ነው\"ይላል</strong></span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለመንፈስ ቅዱስ የተለየ ግብር የተሰጠው መቼ ነው ቅብዕነት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>የመንፈስ ቅዱስ ግብር መስረፅ ከሆነ ቅብዕነት ደግሞ ለመንፈስ ቅዱስ መቼ ተጨመረለት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለወልድና ለአብስ ምን የተለየ ግብር ምን ተጨመረላቸው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp;ከዚያ ባለፈ አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ማለት </span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ➠ሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ➠ተሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ➠ስጦታ ማለት ነው።</span></em></li>\r\n</ul>\r\n<p><em><strong>↪<span style=\"font-size: 12pt;\"> ይህ ከሆነ&nbsp; &nbsp;</span></strong></em></p>\r\n</div>\r\n<div>\r\n<div>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ አለን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ ካለ ሰጪ ከተሰጪ ይበልጣል;ተሰጪ ከሰጪ ያንሳል!!ታዲያ አብ ከወልድ ከመንፈስ ቅዱስ ይበልጣልን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>ወልድስ ከአብ ከመንፈስ ቅዱስ ያንሳልን❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; color: rgb(132, 63, 161); background-color: rgb(206, 212, 217);\"><em><strong>✔፭ኛ.\"ስጋ ሲፈጠር መለኮትም ከስጋ ጋር አብሮ ተፈጠረ ካላሉ&nbsp;ይላል\"ወልደ አብ ገጽ 127</strong></em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>መለኮት(ቃል) ራሱ ፈጣሪ ነው;ራሱ ፈጣሪ ከሆነ ከስጋ ጋር አብሮ ማን ፈጠረው ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ጸሎተ ሐይማኖት ላይ\"ዘተወልደ ወአኮ ዘተገብረ\"የተወለደ እንጂ ያልተፈጠረ የምትለዋን ፋቃችኋት እንዴ ታዲያ ወገኖቼ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ፍጡር ከሆነ ታዲያ እመቤታችን ወላዲተ አምላክ ሳይሆን ወላዲተ ሰብእ ናት ልትሉ ነው እንደ ፎጢኖስ❓</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><strong><em><span style=\"color: rgb(132, 63, 161); background-color: rgb(241, 196, 15); font-size: 18pt;\">✔፮ኛ.\"እኛ የምንቀበለው የጸጋ ጌታ የሚቀበለው የባህርይ ነው ማለት&nbsp;እንዴት ነው ቢሉ እኛ በተወለድን በ፵ ቀን እናገኘዋለን በክህደት&nbsp;በኃጢአት ይነሳል ስለዚህ ስለዚህ የጸጋ ይባላል።ጌታ ግን ሲዋሐድ የባህርይ ህይወት መንፈስ ቅዱስን ከአካሉ ጋር አግኝቶታልና የባህርይ&nbsp;ይባላል\"ወልደ አብ ገጽ 188</span></em></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ጌታ የባህርይ ህይወቱን መንፈስን ከአካሉ ጋር አግኝቶታል ይላል;የመንፈስ ቅዱስን አካሉን ነው ወይስ ሀብቱን የተቀበለው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>አካሉን ከተባለ መንፈስ ቅዱስ ከስጋ ጋር ተዋህዷልን ❓</em></strong></span></li>\r\n<li style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ሀብቱን ካላችሁስ ክርስቶስ ዕሩቅ ብእሲ መሆኑ አይደለምን ❓</em></strong><em><span style=\"color: rgb(0, 0, 0);\">ብላችሁ ስትጠይቋቸው ምላሽ ያጣሉ።</span></em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp;</strong></span></p>\r\n<div><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;በነገረ ቅባት በመንፈስ ቅዱስ ከበረ ለማለት የሚነሱ ጥቅሶች</strong></span></div>\r\n<div>&nbsp;</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.የዘመኑ ቅባት ነን ባዮች በመንፈስ ቅዱስ ከበረ ለማለት በጣም በርካታ የመጽሐፍ ቅዱስ ጥቅሶችን ቢያነሱም ከብዙዉ በጥቂቱ ተደጋጋሚ ሁሌም የሚያነሷቸው የአፍ መፍቻ ጥያቄዎች የሚከተሉት ሲሆኑ ቤተክርስቲያናችን አረዳዷ ሚን ዪመስላል የሚለዉን ትርጓሜዉን እናያለን።</span></em></div>\r\n<div><strong><span style=\"background-color: rgb(194, 224, 244);\"><em><span style=\"font-size: 14pt; background-color: rgb(194, 224, 244);\"><span style=\"font-size: 18pt;\"><span style=\"color: rgb(45, 194, 107);\">1ኛ. </span>\"<span style=\"color: rgb(45, 194, 107);\">ዘአንገሦ ለሥጋ አዳም በመንፈስቅዱስ ወረሰዮ ቅዱሰ&nbsp;ወማሕየዌ ዘለብሶ ለአዳም መዋቲ</span></span>\"በመንፈስቅዱስ ህይወትነት&nbsp;የአዳምን ባህርይ ያከበረው የባህርይ አምላክ ያደረገው እርሱ ነው\"ሃይ.አበ.ዘእልመስጦአግያ ፪:፭</span></em></span></strong></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡በመጀመሪያ ያከበረው አለ እንጂ ክብር የሆነው አይልም አስተውሉ ወዳጄ!!</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>መንፈስ ቅዱስ ቅብዕ(ክብር) ከሆነው ለምን ያከበረው አለ ለምን ክብር የሆነው አላለም❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>፫ቱ በአክባሪነት አንድ አይደሉምን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም ይህ የተነገረው የመንፈስቅዱስን ህይወትነት ሥጋ ገንዘብ ማድረጉን ሲናገር ነው!!አንድም \"የአዳምን ሥጋ በመንፈስ ቅዱስ አዋሐጅነት የተዋሐደው እርሱ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም በመንፈስቅዱስ ህይወትነት ማለት በረቂቅ የሥላሴ ግብር ማለት እንጂ መንፈስ ቅዱስ ክብር ሆነው ለማለት አይደለም ወዳጄ!!የአዳምን ሥጋ በግብረ መንፈስ ቅዱስ ተዋሕዶ የባሕርይ ንጉሥ ያደረገው&nbsp;</span></em><em><span style=\"font-size: 14pt;\">እርሱ ነው!!\"<strong>ወረሰዮ ቅዱሰ ወማሕየዌ ክቡር ወሀቤ ሕይወት</strong> አምላክ ያደረገው እርሱ ነው ካለ በኋላ ዘለብሶ ለአዳም መዋቲ\"አለ;ለምን ከተባለ ስጋን የተዋሐደ በተለየ አካሉ ወልድ ነውና።ግብረ መንፈስ ቅዱስ </span></em><em><span style=\"font-size: 14pt;\">ማለት ረቂቁን ለመንፈስ ቅዱስ መስጠት ነው እንጂ በማዋሐድ፣ በመፍጠር፣ በመግዛት፣ በመንግሥት፣በክብር ሦስቱ አካላት አንድ ናቸውና በአንዲት ግብረ ባሕርይ መሆኑን እናስተውል።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(194, 224, 244);\">2ኛ. \"ለሊሁ ዘይሁብ ወለሊሁ ዘይትወሀብ\"-ጸጋውን የሚሰጥ እርሱ ነው ጸጋም ሆኖ የሚሰጥ እርሱ ነው\"</span></strong></span><span style=\"text-decoration: underline;\">አረ.መን.ድር.11</span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ይህ ቃሉ የተነገረው ለመንፈስ ቅዱስ ሳይሆን ለወልድ ነው ምክንያቱም እርሱ ለኩነተ ሥጋ ተሰጦአልና ነው ወዳጄ!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም በሰባኪ አድሮ ጸጋን ይሰጣል.በሰሚ አድሮ ይቀበላልና!!</em></span></div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em>3ኛ. \"አማን አንገለጉ በዛቲ ሀገር ላዕለ ቅዱስ ወልድከ ኢየሱስ&nbsp;ዘቀባእካሁ.ሐዋ.4&divide;27</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ከዚህ ላይ የምናስተዉለው ነገር አለ።ይኽውም፦</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>መንፈስ ቅዱስ ቅብዕ ከሆነው በቀባኸው አለ እንጂ ቅብዕ በሆንኸው ለምን አላለም❓</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>-ቅብ የሆነው መንፈስ ቅዱስ ነው ከተባለ ይህ ቃል ደግሞ የአብን ቀባዒነት የክርስቶስን&nbsp;ተቀባዒነት ይናገራል እንጂ የመንፈስቅዱስን ቅብዕነት አይናገርም እኮ!!</em></span></div>\r\n<div><span style=\"font-size: 18pt; color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em><strong>4.&nbsp;እንደእሱ አካል ባለ አካል አክብሮታልና.ዮሐ.አፈ.ወ.ድር 3&divide;100</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>➡አስተውሉ</strong>:-ሥጋን በቃል አንቀጽ ሲጠራው እንደሱ አካል አለ፤ባለአካል ብሎ ቃልን ጠራው&nbsp;አክብሮታል አለ እንጂ ክብር ሆኖታል አላለም</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም አካለቃል ከአካለሥጋ፣ባህርየ ቃል ከባህርየ ሥጋ ጋር መዋሀዳቸውን እየተናገረ ነው!!</em></span></div>\r\n<div><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>5 .\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከ እግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ\"<span style=\"font-size: 14pt;\">መዝ 44 &divide;7</span></em></span></strong></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>✔ \"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን&nbsp;ቀባህ\"</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;በመጀመሪያ እነዚህን ጥያቄዎች እንመልስ &nbsp;</em></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ቃሉ በባለቤትነት የተነገረው ለማን ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>እግዚአብሔር ሲል ከ3ቱ አካል ለአንዱ የመንፈስ ቅዱስ ስም ብቻ ነው የሦስት ስም አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ከባልንጀሮችህ ይልቅ ሲልስ ባልንጀሮቹ እነማን ናቸው ይልቅ የሚለውስ ለምን መቀጸል አስፈለገ❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>የደስታን ዘይት ቀባህ ማለት ትርጉሙ ምንድን ነው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>* በመጀመሪያ\"ጽ<strong>ድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ&nbsp;የደስታ ዘይትን ቀባህ</strong>\"በሚለውኃይለ ቃል ውስጥ \"<span style=\"text-decoration: underline;\"><strong>አንተ</strong>\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ </span></em></span><span style=\"font-size: 14pt;\"><em><span style=\"text-decoration: underline;\">እናስተውል:;ይኸውም&nbsp;\"<strong>ትስብእት\"</strong>ነው።\"ባልንጀሮችህ\"የተባሉት ደግሞ ቀደምት ነቢያት፣ካህናት ነገስታት ናቸው።</span></em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 14pt;\"><em>❓=ታዲያ \"ከባልንጀሮችህ ይልቅ\"ለምን አለ ትሉኝ እንደሆን እነርሱ ሲሾሙ የነበረው በቅብዓ ዘይት ነበርና እነ ዳዊት መመልከት ይቻላል!!ለእነርሱ ሹመት ከእግዚአብሔር የሚያገኙት የሚቀበሉት ጸጋ </em></span><span style=\"font-size: 14pt;\"><em>ጊዜያዊ የሚያልፍ ነው።የክርስቶስ ሰው መሆን የትስብእት መክበር ግን ከማንም የማይቀበለው የባህርይው በተጭና በተሰጭ መካከል የሚደረግ አይደለም ሲል ነው፣ታዲያ የስጋ መክበር እንዴት ነው ትለኝ&nbsp;</em></span><span style=\"font-size: 14pt;\"><em>እንደሆነ\"<span style=\"color: rgb(224, 62, 45);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"መለኮት ለስጋ ክብር ሆነው እርሱ ራሱ በባህርይ ክብሩ ከበረ፣ስጋ&nbsp;እርሱ ራሱ ክብሩ አምላክነቱ የባህርይ ከሆነ መለኮት ጋር ስለተዋሐደ\"እልሃለሁ ወዳጄ!!</em></span><span style=\"font-size: 14pt;\"><em>አንድም እግዚአብሔር አምላክ ብሎ ለምን አራቀቀው ትለኝ እንደሆነ\"<strong>የተዋሐደው የፈጠረውን ስጋ</strong>\"ነውና&nbsp;ማለትም\"እርሱ ራሱ የፈጠረውን ስጋ ተዋሐደ እንዲል ሊቁ!!!</em></span>\r\n<div>&nbsp;<span style=\"font-size: 14pt;\"><em>አንድም ይልቅ ማለቱ\"አምላክነት የባህርይው ስለሚሆን በጸጋ እንዳደረባቸው እንደቅዱሳኑ ሳይሆን አንተ ገንዘብህ የሚሆነውን መለኮትን ስለተዋሐድክ ነው ሲል ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን&nbsp;መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው </em></span><span style=\"font-size: 14pt;\"><em>ትለኝ እንደሆነም ሰው መሆንን ወደድህ የተባለ ቃል ነው፣ከበረ የተባለ ደግሞ ሥጋ ነው!!ሁለቱን&nbsp;መናገሩ፣በአንድ አንቀጽ ሁለቱን መናገር ነው።\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቦ ዘይቤላ በእንተ ትስብእቱ ወመለኮቱ</strong></span>\"እንዲል </em></span><span style=\"font-size: 14pt;\"><em>አንድም ሰው ማለት ክብርና መክበር ተዋህደው ክርስቶስ ነውና \"የደስታ ዘይትን (ቅብዓ ትፍስሕት)የተባለውስ ማነው ካልከኝ ወልድ(ቃል) ነው ቀባህ ሲልም&nbsp;\"አከበረህ\"ማለቱ ነው።</em></span><span style=\"font-size: 14pt;\"><em>አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቀብዐከ እግዚአብሔር አምላክከ</strong></span>\"ብሎ ባህርያዊ ግብሩን በሚገልጥ መጥራቱ አብ አብ ቀባዒ እንደሆነ በምን ያስረዳል❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ነውስ\"<span style=\"color: rgb(132, 63, 161);\"><strong>አንሰ ሶበ እቤ እግዚአብሔር እብል በእንተ አብ ወወልድ ወመንፈስ ቅዱስ</strong></span>\"-እኔ እግዚአብሔር&nbsp;ብየ በተጣራሁ ጊዜ ስለ አብ ስለወልድ ስለመንፈስ ቅዱስ መናገሬ ነው የሚለው ተዘነጋ እንዴ❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ታዲያ እግዚአብሔር ማለት የሦስት የባህርይ ግብር ለመግለጥ የምንጠቀምበት ስም ከሆነ አብን ቀባዒ&nbsp;ለማድረግ ምክንያቱ ምንድን ነው❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>&nbsp;6.ወበከመ ለአብ ቦቱ ህይወት ኀቤሁ.ዮሐ 5&divide;26</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;ለምሳሌ ክርስቶስ ከተነሣ በኃላ ሥልጣን ተሰጠኝ. ማቴ 28&divide;18 ይላልና ያን ጊዜ ሥልጣን ተሰጠው ማለት ነውን❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>ስለዚህ ህይወቱን ሰጠው ማለት፡-</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ተሰጠኝ ሲል ተሰጦት አይደለም ገንዘብ ማድረጉን ሲሻ ነው እንጂ&nbsp;</em></span>\r\n<div><span style=\"font-size: 14pt;\"><em>➠የቃል ገንዘብ ለስጋ ሲሆን ህይወትነት ለሥጋ ገንዘቡ ሆነ ማለት ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ሕይወት ያለው መንፈስ ቅዱስን አይደለም ለሚወዳቸው ህይወትን ሰጣቸው ይላልና.ዮሐ 5&divide;21</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠አንድም ስለሥጋ እንግድነት የተነገረ ነው አለዚያማ ለወልድም ህይወቱ ይሆን ዘንድ ይላልና መንፈስ ቅዱስ ከወልድ የተለየበት ጊዜ አለ ያሰኛል።</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>ከሁሉ አስቀድሞ ግን የረሳሁት ነገር......</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ተቀብዓን ህይወት ተብሎ ከተተረጎመና ለስጋ ክብር የሆነው መንፈስ ቅዱስ ነው የምንለው የባህርይ ህይወቱ ስለሆነ ነው&nbsp;ከተባለ አብም የባህርይ ልቡ ነውና ምን እንበለው እሽ ወገኖቼ ❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250);\"><em><span style=\"font-size: 18pt; color: rgb(52, 73, 94); background-color: rgb(236, 202, 250);\"><strong>7.\"እነሆ ናዝራዊው ኢየሱስ ቅባትን ተቀብቶ የመቀባትን&nbsp;መንግስት ተቀበለ፣አምላክ ሲሆን ስለሰውነቱም የመለኮትን ቅባት&nbsp;ተቀብቶ ሰው ሆነ እግዚአብሔር ሰው ለመሆን ወረደ ሰውም&nbsp;እግዚአብሔር ለመሆን ከፍ ከፍ አለ\"<span style=\"font-size: 14pt;\">መ.ምሥጢር ገጽ 214</span></strong></span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ በመጀመሪያ ናዝራዊው ኢየሱስየሚለው ከሁለት አካል አንድ አካል ከሁለት ባህርይ አንድ ባህርይ ሲሆን&nbsp;የወጣለት የተዋህዶ ስም ነው!!ትርጓሜውም መሲህ፣የተቀባ፣የተሾመ ማለት ነው።የተቀባ የተሾመ ሲባል ግን ለእርሱ ቀቢ ሿሚ ኖሮት አይደለም።ቀቢውም ሿሚውም ተሿሚውም አንድ&nbsp;እርሱ ነው እንጂ!!ዮሐ 4&divide;25 -30 ማለትም<span style=\"color: rgb(132, 63, 161);\"><strong>\"ለሊየ እቄድስ ርእስየ\" </strong></span>እንዲል ይህ ሲባል ኢየሱስ ክርስቶስ ቅባትን ተቀብቶ ሲል አንቀጹ ለትስብእት ነው።ማለትም መለኮት&nbsp;ለተዋሐደው ስጋ ክብር ሁኗል;አንድም ቅድመ ተዋህዶ ትስብእት ትሑት፣ህፁፅ ስለሆነ ተለዓለ ተብሎ ተነገረለት።ማለትም ያ ህፀፅ ንዴት የነበረበት ትስብእት ከቃል ጋር ሲዋሐድ ቃል ለተዋሐደው ስጋ ክብር&nbsp;ሆነው\"<span style=\"color: rgb(132, 63, 161);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"እንዲል ቅዱስ ቄርሎስ &nbsp;የቃል ገንዘብ በተዋህዶ ለስጋ ገንዘቡ ሲሆን ከበረ አምላክ ሆነ፣የባህርይ ልጅ ሆነ ሲል የመቀባትን መንግስት ተቀበለ አለ።ማለትም ስጋ ከተዋህዶ በኋላ የመለኮት ገንዘብን ገንዘቡ አድርጓልና\"\"<span style=\"color: rgb(132, 63, 161);\"><strong>እንቲአሁ ለቃል ኮነ ለስጋ ወእንቲአሁ ለስጋ ኮነ ለቃል</strong></span>\"እንዲል ቅዱስ ቄርሎስ!አንድም ስጋ ልዕልናን ግብረ አምላካዊውን ባህርይው ረቂቅባህርየ መለኮትን ገንዘቡ አደረገ።ማለትም&nbsp;የሚሞት ሲሆን የማይሞት ሆነ፣\"ምድራዊ ሲሆን ከልዕልና በላይ ያለ ልዕልናን ገንዘቡ አደረገ በአጠቃላይ የማይመረመር ጌትነትን አገኘ።አንድም በዚያው አጋጣሚ ነስአ ተወክፈ አይሉም እንባለለን;ነገር ግን ስንተረጉምና ስንል&nbsp;እመንገለ ሥጋሁ እንጂ እመንገለ መለኮቱ አንልም።ምክንያቱም በመለኮቱ በኩል&nbsp;ብንል \"ኢይጽሕቅ ቅብዓተ በህላዌ በመለኮቱ\"ማለትም በመለኮቱ መቀባትን(ክብርን)አይሻል!!ከዚህ በተጨማሪ እግዚአብሔር ሰው ለመሆን ወረደ ሲል የሰውን ባህርይ ባህርይው ለማድረግ ማለትም&nbsp;የማይራበው እንዲራብ መሆኑ፣ባእለ ጸጋ የነበረው ባህርይውን ሳይለቅ በተዓቅቦ ነዳይ መሆኑ የንጉሶች ንጉሥ ሲሆን የጌቶች ጌታ ሲሆን በአይሁድ ፊት መገረፉ በአጠቃላይ ራሱን በሰው መልክና አርዓያ መምጣቱን&nbsp;ያመለክታል። ምክንያቱም\"ነገር ግን የባህርይን መልክን ይዞ በሠውም ምሳሌ ሆኖ ራሱን ባዶ አደረገ&nbsp;በምስሉም እንደሰው ተገኝቶ ራሱን አዋረደ\"እንዲል ፊል 2&divide;8</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ሕቀ አሕጸጽኮ እምመላእክቲከ</strong></span>\"-ከመላእክት እጅግ ጥቂት አሳነስኸው\"መዝ 8&divide;5 እንዲል&nbsp;አንድም \"ሰውም እግዚአብሔርን ለመሆን ከፍ ከፍ አለ ሲል በተዋህዶ የመለኮትን ገንዘብ ገንዘቡ </em></span><span style=\"font-size: 14pt;\"><em>ስለሚያደርግ የስጋ በአምላክነት መክበር መቀባት ተብሎ ተነግሯል።አምላክነቱ የባህርይው ስለሚሆን በጸጋ&nbsp;እንዳደረባቸው ቅዱሳን አይደለም ሲል ነው።አንድም ቅዱስ ዮሐንስ አፈወርቅ እንደገለጸው </em></span><span style=\"font-size: 14pt;\"><em>ትስብእት ከመለኮት ጋር በመዋሐዱ ያገኘውን የክብር መጠን ሲያብራራ እንዲህ በማለት በሰፊው&nbsp;አብራርቷል!!\"ወዴት ስፍራ እንዳወጣው ዕወቅ:ከፍጡራን ሁሉ ከመላእክትም ሁሉ በላይ አደረገው\"አለ።ረቂቅ </em></span><span style=\"font-size: 14pt;\"><em>እውቀትን እንዲገልጽልህ ከወደድክ በእግዚአብሔር ባህርይና በሰው ባህርይ መካከል ያለ ልዩነት ምን ያህል እንደሆነ አንተ እወቅ፣ማንም ሊናገረው ወደማይቺለው ክብረ መለኮት ትስብእትን ከፍ ከፍ </em></span><span style=\"font-size: 14pt;\"><em>አደረገው፣ከልዑላን መላእክት ሁሉ በላይ አደረገው\"ሃይ.አበው 67 ክፍል 16 &divide;23 ስለዚህ ተለዓለ መባሉ ስለዚህ ነው።</em></span></div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244); color: rgb(224, 62, 45);\"><em><strong>8. \"ዘቀብኦ እግዚአብሔር መንፈሰ ቅዱሰ ወኃይለ\"ሐዋ 10&divide;38</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡\"እግዚአብሔርም የናዝሪቱን ኢየሱስን በኃይል በመንፈስ ቅዱስ ቀባው\" ሲል </em></span><span style=\"font-size: 14pt;\"><em>በመንፈስ ቅዱስ ማለት በግብረ መንፈስ ቅዱስ(በረቂቅ ምሥጢር)ሥጋን አከበርኸው ማለት ነው!!</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>&nbsp;እንደዚህማ ባይሆን ኖሮ ሐዋርያው ቅዱስ ጴጥሮስ</em></span></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>\"እግዚአብሔር የናዝሬንቱን ኢየሱስን ከሙታን መካከል ለይቶ አስነሳው\"ሲል በመንፈስ ቅዱስ ወይም </em><em>በአብ ስልጣን ነው የተነሳ በራሱ ስልጣን የተነሳ አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>በራሱ ስልጣን ካልተነሳ \"እንዴት አልዓዛርን ከመቃብር አስነሳው\"ለራሱ የሌለው ለሰው </em><em>ያበድራልን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም በመንፈስቅዱስ በቀባኸው አለ እንጂ ቅብዕ በሆነው አይልም!!</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(224, 62, 45); font-size: 18pt; background-color: rgb(251, 238, 184);\"><strong><em>9.\"መንፈሰ እግዚአብሔር ላእሌየ ዘበእንቲአሁ ቀብዐኒ\"ኢሳ 61</em><em>&divide;1</em></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp; ↪ የእግዚአብሔር መንፈስ ሲል መንፈስ ቅዱስ ነው፣እኔ ያለው ደግሞ ባለቤቱ ወልድ ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>☝በእኔ ላይ ማለቱም መንፈስ ቅዱስ በእኔ በወልድ ህልው ነው ማለቱ ነው!!</em></span><span style=\"font-size: 14pt;\"><em>ቀባኝ ማለቱም አዋሐደኝ ሲል ነው!!</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>\"ስለዚህ የእግዚአብሔር መንፈስ በእኔ ህልው ነው፣ስለዚህ ነገር አዋሐደኝ ሲል በኢሳያስ የተነገረለትን የባህርይ ህይወቱን መንፈስ ቅዱስን እርሱ ገንዘብ እንዳደረገ ሊነገር ይገባል።ስለዚህ በባህርይ ገንዘቤ&nbsp;የሚሆን መንፈስ ቅዱስ በህልውናየ ጸና ብሎ ብሎ አስተማረ\"ሃይ.አበው ዘሳዊሮስ 87 ክፍል 17-18</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;&nbsp;***አዋሐደኝ ማለቱም የአምላክ ሰው መሆን በፈቃደ አብ፣በፈቃደ ወልድ፣በፈቃደ መምፈስ ቅዱስ የሆነ ማለት ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ በሌላ አነጋገር </em></span><span style=\"font-size: 14pt;\"><em>አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ከተባለ ታዲያ ከዚህ ጥቅስ ላይ </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>በእኔ ላይ ያለ የእግዚአብሔር መንፈስ ቀባኝ ሲል ቀባዒው ማነው❓</em></span></li>\r\n<li><em style=\"font-size: 14pt;\">በዚህ ጥቅስ ቀባዒው አብ መሆኑ አይደለምን❓</em></li>\r\n<li><em style=\"font-size: 14pt;\">ታዲያ መንፈስ ቅዱስ ቅብዕ የሚል ከየት ይመጣል❓</em></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h1><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><em><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የዘመኑ ቅባት ነን ባዮች የሚያነሷቸው ጥያቄዎችና መልሶቻቸው</strong></em></span></h1>\r\n<div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(45, 194, 107); background-color: rgb(241, 196, 15);\"><em>=&gt;.እኛ የተዋህዶ ልጆች ትሥብእት ወይም ሥጋ ከባሪ መለኮት(ቃል) ክብር ስንል አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርጋችሁ ስትናገሩ መለኮት የመለኮትን ሥራ ይሰራል ሥጋም የሥጋን ሥራ ይሰራል </em><em>ከሚሉት መለካዊያን በምን ትለያላችሁ?ይሉናል።</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.ቅባት ወገኖቻችን ሆይ እኛ አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርገን እናንተ እንደምትሉት ያለ&nbsp;ፍልስፍና ላይ አልተሰማራንም በሉልኝማ የተዋህዶ ልጆች። ከበረ፣ አከበረ የምንለው በጊዜ ተዋሕዶ ላይ </em></span><span style=\"font-size: 14pt;\"><em>ያለን ጊዜ ብቻ ናት። መክበር ይሻ የነበረን ሥጋ አካላዊ ቃል በአምላክነት ክብሩ አከበረው። ይች እመቤታችን&nbsp;\"<span style=\"color: rgb(132, 63, 161);\"><strong>ይኩነኒ በከመ ትቤለኒ</strong></span>\"ባለችው ጊዜ የተፈጸመች ድንቅ ምስጢር ናት። ከዚህ ጊዜ በኋላ መለኮትና ትስብእት&nbsp;አንድ ስለኾኑ ከባሪና አክባሪ የለም።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ ወልድ አምላክ ነውና በአምላክነት ክብሩ ያከብራል ስንል ወልድ ማክበር አይችልም ካላችሁን </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\"><em>\"በመንፈስ ቅዱስ ከበረ\"ስትሉ መንፈስ ቅዱስስ ማክበር የብቻው ግብሩ ነው ብላችሁ ነውን? </em></span></strong></span></li>\r\n<li><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\">አዎ ካላችሁ ለመንፈስ ቅዱስ ከመሥረጽ ውጭ ሌላ አካላዊ ግብር እንዳለው ከየት ተማራችሁት? </span></strong></span>ማስረጃችሁ ምንድን ነው ወገኖቼ?ብላችሁ ጠይቁልኝ!!</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.አንዱ አካል አክባሪ ያሉ ቃልን አንዱ አካል ከባሪ የሚሉን ደግሞ ትስብእትን ለማለት ፈልጋችሁ ነው። እናንተ \"<span style=\"text-decoration: underline;\"><strong>በመንፈስ ቅዱስ ከበረ\"</strong></span> የምትሉት ሥግው ቃልን ነው።ታዲያ ሥግዉ ቃልን ከሆነስ</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ሥግው ቃል አምላክ ነው ወይስ አይደለም?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>&nbsp;ሥግው ቃል እስከሚከብር ድረስ የአብ የመንፈስ ቅዱስ ቃላቸው ማን ነበር?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ትስብእት አምላክ የኾነው በቅብዐተ መንፈስ ቅዱስ ከኾነ ሥግው ቃል እስኪከብር ድረስ አብና መንፈስ ቅዱስ ዲዳ ነበሩ (ሎቱ ስብሐት)?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(22, 145, 121); background-color: rgb(194, 224, 244);\"><em><strong><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244);\">=&gt;&ldquo;እራሱ(አብ) አክብሮ አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ አለው&rdquo; ዮሐንስ አፈ ወርቅ ድር 8&divide;69 ብሎ አብ ወልድን እንዳከበረው እየተናገረ ለምን እራሱን በራሱ አከበረ ለማለት ደፈራችሁ? ምን ምስክርስ አላችሁ?ይሉናል።</span></strong></em></span></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✔. አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ የሚለው ቃል መነሻው ዳዊት ነው። ይህን የጻፈው ዳዊት 2&divide;7 ላይ ነው።ማክበር አምላካዊ ግብር እንደመኾኑ መጠን በአብ በወልድ በመንፈስ ቅዱስ ሊነገር ይችላል። ይህ </span><span style=\"font-size: 14pt;\">ችግር ነው ብለን አናውቅም። በመጀመሪያ</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ማክበር የማን ግብር ነው ብለው ያስባሉ?</em></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ግብርነቱስ የአካል ነው ወይስ የአምላክነት?የሚሉትን ጥያቄዎች ማጤን ያስፈልጋል።</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.እኛ ወልድ ዋህድ በተዋህዶ ከበረ ብለን የምናምን እርሱ ራሱን እንዳከበረ መጽሐፍትን አብነት አድርገን&nbsp;እንናገራለን።ይኸውም&laquo;ዳግመኛ ክርስቶስስ ክብር መሻት ኖሮበት አልከበረም እርሱ ራሱ አክባሪ ነው እንጂ ሰው ቢኾንም በባሕርይ&nbsp;ክብሩ ከበረ እርሱ ራሱ እግዚአብሔር አምላክ ነው ሥጋ ትሁት ሕጹጽ ነዳይ ስለኾነ ተለዐለ ተብሎ ተነገረለት ከኹሉ በላይ የኾነ ስምንም እርሱ ራሱ ሰጠው ተባለ ይህም የኾነ በባሕርይ ተዋሕዶ ነው አምላክ እንደኾነ&nbsp;እኛንም እርሱ ወደ አለበት ያቀርበን ዘንድ&raquo; ሊቁ ቅዱስ ቄርሎስ በሃይማኖተ አበው ስምዐት 124 &divide;34 ላይ ይላል።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ታላቁ ሊቅ ቅዱስ ዮሐንስ አፈወርቅም በሃይማኖተ አበው 66 &divide;18 -19&nbsp;ላይ አካላዊ ቃል የተዋሐደውን የእኛን ሥጋ እንዳከበረው በመደነቅ እንዲህ ይላል፡-</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;ክብሩ ተለይቶ የነበረ ሥጋን ክቡር አምላክ ሊያደርገው የጸጋ ገዥነትን አጥቶ የነበረ ሥጋንም የባሕርይ ገዥ&nbsp;ሊያደርገው ወደደ አዳም ከእኛ እንደ አንዱ ኾነ ያለውንም ሰው በመኾን ሊገልጠው ወደደ። ስለዚህ ሥጋዬን&nbsp;ተዋሐደ። ወንጌልን ሲያስተምር እሰማው ዘንድ ሥጋዬን በተዋሕዶ ገንዘብ አደረገ፤ መንፈስ ቅዱስን ሰጠኝ ሰጠሁ ተቀበልኩ ለእኔም ፍጹም ሕይወትን ገንዘብ አደረግሁ። እርሱ ያከብረው ዘንድ ሥጋዬን ተዋሐደው። የሚያድነኝ መንፈስ ቅዱስን ሰጠኝ&raquo;በዚህ አነጋገር መሠረት <strong><span style=\"text-decoration: underline;\">እርሱ የተባለው አካላዊ ቃል ነው</span></strong>። አንዳንድ የቅብዐት እምነት ተከታዮች ግን እርሱ የሚለውን ለመንፈስ ቅዱስ ቀጽለው በመንፈስ ቅዱስ ከበረ ለሚለው ኑፋቄያቸው ደጋፊ ጥቅስ አድርገው ይጠቅሱታል። እርሱ የሚለውን ለመንፈስ ቅዱስ ከቀጸሉት ሥጋዬን የተዋሐደው መንፈስ ቅዱስ ነው ያሰኛልና ፍጹም ክህደት ነው። መንፈስ ቅዱስ ሥጋዬን ተዋሕዶ ሰው ኾነ የሚያሰኝ ክፉ መንገድ ነው። በተዋሕዶ ከበረ&nbsp;ብለው ላለማመን ወደ ሌላ ስህተት ሲያመሩ ይታያሉ። ሊቁ እንደጻፈው ግን እርሱ የሚለው ለአካላዊ ቃል የተነገረ ነው። ስለዚህም እርሱ መንፈስ ቅዱስን ሰጠኝ ሲል አካላዊ ቃል ለተዋሐደው ሥጋ የባሕርይ ሕይወቱ&nbsp;መንፈስ ቅዱስን መስጠቱንና ሥጋ የመንፈስ ቅዱስን ሕይወትነት ገንዘቡ ማድረጉን መናገር ነው። ይህ የተደረገው ደግሞ <span style=\"text-decoration: underline;\"><strong>በተዋሕዶ</strong></span> ብቻ ነው።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች&nbsp;የሊቁን ትምህርት በማስተዋል ተመልከቱና ከሰፊው የምስጢር ባሕር ውስጥ ገብታችሁ የምሥጢሩን ጥልቀት የትምህርቱን ርቀት (ቀ ይጠብቃል) አድንቁ ከዚህ በላይ ምን ማስረጃ አለ??</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;<span style=\"color: rgb(186, 55, 42);\"><strong>ወከመዝ ነአምሮ ለሊሁ ተቀብዐ ከመ ሥርዓተ ትስብእት ወዳእሙ ውእቱ ዘይቀብዕ ርእሶ በ</strong></span><span style=\"color: rgb(186, 55, 42);\"><strong>መንፈሱ ባሕቲቱ</strong></span>\"በተዋሕዶ እንደከበረ እናውቃለን ግን በገዛ ሥልጣኑ ራሱን የሚያከብር እርሱ ነው&raquo; ሃይማኖተ አበው ስምዓት 124 &divide;14 ይላል።</span></em><em><span style=\"font-size: 14pt;\">ወንጌላዊው ዮሐንስም በወንጌሉ ዮሐ 17&divide;19 ላይ &laquo;<strong><span style=\"color: rgb(186, 55, 42);\">አነ እቄድስ ርእስየ </span></strong>-እኔ ራሴን አከብራለሁ&raquo; ብሎ ጌታ የተናገረውን ጽፎት እናገኛለን። እኔ ራሴን አከብራለሁ ሲል በተዋሕዶ ማለቱ ነው። እኔ ሲልም በቃል ርስት ኾኖ ነው በሥጋ ርስትማ ይህን አይናገርም። ሥጋማ እንኳንስ ሊያከብር የጸጋ ልጅነትን እንኳ ያጣ ነበርና። ቃል ሲዋሐደው ግን ክቡር አምላክ ኾነ ይባላል። እኔ ብሎ አምላክነቱን (አክባሪነቱን) ራሴን ብሎ ሰውነቱን (ከባሪነቱን) ይናገራል። እርሱ ራሱ አክባሪ ነው እርሱ ራሱም ከባሪ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>↪\"እምቅድመ ቅብዓትሰ ነበሩ መላእክትከመ ህፃናት በዝንጋዔ ወሶበ ተቀብዑ መልዓ ላዕ', 'ነገረ ቅባት', 'Advanced', 'uploads/course_media/images/1783691519_dac8df41.jpg', '500.00', 'ዲ/ን ሶፎንያስ ደመቀ', 'uploads/course_media/pdfs/1783691519_02389ad4.pdf', '', '<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</h1>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"color: rgb(132, 63, 161); font-size: 36pt;\">ቅባት(ቅብዓት)</span></h1>\r\n<h2>&nbsp;<span style=\"font-size: 18pt;\"> <span style=\"font-size: 14pt;\"><em><strong>ቅባት(ቅብዓት) ትርጉሙ ምንድን ነው❓</strong></em></span></span></h2>\r\n<div><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(224, 62, 45);\">↪ቅባት በቅዱሳት መጽሐፍት ሲተረጎም የሚከተሉት ትርጉሞች አሉት።እነርሱም:-✔</span></strong></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">1ኛ.ቅባት ማለት በቁሙ ሲፈታ ቅባት ማለት ነው</span>።</strong>ቀባ፣ለከከ፣ለቀለቀ፣ቀባ የሚል ትርጉም ያመጣል።ለዚህም ማስረጃው-\"የመገናኛውንም ድንኳን የምስክሩንም ታቦት ገበታውንም ዕቃውንም ሁሉ መቅረዙንም ዕቃውንም መሰዊያውን ሁሉ ለሚቃጠለውም መሥዋዕት ለሚሆነው መሰዊያና ዕቃውንም ሁሉ የመታጠቢያውን ሰንና&nbsp;መቀመጫውን ትቀባበታለህ\"ዘጸ 30&divide;26</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">-\"ማርያምም እጅግ ዋጋው የከበረ የጥሩ ናርዶስ ሽቱ ንጥር ወስዳ የኢየሱስን እግር ቀባች\"ዮሐ 12 &divide;3 </span><span style=\"font-size: 14pt;\">=&gt;<span style=\"text-decoration: underline; color: rgb(185, 106, 217);\">ቅባት </span></span><span style=\"text-decoration: underline; color: rgb(185, 106, 217);\"><span style=\"font-size: 14pt;\">በቁሙ ሲፈታ</span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">2ኛ.ተቀብዐ:-ከበረ ተብሎ ይተረጎማል።</span></strong>ለዚህም ማስረጃ \"<strong>እለሰ የአምኑ ርቱዓ ይሜሀሩ ከመ ተቀብዓ ቃል በስጋሁ</strong>\"ትርጓሜውም ሲቀባም የሚለውም ሲከብርም ሲዋሐድም አንድ ጊዜ ነው ሲል ነው እንጂ በቁሙ ሲቀባ ስላለ ሲቀባ ተብሎ አይተረጎምም በቁም የሚተረጉሙ አሉና!!ወዳጄ \"መጽሐፍት ትርጓሜን እንጂ ዘይቤን አይጠነቅቁም \" እሽ!!ይህ ማለት ስጋ ከቃል ጋር ሲዋሐድ መጀመሪያ ተዋሕዶ በኋላ የከበረ አይደለም:ከብሮም ሳይዋሐድ አልቀረም;ሲከብርም ሲዋሐድም አንድ ጊዜ ነው እንጂ!! አንድም ከላይ ያለውን ያነሳነውን ቃል ሊቃውንተ ቤተ ክርስቲያን እንዲህ እያሉ አቅንተው ይተረጉሙታል።ኦሪት ወነቢያት ሰበኩ በክርስቶስ ሲል \"በክርስቶስ\" ያለው ክርስቶስሀ ማለት ነው። \"<strong>በ</strong>\" አገባብ በማድረግ \"<strong>ን</strong>\"የሚል ፍቺ ይሰጡና ኦሪትና ነቢያት በክርስቶስ ሰበኩ የሚለውን በቁሙ ኦሪትና ነቢያት ክርስቶስን ሰበኩ በማለት ይገልጹታል።ማለትም ክርስቶስን ይወርዳል ይወለዳል እያሉ ሰበኩ የወንጌልን አዝመራ ዘሩ ሐዋርያትም አጨዱት ነውና ቅሉ።ስለዚህ ይህንን ቃልም በሥጋሁ የሚለውን\"በ\"ን አገባብ አድርገው \"<strong>ሥጋን</strong>\" በማለት ይተረጉሙና ስጋን ተዋሐደ ብለው ያቀኑታል።</span></li>\r\n</ul>\r\n<p><span style=\"color: rgb(230, 126, 35);\"><strong><span style=\"font-size: 14pt;\">=&gt;.ያም ሆነ ይህ ግን ይህንን ነገር ስናነሳ እነዚህን ጥያቄዎች ማሰብ ያስፈልጋል።ማለትም በቁሙ መለኮት በስጋው ከበረ ከተባለ</span></strong></span></p>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቅድመ ተዋህዶ ቃል ክብር አልባ ነበርን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ነውስ ቃል በጊዜ ተዋህዶ የባሕርይ ክብሩን አጥቷል?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ወልድን ከመለኮታዊ ክብሩ ዝቅ አያደርገውምን?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.ቃል(መለኮት) በስጋው ከበረ ከተባለ ስጋን የተዋሐደ ከሦስቱ አካል አንዱ አካል ወልድ(አካላዊ ቃል) ነውና ሥላሴ በማክበር ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">መለኮት በስጋው ከከበረ በመለኮትነት ስንት ናቸው?</span></em></span></strong></li>\r\n<li style=\"font-style: italic; color: rgb(132, 63, 161); font-weight: bold;\"><strong><span style=\"color: rgb(132, 63, 161);\"><em><span style=\"font-size: 14pt;\">✔.መክበር የተፈጸመውስ መቼ ነው???በጊዜ ተዋህዶ \"ርስት\" ሰጥቶ መናገርን የትኞቱ አበውና መጽሐፍት አስተማሩን?</span></em></span></strong></li>\r\n</ul>\r\n</div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\"><strong><span style=\"color: rgb(35, 111, 161);\">3ኛ.ተቀብዐ:-ተዋሐደ ተብሎ ይተረጎማል።</span></strong>ብዙ ወገኖቻችን ግን ቀብዓን ተዋሐደ ብለው አይተረጉሙትም።ለዚህም ማስረጃ ታላቁ ሊቁ አባ ጊዮርጊስ ዘጋስጫ በመጽሐፈ አርጋኖን ዘአርብ ዕለት\"ዘተቀባዕከ ስጋሃ ለማርያም\"ብለዋል!!ይህ ንባብ የሚተረጎመው የማርያምን ስጋ የተዋሐድክ ተብሎ ነው!!ምክንያቱም በከበረ እንዳይተረጎም የማርያምን ስጋ የተከበርክ አይባልም::በቀብዓ እንዳይተረጎም የማርያምን ስጋ የተቀባህ አይባልም ስጋ ቅብዕ ይሆናልና።ስለዚህ የተዋሐድክ ብሎ አቅንቶ መተርጎም ያስፈልጋል ወዳጄ!!!</span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">➠ስለዚህ ሳጠቃልለው አንድ ቃል እንደአውዱ እንደአገባቡ የተለያየ ትርጉም ይኖረዋልና አንዲትን </span><span style=\"font-size: 14pt;\">በዘፈቀደ አንጠልጥሎ ሁሌም በዚህ ነው የሚፈታ ማለት የዕውር ክርክር ነው።ለምሳሌ \"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልክት ማኅበር ቆመ\"መዝ 81&divide;1 ይላልና ቆመ ስላለ ብቻ ቆመ ብለን ልንተረጉመው ነው??በጭራሽ</span></div>\r\n<div><span style=\"font-size: 14pt;\">ቆመ ብለን አንተረጉመውም!!ታዲያ ምን ብለን እንተረጉመዋለን ትሉኝ እንደሆነ\"እግዚአብሔር </span><span style=\"font-size: 14pt;\">በአማልዕክት መካከል ተገለጠ\"ብለን ነዋ!!እንደዚህም ሁሉ ተቀብዐን እንደአውዱ እንደ አገባቡ ይፈታል!!</span></div>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"color: rgb(224, 62, 45); font-size: 18pt;\"><strong>➠የቅባት ትርጉም እንደ ቅባት አስተምሮ ግን......</strong></span></h2>\r\n<div>\r\n<ul>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt; color: rgb(22, 145, 121);\">✔. ቅባት መንፈስ ቅዱስ ተብሎ ይተረጎማል!!</span></strong></li>\r\n<li style=\"color: rgb(22, 145, 121); font-weight: bold;\"><strong><span style=\"font-size: 14pt;\">✔.ቅባት ሕይወት ተብሎ እንደሚተረጎም ወልደ አብ መጽሐፍ ገጽ 179 ;</span><span style=\"font-size: 14pt;\">አዕማደ ምስጢር ገጽ 22 </span><span style=\"font-size: 14pt;\">ይናገራል!!</span></strong></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">&nbsp;ከዚህ ውጭ ግን <strong><span style=\"text-decoration: underline;\">ተቀብዐን ተዋሐደ</span></strong> ብለው ተርጉመው ፈጽሞ አይናገሩም;ተዋሐደ ብለው </span><span style=\"font-size: 14pt;\">መተርጎም ስህተት ነው ይላሉ \"ተዋሐደ\"ካሉ መንፈስ ቅዱስ ቅብዕ መሆንን ያፈርስባቸዋልና!!</span><span style=\"font-size: 14pt;\">ምናልባት በነገረ ሥጋዌ ጉዳይ እመቤታችንን ተቀባትም ተዋሐዳትም ማለት ክህደት ነው </span><span style=\"font-size: 14pt;\">ሲባል ብዙ ሰዎች ግራ ይጋባሉ;ነገር ግን ጊዜ ተዋህዶ ላይ የተፈጸሙ ተግባራትን ካለማወቅ </span><span style=\"font-size: 14pt;\">የተነሳ ነው ወገኖቼ!!!በምሥጢረ ሥጋዌ ትምህርታችን ስንነጋገር እነዚህን ነገሮች </span><span style=\"font-size: 14pt;\">ካስታወሳችሁ የጥያቄያችሁ መልስ ታገኛላችሁ!!!ይኸውም ቃል በጊዜ ተዋህዶ የማይቀዳደሙ </span><span style=\"font-size: 14pt;\">፫ት ነገሮች ተከናውነዋል። እነርሱም:-</span></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መክፈል፤</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">መዋሐድ እና</span></strong></span></li>\r\n<li style=\"color: rgb(52, 73, 94); font-weight: bold;\"><span style=\"color: rgb(52, 73, 94);\"><strong><span style=\"font-size: 14pt;\">&nbsp;መክበር ናቸው።</span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\">✟✔.ከፍሎ ሳይዋሐድ ቢቀር በሰው ወይም በእመቤታችን አደረ ያሰኛል።ይኼውም ኀደረ </span><span style=\"font-size: 14pt;\">በብእሲ ብሎ እንደካደው ጳውሎስ ሳምሳጢ ክህደት መግባት ነው።ተዋህዶ ሳይከፈል ቢቀር </span><span style=\"font-size: 14pt;\">እመቤታችን አምላክ ሆነቺ ያሰኛል።ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል።አካለ ቃል ክብር </span><span style=\"font-size: 14pt;\">አልባ ያሰኛል የሚሉት ናቸው።ስለዚህ ሲከፈልም፤ሲዋሐድም፤ሲከብርም(ሲቀባ) </span><span style=\"font-size: 14pt;\">አንድ ጊዜ ነው።</span></div>\r\n<div>\r\n<h1>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"font-size: 24pt; color: rgb(132, 63, 161);\">ምሥጢረ ሥጋዌ በቅባት አስተምህሮ (በወልደ አብ) ዕይታ</span></h1>\r\n<p><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 14pt;\">የኢትዮጵያ ኦርቶዶክስ ቤተ ክርስቲያን የምታስተምረው ትምህርት ከቅባት እምነት በጣም ሰፊ ልዩነት ሲኖራት የቅባት እምነት ተከታዮች ከዚህ በተለየ መልኩ ብዙ ክህደትን ሲያስተምሩ ይስተዋላሉ።ከነዚህም መካከል በጣም የጎሉትን የክህደት መንገዶ ከዚህ በታች ለማየት እንሞክራለን።&nbsp;</span></strong></span></p>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\">✔፩ኛ.እግዚአብሔር ወልድ ሁለት ልደታት አሉት እያሉ በቃል ደረጃ&nbsp;ይናገራሉ ።ነገር ግን በተግባር ደረጃ እንደጸጋ አስተምህሮ ፫ት ልደትን&nbsp;አማኝ ናቸው!!ለዚህ ማስረጃየ ወልደ አብ መጽሐፋቸው&nbsp;የመጀመሪያው ዕትም ገጽ 217 እና 218 እንዲህ ይላል!!</span></strong></div>\r\n<div style=\"padding-left: 80px;\"><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(132, 63, 161);\">\"<strong>የጌታችን ልደት ስንት ነው ቢሉ ፪ት ነው።እንዴት ፪ት ነው ቢሉ&nbsp;እምቅድመ ዓለም በመለኮቱ ተወለደ ብለናል ኋላም በማኅጸን በሰውነቱ&nbsp;ከአብ ተወለደ እንላለን ዳግም ከእመቤታችን በስጋ በጎል ተወለደ&nbsp;እንላለን</strong> \"</span></em>ወልደ አብ ገጽ ገጽ 217 ይላል!!</span></div>\r\n<div><span style=\"font-size: 14pt;\"><span style=\"font-size: 18pt; color: rgb(186, 55, 42);\"><strong>↪አስተዉሉ፦</strong></span></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ታዲያ ጌታችን ቅድመ ዓለም ከአብ በመለኮቱ፣ድኅረ ዓለም ከእመቤታችን በትስብእቱ፣ድኅረ ዓለም በማኅጸን በሰውነቱ ከአብ ተወለደ ከተባለ ሁለት ልደታት ማመን ከየት ይመጣል ይህ ፫ት ልደት&nbsp;አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ይህ ከሆነስ ወልደ አብ በመለኮቱ:ወልደ ማርያም በትስብእት፣አሁንም በድጋሜ በማህጸን ከወለደው እንደገና ወልደ አብ በትስብእቱ ሊባል ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ለማንኛውም \"በቃል ሁለት ልደት፣በተዘዋዋሪ በተግባር ግን ሦስት ልደት ይላሉ!!አይ ወገኔ\"አልሸሹምዞር አሉ\"ማለት ይሄ ነው እኮ ወገኔ ገባህ?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(52, 73, 94); background-color: rgb(248, 202, 198);\"><strong><span style=\"font-size: 14pt; background-color: rgb(248, 202, 198);\">፪ኛ.\"ሰባቱን ሀብታተ መንፈስ ቅዱስ እርሱ በስጋ ርስት በጊዜ ፅንስ ያለምክንያት ከአብ ተቀብሎ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉሥ ሆነባቸው\"ወልደ አብ ገጽ 211 ይላል</span></strong></span></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች የነገረ ቅባትን አስተምህሮ እና ጥያቄ የሚመለሰው ብዙ ጥቅስ መዘርዘር ሳያስፈልገው ጥያቄን በጥያቄ መመለስ እና በደንድ አገናዝቦ ማስተዋል ነው።ስለዚህ ከላይ እንዳያችሁት እንዲህ ካሉ&nbsp;እስኪ በሞቴ ንገሩኝ.........</span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ የባህርይ ልጅ የባህርይ አምላክ የባህርይ ንጉስ ሆነባቸው ማለት ቀድሞውንስ የባህርይ አምላክ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">እግዚአብሔር ወልድ ሰው የሆነስ በአባቱ ፈቃድ በእርሱ ፈቃድ በመንፈስ ቅዱስ ፈቃድ አይደለምን❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">ታዲያ እነማንን ነው የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸው❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በግድ ነው በኃይል የባህርይ አምላክ የባህርይ ንጉስ የባህርይ ልጅ የሆነባቸውስ❓</span></strong></em></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; font-style: italic; color: rgb(45, 194, 107);\"><span style=\"color: rgb(45, 194, 107);\"><em><strong><span style=\"font-size: 12pt;\">በመጀመሪያ \"ሆነባቸው\"ማለት በግድ አምላክ ሆኖባቸዋልን❓የእነርሱ ፈቃድስ❓</span></strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><em><strong><span style=\"color: rgb(52, 73, 94); background-color: rgb(236, 202, 250); font-size: 18pt;\">✔፫ኛ.\"መንፈስ ቅዱስ ሠጪም ተሠጭም ነው\"ወልደ አብ ገጽ 181&nbsp;ይላል።</span><span style=\"color: rgb(52, 73, 94); font-size: 18pt;\">ይህ ከሆነ.......</span></strong></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ምንድን ነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ ለማነው የሚሰጥ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለው ምንን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሚቀበለውስ ከማን ነው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>መንፈስ ቅዱስ የሌለው አለን ከሌላ የሚቀበል❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>በዓለመ ሥላሴ ነው መንፈስ ቅዱስን ሰጪም ተሰጪም ነው የምንል እንዳትሉኝ በዓለመ ሥላሴ በባህርይ በክብር በስልጣን አንድ ናቸው አንዱ ከአንዱ አያንስም አንዱ ከአንዱ አይበልጥ;ታዲያ አንዱ ከአንዱ ከአልበለጠ አንዱ ከአንዱ ካላነሰ ሰጪና ተሰጪ የሚል ከየት ይመጣል ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪና ተሰጪ ያልን ለፍጡራን ነው እንዳትሉኝ መንፈስ ቅዱስን ፍጡር እያላችሁት መሆኑ አይደለምን❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(230, 126, 35);\"><span style=\"color: rgb(230, 126, 35); font-size: 12pt;\"><strong><em>ሰጪም ተሰጪም ነውያልነው በፈጣሪና በፍጡር መካከል ነው እንዳትሉኝ መንፈስ ቅዱስ ፈጣሪ ነው ከፍጡር ይቀበላላልን❓ተሰጪ የሚለው አያፈርስባችሁምን❓ተብለዉ ሲጠየቁ መልስ የላቸዉም አፋቸዉን ይያዛሉ።</em></strong></span></li>\r\n</ul>\r\n<div><span style=\"background-color: rgb(194, 224, 244); color: rgb(52, 73, 94); font-size: 18pt;\"><em><strong>፬ኛ.አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ነው ይላሉ!!</strong></em></span></div>\r\n<div>-<em><span style=\"font-size: 14pt;\">ይህ ማለት፦</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ-አክባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ ከባሪ </span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል።በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።</span></em></li>\r\n</ul>\r\n<p><span style=\"font-size: 14pt;\"><strong>↪ታዲያ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን</strong></span></p>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>&nbsp;አብ አክባሪ፣ወልድ ከባሪ መንፈስ ቅዱስ ክብር የሚል ከየት ይመጣል❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(186, 55, 42); font-size: 12pt;\"><span style=\"color: rgb(186, 55, 42); font-size: 12pt;\"><em><strong>ምሥጢረ ሥላሴ ላይ የተነገረውን ለምስጢረ ሥጋዌ መቀፀልስ ለምን አስፈለገ❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\"><strong>↪\"ሥላሴ በተለየ ግብር ሦስት ናቸው።ይኸውም መውለድ፣ማስረፅ፣መወለድ፣መስረፅ ነው\"ይላል ገጽ 53;እንደገና 133 ላይ ደግሞ\"ቅብዕ የሆነ ግን በተለየ አካሉ በተለየ ግብሩ መንፈስ&nbsp;ቅዱስ ነው\"ይላል</strong></span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለመንፈስ ቅዱስ የተለየ ግብር የተሰጠው መቼ ነው ቅብዕነት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>የመንፈስ ቅዱስ ግብር መስረፅ ከሆነ ቅብዕነት ደግሞ ለመንፈስ ቅዱስ መቼ ተጨመረለት❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; color: rgb(45, 194, 107); font-weight: bold; font-size: 12pt;\"><span style=\"font-size: 12pt;\"><strong><span style=\"color: rgb(45, 194, 107);\"><em>ታዲያ ለወልድና ለአብስ ምን የተለየ ግብር ምን ተጨመረላቸው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">&nbsp;ከዚያ ባለፈ አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ማለት </span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: circle;\">\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">አብ➠ሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">ወልድ➠ተሠጭ</span></em></li>\r\n<li style=\"font-size: 14pt; font-style: italic;\"><em><span style=\"font-size: 14pt;\">መንፈስ ቅዱስ➠ስጦታ ማለት ነው።</span></em></li>\r\n</ul>\r\n<p><em><strong>↪<span style=\"font-size: 12pt;\"> ይህ ከሆነ&nbsp; &nbsp;</span></strong></em></p>\r\n</div>\r\n<div>\r\n<div>\r\n<ul>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ አለን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>በሥላሴ ዘንድ ሰጪና ተሰጪ ካለ ሰጪ ከተሰጪ ይበልጣል;ተሰጪ ከሰጪ ያንሳል!!ታዲያ አብ ከወልድ ከመንፈስ ቅዱስ ይበልጣልን❓</strong></em></span></li>\r\n<li style=\"font-weight: bold; font-style: italic; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><em><strong>ወልድስ ከአብ ከመንፈስ ቅዱስ ያንሳልን❓</strong></em></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; color: rgb(132, 63, 161); background-color: rgb(206, 212, 217);\"><em><strong>✔፭ኛ.\"ስጋ ሲፈጠር መለኮትም ከስጋ ጋር አብሮ ተፈጠረ ካላሉ&nbsp;ይላል\"ወልደ አብ ገጽ 127</strong></em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>መለኮት(ቃል) ራሱ ፈጣሪ ነው;ራሱ ፈጣሪ ከሆነ ከስጋ ጋር አብሮ ማን ፈጠረው ወዳጄ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ጸሎተ ሐይማኖት ላይ\"ዘተወልደ ወአኮ ዘተገብረ\"የተወለደ እንጂ ያልተፈጠረ የምትለዋን ፋቃችኋት እንዴ ታዲያ ወገኖቼ❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; color: rgb(35, 111, 161); font-size: 12pt;\"><span style=\"color: rgb(35, 111, 161); font-size: 12pt;\"><strong><em>ፍጡር ከሆነ ታዲያ እመቤታችን ወላዲተ አምላክ ሳይሆን ወላዲተ ሰብእ ናት ልትሉ ነው እንደ ፎጢኖስ❓</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><strong><em><span style=\"color: rgb(132, 63, 161); background-color: rgb(241, 196, 15); font-size: 18pt;\">✔፮ኛ.\"እኛ የምንቀበለው የጸጋ ጌታ የሚቀበለው የባህርይ ነው ማለት&nbsp;እንዴት ነው ቢሉ እኛ በተወለድን በ፵ ቀን እናገኘዋለን በክህደት&nbsp;በኃጢአት ይነሳል ስለዚህ ስለዚህ የጸጋ ይባላል።ጌታ ግን ሲዋሐድ የባህርይ ህይወት መንፈስ ቅዱስን ከአካሉ ጋር አግኝቶታልና የባህርይ&nbsp;ይባላል\"ወልደ አብ ገጽ 188</span></em></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ጌታ የባህርይ ህይወቱን መንፈስን ከአካሉ ጋር አግኝቶታል ይላል;የመንፈስ ቅዱስን አካሉን ነው ወይስ ሀብቱን የተቀበለው❓</em></strong></span></li>\r\n<li style=\"font-style: italic; font-weight: bold; font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>አካሉን ከተባለ መንፈስ ቅዱስ ከስጋ ጋር ተዋህዷልን ❓</em></strong></span></li>\r\n<li style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><span style=\"font-size: 12pt; color: rgb(186, 55, 42);\"><strong><em>ሀብቱን ካላችሁስ ክርስቶስ ዕሩቅ ብእሲ መሆኑ አይደለምን ❓</em></strong><em><span style=\"color: rgb(0, 0, 0);\">ብላችሁ ስትጠይቋቸው ምላሽ ያጣሉ።</span></em></span></li>\r\n</ul>\r\n<p><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp;</strong></span></p>\r\n<div><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;በነገረ ቅባት በመንፈስ ቅዱስ ከበረ ለማለት የሚነሱ ጥቅሶች</strong></span></div>\r\n<div>&nbsp;</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.የዘመኑ ቅባት ነን ባዮች በመንፈስ ቅዱስ ከበረ ለማለት በጣም በርካታ የመጽሐፍ ቅዱስ ጥቅሶችን ቢያነሱም ከብዙዉ በጥቂቱ ተደጋጋሚ ሁሌም የሚያነሷቸው የአፍ መፍቻ ጥያቄዎች የሚከተሉት ሲሆኑ ቤተክርስቲያናችን አረዳዷ ሚን ዪመስላል የሚለዉን ትርጓሜዉን እናያለን።</span></em></div>\r\n<div><strong><span style=\"background-color: rgb(194, 224, 244);\"><em><span style=\"font-size: 14pt; background-color: rgb(194, 224, 244);\"><span style=\"font-size: 18pt;\"><span style=\"color: rgb(45, 194, 107);\">1ኛ. </span>\"<span style=\"color: rgb(45, 194, 107);\">ዘአንገሦ ለሥጋ አዳም በመንፈስቅዱስ ወረሰዮ ቅዱሰ&nbsp;ወማሕየዌ ዘለብሶ ለአዳም መዋቲ</span></span>\"በመንፈስቅዱስ ህይወትነት&nbsp;የአዳምን ባህርይ ያከበረው የባህርይ አምላክ ያደረገው እርሱ ነው\"ሃይ.አበ.ዘእልመስጦአግያ ፪:፭</span></em></span></strong></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡በመጀመሪያ ያከበረው አለ እንጂ ክብር የሆነው አይልም አስተውሉ ወዳጄ!!</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>መንፈስ ቅዱስ ቅብዕ(ክብር) ከሆነው ለምን ያከበረው አለ ለምን ክብር የሆነው አላለም❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(185, 106, 217);\"><span style=\"color: rgb(185, 106, 217);\"><strong><span style=\"font-size: 12pt;\"><em>፫ቱ በአክባሪነት አንድ አይደሉምን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም ይህ የተነገረው የመንፈስቅዱስን ህይወትነት ሥጋ ገንዘብ ማድረጉን ሲናገር ነው!!አንድም \"የአዳምን ሥጋ በመንፈስ ቅዱስ አዋሐጅነት የተዋሐደው እርሱ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">➡አንድም በመንፈስቅዱስ ህይወትነት ማለት በረቂቅ የሥላሴ ግብር ማለት እንጂ መንፈስ ቅዱስ ክብር ሆነው ለማለት አይደለም ወዳጄ!!የአዳምን ሥጋ በግብረ መንፈስ ቅዱስ ተዋሕዶ የባሕርይ ንጉሥ ያደረገው&nbsp;</span></em><em><span style=\"font-size: 14pt;\">እርሱ ነው!!\"<strong>ወረሰዮ ቅዱሰ ወማሕየዌ ክቡር ወሀቤ ሕይወት</strong> አምላክ ያደረገው እርሱ ነው ካለ በኋላ ዘለብሶ ለአዳም መዋቲ\"አለ;ለምን ከተባለ ስጋን የተዋሐደ በተለየ አካሉ ወልድ ነውና።ግብረ መንፈስ ቅዱስ </span></em><em><span style=\"font-size: 14pt;\">ማለት ረቂቁን ለመንፈስ ቅዱስ መስጠት ነው እንጂ በማዋሐድ፣ በመፍጠር፣ በመግዛት፣ በመንግሥት፣በክብር ሦስቱ አካላት አንድ ናቸውና በአንዲት ግብረ ባሕርይ መሆኑን እናስተውል።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><span style=\"font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(194, 224, 244);\">2ኛ. \"ለሊሁ ዘይሁብ ወለሊሁ ዘይትወሀብ\"-ጸጋውን የሚሰጥ እርሱ ነው ጸጋም ሆኖ የሚሰጥ እርሱ ነው\"</span></strong></span><span style=\"text-decoration: underline;\">አረ.መን.ድር.11</span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ይህ ቃሉ የተነገረው ለመንፈስ ቅዱስ ሳይሆን ለወልድ ነው ምክንያቱም እርሱ ለኩነተ ሥጋ ተሰጦአልና ነው ወዳጄ!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም በሰባኪ አድሮ ጸጋን ይሰጣል.በሰሚ አድሮ ይቀበላልና!!</em></span></div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em>3ኛ. \"አማን አንገለጉ በዛቲ ሀገር ላዕለ ቅዱስ ወልድከ ኢየሱስ&nbsp;ዘቀባእካሁ.ሐዋ.4&divide;27</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ከዚህ ላይ የምናስተዉለው ነገር አለ።ይኽውም፦</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>መንፈስ ቅዱስ ቅብዕ ከሆነው በቀባኸው አለ እንጂ ቅብዕ በሆንኸው ለምን አላለም❓</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>-ቅብ የሆነው መንፈስ ቅዱስ ነው ከተባለ ይህ ቃል ደግሞ የአብን ቀባዒነት የክርስቶስን&nbsp;ተቀባዒነት ይናገራል እንጂ የመንፈስቅዱስን ቅብዕነት አይናገርም እኮ!!</em></span></div>\r\n<div><span style=\"font-size: 18pt; color: rgb(45, 194, 107); background-color: rgb(236, 202, 250);\"><em><strong>4.&nbsp;እንደእሱ አካል ባለ አካል አክብሮታልና.ዮሐ.አፈ.ወ.ድር 3&divide;100</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>➡አስተውሉ</strong>:-ሥጋን በቃል አንቀጽ ሲጠራው እንደሱ አካል አለ፤ባለአካል ብሎ ቃልን ጠራው&nbsp;አክብሮታል አለ እንጂ ክብር ሆኖታል አላለም</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡አንድም አካለቃል ከአካለሥጋ፣ባህርየ ቃል ከባህርየ ሥጋ ጋር መዋሀዳቸውን እየተናገረ ነው!!</em></span></div>\r\n<div><span style=\"color: rgb(45, 194, 107); background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>5 .\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከ እግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ\"<span style=\"font-size: 14pt;\">መዝ 44 &divide;7</span></em></span></strong></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em><strong>✔ \"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን&nbsp;ቀባህ\"</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;በመጀመሪያ እነዚህን ጥያቄዎች እንመልስ &nbsp;</em></span></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ቃሉ በባለቤትነት የተነገረው ለማን ነው❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>እግዚአብሔር ሲል ከ3ቱ አካል ለአንዱ የመንፈስ ቅዱስ ስም ብቻ ነው የሦስት ስም አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ከባልንጀሮችህ ይልቅ ሲልስ ባልንጀሮቹ እነማን ናቸው ይልቅ የሚለውስ ለምን መቀጸል አስፈለገ❓</em></span></strong></span></li>\r\n<li style=\"font-style: italic; font-size: 12pt; font-weight: bold; color: rgb(132, 63, 161);\"><span style=\"color: rgb(132, 63, 161);\"><strong><span style=\"font-size: 12pt;\"><em>የደስታን ዘይት ቀባህ ማለት ትርጉሙ ምንድን ነው❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>* በመጀመሪያ\"ጽ<strong>ድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ&nbsp;የደስታ ዘይትን ቀባህ</strong>\"በሚለውኃይለ ቃል ውስጥ \"<span style=\"text-decoration: underline;\"><strong>አንተ</strong>\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ </span></em></span><span style=\"font-size: 14pt;\"><em><span style=\"text-decoration: underline;\">እናስተውል:;ይኸውም&nbsp;\"<strong>ትስብእት\"</strong>ነው።\"ባልንጀሮችህ\"የተባሉት ደግሞ ቀደምት ነቢያት፣ካህናት ነገስታት ናቸው።</span></em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 14pt;\"><em>❓=ታዲያ \"ከባልንጀሮችህ ይልቅ\"ለምን አለ ትሉኝ እንደሆን እነርሱ ሲሾሙ የነበረው በቅብዓ ዘይት ነበርና እነ ዳዊት መመልከት ይቻላል!!ለእነርሱ ሹመት ከእግዚአብሔር የሚያገኙት የሚቀበሉት ጸጋ </em></span><span style=\"font-size: 14pt;\"><em>ጊዜያዊ የሚያልፍ ነው።የክርስቶስ ሰው መሆን የትስብእት መክበር ግን ከማንም የማይቀበለው የባህርይው በተጭና በተሰጭ መካከል የሚደረግ አይደለም ሲል ነው፣ታዲያ የስጋ መክበር እንዴት ነው ትለኝ&nbsp;</em></span><span style=\"font-size: 14pt;\"><em>እንደሆነ\"<span style=\"color: rgb(224, 62, 45);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"መለኮት ለስጋ ክብር ሆነው እርሱ ራሱ በባህርይ ክብሩ ከበረ፣ስጋ&nbsp;እርሱ ራሱ ክብሩ አምላክነቱ የባህርይ ከሆነ መለኮት ጋር ስለተዋሐደ\"እልሃለሁ ወዳጄ!!</em></span><span style=\"font-size: 14pt;\"><em>አንድም እግዚአብሔር አምላክ ብሎ ለምን አራቀቀው ትለኝ እንደሆነ\"<strong>የተዋሐደው የፈጠረውን ስጋ</strong>\"ነውና&nbsp;ማለትም\"እርሱ ራሱ የፈጠረውን ስጋ ተዋሐደ እንዲል ሊቁ!!!</em></span>\r\n<div>&nbsp;<span style=\"font-size: 14pt;\"><em>አንድም ይልቅ ማለቱ\"አምላክነት የባህርይው ስለሚሆን በጸጋ እንዳደረባቸው እንደቅዱሳኑ ሳይሆን አንተ ገንዘብህ የሚሆነውን መለኮትን ስለተዋሐድክ ነው ሲል ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን&nbsp;መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው </em></span><span style=\"font-size: 14pt;\"><em>ትለኝ እንደሆነም ሰው መሆንን ወደድህ የተባለ ቃል ነው፣ከበረ የተባለ ደግሞ ሥጋ ነው!!ሁለቱን&nbsp;መናገሩ፣በአንድ አንቀጽ ሁለቱን መናገር ነው።\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቦ ዘይቤላ በእንተ ትስብእቱ ወመለኮቱ</strong></span>\"እንዲል </em></span><span style=\"font-size: 14pt;\"><em>አንድም ሰው ማለት ክብርና መክበር ተዋህደው ክርስቶስ ነውና \"የደስታ ዘይትን (ቅብዓ ትፍስሕት)የተባለውስ ማነው ካልከኝ ወልድ(ቃል) ነው ቀባህ ሲልም&nbsp;\"አከበረህ\"ማለቱ ነው።</em></span><span style=\"font-size: 14pt;\"><em>አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ቀብዐከ እግዚአብሔር አምላክከ</strong></span>\"ብሎ ባህርያዊ ግብሩን በሚገልጥ መጥራቱ አብ አብ ቀባዒ እንደሆነ በምን ያስረዳል❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ነውስ\"<span style=\"color: rgb(132, 63, 161);\"><strong>አንሰ ሶበ እቤ እግዚአብሔር እብል በእንተ አብ ወወልድ ወመንፈስ ቅዱስ</strong></span>\"-እኔ እግዚአብሔር&nbsp;ብየ በተጣራሁ ጊዜ ስለ አብ ስለወልድ ስለመንፈስ ቅዱስ መናገሬ ነው የሚለው ተዘነጋ እንዴ❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ታዲያ እግዚአብሔር ማለት የሦስት የባህርይ ግብር ለመግለጥ የምንጠቀምበት ስም ከሆነ አብን ቀባዒ&nbsp;ለማድረግ ምክንያቱ ምንድን ነው❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250); font-size: 18pt;\"><strong><span style=\"background-color: rgb(236, 202, 250);\"><em>&nbsp;6.ወበከመ ለአብ ቦቱ ህይወት ኀቤሁ.ዮሐ 5&divide;26</em></span></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;ለምሳሌ ክርስቶስ ከተነሣ በኃላ ሥልጣን ተሰጠኝ. ማቴ 28&divide;18 ይላልና ያን ጊዜ ሥልጣን ተሰጠው ማለት ነውን❓</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>ስለዚህ ህይወቱን ሰጠው ማለት፡-</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ተሰጠኝ ሲል ተሰጦት አይደለም ገንዘብ ማድረጉን ሲሻ ነው እንጂ&nbsp;</em></span>\r\n<div><span style=\"font-size: 14pt;\"><em>➠የቃል ገንዘብ ለስጋ ሲሆን ህይወትነት ለሥጋ ገንዘቡ ሆነ ማለት ነው።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠ሕይወት ያለው መንፈስ ቅዱስን አይደለም ለሚወዳቸው ህይወትን ሰጣቸው ይላልና.ዮሐ 5&divide;21</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➠አንድም ስለሥጋ እንግድነት የተነገረ ነው አለዚያማ ለወልድም ህይወቱ ይሆን ዘንድ ይላልና መንፈስ ቅዱስ ከወልድ የተለየበት ጊዜ አለ ያሰኛል።</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>ከሁሉ አስቀድሞ ግን የረሳሁት ነገር......</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ተቀብዓን ህይወት ተብሎ ከተተረጎመና ለስጋ ክብር የሆነው መንፈስ ቅዱስ ነው የምንለው የባህርይ ህይወቱ ስለሆነ ነው&nbsp;ከተባለ አብም የባህርይ ልቡ ነውና ምን እንበለው እሽ ወገኖቼ ❓</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"background-color: rgb(236, 202, 250);\"><em><span style=\"font-size: 18pt; color: rgb(52, 73, 94); background-color: rgb(236, 202, 250);\"><strong>7.\"እነሆ ናዝራዊው ኢየሱስ ቅባትን ተቀብቶ የመቀባትን&nbsp;መንግስት ተቀበለ፣አምላክ ሲሆን ስለሰውነቱም የመለኮትን ቅባት&nbsp;ተቀብቶ ሰው ሆነ እግዚአብሔር ሰው ለመሆን ወረደ ሰውም&nbsp;እግዚአብሔር ለመሆን ከፍ ከፍ አለ\"<span style=\"font-size: 14pt;\">መ.ምሥጢር ገጽ 214</span></strong></span></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ በመጀመሪያ ናዝራዊው ኢየሱስየሚለው ከሁለት አካል አንድ አካል ከሁለት ባህርይ አንድ ባህርይ ሲሆን&nbsp;የወጣለት የተዋህዶ ስም ነው!!ትርጓሜውም መሲህ፣የተቀባ፣የተሾመ ማለት ነው።የተቀባ የተሾመ ሲባል ግን ለእርሱ ቀቢ ሿሚ ኖሮት አይደለም።ቀቢውም ሿሚውም ተሿሚውም አንድ&nbsp;እርሱ ነው እንጂ!!ዮሐ 4&divide;25 -30 ማለትም<span style=\"color: rgb(132, 63, 161);\"><strong>\"ለሊየ እቄድስ ርእስየ\" </strong></span>እንዲል ይህ ሲባል ኢየሱስ ክርስቶስ ቅባትን ተቀብቶ ሲል አንቀጹ ለትስብእት ነው።ማለትም መለኮት&nbsp;ለተዋሐደው ስጋ ክብር ሁኗል;አንድም ቅድመ ተዋህዶ ትስብእት ትሑት፣ህፁፅ ስለሆነ ተለዓለ ተብሎ ተነገረለት።ማለትም ያ ህፀፅ ንዴት የነበረበት ትስብእት ከቃል ጋር ሲዋሐድ ቃል ለተዋሐደው ስጋ ክብር&nbsp;ሆነው\"<span style=\"color: rgb(132, 63, 161);\"><strong>መለኮቱ ቀብዖ ለትስብእቱ</strong></span>\"እንዲል ቅዱስ ቄርሎስ &nbsp;የቃል ገንዘብ በተዋህዶ ለስጋ ገንዘቡ ሲሆን ከበረ አምላክ ሆነ፣የባህርይ ልጅ ሆነ ሲል የመቀባትን መንግስት ተቀበለ አለ።ማለትም ስጋ ከተዋህዶ በኋላ የመለኮት ገንዘብን ገንዘቡ አድርጓልና\"\"<span style=\"color: rgb(132, 63, 161);\"><strong>እንቲአሁ ለቃል ኮነ ለስጋ ወእንቲአሁ ለስጋ ኮነ ለቃል</strong></span>\"እንዲል ቅዱስ ቄርሎስ!አንድም ስጋ ልዕልናን ግብረ አምላካዊውን ባህርይው ረቂቅባህርየ መለኮትን ገንዘቡ አደረገ።ማለትም&nbsp;የሚሞት ሲሆን የማይሞት ሆነ፣\"ምድራዊ ሲሆን ከልዕልና በላይ ያለ ልዕልናን ገንዘቡ አደረገ በአጠቃላይ የማይመረመር ጌትነትን አገኘ።አንድም በዚያው አጋጣሚ ነስአ ተወክፈ አይሉም እንባለለን;ነገር ግን ስንተረጉምና ስንል&nbsp;እመንገለ ሥጋሁ እንጂ እመንገለ መለኮቱ አንልም።ምክንያቱም በመለኮቱ በኩል&nbsp;ብንል \"ኢይጽሕቅ ቅብዓተ በህላዌ በመለኮቱ\"ማለትም በመለኮቱ መቀባትን(ክብርን)አይሻል!!ከዚህ በተጨማሪ እግዚአብሔር ሰው ለመሆን ወረደ ሲል የሰውን ባህርይ ባህርይው ለማድረግ ማለትም&nbsp;የማይራበው እንዲራብ መሆኑ፣ባእለ ጸጋ የነበረው ባህርይውን ሳይለቅ በተዓቅቦ ነዳይ መሆኑ የንጉሶች ንጉሥ ሲሆን የጌቶች ጌታ ሲሆን በአይሁድ ፊት መገረፉ በአጠቃላይ ራሱን በሰው መልክና አርዓያ መምጣቱን&nbsp;ያመለክታል። ምክንያቱም\"ነገር ግን የባህርይን መልክን ይዞ በሠውም ምሳሌ ሆኖ ራሱን ባዶ አደረገ&nbsp;በምስሉም እንደሰው ተገኝቶ ራሱን አዋረደ\"እንዲል ፊል 2&divide;8</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም\"<span style=\"color: rgb(132, 63, 161);\"><strong>ሕቀ አሕጸጽኮ እምመላእክቲከ</strong></span>\"-ከመላእክት እጅግ ጥቂት አሳነስኸው\"መዝ 8&divide;5 እንዲል&nbsp;አንድም \"ሰውም እግዚአብሔርን ለመሆን ከፍ ከፍ አለ ሲል በተዋህዶ የመለኮትን ገንዘብ ገንዘቡ </em></span><span style=\"font-size: 14pt;\"><em>ስለሚያደርግ የስጋ በአምላክነት መክበር መቀባት ተብሎ ተነግሯል።አምላክነቱ የባህርይው ስለሚሆን በጸጋ&nbsp;እንዳደረባቸው ቅዱሳን አይደለም ሲል ነው።አንድም ቅዱስ ዮሐንስ አፈወርቅ እንደገለጸው </em></span><span style=\"font-size: 14pt;\"><em>ትስብእት ከመለኮት ጋር በመዋሐዱ ያገኘውን የክብር መጠን ሲያብራራ እንዲህ በማለት በሰፊው&nbsp;አብራርቷል!!\"ወዴት ስፍራ እንዳወጣው ዕወቅ:ከፍጡራን ሁሉ ከመላእክትም ሁሉ በላይ አደረገው\"አለ።ረቂቅ </em></span><span style=\"font-size: 14pt;\"><em>እውቀትን እንዲገልጽልህ ከወደድክ በእግዚአብሔር ባህርይና በሰው ባህርይ መካከል ያለ ልዩነት ምን ያህል እንደሆነ አንተ እወቅ፣ማንም ሊናገረው ወደማይቺለው ክብረ መለኮት ትስብእትን ከፍ ከፍ </em></span><span style=\"font-size: 14pt;\"><em>አደረገው፣ከልዑላን መላእክት ሁሉ በላይ አደረገው\"ሃይ.አበው 67 ክፍል 16 &divide;23 ስለዚህ ተለዓለ መባሉ ስለዚህ ነው።</em></span></div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244); color: rgb(224, 62, 45);\"><em><strong>8. \"ዘቀብኦ እግዚአብሔር መንፈሰ ቅዱሰ ወኃይለ\"ሐዋ 10&divide;38</strong></em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>➡\"እግዚአብሔርም የናዝሪቱን ኢየሱስን በኃይል በመንፈስ ቅዱስ ቀባው\" ሲል </em></span><span style=\"font-size: 14pt;\"><em>በመንፈስ ቅዱስ ማለት በግብረ መንፈስ ቅዱስ(በረቂቅ ምሥጢር)ሥጋን አከበርኸው ማለት ነው!!</em></span></div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(186, 55, 42);\"><em>&nbsp;እንደዚህማ ባይሆን ኖሮ ሐዋርያው ቅዱስ ጴጥሮስ</em></span></strong></div>\r\n<div>\r\n<ul>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>\"እግዚአብሔር የናዝሬንቱን ኢየሱስን ከሙታን መካከል ለይቶ አስነሳው\"ሲል በመንፈስ ቅዱስ ወይም </em><em>በአብ ስልጣን ነው የተነሳ በራሱ ስልጣን የተነሳ አይደለምን❓</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>በራሱ ስልጣን ካልተነሳ \"እንዴት አልዓዛርን ከመቃብር አስነሳው\"ለራሱ የሌለው ለሰው </em><em>ያበድራልን❓</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔ አንድም በመንፈስቅዱስ በቀባኸው አለ እንጂ ቅብዕ በሆነው አይልም!!</em></span></div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(224, 62, 45); font-size: 18pt; background-color: rgb(251, 238, 184);\"><strong><em>9.\"መንፈሰ እግዚአብሔር ላእሌየ ዘበእንቲአሁ ቀብዐኒ\"ኢሳ 61</em><em>&divide;1</em></strong></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp; ↪ የእግዚአብሔር መንፈስ ሲል መንፈስ ቅዱስ ነው፣እኔ ያለው ደግሞ ባለቤቱ ወልድ ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>☝በእኔ ላይ ማለቱም መንፈስ ቅዱስ በእኔ በወልድ ህልው ነው ማለቱ ነው!!</em></span><span style=\"font-size: 14pt;\"><em>ቀባኝ ማለቱም አዋሐደኝ ሲል ነው!!</em></span></div>\r\n<div>\r\n<div><span style=\"font-size: 14pt;\"><em>\"ስለዚህ የእግዚአብሔር መንፈስ በእኔ ህልው ነው፣ስለዚህ ነገር አዋሐደኝ ሲል በኢሳያስ የተነገረለትን የባህርይ ህይወቱን መንፈስ ቅዱስን እርሱ ገንዘብ እንዳደረገ ሊነገር ይገባል።ስለዚህ በባህርይ ገንዘቤ&nbsp;የሚሆን መንፈስ ቅዱስ በህልውናየ ጸና ብሎ ብሎ አስተማረ\"ሃይ.አበው ዘሳዊሮስ 87 ክፍል 17-18</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>&nbsp;&nbsp;***አዋሐደኝ ማለቱም የአምላክ ሰው መሆን በፈቃደ አብ፣በፈቃደ ወልድ፣በፈቃደ መምፈስ ቅዱስ የሆነ ማለት ነው!!</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ በሌላ አነጋገር </em></span><span style=\"font-size: 14pt;\"><em>አብ ቀባዒ ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ ከተባለ ታዲያ ከዚህ ጥቅስ ላይ </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li><span style=\"font-size: 14pt;\"><em>በእኔ ላይ ያለ የእግዚአብሔር መንፈስ ቀባኝ ሲል ቀባዒው ማነው❓</em></span></li>\r\n<li><em style=\"font-size: 14pt;\">በዚህ ጥቅስ ቀባዒው አብ መሆኑ አይደለምን❓</em></li>\r\n<li><em style=\"font-size: 14pt;\">ታዲያ መንፈስ ቅዱስ ቅብዕ የሚል ከየት ይመጣል❓</em></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h1><span style=\"font-size: 24pt; color: rgb(132, 63, 161);\"><em><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;የዘመኑ ቅባት ነን ባዮች የሚያነሷቸው ጥያቄዎችና መልሶቻቸው</strong></em></span></h1>\r\n<div>\r\n<div><strong><span style=\"font-size: 14pt; color: rgb(45, 194, 107); background-color: rgb(241, 196, 15);\"><em>=&gt;.እኛ የተዋህዶ ልጆች ትሥብእት ወይም ሥጋ ከባሪ መለኮት(ቃል) ክብር ስንል አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርጋችሁ ስትናገሩ መለኮት የመለኮትን ሥራ ይሰራል ሥጋም የሥጋን ሥራ ይሰራል </em><em>ከሚሉት መለካዊያን በምን ትለያላችሁ?ይሉናል።</em></span></strong></div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.ቅባት ወገኖቻችን ሆይ እኛ አንዱን አካል አክባሪ አንዱን አካል ከባሪ አድርገን እናንተ እንደምትሉት ያለ&nbsp;ፍልስፍና ላይ አልተሰማራንም በሉልኝማ የተዋህዶ ልጆች። ከበረ፣ አከበረ የምንለው በጊዜ ተዋሕዶ ላይ </em></span><span style=\"font-size: 14pt;\"><em>ያለን ጊዜ ብቻ ናት። መክበር ይሻ የነበረን ሥጋ አካላዊ ቃል በአምላክነት ክብሩ አከበረው። ይች እመቤታችን&nbsp;\"<span style=\"color: rgb(132, 63, 161);\"><strong>ይኩነኒ በከመ ትቤለኒ</strong></span>\"ባለችው ጊዜ የተፈጸመች ድንቅ ምስጢር ናት። ከዚህ ጊዜ በኋላ መለኮትና ትስብእት&nbsp;አንድ ስለኾኑ ከባሪና አክባሪ የለም።</em></span></div>\r\n<div><span style=\"font-size: 14pt;\"><em>↪ ወልድ አምላክ ነውና በአምላክነት ክብሩ ያከብራል ስንል ወልድ ማክበር አይችልም ካላችሁን </em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\"><em>\"በመንፈስ ቅዱስ ከበረ\"ስትሉ መንፈስ ቅዱስስ ማክበር የብቻው ግብሩ ነው ብላችሁ ነውን? </em></span></strong></span></li>\r\n<li><span style=\"font-size: 14pt;\"><em><span style=\"color: rgb(22, 145, 121);\"><strong><span style=\"font-size: 12pt;\">አዎ ካላችሁ ለመንፈስ ቅዱስ ከመሥረጽ ውጭ ሌላ አካላዊ ግብር እንዳለው ከየት ተማራችሁት? </span></strong></span>ማስረጃችሁ ምንድን ነው ወገኖቼ?ብላችሁ ጠይቁልኝ!!</em></span></li>\r\n</ul>\r\n</div>\r\n<div><span style=\"font-size: 14pt;\"><em>✔.አንዱ አካል አክባሪ ያሉ ቃልን አንዱ አካል ከባሪ የሚሉን ደግሞ ትስብእትን ለማለት ፈልጋችሁ ነው። እናንተ \"<span style=\"text-decoration: underline;\"><strong>በመንፈስ ቅዱስ ከበረ\"</strong></span> የምትሉት ሥግው ቃልን ነው።ታዲያ ሥግዉ ቃልን ከሆነስ</em></span></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ሥግው ቃል አምላክ ነው ወይስ አይደለም?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>&nbsp;ሥግው ቃል እስከሚከብር ድረስ የአብ የመንፈስ ቅዱስ ቃላቸው ማን ነበር?</em></span></strong></span></li>\r\n<li style=\"font-size: 12pt; font-weight: bold; color: rgb(35, 111, 161);\"><span style=\"color: rgb(35, 111, 161);\"><strong><span style=\"font-size: 12pt;\"><em>ትስብእት አምላክ የኾነው በቅብዐተ መንፈስ ቅዱስ ከኾነ ሥግው ቃል እስኪከብር ድረስ አብና መንፈስ ቅዱስ ዲዳ ነበሩ (ሎቱ ስብሐት)?</em></span></strong></span></li>\r\n</ul>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><span style=\"color: rgb(22, 145, 121); background-color: rgb(194, 224, 244);\"><em><strong><span style=\"font-size: 18pt; background-color: rgb(194, 224, 244);\">=&gt;&ldquo;እራሱ(አብ) አክብሮ አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ አለው&rdquo; ዮሐንስ አፈ ወርቅ ድር 8&divide;69 ብሎ አብ ወልድን እንዳከበረው እየተናገረ ለምን እራሱን በራሱ አከበረ ለማለት ደፈራችሁ? ምን ምስክርስ አላችሁ?ይሉናል።</span></strong></em></span></div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">✔. አንተ ልጄ ነህ እኔ ዛሬ ወለድኩህ የሚለው ቃል መነሻው ዳዊት ነው። ይህን የጻፈው ዳዊት 2&divide;7 ላይ ነው።ማክበር አምላካዊ ግብር እንደመኾኑ መጠን በአብ በወልድ በመንፈስ ቅዱስ ሊነገር ይችላል። ይህ </span><span style=\"font-size: 14pt;\">ችግር ነው ብለን አናውቅም። በመጀመሪያ</span></em></div>\r\n<div>\r\n<ul style=\"list-style-type: square;\">\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ማክበር የማን ግብር ነው ብለው ያስባሉ?</em></strong></span></li>\r\n<li style=\"font-size: 12pt; font-style: italic; font-weight: bold; color: rgb(22, 145, 121);\"><span style=\"font-size: 12pt; color: rgb(22, 145, 121);\"><strong><em>ግብርነቱስ የአካል ነው ወይስ የአምላክነት?የሚሉትን ጥያቄዎች ማጤን ያስፈልጋል።</em></strong></span></li>\r\n</ul>\r\n</div>\r\n<div><em><span style=\"font-size: 14pt;\">✔.እኛ ወልድ ዋህድ በተዋህዶ ከበረ ብለን የምናምን እርሱ ራሱን እንዳከበረ መጽሐፍትን አብነት አድርገን&nbsp;እንናገራለን።ይኸውም&laquo;ዳግመኛ ክርስቶስስ ክብር መሻት ኖሮበት አልከበረም እርሱ ራሱ አክባሪ ነው እንጂ ሰው ቢኾንም በባሕርይ&nbsp;ክብሩ ከበረ እርሱ ራሱ እግዚአብሔር አምላክ ነው ሥጋ ትሁት ሕጹጽ ነዳይ ስለኾነ ተለዐለ ተብሎ ተነገረለት ከኹሉ በላይ የኾነ ስምንም እርሱ ራሱ ሰጠው ተባለ ይህም የኾነ በባሕርይ ተዋሕዶ ነው አምላክ እንደኾነ&nbsp;እኛንም እርሱ ወደ አለበት ያቀርበን ዘንድ&raquo; ሊቁ ቅዱስ ቄርሎስ በሃይማኖተ አበው ስምዐት 124 &divide;34 ላይ ይላል።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ታላቁ ሊቅ ቅዱስ ዮሐንስ አፈወርቅም በሃይማኖተ አበው 66 &divide;18 -19&nbsp;ላይ አካላዊ ቃል የተዋሐደውን የእኛን ሥጋ እንዳከበረው በመደነቅ እንዲህ ይላል፡-</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;ክብሩ ተለይቶ የነበረ ሥጋን ክቡር አምላክ ሊያደርገው የጸጋ ገዥነትን አጥቶ የነበረ ሥጋንም የባሕርይ ገዥ&nbsp;ሊያደርገው ወደደ አዳም ከእኛ እንደ አንዱ ኾነ ያለውንም ሰው በመኾን ሊገልጠው ወደደ። ስለዚህ ሥጋዬን&nbsp;ተዋሐደ። ወንጌልን ሲያስተምር እሰማው ዘንድ ሥጋዬን በተዋሕዶ ገንዘብ አደረገ፤ መንፈስ ቅዱስን ሰጠኝ ሰጠሁ ተቀበልኩ ለእኔም ፍጹም ሕይወትን ገንዘብ አደረግሁ። እርሱ ያከብረው ዘንድ ሥጋዬን ተዋሐደው። የሚያድነኝ መንፈስ ቅዱስን ሰጠኝ&raquo;በዚህ አነጋገር መሠረት <strong><span style=\"text-decoration: underline;\">እርሱ የተባለው አካላዊ ቃል ነው</span></strong>። አንዳንድ የቅብዐት እምነት ተከታዮች ግን እርሱ የሚለውን ለመንፈስ ቅዱስ ቀጽለው በመንፈስ ቅዱስ ከበረ ለሚለው ኑፋቄያቸው ደጋፊ ጥቅስ አድርገው ይጠቅሱታል። እርሱ የሚለውን ለመንፈስ ቅዱስ ከቀጸሉት ሥጋዬን የተዋሐደው መንፈስ ቅዱስ ነው ያሰኛልና ፍጹም ክህደት ነው። መንፈስ ቅዱስ ሥጋዬን ተዋሕዶ ሰው ኾነ የሚያሰኝ ክፉ መንገድ ነው። በተዋሕዶ ከበረ&nbsp;ብለው ላለማመን ወደ ሌላ ስህተት ሲያመሩ ይታያሉ። ሊቁ እንደጻፈው ግን እርሱ የሚለው ለአካላዊ ቃል የተነገረ ነው። ስለዚህም እርሱ መንፈስ ቅዱስን ሰጠኝ ሲል አካላዊ ቃል ለተዋሐደው ሥጋ የባሕርይ ሕይወቱ&nbsp;መንፈስ ቅዱስን መስጠቱንና ሥጋ የመንፈስ ቅዱስን ሕይወትነት ገንዘቡ ማድረጉን መናገር ነው። ይህ የተደረገው ደግሞ <span style=\"text-decoration: underline;\"><strong>በተዋሕዶ</strong></span> ብቻ ነው።</span></em></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div><em><span style=\"font-size: 14pt;\">↪ዉድ የተዋህዶ ልጆች&nbsp;የሊቁን ትምህርት በማስተዋል ተመልከቱና ከሰፊው የምስጢር ባሕር ውስጥ ገብታችሁ የምሥጢሩን ጥልቀት የትምህርቱን ርቀት (ቀ ይጠብቃል) አድንቁ ከዚህ በላይ ምን ማስረጃ አለ??</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\">&laquo;<span style=\"color: rgb(186, 55, 42);\"><strong>ወከመዝ ነአምሮ ለሊሁ ተቀብዐ ከመ ሥርዓተ ትስብእት ወዳእሙ ውእቱ ዘይቀብዕ ርእሶ በ</strong></span><span style=\"color: rgb(186, 55, 42);\"><strong>መንፈሱ ባሕቲቱ</strong></span>\"በተዋሕዶ እንደከበረ እናውቃለን ግን በገዛ ሥልጣኑ ራሱን የሚያከብር እርሱ ነው&raquo; ሃይማኖተ አበው ስምዓት 124 &divide;14 ይላል።</span></em><em><span style=\"font-size: 14pt;\">ወንጌላዊው ዮሐንስም በወንጌሉ ዮሐ 17&divide;19 ላይ &laquo;<strong><span style=\"color: rgb(186, 55, 42);\">አነ እቄድስ ርእስየ </span></strong>-እኔ ራሴን አከብራለሁ&raquo; ብሎ ጌታ የተናገረውን ጽፎት እናገኛለን። እኔ ራሴን አከብራለሁ ሲል በተዋሕዶ ማለቱ ነው። እኔ ሲልም በቃል ርስት ኾኖ ነው በሥጋ ርስትማ ይህን አይናገርም። ሥጋማ እንኳንስ ሊያከብር የጸጋ ልጅነትን እንኳ ያጣ ነበርና። ቃል ሲዋሐደው ግን ክቡር አምላክ ኾነ ይባላል። እኔ ብሎ አምላክነቱን (አክባሪነቱን) ራሴን ብሎ ሰውነቱን (ከባሪነቱን) ይናገራል። እርሱ ራሱ አክባሪ ነው እርሱ ራሱም ከባሪ ነው።</span></em></div>\r\n<div><em><span style=\"font-size: 14pt;\"><span style=\"color: rgb(186, 55, 42);\"><strong>↪\"እም', '', '', '', 'Module: ነገረ ቅባት\n- Lesson: ቅባት(ቅብዓት)\n- Lesson: ቅባት(ቅብዓት) ትርጉሙ በቅዱሳት መጻሕፍት ዕይታ\n- Lesson: ቅባት(ቅብዓት) ትርጉሙ በቅባት አረዳድ ዕይታ\n- Lesson: በነገረ ቅባት በመንፈስ ቅዱስ ከበረ ለማለት የሚነሱ ጥቅሶች\n- Lesson: የዘመኑ ቅባት ነን ባዮች የሚያነሷቸው ጥያቄዎችና መልሶቻቸው', '<article class=\"builder-output-card\"><h4>Question 1</h4><ol></ol></article>', '<article class=\"builder-output-card\"><h4>ነገረ ቅባት አሳይመንት</h4><p>እባክዎት መልስዎትን በጥንቃቄ ይስሩ።</p><p class=\"small\">Due: አሳይመንቱ የሚገባበት ቀን ከማጠቃለያ ፈተና በፊት • Points: 10%</p></article>', '', '2026-07-10 16:51:59', '', 'http://localhost/sofiproject/sofi fikr.jpg');

DROP TABLE IF EXISTS `discussion_posts`;
CREATE TABLE `discussion_posts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `topic` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `author_name` varchar(255) NOT NULL,
  `author_role` varchar(50) NOT NULL DEFAULT 'Guest',
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `discussion_posts` (`id`, `topic`, `message`, `author_name`, `author_role`, `created_at`) VALUES ('1', 'ምሥጢረ ሥላሴ', 'ኩነት ምንድን ነው?', 'sofonyas', 'Admin', '2026-06-23 22:56:20');

DROP TABLE IF EXISTS `discussion_replies`;
CREATE TABLE `discussion_replies` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `post_id` int(11) NOT NULL,
  `author_name` varchar(255) NOT NULL,
  `author_role` varchar(50) NOT NULL DEFAULT 'Guest',
  `message` text NOT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `post_id` (`post_id`),
  CONSTRAINT `discussion_replies_ibfk_1` FOREIGN KEY (`post_id`) REFERENCES `discussion_posts` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `email_notifications`;
CREATE TABLE `email_notifications` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `admin_id` int(11) NOT NULL,
  `recipient_email` varchar(255) NOT NULL,
  `subject` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `sent_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `email_notifications` (`id`, `admin_id`, `recipient_email`, `subject`, `message`, `sent_at`) VALUES ('1', '1', 'yilkaldemeke21@gmail.com', 'የውይይት ፎርም አዲስ ልጥፍ', 'አዲስ የውይይት ልጥፍ ተሰብስቧል። ርዕስ: ምሥጢረ ሥላሴ በ sofonyas አማካኝነት', '2026-06-23 22:56:20');

DROP TABLE IF EXISTS `email_verification_tokens`;
CREATE TABLE `email_verification_tokens` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `email` varchar(255) NOT NULL,
  `token` varchar(255) NOT NULL,
  `expires_at` datetime NOT NULL,
  `used` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_email_verification_token` (`token`),
  KEY `idx_email_verification_email` (`email`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

