DROP TABLE IF EXISTS `event_announcements`;
CREATE TABLE `event_announcements` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `event_title` varchar(255) NOT NULL,
  `event_description` text NOT NULL,
  `event_date` datetime NOT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `content_type` varchar(30) NOT NULL DEFAULT 'announcement',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `exam_access_codes`;
CREATE TABLE `exam_access_codes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_type` varchar(50) NOT NULL,
  `access_code` varchar(50) NOT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `expiry_date` datetime DEFAULT NULL,
  `created_by` varchar(100) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_exam_access_code` (`exam_type`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `exam_access_codes` (`id`, `exam_type`, `access_code`, `is_active`, `expiry_date`, `created_by`, `created_at`) VALUES ('1', 'exam20', 'SOFI2721', '1', NULL, 'sofonyas', '2026-06-30 07:13:56');
INSERT INTO `exam_access_codes` (`id`, `exam_type`, `access_code`, `is_active`, `expiry_date`, `created_by`, `created_at`) VALUES ('4', 'mid_exam', 'SOFI2721', '1', NULL, 'sofonyas', '2026-06-28 11:18:24');
INSERT INTO `exam_access_codes` (`id`, `exam_type`, `access_code`, `is_active`, `expiry_date`, `created_by`, `created_at`) VALUES ('7', 'final_exam', 'SOFI2721', '1', NULL, 'sofonyas', '2026-06-29 01:00:48');

DROP TABLE IF EXISTS `exam_reminders`;
CREATE TABLE `exam_reminders` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(100) NOT NULL,
  `exam_type` varchar(100) NOT NULL,
  `exam_date` datetime NOT NULL,
  `reminder_message` text NOT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `exam_seats`;
CREATE TABLE `exam_seats` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_type` varchar(50) NOT NULL,
  `student_id` varchar(100) NOT NULL,
  `seat_label` varchar(100) NOT NULL,
  `assigned_by` varchar(100) DEFAULT NULL,
  `assigned_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_exam_seat_label` (`exam_type`,`seat_label`),
  UNIQUE KEY `uq_exam_student` (`exam_type`,`student_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `exam_submissions`;
CREATE TABLE `exam_submissions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(100) NOT NULL,
  `student_name` varchar(255) NOT NULL,
  `exam_type` varchar(50) NOT NULL,
  `access_code` varchar(50) NOT NULL,
  `score` int(11) NOT NULL DEFAULT 0,
  `total_questions` int(11) NOT NULL DEFAULT 0,
  `answers` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`answers`)),
  `submitted_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `exam_submissions` (`id`, `student_id`, `student_name`, `exam_type`, `access_code`, `score`, `total_questions`, `answers`, `submitted_at`) VALUES ('1', '027', 'Yilkal Demeke', 'exam20', '', '7', '30', '[{\"question\":\"13.አብ ቀባዒ፣ወልድ ተቀባዒ እና መንፈስ ቅዱስ ቅብዕ የሚለዉ አስተምህሮ እንዴት ይታያል?\",\"selected\":\"x\",\"correct\":\"በመጀመሪያ ይህ አስተምህሮ የቅባት እምነት ተከታዮች አስተምህሮ ሲሆን -ይህ ማለት-አብ-አክባሪ  -ወልድ ከባሪ -መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል::በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።ታዲያ ↪ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን አብ አክባሪ፣ወልድ ከባሪ መንፈስ \",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"12.\\\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከእግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ-ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን ቀባህ\\\"መዝ 44÷7  ሲል ምን ማለቱ ነው?\",\"selected\":\"d\",\"correct\":\"በመጀመሪያ\\\"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን ቀባህ\\\"በሚለውኃይለ ቃል ውስጥ \\\"አንተ\\\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ እናስተውል።ይኸውም \\\"ትስብእት\\\"ነው።➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"11.ወልድ ለአብ ልጁ ከሆነ ለመንፈስ ቅዱስ ምኑ ነው?\",\"selected\":\"z\",\"correct\":\"ወልድ ለአብ ልጁ ከሆነ ለመንፈስ ቅዱስ ቃሉ ነው።\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"10.የምሥጢረ ፈጣሪ እና ምሥጢረ ፍጡራን ልዩነታቸው ምንድን ነው?\",\"selected\":\"x\",\"correct\":\"ምሥጢረ ፍጡራን:-ምሥጢረ ፍጡራን ማለት በፍጡራን ውስጥ ያለ የማይታወቅ ነገር ነው።እርሱ ሦስት ወገን ነው።እነርሱም:-ምሥጢረ ሰማይ ወምድር፤ምሥጢረ ሰብእ፤ምሥጢረ መላእክት ሲሆኑ ምሥጢረ ፈጣሪ(እግዚአብሔር) የምንለው ደግሞ ዓለምን እምኀበ አልቦ መፍጠሩ፤አንድ ሲሆን ሦስት፤ሦስት ሲሆኑ አንድ ቀዳማዊነቱ፤ርቀቱ፤ምልዓቱ ይህንን ዓለም እምኀበ አልቦ ኀበ ቦ ከኢምንት ኀበ ምንት የፈጠረበት ረቂቅ ምስጢር ነው።\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"9.እግዚአብሔር ወልድ በ30 ዘመኑ ከተጠመቀ ዛሬ ህፃናት ለምን በ40 እና በ80 ቀን ለምን ይጠመቃሉ?\",\"selected\":\"x\",\"correct\":\"አዳም ወደ ገነት የገባዉ በ40 ቀኑ ሄዋን ደግሞ በ80 ቀኗ ስለሆነ ነው\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"8.ተዓቅቦ ማለት ምን ማለት ነው?\",\"selected\":\"x\",\"correct\":\"ተዓቅቦ:-ማለት መለኮት ርቀቱን፤ስፋቱን፤ምልዓቱን፤አይመረመሬነቱን፤ አምላክነቱን ሳይለቅ ባለመጣፋፋት በመጠባበቅ በስጋ ርስት መመርመር ፤መግዘፍ፤መወሰን;ስጋም የሚመረመር፤ረቂቅ፤ግዙፍ፤ውሱንነቱን ሳይለቅ ባለመጠፋፋት በመጠባበቅ በመለኮት ገንዘብ የማይመረመር የማይታመም ረቂቅ፤ስፉህ፤ምልዑ መሆን ተዓቅቦ ይባላል።\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"7.በነገረ ሥጋዌ ትምህርት አክባሪ፣ከባሪ እና ክብር የሚባሉ ነገሮች ለማን ተሰጥተው ይነገራሉ?\",\"selected\":\"x\",\"correct\":\"አክባሪነት➠አብ ወልድ መንፈስ ቅዱስ(አፋዊ ግብር) ፣ትስብእት(ስጋ)➠ከባሪ(የከበረ)፣ወልድ(ቃል) ክብር(ቅብዕ) ነው።\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"6.የትንሣኤ ዘለሕይወት እና ትንሣኤ ዘለደይን ልዩነት ምንድን ነው?\",\"selected\":\"x\",\"correct\":\"ትንሣኤ ዘለሕይወት እና ትንሣኤ ዘለደይን ሁለቱ የፍርድ አይነቶች ሲሆኑ በትንሣኤ ዘጉባኤ ጊዜ ኃጥኣንን ለኃሳር ጻድቃንን ለክብር የሚጠራበት ነው።\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"5.አምላክ እንዴት ሰው ሆነ?\",\"selected\":\"x\",\"correct\":\"አምላክ ሰው የሆነው እንበለ ቱሳሔ፣እንበለ ውላጤ፣እንበለ ቡአዴ፣እንበለ ትድምርት፣እንበለ ሚጠት፣እንበለ ተጋውሮ፣እንበለ ፍልጠት ነው።ታዲያ በአጭሩ ታዲያ ክርስቶስ ሰው የሆነው እንዴት ነው ትለኝ እንደሆነ በፍጹም ተዋህዶ ነው\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"4.በዓለ ጥምቀት ወይም ልደት እሑድ ቢውል መቼ ይጾማል?\",\"selected\":\"x\",\"correct\":\"በዓለ ጥምቀት ወይም ልደት እሑድ ቢውል ቅዳሜ ጥሉላት አይበላም።“ገሃድ” አንድ ስለሆነ (ስንክሳር ጥር ፲ “ሰላም ለዕለት ዋሕድ ዘስሙ ገሃድ” እንዲል) የጥምቀትም ይሁን የልደት ገሃድ(ጋድ) አንድ ቀን ስለሆነ ዋዜማዉን ብቻ ይጾማል እንጂ ሁለት ቀን አይጾምም።\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"3.በተዋሕዶ የከበረ ማን ነው?አክባሪዉስ?\",\"selected\":\"c\",\"correct\":\"በተዋህዶ የከበረ ስጋ ወይም ትስብእት ሲሆን አክባሪው ደግሞ ቃል(መለኮት) ነው።\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"2.ንዴት እንዴት ጠፋ?\",\"selected\":\"a\",\"correct\":\" ንዴት ማለት በግድ(መራብ:መጠማት) ለፈቃዳት መገዛት ማለት ነው።ይህ እንዴት ጠፋ ሲባል ቃል ከስጋ ጋር ፈጽሞ በመዋሐዱ ነው። ☝ቅድመ ተዋህዶ ነዳይ የነበረ ስጋ በግድ የሚራብ የሚጠማ ሲሆን ከባለጸጋው መለኮት ጋር ሲዋሐድ ግን ሁሉ የእርሱ ሆነ።ይሁን እንጂ ተዋሕዶ ሁለትነትን እንጂ ንዴትን አላጠፋም የሚሉ አሉ;መጽሐፍ ግን አይልም።  ለዚህም ማስረጃ  ➡\\\"እርሱ መለኮት የተዋሐደውን ከእርሱ ጋር አንድ አካ\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"1.የአንዲት ሃይማኖት መጠሪያ ስያሜ ማነው?መቼ የት አገኘ?\",\"selected\":\"h\",\"correct\":\"✔ .የአንዲት ሃይማኖት መጠሪያ ስያሜ በብሉይ ኪዳን \\\"ህዝበ እግዚአብሔር\\\"ይባሉ ነበር።የማያምኑትም አህዛብ ይባላሉ። ✔ .የአንዲት ሃይማኖት መጠሪያ ስያሜ በዘመነ አበው\\\"ክርስቲያን\\\"ይባሉ ነበር።ለዚህም ማስረጃ:- \\\"ወነበሩ አሐተ ዓመተ ኅቡረ በቤተ ክርስቲያን ወመሀሩ ለብዙኃን አህዛብ ወተሰምዩ አርድእት ክርስቲያን በአንጾኪያ ቀዲሙ\\\"ሐዋ 11 ÷26 ብሎ በመጀመሪያ በአንጾኪያ ክርስቲያን ተባሉ ብሎ ገልጾታል!\",\"is_correct\":false,\"type\":\"short_answer\"},{\"question\":\"10.በምሥጢረ ሥላሴ ትምህርት አካል ያለ ባህርይ፣ባህርይ ደግሞ ያለ አካል ተለይቶ አይገኝም እና ባህርይ በየአካላቸው እንዳላቸው መጽሐፍት ይናገራሉ።\",\"selected\":\"FALSE\",\"correct\":\"FALSE\",\"is_correct\":true,\"type\":\"true_false\"},{\"question\":\"9.የኢትዮጵያ ኦርቶዶክስ ተዋሕዶ ቤተ ክርስቲያን መሰረታዊ የምሥጢረ ሥላሴ ትምህርት አብ ቀባዒ፣ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ የሚል ነው።\",\"selected\":\"FALSE\",\"correct\":\"FALSE\",\"is_correct\":true,\"type\":\"true_false\"},{\"question\":\"8.በአፍአ ከሚደረጉ ነገሮች ጋር የማይገናኝ ጊዜያት እና ዘመናት፣ዓለማት እና ፍጥረታት፣ቀናት እና ሰዓታት፣ዓመታት እና ወራት በማይነገሩበት አብ ከወልድ ከመንፈስ ቅዱስ ሳይቀድም እና በባህርይዉ ሳይለይ በባህርይው ወልድን የወለደበት፣መንፈስ ቅዱስን ያሰረጸበት ግብር ዉሳጣዊ አካላዊ ግላዊ ግብር ይባላል።\",\"selected\":\"TRUE\",\"correct\":\"TRUE\",\"is_correct\":true,\"type\":\"true_false\"},{\"question\":\"7.ለምሥጢረ ሥላሴ ትምህርት ማስረጃ ሆነው ከሚያገለግሉ ፍጥረታት መካከል ሊቁ ቅዱስ ቄርሎስ የመሰለው የእሳት እና የብረት ተዋሕዶ ዋነኛ ማስረጃ ነው።\",\"selected\":\"TRUE\",\"correct\":\"FALSE\",\"is_correct\":false,\"type\":\"true_false\"},{\"question\":\"6.በጊዜ ተዋህዶ ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል፣አካለ ቃል ክብር አልባ ያሰኛል።\",\"selected\":\"FALSE\",\"correct\":\"TRUE\",\"is_correct\":false,\"type\":\"true_false\"},{\"question\":\"5.ክርስቶስ ቅድመ ተዋህዶ አንድ አካል አንድ ባህርይ ሲሆን በጊዜ ተዋህዶ መክፈል፣መዋሐድ እና መክበር ተፈጽመዋል።\",\"selected\":\"FALSE\",\"correct\":\"FALSE\",\"is_correct\":true,\"type\":\"true_false\"},{\"question\":\"21..በኦሪት ዘፍጥረት \\\"ሰውን እንደምሳሌያችንና እንደ መልካችን እንፍጠር ሲሉ ሥላሴ ይህ የምን ግብር ነው?\",\"selected\":\"A\",\"correct\":\"ሐ\",\"is_correct\":false,\"type\":\"multiple_choice\"},{\"question\":\"4.መንፈስ ቅዱስ ለአብ እና ለወልድ ሕይወታቸዉ ብቻ ሳይሆን ክብራቸዉ መንግስታቸዉ እስትንፋሳቸዉ ነው።\",\"selected\":\"FALSE\",\"correct\":\"FALSE\",\"is_correct\":true,\"type\":\"true_false\"},{\"question\":\"3.እምነት ማለት በዓይን ሳያዩ፤በጆሮ ሳይሰሙ ሳይመረምሩ መቀበል ነው።\",\"selected\":\"FALSE\",\"correct\":\"FALSE\",\"is_correct\":true,\"type\":\"true_false\"},{\"question\":\"2.አካላዊ ቃል ለተዋሐደው ስጋ ክብር ሆነው።\",\"selected\":\"FALSE\",\"correct\":\"TRUE\",\"is_correct\":false,\"type\":\"true_false\"},{\"question\":\"1.አካላዊ ቃል ከስጋ ጋር ሲዋሐድ አሐቲ ባህርየ ሥላሴ ተዋሐደች ማለት ይቻላል።\",\"selected\":\"FALSE\",\"correct\":\"FALSE\",\"is_correct\":true,\"type\":\"true_false\"},{\"question\":\"20.ከሚከተሉት ዉስጥ በተዋህዶ ጊዜ በትክክል የተዛመደው የቱ ነው?\",\"selected\":\"A\",\"correct\":\"ሀ\",\"is_correct\":false,\"type\":\"multiple_choice\"},{\"question\":\"19.አብ፣ወልድ፤መንፈስ ቅዱስ የሚለው የምን ስም ነው?\",\"selected\":\"C\",\"correct\":\"ሐ\",\"is_correct\":false,\"type\":\"multiple_choice\"},{\"question\":\"18.ከሚከተቱት አንዱ ልዩ የሆነው የቱ ነው?\",\"selected\":\"C\",\"correct\":\"ለ\",\"is_correct\":false,\"type\":\"multiple_choice\"},{\"question\":\"17.አብ በሁሉ የመላ ከሆነ ወልድና መንፈስ ቅዱስ በምን ይመላሉ?\",\"selected\":\"C\",\"correct\":\"ሐ\",\"is_correct\":false,\"type\":\"multiple_choice\"},{\"question\":\"16.በጊዜ ተዋሕዶ የከበረ ማን ነው?\",\"selected\":\"B\",\"correct\":\"ለ\",\"is_correct\":false,\"type\":\"multiple_choice\"},{\"question\":\"15.ሥላሴን በአካል ፫ ስንል ልብ ልንላቸው የሚገቡ ነገሮች የትኞቹ ናቸው?\",\"selected\":\"B\",\"correct\":\"መ\",\"is_correct\":false,\"type\":\"multiple_choice\"}]', '2026-06-26 04:30:49');
INSERT INTO `exam_submissions` (`id`, `student_id`, `student_name`, `exam_type`, `access_code`, `score`, `total_questions`, `answers`, `submitted_at`) VALUES ('2', '027', 'Yilkal Demeke', 'mid_exam', 'SOFI2721', '0', '44', '[{\"question\":\"1.እግዚአብሔር ወልድ ከቅድስት ድንግል ማርያም ከሥጋዋ ሥጋን ከነፍሷ ነፍስን ነስቶ ሲዋሐድ ለወልድ ብቻ የሚሰጥ ግብር የትኛው ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"2.ሥጋ ከበረ ስንል ሁልጊዜ የምናስበው የትኛዉን ጊዜ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"3.ስለምሥጢረ ሥላሴ ትክክል ያልሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"4.ከሚከተሉት አንዱ ልዩ ነው።\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"5.ስለ እግዚአብሔር ወልድ ዳግም ልደትና የማዳን ስራ የሚያስረዳን ምሥጢር ምን ይባላል?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"6.ከሚከተሉት መካከል የቃል እና የስጋን ተዋህዶ የማይገልጸው የቱ ነው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"7.ሃይማኖት ማለት በአንድ እግዚአብሔር በህላዌ መለኮቱ፤በፈጣሪነቱ፤ በመጋቢነቱ ፤በባህርይ ግብራቱ ማመን ለእርሱም\\r\\nለእርሱም መታመን ማለት ነው።የሚለው የሃይማኖት ትርጉም የምን ትርጉም ይባላል?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"8.ከሚከተሉት መካከል ስለ ምሥጢረ ሥላሴ ትክክል የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"9..በደቡብ ወሎ ዞሮ በጣም በርካታ (ሰው) አለ። ከእነዚህም መካከል (ሶፎንያስ) በመቅደላ አምባ ዩኒቨርሲቲ የ4ኛ ዓመት የኮምፒዪተር ሳይንስ ተማሪ ነው፤ሶፎንያስ ለ12ኛ ክፍል፤ለ1ኛ ዓመትና ለሁለተኛ ዓመት ተማሪዎች የነገረ ሃይማኖት በመስጠት ለተወሰኑ ወራት (መምህራቸው) በመሆን ሲሰጥ ከቆዬ በኋላ አሁን ላይ ኮርሱን በሰላም አጠናቆ ፈተና በመስጠት ላይ ይገኛል።በቅንፍ የተቀመጡት ቃላት በቅደም ተከተል ምንን ያመለክታሉ?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"10.\\\"በ\\\" እና \\\"እንደ\\\" የሚል ርስት ሰጥተን የምንናገረው መቸ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"11.አፍአዊ ግብር ማለት ምን ማለት ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"12.ከሚከተሉት አንዱ እዉነት የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"13.በምሥጢረ ሥላሴ ትምህርት ስለ ኩነት ትክክል ያልሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"14.ከሚከተሉት አንዱ ልዩ የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"15.ሥላሴን በአካል ፫ ስንል ልብ ልንላቸው የሚገቡ ነገሮች የትኞቹ ናቸው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"16.በጊዜ ተዋሕዶ የከበረ ማን ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"17.አብ በሁሉ የመላ ከሆነ ወልድና መንፈስ ቅዱስ በምን ይመላሉ?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"18.ከሚከተቱት አንዱ ልዩ የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"19.አብ፣ወልድ፤መንፈስ ቅዱስ የሚለው የምን ስም ነው?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"20.ከሚከተሉት ዉስጥ በተዋህዶ ጊዜ በትክክል የተዛመደው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"1.አካላዊ ቃል ከስጋ ጋር ሲዋሐድ አሐቲ ባህርየ ሥላሴ ተዋሐደች ማለት ይቻላል።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"2.አካላዊ ቃል ለተዋሐደው ስጋ ክብር ሆነው።\",\"selected\":\"\",\"correct\":\"TRUE\",\"is_correct\":false},{\"question\":\"3.እምነት ማለት በዓይን ሳያዩ፤በጆሮ ሳይሰሙ ሳይመረምሩ መቀበል ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"4.መንፈስ ቅዱስ ለአብ እና ለወልድ ሕይወታቸዉ ብቻ ሳይሆን ክብራቸዉ መንግስታቸዉ እስትንፋሳቸዉ ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"21..በኦሪት ዘፍጥረት \\\"ሰውን እንደምሳሌያችንና እንደ መልካችን እንፍጠር ሲሉ ሥላሴ ይህ የምን ግብር ነው?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"5.ክርስቶስ ቅድመ ተዋህዶ አንድ አካል አንድ ባህርይ ሲሆን በጊዜ ተዋህዶ መክፈል፣መዋሐድ እና መክበር ተፈጽመዋል።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"6.በጊዜ ተዋህዶ ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል፣አካለ ቃል ክብር አልባ ያሰኛል።\",\"selected\":\"\",\"correct\":\"TRUE\",\"is_correct\":false},{\"question\":\"7.ለምሥጢረ ሥላሴ ትምህርት ማስረጃ ሆነው ከሚያገለግሉ ፍጥረታት መካከል ሊቁ ቅዱስ ቄርሎስ የመሰለው የእሳት እና የብረት ተዋሕዶ ዋነኛ ማስረጃ ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"8.በአፍአ ከሚደረጉ ነገሮች ጋር የማይገናኝ ጊዜያት እና ዘመናት፣ዓለማት እና ፍጥረታት፣ቀናት እና ሰዓታት፣ዓመታት እና ወራት በማይነገሩበት አብ ከወልድ ከመንፈስ ቅዱስ ሳይቀድም እና በባህርይዉ ሳይለይ በባህርይው ወልድን የወለደበት፣መንፈስ ቅዱስን ያሰረጸበት ግብር ዉሳጣዊ አካላዊ ግላዊ ግብር ይባላል።\",\"selected\":\"\",\"correct\":\"TRUE\",\"is_correct\":false},{\"question\":\"9.የኢትዮጵያ ኦርቶዶክስ ተዋሕዶ ቤተ ክርስቲያን መሰረታዊ የምሥጢረ ሥላሴ ትምህርት አብ ቀባዒ፣ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ የሚል ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"10.በምሥጢረ ሥላሴ ትምህርት አካል ያለ ባህርይ፣ባህርይ ደግሞ ያለ አካል ተለይቶ አይገኝም እና ባህርይ በየአካላቸው እንዳላቸው መጽሐፍት ይናገራሉ።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"1.የአንዲት ሃይማኖት መጠሪያ ስያሜ ማነው?መቼ የት አገኘ?\",\"selected\":\"\",\"correct\":\"✔ .የአንዲት ሃይማኖት መጠሪያ ስያሜ በብሉይ ኪዳን \\\"ህዝበ እግዚአብሔር\\\"ይባሉ ነበር።የማያምኑትም አህዛብ ይባላሉ። ✔ .የአንዲት ሃይማኖት መጠሪያ ስያሜ በዘመነ አበው\\\"ክርስቲያን\\\"ይባሉ ነበር።ለዚህም ማስረጃ:- \\\"ወነበሩ አሐተ ዓመተ ኅቡረ በቤተ ክርስቲያን ወመሀሩ ለብዙኃን አህዛብ ወተሰምዩ አርድእት ክርስቲያን በአንጾኪያ ቀዲሙ\\\"ሐዋ 11 ÷26 ብሎ በመጀመሪያ በአንጾኪያ ክርስቲያን ተባሉ ብሎ ገልጾታል!\",\"is_correct\":false},{\"question\":\"2.ንዴት እንዴት ጠፋ?\",\"selected\":\"\",\"correct\":\" ንዴት ማለት በግድ(መራብ:መጠማት) ለፈቃዳት መገዛት ማለት ነው።ይህ እንዴት ጠፋ ሲባል ቃል ከስጋ ጋር ፈጽሞ በመዋሐዱ ነው። ☝ቅድመ ተዋህዶ ነዳይ የነበረ ስጋ በግድ የሚራብ የሚጠማ ሲሆን ከባለጸጋው መለኮት ጋር ሲዋሐድ ግን ሁሉ የእርሱ ሆነ።ይሁን እንጂ ተዋሕዶ ሁለትነትን እንጂ ንዴትን አላጠፋም የሚሉ አሉ;መጽሐፍ ግን አይልም።  ለዚህም ማስረጃ  ➡\\\"እርሱ መለኮት የተዋሐደውን ከእርሱ ጋር አንድ አካ\",\"is_correct\":false},{\"question\":\"3.በተዋሕዶ የከበረ ማን ነው?አክባሪዉስ?\",\"selected\":\"\",\"correct\":\"በተዋህዶ የከበረ ስጋ ወይም ትስብእት ሲሆን አክባሪው ደግሞ ቃል(መለኮት) ነው።\",\"is_correct\":false},{\"question\":\"4.በዓለ ጥምቀት ወይም ልደት እሑድ ቢውል መቼ ይጾማል?\",\"selected\":\"\",\"correct\":\"በዓለ ጥምቀት ወይም ልደት እሑድ ቢውል ቅዳሜ ጥሉላት አይበላም።“ገሃድ” አንድ ስለሆነ (ስንክሳር ጥር ፲ “ሰላም ለዕለት ዋሕድ ዘስሙ ገሃድ” እንዲል) የጥምቀትም ይሁን የልደት ገሃድ(ጋድ) አንድ ቀን ስለሆነ ዋዜማዉን ብቻ ይጾማል እንጂ ሁለት ቀን አይጾምም።\",\"is_correct\":false},{\"question\":\"5.አምላክ እንዴት ሰው ሆነ?\",\"selected\":\"\",\"correct\":\"አምላክ ሰው የሆነው እንበለ ቱሳሔ፣እንበለ ውላጤ፣እንበለ ቡአዴ፣እንበለ ትድምርት፣እንበለ ሚጠት፣እንበለ ተጋውሮ፣እንበለ ፍልጠት ነው።ታዲያ በአጭሩ ታዲያ ክርስቶስ ሰው የሆነው እንዴት ነው ትለኝ እንደሆነ በፍጹም ተዋህዶ ነው\",\"is_correct\":false},{\"question\":\"6.የትንሣኤ ዘለሕይወት እና ትንሣኤ ዘለደይን ልዩነት ምንድን ነው?\",\"selected\":\"\",\"correct\":\"ትንሣኤ ዘለሕይወት እና ትንሣኤ ዘለደይን ሁለቱ የፍርድ አይነቶች ሲሆኑ በትንሣኤ ዘጉባኤ ጊዜ ኃጥኣንን ለኃሳር ጻድቃንን ለክብር የሚጠራበት ነው።\",\"is_correct\":false},{\"question\":\"7.በነገረ ሥጋዌ ትምህርት አክባሪ፣ከባሪ እና ክብር የሚባሉ ነገሮች ለማን ተሰጥተው ይነገራሉ?\",\"selected\":\"\",\"correct\":\"አክባሪነት➠አብ ወልድ መንፈስ ቅዱስ(አፋዊ ግብር) ፣ትስብእት(ስጋ)➠ከባሪ(የከበረ)፣ወልድ(ቃል) ክብር(ቅብዕ) ነው።\",\"is_correct\":false},{\"question\":\"8.ተዓቅቦ ማለት ምን ማለት ነው?\",\"selected\":\"\",\"correct\":\"ተዓቅቦ:-ማለት መለኮት ርቀቱን፤ስፋቱን፤ምልዓቱን፤አይመረመሬነቱን፤ አምላክነቱን ሳይለቅ ባለመጣፋፋት በመጠባበቅ በስጋ ርስት መመርመር ፤መግዘፍ፤መወሰን;ስጋም የሚመረመር፤ረቂቅ፤ግዙፍ፤ውሱንነቱን ሳይለቅ ባለመጠፋፋት በመጠባበቅ በመለኮት ገንዘብ የማይመረመር የማይታመም ረቂቅ፤ስፉህ፤ምልዑ መሆን ተዓቅቦ ይባላል።\",\"is_correct\":false},{\"question\":\"9.እግዚአብሔር ወልድ በ30 ዘመኑ ከተጠመቀ ዛሬ ህፃናት ለምን በ40 እና በ80 ቀን ለምን ይጠመቃሉ?\",\"selected\":\"\",\"correct\":\"አዳም ወደ ገነት የገባዉ በ40 ቀኑ ሄዋን ደግሞ በ80 ቀኗ ስለሆነ ነው\",\"is_correct\":false},{\"question\":\"10.የምሥጢረ ፈጣሪ እና ምሥጢረ ፍጡራን ልዩነታቸው ምንድን ነው?\",\"selected\":\"\",\"correct\":\"ምሥጢረ ፍጡራን:-ምሥጢረ ፍጡራን ማለት በፍጡራን ውስጥ ያለ የማይታወቅ ነገር ነው።እርሱ ሦስት ወገን ነው።እነርሱም:-ምሥጢረ ሰማይ ወምድር፤ምሥጢረ ሰብእ፤ምሥጢረ መላእክት ሲሆኑ ምሥጢረ ፈጣሪ(እግዚአብሔር) የምንለው ደግሞ ዓለምን እምኀበ አልቦ መፍጠሩ፤አንድ ሲሆን ሦስት፤ሦስት ሲሆኑ አንድ ቀዳማዊነቱ፤ርቀቱ፤ምልዓቱ ይህንን ዓለም እምኀበ አልቦ ኀበ ቦ ከኢምንት ኀበ ምንት የፈጠረበት ረቂቅ ምስጢር ነው።\",\"is_correct\":false},{\"question\":\"11.ወልድ ለአብ ልጁ ከሆነ ለመንፈስ ቅዱስ ምኑ ነው?\",\"selected\":\"\",\"correct\":\"ወልድ ለአብ ልጁ ከሆነ ለመንፈስ ቅዱስ ቃሉ ነው።\",\"is_correct\":false},{\"question\":\"12.\\\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከእግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ-ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን ቀባህ\\\"መዝ 44÷7  ሲል ምን ማለቱ ነው?\",\"selected\":\"\",\"correct\":\"በመጀመሪያ\\\"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን ቀባህ\\\"በሚለውኃይለ ቃል ውስጥ \\\"አንተ\\\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ እናስተውል።ይኸውም \\\"ትስብእት\\\"ነው።➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው\",\"is_correct\":false},{\"question\":\"13.አብ ቀባዒ፣ወልድ ተቀባዒ እና መንፈስ ቅዱስ ቅብዕ የሚለዉ አስተምህሮ እንዴት ይታያል?\",\"selected\":\"\",\"correct\":\"በመጀመሪያ ይህ አስተምህሮ የቅባት እምነት ተከታዮች አስተምህሮ ሲሆን -ይህ ማለት-አብ-አክባሪ  -ወልድ ከባሪ -መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል::በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።ታዲያ ↪ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን አብ አክባሪ፣ወልድ ከባሪ መንፈስ \",\"is_correct\":false}]', '2026-06-28 10:24:16');
INSERT INTO `exam_submissions` (`id`, `student_id`, `student_name`, `exam_type`, `access_code`, `score`, `total_questions`, `answers`, `submitted_at`) VALUES ('3', '027', 'Yilkal Demeke', 'final_exam', 'SOFI2721', '0', '44', '[{\"question\":\"1.እግዚአብሔር ወልድ ከቅድስት ድንግል ማርያም ከሥጋዋ ሥጋን ከነፍሷ ነፍስን ነስቶ ሲዋሐድ ለወልድ ብቻ የሚሰጥ ግብር የትኛው ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"2.ሥጋ ከበረ ስንል ሁልጊዜ የምናስበው የትኛዉን ጊዜ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"3.ስለምሥጢረ ሥላሴ ትክክል ያልሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"4.ከሚከተሉት አንዱ ልዩ ነው።\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"5.ስለ እግዚአብሔር ወልድ ዳግም ልደትና የማዳን ስራ የሚያስረዳን ምሥጢር ምን ይባላል?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"6.ከሚከተሉት መካከል የቃል እና የስጋን ተዋህዶ የማይገልጸው የቱ ነው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"7.ሃይማኖት ማለት በአንድ እግዚአብሔር በህላዌ መለኮቱ፤በፈጣሪነቱ፤ በመጋቢነቱ ፤በባህርይ ግብራቱ ማመን ለእርሱም\\r\\nለእርሱም መታመን ማለት ነው።የሚለው የሃይማኖት ትርጉም የምን ትርጉም ይባላል?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"8.ከሚከተሉት መካከል ስለ ምሥጢረ ሥላሴ ትክክል የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"9..በደቡብ ወሎ ዞሮ በጣም በርካታ (ሰው) አለ። ከእነዚህም መካከል (ሶፎንያስ) በመቅደላ አምባ ዩኒቨርሲቲ የ4ኛ ዓመት የኮምፒዪተር ሳይንስ ተማሪ ነው፤ሶፎንያስ ለ12ኛ ክፍል፤ለ1ኛ ዓመትና ለሁለተኛ ዓመት ተማሪዎች የነገረ ሃይማኖት በመስጠት ለተወሰኑ ወራት (መምህራቸው) በመሆን ሲሰጥ ከቆዬ በኋላ አሁን ላይ ኮርሱን በሰላም አጠናቆ ፈተና በመስጠት ላይ ይገኛል።በቅንፍ የተቀመጡት ቃላት በቅደም ተከተል ምንን ያመለክታሉ?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"10.\\\"በ\\\" እና \\\"እንደ\\\" የሚል ርስት ሰጥተን የምንናገረው መቸ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"11.አፍአዊ ግብር ማለት ምን ማለት ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"12.ከሚከተሉት አንዱ እዉነት የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"13.በምሥጢረ ሥላሴ ትምህርት ስለ ኩነት ትክክል ያልሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"14.ከሚከተሉት አንዱ ልዩ የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"15.ሥላሴን በአካል ፫ ስንል ልብ ልንላቸው የሚገቡ ነገሮች የትኞቹ ናቸው?\",\"selected\":\"\",\"correct\":\"መ\",\"is_correct\":false},{\"question\":\"16.በጊዜ ተዋሕዶ የከበረ ማን ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"17.አብ በሁሉ የመላ ከሆነ ወልድና መንፈስ ቅዱስ በምን ይመላሉ?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"18.ከሚከተቱት አንዱ ልዩ የሆነው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ለ\",\"is_correct\":false},{\"question\":\"19.አብ፣ወልድ፤መንፈስ ቅዱስ የሚለው የምን ስም ነው?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"20.ከሚከተሉት ዉስጥ በተዋህዶ ጊዜ በትክክል የተዛመደው የቱ ነው?\",\"selected\":\"\",\"correct\":\"ሀ\",\"is_correct\":false},{\"question\":\"1.አካላዊ ቃል ከስጋ ጋር ሲዋሐድ አሐቲ ባህርየ ሥላሴ ተዋሐደች ማለት ይቻላል።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"2.አካላዊ ቃል ለተዋሐደው ስጋ ክብር ሆነው።\",\"selected\":\"\",\"correct\":\"TRUE\",\"is_correct\":false},{\"question\":\"3.እምነት ማለት በዓይን ሳያዩ፤በጆሮ ሳይሰሙ ሳይመረምሩ መቀበል ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"4.መንፈስ ቅዱስ ለአብ እና ለወልድ ሕይወታቸዉ ብቻ ሳይሆን ክብራቸዉ መንግስታቸዉ እስትንፋሳቸዉ ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"21..በኦሪት ዘፍጥረት \\\"ሰውን እንደምሳሌያችንና እንደ መልካችን እንፍጠር ሲሉ ሥላሴ ይህ የምን ግብር ነው?\",\"selected\":\"\",\"correct\":\"ሐ\",\"is_correct\":false},{\"question\":\"5.ክርስቶስ ቅድመ ተዋህዶ አንድ አካል አንድ ባህርይ ሲሆን በጊዜ ተዋህዶ መክፈል፣መዋሐድ እና መክበር ተፈጽመዋል።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"6.በጊዜ ተዋህዶ ተዋህዶ ሳይከብር ቢቀር ዜገ ያሰኛል፣አካለ ቃል ክብር አልባ ያሰኛል።\",\"selected\":\"\",\"correct\":\"TRUE\",\"is_correct\":false},{\"question\":\"7.ለምሥጢረ ሥላሴ ትምህርት ማስረጃ ሆነው ከሚያገለግሉ ፍጥረታት መካከል ሊቁ ቅዱስ ቄርሎስ የመሰለው የእሳት እና የብረት ተዋሕዶ ዋነኛ ማስረጃ ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"8.በአፍአ ከሚደረጉ ነገሮች ጋር የማይገናኝ ጊዜያት እና ዘመናት፣ዓለማት እና ፍጥረታት፣ቀናት እና ሰዓታት፣ዓመታት እና ወራት በማይነገሩበት አብ ከወልድ ከመንፈስ ቅዱስ ሳይቀድም እና በባህርይዉ ሳይለይ በባህርይው ወልድን የወለደበት፣መንፈስ ቅዱስን ያሰረጸበት ግብር ዉሳጣዊ አካላዊ ግላዊ ግብር ይባላል።\",\"selected\":\"\",\"correct\":\"TRUE\",\"is_correct\":false},{\"question\":\"9.የኢትዮጵያ ኦርቶዶክስ ተዋሕዶ ቤተ ክርስቲያን መሰረታዊ የምሥጢረ ሥላሴ ትምህርት አብ ቀባዒ፣ወልድ ተቀባዒ መንፈስ ቅዱስ ቅብዕ የሚል ነው።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"10.በምሥጢረ ሥላሴ ትምህርት አካል ያለ ባህርይ፣ባህርይ ደግሞ ያለ አካል ተለይቶ አይገኝም እና ባህርይ በየአካላቸው እንዳላቸው መጽሐፍት ይናገራሉ።\",\"selected\":\"\",\"correct\":\"FALSE\",\"is_correct\":false},{\"question\":\"1.የአንዲት ሃይማኖት መጠሪያ ስያሜ ማነው?መቼ የት አገኘ?\",\"selected\":\"\",\"correct\":\"✔ .የአንዲት ሃይማኖት መጠሪያ ስያሜ በብሉይ ኪዳን \\\"ህዝበ እግዚአብሔር\\\"ይባሉ ነበር።የማያምኑትም አህዛብ ይባላሉ። ✔ .የአንዲት ሃይማኖት መጠሪያ ስያሜ በዘመነ አበው\\\"ክርስቲያን\\\"ይባሉ ነበር።ለዚህም ማስረጃ:- \\\"ወነበሩ አሐተ ዓመተ ኅቡረ በቤተ ክርስቲያን ወመሀሩ ለብዙኃን አህዛብ ወተሰምዩ አርድእት ክርስቲያን በአንጾኪያ ቀዲሙ\\\"ሐዋ 11 ÷26 ብሎ በመጀመሪያ በአንጾኪያ ክርስቲያን ተባሉ ብሎ ገልጾታል!\",\"is_correct\":false},{\"question\":\"2.ንዴት እንዴት ጠፋ?\",\"selected\":\"\",\"correct\":\" ንዴት ማለት በግድ(መራብ:መጠማት) ለፈቃዳት መገዛት ማለት ነው።ይህ እንዴት ጠፋ ሲባል ቃል ከስጋ ጋር ፈጽሞ በመዋሐዱ ነው። ☝ቅድመ ተዋህዶ ነዳይ የነበረ ስጋ በግድ የሚራብ የሚጠማ ሲሆን ከባለጸጋው መለኮት ጋር ሲዋሐድ ግን ሁሉ የእርሱ ሆነ።ይሁን እንጂ ተዋሕዶ ሁለትነትን እንጂ ንዴትን አላጠፋም የሚሉ አሉ;መጽሐፍ ግን አይልም።  ለዚህም ማስረጃ  ➡\\\"እርሱ መለኮት የተዋሐደውን ከእርሱ ጋር አንድ አካ\",\"is_correct\":false},{\"question\":\"3.በተዋሕዶ የከበረ ማን ነው?አክባሪዉስ?\",\"selected\":\"\",\"correct\":\"በተዋህዶ የከበረ ስጋ ወይም ትስብእት ሲሆን አክባሪው ደግሞ ቃል(መለኮት) ነው።\",\"is_correct\":false},{\"question\":\"4.በዓለ ጥምቀት ወይም ልደት እሑድ ቢውል መቼ ይጾማል?\",\"selected\":\"\",\"correct\":\"በዓለ ጥምቀት ወይም ልደት እሑድ ቢውል ቅዳሜ ጥሉላት አይበላም።“ገሃድ” አንድ ስለሆነ (ስንክሳር ጥር ፲ “ሰላም ለዕለት ዋሕድ ዘስሙ ገሃድ” እንዲል) የጥምቀትም ይሁን የልደት ገሃድ(ጋድ) አንድ ቀን ስለሆነ ዋዜማዉን ብቻ ይጾማል እንጂ ሁለት ቀን አይጾምም።\",\"is_correct\":false},{\"question\":\"5.አምላክ እንዴት ሰው ሆነ?\",\"selected\":\"\",\"correct\":\"አምላክ ሰው የሆነው እንበለ ቱሳሔ፣እንበለ ውላጤ፣እንበለ ቡአዴ፣እንበለ ትድምርት፣እንበለ ሚጠት፣እንበለ ተጋውሮ፣እንበለ ፍልጠት ነው።ታዲያ በአጭሩ ታዲያ ክርስቶስ ሰው የሆነው እንዴት ነው ትለኝ እንደሆነ በፍጹም ተዋህዶ ነው\",\"is_correct\":false},{\"question\":\"6.የትንሣኤ ዘለሕይወት እና ትንሣኤ ዘለደይን ልዩነት ምንድን ነው?\",\"selected\":\"\",\"correct\":\"ትንሣኤ ዘለሕይወት እና ትንሣኤ ዘለደይን ሁለቱ የፍርድ አይነቶች ሲሆኑ በትንሣኤ ዘጉባኤ ጊዜ ኃጥኣንን ለኃሳር ጻድቃንን ለክብር የሚጠራበት ነው።\",\"is_correct\":false},{\"question\":\"7.በነገረ ሥጋዌ ትምህርት አክባሪ፣ከባሪ እና ክብር የሚባሉ ነገሮች ለማን ተሰጥተው ይነገራሉ?\",\"selected\":\"\",\"correct\":\"አክባሪነት➠አብ ወልድ መንፈስ ቅዱስ(አፋዊ ግብር) ፣ትስብእት(ስጋ)➠ከባሪ(የከበረ)፣ወልድ(ቃል) ክብር(ቅብዕ) ነው።\",\"is_correct\":false},{\"question\":\"8.ተዓቅቦ ማለት ምን ማለት ነው?\",\"selected\":\"\",\"correct\":\"ተዓቅቦ:-ማለት መለኮት ርቀቱን፤ስፋቱን፤ምልዓቱን፤አይመረመሬነቱን፤ አምላክነቱን ሳይለቅ ባለመጣፋፋት በመጠባበቅ በስጋ ርስት መመርመር ፤መግዘፍ፤መወሰን;ስጋም የሚመረመር፤ረቂቅ፤ግዙፍ፤ውሱንነቱን ሳይለቅ ባለመጠፋፋት በመጠባበቅ በመለኮት ገንዘብ የማይመረመር የማይታመም ረቂቅ፤ስፉህ፤ምልዑ መሆን ተዓቅቦ ይባላል።\",\"is_correct\":false},{\"question\":\"9.እግዚአብሔር ወልድ በ30 ዘመኑ ከተጠመቀ ዛሬ ህፃናት ለምን በ40 እና በ80 ቀን ለምን ይጠመቃሉ?\",\"selected\":\"\",\"correct\":\"አዳም ወደ ገነት የገባዉ በ40 ቀኑ ሄዋን ደግሞ በ80 ቀኗ ስለሆነ ነው\",\"is_correct\":false},{\"question\":\"10.የምሥጢረ ፈጣሪ እና ምሥጢረ ፍጡራን ልዩነታቸው ምንድን ነው?\",\"selected\":\"\",\"correct\":\"ምሥጢረ ፍጡራን:-ምሥጢረ ፍጡራን ማለት በፍጡራን ውስጥ ያለ የማይታወቅ ነገር ነው።እርሱ ሦስት ወገን ነው።እነርሱም:-ምሥጢረ ሰማይ ወምድር፤ምሥጢረ ሰብእ፤ምሥጢረ መላእክት ሲሆኑ ምሥጢረ ፈጣሪ(እግዚአብሔር) የምንለው ደግሞ ዓለምን እምኀበ አልቦ መፍጠሩ፤አንድ ሲሆን ሦስት፤ሦስት ሲሆኑ አንድ ቀዳማዊነቱ፤ርቀቱ፤ምልዓቱ ይህንን ዓለም እምኀበ አልቦ ኀበ ቦ ከኢምንት ኀበ ምንት የፈጠረበት ረቂቅ ምስጢር ነው።\",\"is_correct\":false},{\"question\":\"11.ወልድ ለአብ ልጁ ከሆነ ለመንፈስ ቅዱስ ምኑ ነው?\",\"selected\":\"\",\"correct\":\"ወልድ ለአብ ልጁ ከሆነ ለመንፈስ ቅዱስ ቃሉ ነው።\",\"is_correct\":false},{\"question\":\"12.\\\"አፍቀርከ ጽድቀ ወዓመጻ ጸላእከ በእንተዝ ቀብዐከእግዚአብሄር አምላክከ ቅብዐ ትፍሥህት እምእለ ከማከ-ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን ቀባህ\\\"መዝ 44÷7  ሲል ምን ማለቱ ነው?\",\"selected\":\"\",\"correct\":\"በመጀመሪያ\\\"ጽድቅን ወደድህ አመጻን ጠላህ ስለዚህ ከባልንጀሮችህ ይልቅ እግዚአብሔር አምላክ የደስታ ዘይትን ቀባህ\\\"በሚለውኃይለ ቃል ውስጥ \\\"አንተ\\\"ተብሎ በውስጠ ታዋቂ የተጠራ እንዳለ እናስተውል።ይኸውም \\\"ትስብእት\\\"ነው።➡ጽድቅን ወደድክ አመጻን ጠላህ ማለትስ ታልከኝ ሰው መሆንን ወደድክ አንድም ትንቢተ ነቢያትን መፈጸምን ወደድክ ወድድክ ሰው አለመሆንን ጠላህ ማለቱ ነው!!ሰው መሆንን ወደድክ የተባለው ማነው\",\"is_correct\":false},{\"question\":\"13.አብ ቀባዒ፣ወልድ ተቀባዒ እና መንፈስ ቅዱስ ቅብዕ የሚለዉ አስተምህሮ እንዴት ይታያል?\",\"selected\":\"\",\"correct\":\"በመጀመሪያ ይህ አስተምህሮ የቅባት እምነት ተከታዮች አስተምህሮ ሲሆን -ይህ ማለት-አብ-አክባሪ  -ወልድ ከባሪ -መንፈስ ቅዱስ ክብር ማለት ነው።አሁን አሁን ከሆነ በምሥጢረ ሥላሴ ትምህርትና ምስጢረ ሥላሴ መለየት ተስኖናል ይመስለኛል::በምስጢረ ሥላሴ ትምህርት ሥላሴ በክብር አንድ አንድ ናቸው ብለናል።ታዲያ ↪ ሥላሴ አብ ወልድ መንፈስ ቅዱስ በክብር አንዲት ናቸው ካልን አብ አክባሪ፣ወልድ ከባሪ መንፈስ \",\"is_correct\":false}]', '2026-06-29 01:04:15');

DROP TABLE IF EXISTS `gallery_images`;
CREATE TABLE `gallery_images` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(255) DEFAULT NULL,
  `file_path` varchar(255) NOT NULL,
  `uploaded_by` varchar(255) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
